import { useState, useEffect, useRef } from 'react';
import { View, Text, StyleSheet, Pressable, ScrollView, Dimensions, Alert } from 'react-native';
import { useLocalSearchParams, useRouter } from 'expo-router';
import { SafeAreaView } from 'react-native-safe-area-context';
import { Video, ResizeMode, AVPlaybackStatus } from 'expo-av';
import { Ionicons } from '@expo/vector-icons';
import { api } from '@/lib/api';
import { colors } from '@/lib/colors';

const { width } = Dimensions.get('window');
const VIDEO_HEIGHT = width * (16 / 9);

interface VideoData {
  id: number;
  title: string;
  duration: number;
  videoUrl: string;
  status: string;
}

interface Caption {
  start: number;
  end: number;
  originalText: string;
  viralText: string;
  words: { word: string; start: number; end: number }[];
}

interface Transcription {
  captions: Caption[];
}

export default function EditorScreen() {
  const { videoId } = useLocalSearchParams<{ videoId: string }>();
  const router = useRouter();
  const videoRef = useRef<Video>(null);

  const [video, setVideo] = useState<VideoData | null>(null);
  const [transcription, setTranscription] = useState<Transcription | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [currentCaption, setCurrentCaption] = useState<Caption | null>(null);
  const [currentWordIndex, setCurrentWordIndex] = useState(0);
  const [isExporting, setIsExporting] = useState(false);

  useEffect(() => {
    fetchData();
  }, [videoId]);

  useEffect(() => {
    if (!transcription?.captions) return;

    const activeCaption = transcription.captions.find(
      cap => currentTime >= cap.start && currentTime <= cap.end
    );
    setCurrentCaption(activeCaption || null);

    if (activeCaption) {
      const wordIdx = activeCaption.words.findIndex(
        w => currentTime >= w.start && currentTime < w.end
      );
      setCurrentWordIndex(wordIdx >= 0 ? wordIdx : 0);
    }
  }, [currentTime, transcription]);

  const fetchData = async () => {
    try {
      const [videoData, transcriptionData] = await Promise.all([
        api.getVideo(videoId),
        api.getTranscription(videoId).catch(() => null),
      ]);
      setVideo(videoData as VideoData);
      setTranscription(transcriptionData as Transcription);
    } catch (err) {
      console.error('Failed to fetch video:', err);
    }
  };

  const handlePlaybackStatusUpdate = (status: AVPlaybackStatus) => {
    if (status.isLoaded) {
      setCurrentTime(status.positionMillis / 1000);
      setIsPlaying(status.isPlaying);
    }
  };

  const togglePlayPause = async () => {
    if (!videoRef.current) return;

    if (isPlaying) {
      await videoRef.current.pauseAsync();
    } else {
      await videoRef.current.playAsync();
    }
  };

  const handleExport = async () => {
    setIsExporting(true);
    try {
      await api.exportVideo(videoId);
      Alert.alert('Success', 'Video exported successfully!', [
        { text: 'View in Library', onPress: () => router.replace('/(tabs)/library') },
        { text: 'Stay Here', style: 'cancel' },
      ]);
    } catch (err: any) {
      Alert.alert('Export Failed', err.message);
    } finally {
      setIsExporting(false);
    }
  };

  const renderCaption = () => {
    if (!currentCaption) return null;

    const words = currentCaption.words.slice(
      Math.max(0, currentWordIndex - 1),
      currentWordIndex + 4
    );

    return (
      <View style={styles.captionOverlay}>
        <View style={styles.captionContainer}>
          {words.map((word, idx) => {
            const isActive = idx === (currentWordIndex > 0 ? 1 : 0);
            return (
              <Text
                key={`${word.start}-${idx}`}
                style={[styles.captionWord, isActive && styles.captionWordActive]}
              >
                {word.word}
              </Text>
            );
          })}
        </View>
      </View>
    );
  };

  return (
    <SafeAreaView style={styles.container}>
      {/* Header */}
      <View style={styles.header}>
        <Pressable style={styles.backButton} onPress={() => router.back()}>
          <Ionicons name="chevron-back" size={24} color={colors.white} />
        </Pressable>
        <Text style={styles.headerTitle} numberOfLines={1}>
          {video?.title || 'Editor'}
        </Text>
        <Pressable 
          style={[styles.exportButton, isExporting && styles.exportButtonDisabled]}
          onPress={handleExport}
          disabled={isExporting}
        >
          <Text style={styles.exportButtonText}>
            {isExporting ? 'Exporting...' : 'Export'}
          </Text>
        </Pressable>
      </View>

      {/* Video Preview */}
      <View style={styles.videoContainer}>
        {video?.videoUrl ? (
          <Pressable style={styles.videoWrapper} onPress={togglePlayPause}>
            <Video
              ref={videoRef}
              source={{ uri: video.videoUrl }}
              style={styles.video}
              resizeMode={ResizeMode.CONTAIN}
              onPlaybackStatusUpdate={handlePlaybackStatusUpdate}
              shouldPlay={false}
            />
            {renderCaption()}
            {!isPlaying && (
              <View style={styles.playOverlay}>
                <View style={styles.playButton}>
                  <Ionicons name="play" size={32} color={colors.white} />
                </View>
              </View>
            )}
          </Pressable>
        ) : (
          <View style={styles.videoPlaceholder}>
            <Ionicons name="videocam-outline" size={48} color={colors.text.muted} />
            <Text style={styles.placeholderText}>Loading video...</Text>
          </View>
        )}
      </View>

      {/* Caption Timeline */}
      <View style={styles.timelineSection}>
        <Text style={styles.sectionTitle}>Captions</Text>
        <ScrollView style={styles.captionList}>
          {transcription?.captions?.map((caption, index) => (
            <View
              key={index}
              style={[
                styles.captionItem,
                currentCaption === caption && styles.captionItemActive,
              ]}
            >
              <Text style={styles.captionTimestamp}>
                {formatTime(caption.start)}
              </Text>
              <Text style={styles.captionText}>{caption.viralText}</Text>
            </View>
          )) || (
            <View style={styles.emptyCaptions}>
              <Text style={styles.emptyText}>No captions available</Text>
            </View>
          )}
        </ScrollView>
      </View>
    </SafeAreaView>
  );
}

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = Math.floor(seconds % 60);
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: colors.black,
  },
  header: {
    flexDirection: 'row',
    alignItems: 'center',
    paddingHorizontal: 16,
