"use server";

import { auth } from "@/auth";
import { db } from "@/db";
import { posts, clips, videos } from "@/db/schema";
import { eq, and, asc } from "drizzle-orm";
import { revalidatePath } from "next/cache";
import { writeFile, mkdir, rm } from "fs/promises";
import { join } from "path";
import ffmpeg from "fluent-ffmpeg";
import ffmpegStatic from "ffmpeg-static";

// Set ffmpeg path
if (ffmpegStatic) {
    ffmpeg.setFfmpegPath(ffmpegStatic);
}

const UPLOAD_DIR = join(process.cwd(), "public/uploads");
const VIDEO_OUTPUT_DIR = join(UPLOAD_DIR, "videos");
const TEMP_DIR = join(process.cwd(), "tmp/exports");

interface ExportSettings {
    hasCaption: boolean;
    musicStyle: string;
    clips?: { url: string;[key: string]: unknown }[];
    captionText?: string;
}

export async function exportVideo(postId: string, settings: ExportSettings) {
    const session = await auth();
    if (!session?.user?.id) throw new Error("Unauthorized");

    // 1. Ensure directories exist
    await mkdir(VIDEO_OUTPUT_DIR, { recursive: true });
    await mkdir(TEMP_DIR, { recursive: true });

    const jobDir = join(TEMP_DIR, `job-${postId}-${Date.now()}`);
    await mkdir(jobDir, { recursive: true });

    try {
        // 2. Fetch all clips for this post
        const postClips = await db.query.clips.findMany({
            where: eq(clips.postId, postId),
            orderBy: [asc(clips.recordedAt), asc(clips.createdAt)],
        });

        if (postClips.length === 0) throw new Error("No clips found for this post");

        // 3. Prepare Clip Files
        const clipPaths: string[] = [];
        for (let i = 0; i < postClips.length; i++) {
            const clip = postClips[i];
            const clipPath = join(jobDir, `clip-${i}.webm`);

            if (clip.videoData) {
                const base64Data = clip.videoData.replace(/^data:video\/\w+;base64,/, "");
                const buffer = Buffer.from(base64Data, "base64");
                await writeFile(clipPath, buffer);
            } else if (clip.url) {
                const response = await fetch(clip.url);
                const arrayBuffer = await response.arrayBuffer();
                await writeFile(clipPath, Buffer.from(arrayBuffer));
            }
            clipPaths.push(clipPath);
        }

        // 4. Merge clips with FFmpeg
        const outputFilename = `video-${postId}-${Date.now()}.mp4`;
        const outputPath = join(VIDEO_OUTPUT_DIR, outputFilename);
        const publicUrl = `/uploads/videos/${outputFilename}`;

        await new Promise((resolve, reject) => {
            let command = ffmpeg();

            clipPaths.forEach(p => {
                command = command.input(p);
            });

            command
                .on('error', (err: any) => {
                    console.error('FFmpeg Error:', err);
                    reject(err);
                })
                .on('end', () => {
                    resolve(true);
                })
                .mergeToFile(outputPath, jobDir)
                .videoFilter([
                    'scale=1080:1920:force_original_aspect_ratio=decrease',
                    'pad=1080:1920:(ow-iw)/2:(oh-ih)/2'
                ])
                .videoCodec('libx264')
                .outputOptions([
                    '-preset veryfast',
                    '-crf 24',
                    '-movflags +faststart'
                ])
                .audioCodec('aac')
                .audioBitrate('128k');
        });

        // 5. Update Post & Create Video Record
        await db.update(posts)
            .set({
                status: "completed",
                videoUrl: publicUrl,
                musicVibe: settings.musicStyle,
                caption: settings.captionText || "",
            })
            .where(and(eq(posts.id, postId), eq(posts.userId, session.user.id)));

        await db.insert(videos).values({
            userId: session.user.id,
            projectId: (postClips[0].projectId as string | null) || "",
            postId: postId,
            url: publicUrl,
            filename: outputFilename,
            status: "completed",
        });

        revalidatePath("/dashboard");
        revalidatePath(`/post/${postId}/editor`);

        return { success: true, url: publicUrl };

    } catch (err) {
        console.error("Export failed:", err);
        throw err;
    } finally {
        await rm(jobDir, { recursive: true, force: true });
    }
}

