import { memo } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { CaptionWord } from "./CaptionWord";
import type { CaptionSegment, CaptionStyle } from "@/lib/transcript/types";

interface CaptionLineProps {
  segment: CaptionSegment;
  activeWordIndex: number;
  wordProgress: number;
  style: CaptionStyle;
  lineCount: 1 | 2;
}

function CaptionLineInner({
  segment,
  activeWordIndex,
  wordProgress,
  style,
  lineCount,
}: CaptionLineProps) {
  const words = segment.words;
  const maxPerLine = Math.ceil(words.length / lineCount);

  const lines: typeof words[] = [];
  for (let i = 0; i < words.length; i += maxPerLine) {
    lines.push(words.slice(i, i + maxPerLine));
  }

  let globalIdx = 0;

  return (
    <AnimatePresence mode="wait">
      <motion.div
        key={segment.id}
        initial={{ opacity: 0, y: 12 }}
        animate={{ opacity: 1, y: 0 }}
        exit={{ opacity: 0, y: -12 }}
        transition={{ duration: 0.2, ease: "easeOut" }}
        style={{
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          gap: 4,
          lineHeight: style.lineHeight,
        }}
      >
        {lines.map((line, lineIdx) => (
          <div
            key={`${segment.id}-line-${lineIdx}`}
            style={{
              display: "flex",
              flexWrap: "wrap",
              justifyContent: "center",
              alignItems: "baseline",
            }}
          >
            {line.map((word) => {
              const idx = globalIdx++;
              const isActive = idx === activeWordIndex;
              const isPast = idx < activeWordIndex;
              return (
                <CaptionWord
                  key={word.id}
                  text={
                    style.textTransform === "uppercase"
                      ? word.text.toUpperCase()
                      : style.textTransform === "lowercase"
                        ? word.text.toLowerCase()
                        : style.textTransform === "capitalize"
                          ? word.text.charAt(0).toUpperCase() + word.text.slice(1)
                          : word.text
                  }
                  isActive={isActive}
                  isPast={isPast}
                  progress={isActive ? wordProgress : isPast ? 1 : 0}
                  style={style}
                  index={idx}
                />
              );
            })}
          </div>
        ))}
      </motion.div>
    </AnimatePresence>
  );
}

export const CaptionLine = memo(CaptionLineInner, (prev, next) => {
  return (
    prev.segment.id === next.segment.id &&
    prev.activeWordIndex === next.activeWordIndex &&
    prev.style.id === next.style.id &&
    prev.style.fontSize === next.style.fontSize &&
    prev.style.textTransform === next.style.textTransform &&
    prev.style.strokeWidth === next.style.strokeWidth &&
    prev.style.shadow === next.style.shadow &&
    prev.lineCount === next.lineCount &&
    Math.abs(prev.wordProgress - next.wordProgress) < 0.008
  );
});

