import { useQuery } from "@tanstack/react-query";
import { useState } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { 
  PlusIcon, 
  PlayCircleIcon, 
  PencilSquareIcon, 
  CalendarIcon, 
  CheckCircleIcon, 
  VideoCameraIcon, 
  ArrowTrendingUpIcon, 
  ClockIcon, 
  SparklesIcon, 
  ArrowRightIcon,
  CreditCardIcon,
  BoltIcon,
  ExclamationTriangleIcon,
} from "@heroicons/react/24/outline";
import { Link } from "wouter";
import { EditPlanChat } from "@/components/edit-plan-chat";
import { getQueryFn } from "@/lib/queryClient";
import { useAuth } from "@/hooks/useAuth";
import type { Post, ContentPlan } from "@shared/schema";

interface SubscriptionData {
  plan: string;
  status: string;
  watermarkRequired: boolean;
  aiBroll: boolean;
  aiVoice: boolean;
  maxExports: number;
  exportsUsedToday: number;
  exportAllowed: boolean;
  currentPeriodEnd?: string;
  stripeCustomerId?: string;
  cancelAtPeriodEnd?: boolean;
  billingInterval?: "monthly" | "yearly" | null;
}

interface DebugData {
  userId: string;
  projectCount: number;
  projects: Array<{ id: string; name: string; userId: string }>;
  planCount: number;
  postCount: number;
}

export default function Dashboard() {
  const { isAuthenticated, session, user } = useAuth();

  const { data: debugData } = useQuery<DebugData | null>({
    queryKey: ["/api/debug/user-data"],
    queryFn: getQueryFn({ on401: "returnNull" }),
    enabled: isAuthenticated,
  });

  const { data: contentPlan, isLoading: planLoading, error: planError, refetch: refetchPlan } = useQuery<ContentPlan | null>({
    queryKey: ["/api/content-plan"],
    queryFn: getQueryFn({ on401: "returnNull" }),
    enabled: isAuthenticated,
  });

  const { data: posts, isLoading: postsLoading, error: postsError, refetch: refetchPosts } = useQuery<Post[] | null>({
    queryKey: ["/api/posts"],
    queryFn: getQueryFn({ on401: "returnNull" }),
    enabled: isAuthenticated,
  });

  const { data: subscription, isLoading: subscriptionLoading, error: subscriptionError } = useQuery<SubscriptionData | null>({
    queryKey: ["/api/subscription"],
    queryFn: getQueryFn({ on401: "returnNull" }),
    enabled: isAuthenticated,
  });

  if (!isAuthenticated || planLoading || postsLoading) {
    return (
      <div className="p-8 lg:p-12 min-h-screen">
        <div className="max-w-7xl mx-auto space-y-10">
          <div className="space-y-2">
            <Skeleton className="h-10 w-48 bg-gray-100" />
            <Skeleton className="h-5 w-64 bg-gray-100" />
          </div>
          <div className="grid grid-cols-2 lg:grid-cols-4 gap-6">
            {[1, 2, 3, 4].map((i) => (
              <Skeleton key={i} className="h-28 rounded-3xl bg-gray-100" />
            ))}
          </div>
          <Skeleton className="h-6 w-32 bg-gray-100" />
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            {[1, 2, 3, 4].map((i) => (
              <Skeleton key={i} className="h-72 rounded-3xl bg-gray-100" />
            ))}
          </div>
        </div>
      </div>
    );
  }

  if (!contentPlan) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[85vh] p-8">
        <div className="text-center space-y-12 max-w-sm">
          <div className="space-y-8">
            <div className="h-16 w-16 rounded-3xl bg-gray-100 flex items-center justify-center mx-auto">
              <SparklesIcon className="h-7 w-7 text-[#111111]" />
            </div>
            <div className="space-y-3">
              <h1 className="text-2xl font-bold tracking-tight text-[#111111]">Welcome to Navinta AI</h1>
              <p className="text-sm text-[#666666] leading-relaxed">
                Create your personalized content plan to start producing professional videos.
              </p>
            </div>
          </div>
          <Link href="/onboarding">
            <Button size="lg" className="h-12 px-8 text-sm font-medium bg-[#3B82F6] text-white hover:bg-[#2563EB] rounded-full" data-testid="button-create-plan">
              Create Content Plan
            </Button>
          </Link>
        </div>
      </div>
    );
  }

  const allPosts = posts || [];
  const groupedPosts = groupPostsByWeek(allPosts);
  const completedCount = allPosts.filter(p => p.status === "completed").length;
  const recordingCount = allPosts.filter(p => p.status === "recording").length;
  const plannedCount = allPosts.filter(p => p.status === "planned").length;

  return (
    <div className="p-8 lg:p-12 min-h-screen">
      <div className="max-w-7xl mx-auto space-y-10">
        <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
          <div className="space-y-1">
            <h1 className="text-2xl font-bold tracking-tight text-[#111111]">Dashboard</h1>
            <p className="text-sm text-[#666666]">
              Your 4-week content calendar
            </p>
          </div>
          <div className="flex gap-3">
            {contentPlan && (
              <EditPlanChat 
                projectId={debugData?.projects?.[0]?.id || ""} 
                contentPlanId={contentPlan.id} 
              />
            )}
            <Link href="/onboarding">
              <Button variant="outline" className="gap-2 h-10 px-5 text-sm bg-white border-gray-200 text-[#111111] hover:bg-gray-50 hover:border-gray-200 rounded-full" data-testid="button-new-plan">
                <PlusIcon className="h-4 w-4" />
                New Plan
              </Button>
            </Link>
          </div>
        </div>

        <div className="grid grid-cols-2 lg:grid-cols-4 gap-5">
          <StatCard
            icon={<VideoCameraIcon className="h-5 w-5" />}
            value={allPosts.length}
            label="Total Posts"
            color="blue"
          />
          <StatCard
            icon={<CheckCircleIcon className="h-5 w-5" />}
            value={completedCount}
            label="Completed"
            color="green"
          />
          <StatCard
            icon={<PlayCircleIcon className="h-5 w-5" />}
            value={recordingCount}
            label="Recording"
            color="orange"
          />
          <StatCard
            icon={<ClockIcon className="h-5 w-5" />}
            value={plannedCount}
            label="Planned"
            color="purple"
          />
        </div>

        <PlanCard subscription={subscription} isLoading={subscriptionLoading} error={subscriptionError} />

        {contentPlan && (
          <div className="p-5 rounded-3xl bg-white border border-gray-100 shadow-sm">
            <div className="flex items-center justify-between flex-wrap gap-4">
              <div className="flex items-center gap-3">
                <div className="h-10 w-10 rounded-xl bg-gray-100 flex items-center justify-center text-[#111111]">
                  <ArrowTrendingUpIcon className="h-5 w-5" />
                </div>
                <div>
                  <h3 className="text-sm font-semibold text-[#111111]">Plan Overview</h3>
                  <p className="text-xs text-[#666666]">
                    {contentPlan.platforms.join(", ")}
                  </p>
                </div>
              </div>
              <div className="flex gap-2 flex-wrap">
                {contentPlan.contentGoals.slice(0, 3).map((goal) => (
                  <span key={goal} className="px-3 py-1.5 text-xs bg-gray-50 rounded-full text-[#666666] font-medium border border-gray-100">
                    {goal}
                  </span>
                ))}
              </div>
            </div>
          </div>
        )}

        <div className="space-y-10">
          {[1, 2, 3, 4].map((weekNum) => (
            <div key={weekNum} className="space-y-4">
              <div className="flex items-center gap-4">
                <h2 className="text-sm font-semibold text-[#111111]">Week {weekNum}</h2>
                <div className="h-px flex-1 bg-gray-100" />
                <span className="text-xs text-[#666666] font-medium">
                  {groupedPosts[weekNum]?.length || 0} posts
                </span>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-5">
                {groupedPosts[weekNum]?.map((post, postIndex) => (
                  <PostCard key={post.id} post={post} index={postIndex} />
                ))}
                {(!groupedPosts[weekNum] || groupedPosts[weekNum].length === 0) && (
                  <div className="border-dashed border-2 border-gray-200 bg-white/50 rounded-3xl h-56 flex flex-col items-center justify-center text-center">
                    <CalendarIcon className="h-10 w-10 text-[#666666]/30 mb-3" />
                    <p className="text-sm text-[#666666]/60">No posts scheduled</p>
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

function StatCard({ icon, value, label, color }: { icon: React.ReactNode; value: number; label: string; color?: string }) {
  const colorClasses = {
    blue: { bg: "bg-gray-100", text: "text-[#111111]" },
    green: { bg: "bg-[#10B981]/10", text: "text-[#10B981]" },
    orange: { bg: "bg-[#F59E0B]/10", text: "text-[#F59E0B]" },
    purple: { bg: "bg-[#8B5CF6]/10", text: "text-[#8B5CF6]" },
  };
  const colors = colorClasses[color as keyof typeof colorClasses] || colorClasses.blue;

  return (
    <div className="p-5 rounded-3xl bg-white border border-gray-100 shadow-sm hover:shadow-md transition-shadow duration-200">
      <div className="flex items-center gap-4">
        <div className={`h-11 w-11 rounded-xl ${colors.bg} flex items-center justify-center ${colors.text}`}>
          {icon}
        </div>
        <div>
          <p className="text-2xl font-bold tracking-tight text-[#111111]">{value}</p>
          <p className="text-xs text-[#666666] font-medium">{label}</p>
        </div>
      </div>
    </div>
  );
}

function PlanCard({ subscription, isLoading, error }: { subscription: SubscriptionData | null | undefined; isLoading: boolean; error: Error | null }) {
  const [billingPortalLoading, setBillingPortalLoading] = useState(false);
  const { session } = useAuth();

  const handleManageBilling = async () => {
    setBillingPortalLoading(true);
    try {
      const response = await fetch("/api/stripe/billing-portal", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${session?.access_token}`,
        },
        body: JSON.stringify({ returnUrl: "/dashboard" }),
      });
      const data = await response.json();
      if (data.url) {
        window.location.href = data.url;
      }
    } catch (err) {
      console.error("Failed to open billing portal:", err);
    } finally {
      setBillingPortalLoading(false);
    }
  };

  const planConfig: Record<string, { name: string; color: string; bgColor: string; features: string[] }> = {
    free: {
      name: "Free",
      color: "text-[#666666]",
      bgColor: "bg-gray-100",
      features: ["3 exports/day", "Watermark on videos", "Basic editing"],
    },
    starter: {
      name: "Starter",
      color: "text-[#111111]",
      bgColor: "bg-gray-100",
      features: ["10 exports/day", "No watermark", "AI B-roll"],
    },
    pro: {
      name: "Pro",
      color: "text-[#8B5CF6]",
      bgColor: "bg-[#8B5CF6]/10",
      features: ["Unlimited exports", "AI B-roll + Voice", "Priority support"],
    },
    studio: {
      name: "Studio",
      color: "text-[#F59E0B]",
      bgColor: "bg-[#F59E0B]/10",
      features: ["Unlimited exports", "All AI features", "Team collaboration"],
    },
  };

  if (isLoading) {
    return (
      <div className="p-5 rounded-3xl bg-white border border-gray-100 shadow-sm">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <Skeleton className="h-10 w-10 rounded-xl bg-gray-100" />
            <div className="space-y-2">
              <Skeleton className="h-4 w-24 bg-gray-100" />
              <Skeleton className="h-3 w-32 bg-gray-100" />
            </div>
          </div>
          <Skeleton className="h-9 w-24 rounded-full bg-gray-100" />
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="p-5 rounded-3xl bg-white border border-[#F59E0B]/30 shadow-sm">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="h-11 w-11 rounded-xl bg-[#F59E0B]/10 flex items-center justify-center text-[#F59E0B]">
              <ExclamationTriangleIcon className="h-5 w-5" />
            </div>
            <div>
              <h3 className="text-sm font-semibold text-[#111111]">Plan Status Unavailable</h3>
              <p className="text-xs text-[#666666]">Unable to load subscription info</p>
            </div>
          </div>
          <Link href="/pricing">
            <Button 
              size="sm" 
              variant="outline"
              className="h-9 px-4 text-sm bg-white border-gray-200 text-[#666666] hover:bg-gray-50 rounded-full"
            >
              View Plans
            </Button>
          </Link>
        </div>
      </div>
    );
  }

  const plan = subscription?.plan || "free";
  const config = planConfig[plan] || planConfig.free;
  const isPaid = plan !== "free";
  const exportsText = subscription?.maxExports === -1 
    ? "Unlimited" 
    : `${subscription?.exportsUsedToday || 0}/${subscription?.maxExports || 3}`;

  return (
    <div className="p-5 rounded-3xl bg-white border border-gray-100 shadow-sm">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4">
        <div className="flex items-center gap-4">
          <div className={`h-11 w-11 rounded-xl ${config.bgColor} flex items-center justify-center ${config.color}`}>
            <CreditCardIcon className="h-5 w-5" />
          </div>
          <div className="space-y-1">
            <div className="flex items-center gap-2">
              <h3 className="text-sm font-semibold text-[#111111]">Your Plan</h3>
              <span className={`px-2.5 py-0.5 text-xs font-semibold rounded-full ${config.bgColor} ${config.color}`}>
                {config.name}
              </span>
              {subscription?.status === "active" && isPaid && !subscription?.cancelAtPeriodEnd && (
                <span className="px-2 py-0.5 text-xs font-medium rounded-full bg-[#10B981]/10 text-[#10B981]">
                  Active
                </span>
              )}
              {subscription?.cancelAtPeriodEnd && (
                <span className="px-2 py-0.5 text-xs font-medium rounded-full bg-[#F59E0B]/10 text-[#F59E0B]">
                  Cancels {subscription?.currentPeriodEnd ? new Date(subscription.currentPeriodEnd).toLocaleDateString() : "at period end"}
                </span>
              )}
              {subscription?.billingInterval && (
                <span className="px-2 py-0.5 text-xs font-medium rounded-full bg-gray-100 text-[#3B82F6]">
                  {subscription.billingInterval === "yearly" ? "Annual" : "Monthly"}
                </span>
              )}
            </div>
            <div className="flex items-center gap-3 text-xs text-[#666666]">
              <span>Exports today: <strong className="text-[#111111]">{exportsText}</strong></span>
              {subscription?.watermarkRequired && (
                <span className="text-[#F59E0B]">Watermark enabled</span>
              )}
              {subscription?.aiBroll && (
                <span className="text-[#10B981] flex items-center gap-1">
                  <BoltIcon className="h-3 w-3" /> AI B-roll
                </span>
              )}
              {subscription?.aiVoice && (
                <span className="text-[#8B5CF6] flex items-center gap-1">
                  <SparklesIcon className="h-3 w-3" /> AI Voice
                </span>
              )}
            </div>
          </div>
        </div>
        <div className="flex items-center gap-3">
          {plan !== "studio" && (
            <Link href="/pricing">
              <Button 
                size="sm" 
                className="h-9 px-5 text-sm font-medium bg-[#3B82F6] text-white hover:bg-[#2563EB] rounded-full"
              >
                {isPaid ? "Upgrade" : "Upgrade Plan"}
              </Button>
            </Link>
          )}
          {isPaid && subscription?.stripeCustomerId && (
            <Button 
              variant="outline" 
              size="sm" 
              onClick={handleManageBilling}
              disabled={billingPortalLoading}
              className="h-9 px-4 text-sm bg-white border-gray-200 text-[#666666] hover:bg-gray-50 rounded-full"
            >
              {billingPortalLoading ? "Opening..." : "Manage Billing"}
            </Button>
          )}
        </div>
      </div>
    </div>
  );
}

function PostCard({ post, index }: { post: Post; index: number }) {
  const statusConfig = {
    planned: { icon: CalendarIcon, label: "Planned", color: "text-[#8B5CF6] bg-[#8B5CF6]/10" },
    recording: { icon: PlayCircleIcon, label: "Recording", color: "text-[#F59E0B] bg-[#F59E0B]/10" },
    editing: { icon: PencilSquareIcon, label: "Editing", color: "text-[#111111] bg-gray-100" },
    completed: { icon: CheckCircleIcon, label: "Completed", color: "text-[#10B981] bg-[#10B981]/10" },
    scheduled: { icon: CalendarIcon, label: "Scheduled", color: "text-[#6366F1] bg-[#6366F1]/10" },
  };

  const config = statusConfig[post.status as keyof typeof statusConfig] || statusConfig.planned;
  const StatusIcon = config.icon;

  return (
    <Link href={`/post/${post.id}`}>
      <div 
        className="group cursor-pointer p-5 rounded-3xl bg-white border border-gray-100 h-full hover:border-[#3B82F6]/30 hover:shadow-lg transition-all duration-200" 
        data-testid={`card-post-${post.id}`}
      >
        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <span className="text-xs text-[#666666] font-semibold">
              Day {post.dayNumber}
            </span>
            <div className={`inline-flex items-center gap-1.5 text-xs font-medium px-2.5 py-1 rounded-full ${config.color}`}>
              <StatusIcon className="h-3 w-3" />
              {config.label}
            </div>
          </div>
          <h3 className="text-sm font-semibold leading-snug line-clamp-2 text-[#111111] group-hover:text-[#3B82F6] transition-colors">
            {post.title}
          </h3>
          <p className="text-xs text-[#666666] line-clamp-2 leading-relaxed">
            {post.concept}
          </p>
          <div className="pt-4 border-t border-gray-100">
            <div className="flex items-center justify-between">
              <span className="text-xs text-[#666666]/70 font-medium">
                {post.shotList.length} shots
              </span>
              <span className="text-xs text-[#111111] font-medium">
                {post.platform}
              </span>
            </div>
          </div>
        </div>
      </div>
    </Link>
  );
}

function groupPostsByWeek(posts: Post[]): Record<number, Post[]> {
  return posts.reduce((acc, post) => {
    if (!acc[post.weekNumber]) {
      acc[post.weekNumber] = [];
    }
    acc[post.weekNumber].push(post);
    return acc;
  }, {} as Record<number, Post[]>);
}

