import { useEffect, useRef } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { TIMING, EASE, STAGGER, DELAY } from "@/lib/animation";
import { 
  PencilSquareIcon, 
  CalendarIcon, 
  VideoCameraIcon, 
  FilmIcon 
} from "@heroicons/react/24/outline";

gsap.registerPlugin(ScrollTrigger);

const steps = [
  {
    number: "01",
    icon: PencilSquareIcon,
    title: "Tell us about your brand",
    description: "Answer a few questions about your audience, goals, and style preferences.",
    direction: "left",
  },
  {
    number: "02",
    icon: CalendarIcon,
    title: "Get your content plan",
    description: "AI generates a week of video ideas with scripts, shots, and timing.",
    direction: "right",
  },
  {
    number: "03",
    icon: VideoCameraIcon,
    title: "Record with guidance",
    description: "Director Mode shows exactly what to say and how to frame each shot.",
    direction: "left",
  },
  {
    number: "04",
    icon: FilmIcon,
    title: "Export and publish",
    description: "Get a polished video with captions, ready for any platform.",
    direction: "right",
  },
];

export default function HowItWorksAnimated() {
  const containerRef = useRef<HTMLDivElement>(null);
  const titleRef = useRef<HTMLHeadingElement>(null);
  const spineRef = useRef<HTMLDivElement>(null);
  const spineLineRef = useRef<HTMLDivElement>(null);
  const nodesRef = useRef<(HTMLDivElement | null)[]>([]);
  const cardsRef = useRef<(HTMLDivElement | null)[]>([]);

  useEffect(() => {
    if (!containerRef.current) return;

    const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    if (prefersReducedMotion) {
      gsap.set(titleRef.current, { opacity: 1 });
      gsap.set(spineLineRef.current, { scaleY: 1 });
      gsap.set(nodesRef.current, { opacity: 1, scale: 1 });
      gsap.set(cardsRef.current, { opacity: 1, x: 0 });
      return;
    }

    const ctx = gsap.context(() => {
      gsap.set(titleRef.current, { opacity: 0, y: 40 });
      gsap.set(spineLineRef.current, { scaleY: 0, transformOrigin: "top" });
      nodesRef.current.forEach((node) => {
        gsap.set(node, { opacity: 0, scale: 0 });
      });
      cardsRef.current.forEach((card, i) => {
        const fromLeft = steps[i].direction === "left";
        gsap.set(card, { opacity: 0, x: fromLeft ? -100 : 100, y: 20, scale: 0.9 });
      });

      const tl = gsap.timeline({
        scrollTrigger: {
          trigger: containerRef.current,
          start: "top top",
          end: "+=300%",
          scrub: 1,
          pin: true,
        },
      });

      tl.to(titleRef.current, {
        opacity: 1,
        y: 0,
        duration: TIMING.SLOW,
        ease: EASE,
      }, 0);

      tl.to(titleRef.current, {
        opacity: 0,
        y: -30,
        duration: TIMING.SLOW,
        ease: EASE,
      }, 2);

      tl.to(spineLineRef.current, {
        scaleY: 1,
        duration: 8,
        ease: "linear",
      }, 2.5);

      nodesRef.current.forEach((node, i) => {
        tl.to(node, {
          opacity: 1,
          scale: 1,
          duration: TIMING.MEDIUM,
          ease: EASE,
        }, 3 + i * 2);
      });

      cardsRef.current.forEach((card, i) => {
        tl.to(card, {
          opacity: 1,
          x: 0,
          y: 0,
          scale: 1,
          duration: TIMING.SLOW,
          ease: EASE,
        }, 3.5 + i * 2);
      });

    }, containerRef);

    return () => ctx.revert();
  }, []);

  const setNodeRef = (index: number) => (el: HTMLDivElement | null) => {
    nodesRef.current[index] = el;
  };

  const setCardRef = (index: number) => (el: HTMLDivElement | null) => {
    cardsRef.current[index] = el;
  };

  return (
    <div ref={containerRef} className="h-screen w-full flex items-center justify-center relative overflow-hidden film-cut">
      <h2 
        ref={titleRef} 
        className="absolute top-1/3 left-1/2 -translate-x-1/2 text-4xl md:text-6xl font-bold text-center z-10"
      >
        How it <span className="text-[#B08A5A]">works</span>
      </h2>

      <div ref={spineRef} className="absolute left-1/2 -translate-x-1/2 h-[70%] top-[15%]">
        <div 
          ref={spineLineRef}
          className="w-px h-full bg-[#B08A5A]/30"
        />

        {steps.map((_, i) => (
          <div
            key={i}
            ref={setNodeRef(i)}
            className="absolute left-1/2 -translate-x-1/2 w-3 h-3 rounded-full bg-[#F5F1EC] border-2 border-black"
            style={{ top: `${15 + i * 23}%` }}
          />
        ))}
      </div>

      <div className="absolute left-1/2 -translate-x-1/2 h-[70%] top-[15%] w-full max-w-4xl">
        {steps.map((step, i) => (
          <div
            key={step.number}
            ref={setCardRef(i)}
            className={`absolute w-[42%] ${step.direction === "left" ? "left-0" : "right-0"}`}
            style={{ top: `${10 + i * 23}%` }}
          >
            <div className="p-5 rounded-xl border border-white/10 bg-black/50 backdrop-blur-sm hover:border-[#B08A5A]/50 transition-all duration-300 hover:scale-[1.02] cursor-glow">
              <div className="flex items-start gap-4">
                <div className="flex-shrink-0 w-10 h-10 rounded-lg border border-[#B08A5A]/30 flex items-center justify-center bg-[#B08A5A]/5">
                  <step.icon className="h-5 w-5 text-[#B08A5A]" />
                </div>
                <div className="flex-1">
                  <span className="text-[#B08A5A] text-xs font-medium">{step.number}</span>
                  <h3 className="text-base font-semibold mt-0.5 mb-1 text-[#F5F1EC]">{step.title}</h3>
                  <p className="text-[#F5F1EC]/50 text-sm leading-relaxed">{step.description}</p>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

