apps/web/app/dashboard/page.tsx.content:
import { auth } from "@/auth";
import { redirect } from "next/navigation";
import Link from "next/link";
import { db } from "@/db";
import { contentPlans, posts } from "@/db/schema";
import { eq } from "drizzle-orm";
import { Button, Card, CardContent, CardHeader, CardTitle, CardDescription, Badge } from "@repo/ui";
import { Plus, Calendar as CalendarIcon } from "lucide-react";
import { PostCard } from "@/components/post-card";
import { type Post } from "@/db/schema";

function groupPostsByWeek(postsData: Post[]): Record<number, Post[]> {
    return postsData.reduce((acc, post) => {
        if (!acc[post.weekNumber]) {
            acc[post.weekNumber] = [];
        }
        acc[post.weekNumber].push(post);
        return acc;
    }, {} as Record<number, Post[]>);
}

export default async function DashboardPage() {
    const session = await auth();

    if (!session?.user?.id) {
        redirect("/login");
    }

    // Fetch Content Plan
    const userContentPlans = await db
        .select()
        .from(contentPlans)
        .where(eq(contentPlans.userId, session.user.id));

    const contentPlan = userContentPlans[0];

    // Fetch Posts
    const userPosts = await db
        .select()
        .from(posts)
        .where(eq(posts.userId, session.user.id));

    // Loading state handling is done by Next.js loading.tsx usually, but here we await directly.

    if (!contentPlan) {
        return (
            <div className="flex flex-col items-center justify-center min-h-[60vh] p-4 text-center">
                <div className="inline-flex items-center justify-center w-20 h-20 rounded-full bg-primary/10 mb-6">
                    <CalendarIcon className="h-10 w-10 text-primary" />
                </div>
                <h2 className="text-3xl font-semibold mb-2">No Content Plan Yet</h2>
                <p className="text-muted-foreground max-w-md mb-8">
                    Let&apos;s create your personalized content strategy to get started with professional video content.
                </p>
                <Link href="/onboarding">
                    <Button size="lg">
                        <Plus className="h-5 w-5 mr-2" />
                        Create Content Plan
                    </Button>
                </Link>
            </div>
        );
    }

    const groupedPosts = groupPostsByWeek(userPosts);

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-3xl font-semibold tracking-tight">Content Calendar</h1>
                    <p className="text-muted-foreground mt-1">
                        Your 4-week personalized video plan
                    </p>
                </div>
                <Link href="/onboarding">
                    <Button variant="outline">
                        <Plus className="h-4 w-4 mr-2" />
                        New Plan
                    </Button>
                </Link>
            </div>

            <Card>
                <CardHeader>
                    <CardTitle>Plan Overview</CardTitle>
                    <CardDescription>
                        {contentPlan.platforms?.join(", ")} • {contentPlan.postFrequency}
                    </CardDescription>
                </CardHeader>
                <CardContent>
                    <div className="flex flex-wrap gap-2">
                        {contentPlan.contentGoals?.map((goal) => (
                            <Badge key={goal} variant="secondary">
                                {goal}
                            </Badge>
                        ))}
                    </div>
                </CardContent>
            </Card>

            <div className="space-y-8">
                {[1, 2, 3, 4].map((weekNum) => (
                    <div key={weekNum} className="space-y-4">
                        <h2 className="text-xl font-semibold">Week {weekNum}</h2>
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                            {groupedPosts[weekNum]?.map((post) => (
                                <PostCard key={post.id} post={post} />
                            ))}
                            {(!groupedPosts[weekNum] || groupedPosts[weekNum].length === 0) && (
                                <Card className="border-dashed bg-muted/50">
                                    <CardContent className="flex items-center justify-center h-48">
                                        <p className="text-muted-foreground text-sm">No posts scheduled</p>
                                    </CardContent>
                                </Card>
                            )}
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
}

