import { useEffect, useRef } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { TIMING, EASE, STAGGER, DELAY } from "@/lib/animation";

gsap.registerPlugin(ScrollTrigger);

export default function TheProblemSection() {
  const containerRef = useRef<HTMLDivElement>(null);
  const headlineRef = useRef<HTMLHeadingElement>(null);
  const supportRef = useRef<HTMLParagraphElement>(null);
  const lineRefs = useRef<(HTMLDivElement | null)[]>([]);
  const dotRefs = useRef<(HTMLDivElement | null)[]>([]);

  useEffect(() => {
    if (!containerRef.current) return;

    const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    if (prefersReducedMotion) {
      gsap.set([headlineRef.current, supportRef.current], { opacity: 1 });
      gsap.set(lineRefs.current, { scaleX: 1 });
      gsap.set(dotRefs.current, { opacity: 1, scale: 1 });
      return;
    }

    const ctx = gsap.context(() => {
      gsap.set(headlineRef.current, { opacity: 0, x: -200 });
      gsap.set(supportRef.current, { opacity: 0, x: 200 });
      gsap.set(lineRefs.current, { scaleX: 0, transformOrigin: "left" });
      gsap.set(dotRefs.current, { opacity: 0, scale: 0 });

      const tl = gsap.timeline({
        scrollTrigger: {
          trigger: containerRef.current,
          start: "top 70%",
          end: "bottom 30%",
          scrub: 1,
        },
      });

      tl.to(headlineRef.current, {
        opacity: 1,
        x: 0,
        duration: TIMING.SLOW,
        ease: EASE,
      }, 0);

      tl.to(supportRef.current, {
        opacity: 1,
        x: 0,
        duration: TIMING.SLOW,
        ease: EASE,
      }, TIMING.SLOW + DELAY.SHORT);

      lineRefs.current.forEach((line, i) => {
        tl.to(line, {
          scaleX: 1,
          duration: TIMING.MEDIUM,
          ease: EASE,
        }, TIMING.SLOW * 2 + DELAY.MEDIUM + i * STAGGER.NORMAL);
      });

      dotRefs.current.forEach((dot, i) => {
        tl.to(dot, {
          opacity: 1,
          scale: 1,
          duration: TIMING.FAST,
          ease: EASE,
        }, TIMING.SLOW * 2 + DELAY.LONG + i * STAGGER.TIGHT);
      });

    }, containerRef);

    return () => ctx.revert();
  }, []);

  const setLineRef = (i: number) => (el: HTMLDivElement | null) => {
    lineRefs.current[i] = el;
  };

  const setDotRef = (i: number) => (el: HTMLDivElement | null) => {
    dotRefs.current[i] = el;
  };

  return (
    <div ref={containerRef} className="min-h-screen flex items-center justify-center py-40 px-8 md:px-16 relative atmosphere-copper">
      <div ref={setDotRef(0)} className="absolute top-20 left-[10%] w-2 h-2 bg-[#B08A5A] rounded-full" />
      <div ref={setDotRef(1)} className="absolute top-32 right-[15%] w-3 h-3 bg-[#B08A5A]/60 rounded-full" />
      <div ref={setDotRef(2)} className="absolute bottom-40 left-[20%] w-2 h-2 bg-[#F5F1EC]/40 rounded-full" />
      <div ref={setDotRef(3)} className="absolute bottom-24 right-[25%] w-2 h-2 bg-[#B08A5A]/80 rounded-full" />
      <div ref={setDotRef(4)} className="absolute top-1/2 left-[5%] w-1 h-1 bg-[#F5F1EC]/60 rounded-full" />
      <div ref={setDotRef(5)} className="absolute top-1/3 right-[8%] w-2 h-2 bg-[#B08A5A]/50 rounded-full" />

      <div className="max-w-4xl mx-auto text-center space-y-8">
        <p className="emotional-phrase">This is the hard part. We make it easy.</p>
        <h2 
          ref={headlineRef}
          className="text-3xl md:text-5xl font-bold leading-tight"
        >
          Creating video content is <span className="text-[#B08A5A]">overwhelming</span>
        </h2>

        <div ref={setLineRef(0)} className="w-32 h-px bg-[#B08A5A]/50 mx-auto" />

        <p 
          ref={supportRef}
          className="text-lg md:text-xl text-white/60 max-w-2xl mx-auto leading-relaxed"
        >
          Scripts, lighting, angles, pacing, editing, captions, music. 
          You know video matters, but the process is exhausting.
        </p>

        <div ref={setLineRef(1)} className="w-24 h-px bg-[#F5F1EC]/20 mx-auto" />

        <div className="flex flex-wrap justify-center gap-4 pt-4">
          {["No time", "No equipment", "No experience", "No team"].map((item, i) => (
            <div 
              key={i}
              ref={setDotRef(6 + i)}
              className="px-4 py-2 border border-[#B08A5A]/20 rounded-full text-sm text-[#F5F1EC]/50 hover:border-[#B08A5A]/40 transition-colors"
            >
              {item}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

