"use server";

import { auth } from "@/auth";
import { db } from "@/db";
import { clips, posts } from "@/db/schema"; // Normalized table
import { eq, and, sql } from "drizzle-orm";
import { writeFile, unlink } from "fs/promises";
import { join } from "path";
import { revalidatePath } from "next/cache";

// Ensure upload directory exists (Phase 4.1: Save file safely - Local Dev)
// In prod we'd use S3, but keeping local as per instructions.
const UPLOAD_DIR = join(process.cwd(), "public/uploads");

export async function uploadClip(formData: FormData, projectId: string, postId?: string) {
    const session = await auth();
    if (!session?.user?.id) throw new Error("Unauthorized");

    const file = formData.get("file") as File;
    if (!file) throw new Error("No file uploaded");

    // Validate (Simple check)
    if (file.size > 100 * 1024 * 1024) throw new Error("File too large (Max 100MB)");

    const buffer = Buffer.from(await file.arrayBuffer());
    const uniqueName = `${Date.now()}-${Math.random().toString(36).substring(7)}-${file.name.replace(/[^a-zA-Z0-9.-]/g, "")}`;
    const filePath = join(UPLOAD_DIR, uniqueName);

    // Save to disk
    await writeFile(filePath, buffer);
    const publicUrl = `/uploads/${uniqueName}`;

    // Create DB Record
    const [newClip] = await db.insert(clips).values({
        userId: session.user.id,
        projectId: projectId,
        postId: postId || null,
        url: publicUrl,
        type: file.type.startsWith("video") ? "video" : "image",
        status: "ready", // Local files are ready immediately
        duration: 0, // Duration processing would ideally happen here or client updates it later
    }).returning();

    revalidatePath(`/post/${postId}`);
    return newClip;
}

export async function deleteClip(clipId: string) {
    const session = await auth();
    if (!session?.user?.id) throw new Error("Unauthorized");

    // Get clip to find file path
    const [clip] = await db.select().from(clips).where(and(eq(clips.id, clipId), eq(clips.userId, session.user.id)));
    if (!clip) throw new Error("Clip not found");

    // Delete from DB
    await db.delete(clips).where(eq(clips.id, clipId));

    // Delete file (Optional: Clean up storage)
    // Extract filename from URL: /uploads/filename.mp4 -> filename.mp4
    const filename = clip.url?.split("/uploads/")[1];
    if (filename) {
        try {
            await unlink(join(UPLOAD_DIR, filename));
        } catch (e) {
            console.error("Failed to delete local file", e);
        }
    }

    if (clip.postId) revalidatePath(`/post/${clip.postId}`);
}

export async function saveRecordedClip(data: {
    postId: string;
    projectId: string;
    shotId: string;
    videoData: string; // base64
    duration: number;
}) {
    const session = await auth();
    if (!session?.user?.id) throw new Error("Unauthorized");

    const [newClip] = await db.insert(clips).values({
        userId: session.user.id,
        projectId: data.projectId,
        postId: data.postId,
        shotId: data.shotId,
        videoData: data.videoData,
        duration: data.duration,
        type: "video",
        status: "ready",
        recordedAt: new Date(),
    }).returning();

    // Mark shot as completed in posts table
    await updateShotStatus(data.postId, data.shotId, true);

    revalidatePath(`/director/${data.postId}`);
    revalidatePath(`/post/${data.postId}/editor`);
    return newClip;
}

export async function updateShotStatus(postId: string, shotId: string, completed: boolean) {
    const session = await auth();
    if (!session?.user?.id) throw new Error("Unauthorized");

    const post = await db.query.posts.findFirst({
        where: eq(posts.id, postId)
    });

    if (!post) throw new Error("Post not found");

    const updatedShotList = post.shotList?.map(shot => {
        if (shot.id === shotId) {
            return { ...shot, completed };
        }
        return shot;
    });

    await db.update(posts)
        .set({ shotList: updatedShotList })
        .where(eq(posts.id, postId));

    return { success: true };
}

