import { useState } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { onboardingSchema, type OnboardingData } from "@shared/schema";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Checkbox } from "@/components/ui/checkbox";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Progress } from "@/components/ui/progress";
import { ChevronLeft, ChevronRight, Sparkles } from "lucide-react";
import { useMutation } from "@tanstack/react-query";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useLocation } from "wouter";
import { useToast } from "@/hooks/use-toast";

const STEPS = 7;

export default function Onboarding() {
  const [step, setStep] = useState(1);
  const [, setLocation] = useLocation();
  const { toast } = useToast();

  const form = useForm<OnboardingData>({
    resolver: zodResolver(onboardingSchema),
    defaultValues: {
      brandName: "",
      businessType: "",
      targetAudience: "",
      contentGoals: [],
      platforms: [],
      postFrequency: "",
      tone: "",
      primaryColor: "#3B82F6",
      secondaryColor: "",
      accentColor: "",
    },
  });

  const createPlanMutation = useMutation({
    mutationFn: (data: OnboardingData) => 
      apiRequest("POST", "/api/onboarding", data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/content-plan"] });
      queryClient.invalidateQueries({ queryKey: ["/api/posts"] });
      toast({
        title: "Content plan created!",
        description: "Your personalized 4-week plan is ready.",
      });
      setLocation("/dashboard");
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to create content plan. Please try again.",
        variant: "destructive",
      });
    },
  });

  const onSubmit = (data: OnboardingData) => {
    createPlanMutation.mutate(data);
  };

  const nextStep = async () => {
    const fieldsToValidate = getFieldsForStep(step);
    const isValid = await form.trigger(fieldsToValidate);
    if (isValid && step < STEPS) {
      setStep(step + 1);
    }
  };

  const prevStep = () => {
    if (step > 1) setStep(step - 1);
  };

  const progress = (step / STEPS) * 100;

  // Show loading overlay when generating content plan
  if (createPlanMutation.isPending) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center p-4">
        <Card className="w-full max-w-2xl mx-auto p-12">
          <div className="text-center space-y-6">
            <div className="inline-flex items-center justify-center w-20 h-20 rounded-full bg-primary/10 mb-4 animate-pulse">
              <Sparkles className="h-10 w-10 text-primary animate-spin" />
            </div>
            <div className="space-y-2">
              <h2 className="text-2xl font-semibold">Creating Your Content Plan</h2>
              <p className="text-muted-foreground">
                Our AI is crafting personalized video ideas for your business...
              </p>
            </div>
            <div className="space-y-3 max-w-md mx-auto">
              <Progress value={33} className="h-2" />
              <div className="flex items-center justify-center gap-2 text-sm text-muted-foreground">
                <div className="flex gap-1">
                  <div className="w-2 h-2 rounded-full bg-primary animate-bounce" style={{ animationDelay: "0ms" }} />
                  <div className="w-2 h-2 rounded-full bg-primary animate-bounce" style={{ animationDelay: "150ms" }} />
                  <div className="w-2 h-2 rounded-full bg-primary animate-bounce" style={{ animationDelay: "300ms" }} />
                </div>
                <span>Generating 4 weeks of content</span>
              </div>
            </div>
          </div>
        </Card>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background flex items-center justify-center p-4">
      <Card className="w-full max-w-2xl mx-auto p-8">
        <div className="mb-8">
          <div className="flex items-center justify-between mb-2">
            <h2 className="text-sm font-medium text-muted-foreground">
              Step {step} of {STEPS}
            </h2>
            <span className="text-sm font-medium">{Math.round(progress)}%</span>
          </div>
          <Progress value={progress} className="h-2" data-testid="progress-onboarding" />
        </div>

        <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-8">
          {step === 1 && (
            <div className="space-y-6">
              <div className="text-center mb-8">
                <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-primary/10 mb-4">
                  <Sparkles className="h-8 w-8 text-primary" />
                </div>
                <h1 className="text-3xl font-semibold tracking-tight mb-2">
                  Welcome to Navinta
                </h1>
                <p className="text-muted-foreground leading-relaxed">
                  Let's create your personalized content strategy in just a few steps
                </p>
              </div>

              <div className="space-y-4">
                <Label htmlFor="brandName">What's your brand name?</Label>
                <Input
                  id="brandName"
                  {...form.register("brandName")}
                  placeholder="Enter your brand or business name"
                  className="h-12 text-lg"
                  data-testid="input-brand-name"
                />
                {form.formState.errors.brandName && (
                  <p className="text-sm text-destructive">{form.formState.errors.brandName.message}</p>
                )}
              </div>

              <div className="space-y-4">
                <Label htmlFor="businessType">What type of business do you run?</Label>
                <Input
                  id="businessType"
                  {...form.register("businessType")}
                  placeholder="e.g., Fitness coaching, Coffee shop, Marketing agency"
                  className="h-12"
                  data-testid="input-business-type"
                />
                {form.formState.errors.businessType && (
                  <p className="text-sm text-destructive">{form.formState.errors.businessType.message}</p>
                )}
              </div>
            </div>
          )}

          {step === 2 && (
            <div className="space-y-6">
              <div className="space-y-2">
                <h2 className="text-2xl font-semibold">Who's your target audience?</h2>
                <p className="text-muted-foreground">
                  Help us understand who you're creating content for
                </p>
              </div>

              <div className="space-y-4">
                <Label htmlFor="targetAudience">Describe your ideal viewer</Label>
                <Input
                  id="targetAudience"
                  {...form.register("targetAudience")}
                  placeholder="e.g., Young professionals interested in fitness and wellness"
                  className="h-12"
                  data-testid="input-target-audience"
                />
                {form.formState.errors.targetAudience && (
                  <p className="text-sm text-destructive">{form.formState.errors.targetAudience.message}</p>
                )}
              </div>
            </div>
          )}

          {step === 3 && (
            <div className="space-y-6">
              <div className="space-y-2">
                <h2 className="text-2xl font-semibold">What are your content goals?</h2>
                <p className="text-muted-foreground">Select all that apply</p>
              </div>

              <div className="space-y-4">
                {["Brand Awareness", "Generate Leads", "Drive Sales", "Build Community", "Educate Audience"].map((goal) => (
                  <div key={goal} className="flex items-center space-x-3 p-4 rounded-lg border hover-elevate">
                    <Checkbox
                      id={goal}
                      checked={form.watch("contentGoals").includes(goal)}
                      onCheckedChange={(checked) => {
                        const current = form.getValues("contentGoals");
                        if (checked) {
                          form.setValue("contentGoals", [...current, goal]);
                        } else {
                          form.setValue("contentGoals", current.filter(g => g !== goal));
                        }
                      }}
                      data-testid={`checkbox-goal-${goal.toLowerCase().replace(' ', '-')}`}
                    />
                    <Label htmlFor={goal} className="flex-1 cursor-pointer font-normal">
                      {goal}
                    </Label>
                  </div>
                ))}
                {form.formState.errors.contentGoals && (
                  <p className="text-sm text-destructive">{form.formState.errors.contentGoals.message}</p>
                )}
              </div>
            </div>
          )}

          {step === 4 && (
            <div className="space-y-6">
              <div className="space-y-2">
                <h2 className="text-2xl font-semibold">Which platforms will you post on?</h2>
                <p className="text-muted-foreground">Choose your primary channels</p>
              </div>

              <div className="grid grid-cols-2 gap-4">
                {["Instagram Reels", "TikTok", "YouTube Shorts", "Facebook"].map((platform) => (
                  <div
                    key={platform}
                    className={`p-6 rounded-xl border-2 cursor-pointer transition-all ${
                      form.watch("platforms").includes(platform)
                        ? "border-primary bg-primary/5"
                        : "border-border hover-elevate"
                    }`}
                    onClick={() => {
                      const current = form.getValues("platforms");
                      if (current.includes(platform)) {
                        form.setValue("platforms", current.filter(p => p !== platform));
                      } else {
                        form.setValue("platforms", [...current, platform]);
                      }
                    }}
                    data-testid={`card-platform-${platform.toLowerCase().replace(' ', '-')}`}
                  >
                    <div className="text-center">
                      <p className="font-medium">{platform}</p>
                    </div>
                  </div>
                ))}
                {form.formState.errors.platforms && (
                  <p className="text-sm text-destructive col-span-2">{form.formState.errors.platforms.message}</p>
                )}
              </div>
            </div>
          )}

          {step === 5 && (
            <div className="space-y-6">
              <div className="space-y-2">
                <h2 className="text-2xl font-semibold">How often do you want to post?</h2>
                <p className="text-muted-foreground">Choose a sustainable cadence</p>
              </div>

              <RadioGroup
                value={form.watch("postFrequency")}
                onValueChange={(value) => form.setValue("postFrequency", value)}
              >
                {["2-3 times per week", "4-5 times per week", "Daily", "Custom"].map((frequency) => (
                  <div key={frequency} className="flex items-center space-x-3 p-4 rounded-lg border hover-elevate">
                    <RadioGroupItem value={frequency} id={frequency} data-testid={`radio-frequency-${frequency.toLowerCase().replace(/[^a-z]/g, '-')}`} />
                    <Label htmlFor={frequency} className="flex-1 cursor-pointer font-normal">
                      {frequency}
                    </Label>
                  </div>
                ))}
              </RadioGroup>
              {form.formState.errors.postFrequency && (
                <p className="text-sm text-destructive">{form.formState.errors.postFrequency.message}</p>
              )}
            </div>
          )}

          {step === 6 && (
            <div className="space-y-6">
              <div className="space-y-2">
                <h2 className="text-2xl font-semibold">What's your content tone?</h2>
                <p className="text-muted-foreground">Select the vibe that matches your brand</p>
              </div>

              <RadioGroup
                value={form.watch("tone")}
                onValueChange={(value) => form.setValue("tone", value)}
              >
                {["Professional", "Friendly & Casual", "Inspirational", "Educational", "Entertaining"].map((tone) => (
                  <div key={tone} className="flex items-center space-x-3 p-4 rounded-lg border hover-elevate">
                    <RadioGroupItem value={tone} id={tone} data-testid={`radio-tone-${tone.toLowerCase().replace(/[^a-z]/g, '-')}`} />
                    <Label htmlFor={tone} className="flex-1 cursor-pointer font-normal">
                      {tone}
                    </Label>
                  </div>
                ))}
              </RadioGroup>
              {form.formState.errors.tone && (
                <p className="text-sm text-destructive">{form.formState.errors.tone.message}</p>
              )}
            </div>
          )}

          {step === 7 && (
            <div className="space-y-6">
              <div className="space-y-2">
                <h2 className="text-2xl font-semibold">Set your brand colors</h2>
                <p className="text-muted-foreground">These will be used in your video graphics</p>
              </div>

              <div className="space-y-6">
                <div className="space-y-3">
                  <Label htmlFor="primaryColor">Primary Color</Label>
                  <div className="flex gap-4 items-center">
                    <input
                      type="color"
                      id="primaryColor"
                      {...form.register("primaryColor")}
                      className="h-16 w-28 rounded-lg cursor-pointer border-2 border-border bg-background"
                      data-testid="input-primary-color"
                      style={{ padding: "4px" }}
                    />
                    <Input
                      value={form.watch("primaryColor")}
                      onChange={(e) => form.setValue("primaryColor", e.target.value)}
                      placeholder="#3B82F6"
                      className="flex-1 h-12"
                    />
                  </div>
                  {form.formState.errors.primaryColor && (
                    <p className="text-sm text-destructive">{form.formState.errors.primaryColor.message}</p>
                  )}
                </div>

                <div className="space-y-3">
                  <Label htmlFor="secondaryColor">Secondary Color (Optional)</Label>
                  <div className="flex gap-4 items-center">
                    <input
                      type="color"
                      id="secondaryColor"
                      {...form.register("secondaryColor")}
                      className="h-16 w-28 rounded-lg cursor-pointer border-2 border-border bg-background"
                      data-testid="input-secondary-color"
                      style={{ padding: "4px" }}
                    />
                    <Input
                      value={form.watch("secondaryColor")}
                      onChange={(e) => form.setValue("secondaryColor", e.target.value)}
                      placeholder="#10B981"
                      className="flex-1 h-12"
                    />
                  </div>
                </div>

                <div className="space-y-3">
                  <Label htmlFor="accentColor">Accent Color (Optional)</Label>
                  <div className="flex gap-4 items-center">
                    <input
                      type="color"
                      id="accentColor"
                      {...form.register("accentColor")}
                      className="h-16 w-28 rounded-lg cursor-pointer border-2 border-border bg-background"
                      data-testid="input-accent-color"
                      style={{ padding: "4px" }}
                    />
                    <Input
                      value={form.watch("accentColor")}
                      onChange={(e) => form.setValue("accentColor", e.target.value)}
                      placeholder="#F59E0B"
                      className="flex-1 h-12"
                    />
                  </div>
                </div>
              </div>
            </div>
          )}

          <div className="flex justify-between pt-6 border-t">
            {step > 1 ? (
              <Button
                type="button"
                variant="outline"
                onClick={prevStep}
                data-testid="button-previous"
              >
                <ChevronLeft className="h-4 w-4 mr-2" />
                Previous
              </Button>
            ) : (
              <div />
            )}

            {step < STEPS ? (
              <Button
                type="button"
                onClick={nextStep}
                data-testid="button-next"
              >
                Next
                <ChevronRight className="h-4 w-4 ml-2" />
              </Button>
            ) : (
              <Button
                type="submit"
                disabled={createPlanMutation.isPending}
                data-testid="button-submit"
              >
                {createPlanMutation.isPending ? "Creating plan..." : "Create My Plan"}
                <Sparkles className="h-4 w-4 ml-2" />
              </Button>
            )}
          </div>
        </form>
      </Card>
    </div>
  );
}

function getFieldsForStep(step: number): (keyof OnboardingData)[] {
  switch (step) {
    case 1:
      return ["brandName", "businessType"];
    case 2:
      return ["targetAudience"];
    case 3:
      return ["contentGoals"];
    case 4:
      return ["platforms"];
    case 5:
      return ["postFrequency"];
    case 6:
      return ["tone"];
    case 7:
      return ["primaryColor"];
    default:
      return [];
  }
}

