"use client";

import { useState, useRef, useEffect, useTransition, useCallback } from "react";
import { useRouter } from "next/navigation";
import { Button, Badge } from "@repo/ui";
import { ArrowLeft, RotateCcw, Save, ChevronRight, ChevronLeft } from "lucide-react";
import { type Post } from "@/db/schema";
import { saveRecordedClip } from "@/app/actions/upload";

export function DirectorClient({ post }: { post: Post }) {
    const router = useRouter();
    const [currentShotIndex, setCurrentShotIndex] = useState(
        post.shotList.findIndex(s => !s.completed) === -1 ? 0 : post.shotList.findIndex(s => !s.completed)
    );
    const [isRecording, setIsRecording] = useState(false);
    const [recordedBlob, setRecordedBlob] = useState<Blob | null>(null);
    const [previewUrl, setPreviewUrl] = useState<string | null>(null);
    const [isSaving, startSaving] = useTransition();
    const [timer, setTimer] = useState(0);

    const videoRef = useRef<HTMLVideoElement>(null);
    const mediaRecorderRef = useRef<MediaRecorder | null>(null);
    const chunksRef = useRef<Blob[]>([]);
    const timerRef = useRef<NodeJS.Timeout | null>(null);

    const currentShot = post.shotList[currentShotIndex];

    const stopCamera = useCallback(() => {
        if (videoRef.current?.srcObject) {
            const stream = videoRef.current.srcObject as MediaStream;
            stream.getTracks().forEach(track => track.stop());
        }
    }, []);

    const setupCamera = useCallback(async () => {
        try {
            const stream = await navigator.mediaDevices.getUserMedia({
                video: {
                    facingMode: "user",
                    width: { ideal: 1080 },
                    height: { ideal: 1920 }
                },
                audio: true
            });
            if (videoRef.current) {
                videoRef.current.srcObject = stream;
            }
        } catch (err) {
            console.error("Camera access failed", err);
        }
    }, []);

    useEffect(() => {
        if (!currentShot) return;
        setupCamera();
        return () => {
            stopCamera();
        };
    }, [currentShotIndex, setupCamera, stopCamera]);

    const startRecording = () => {
        if (!videoRef.current?.srcObject) return;

        const stream = videoRef.current.srcObject as MediaStream;
        const options = { mimeType: "video/webm;codecs=vp8,opus" };
        const mediaRecorder = new MediaRecorder(stream, options);

        mediaRecorderRef.current = mediaRecorder;
        chunksRef.current = [];

        mediaRecorder.ondataavailable = (e) => {
            if (e.data.size > 0) chunksRef.current.push(e.data);
        };

        mediaRecorder.onstop = () => {
            const blob = new Blob(chunksRef.current, { type: "video/webm" });
            setRecordedBlob(blob);
            setPreviewUrl(URL.createObjectURL(blob));
            clearInterval(timerRef.current!);
        };

        mediaRecorder.start();
        setIsRecording(true);
        setTimer(0);
        timerRef.current = setInterval(() => setTimer(t => t + 1), 1000);
    };

    const stopRecording = () => {
        if (mediaRecorderRef.current && isRecording) {
            mediaRecorderRef.current.stop();
            setIsRecording(false);
        }
    };

    const handleSave = () => {
        if (!recordedBlob) return;

        startSaving(async () => {
            const reader = new FileReader();
            reader.readAsDataURL(recordedBlob);
            reader.onloadend = async () => {
                const base64data = reader.result as string;
                try {
                    await saveRecordedClip({
                        postId: post.id,
                        projectId: post.projectId,
                        shotId: currentShot.id,
                        videoData: base64data,
                        duration: timer,
                    });

                    // Proceed to next shot if available
                    if (currentShotIndex < post.shotList.length - 1) {
                        setCurrentShotIndex(prev => prev + 1);
                        setRecordedBlob(null);
                        setPreviewUrl(null);
                    } else {
                        // All shots done
                        router.push(`/post/${post.id}/editor?completed=true`);
                    }
                } catch (err) {
                    console.error("Failed to save clip", err);
                    alert("Failed to save clip");
                }
            };
        });
    };

    const handleRetake = () => {
        setRecordedBlob(null);
        setPreviewUrl(null);
        setupCamera();
    };

    if (!currentShot) return null;

    const completedShots = post.shotList.filter(s => s.completed).length;
    const totalShots = post.shotList.length;
    const progress = (completedShots / totalShots) * 100;

    return (
        <div className="flex flex-col h-screen bg-black text-white overflow-hidden">
            {/* Header */}
            <div className="flex items-center justify-between p-4 bg-zinc-900/50 backdrop-blur-md z-10">
                <Button variant="ghost" size="icon" onClick={() => router.back()}>
                    <ArrowLeft className="h-6 w-6" />
                </Button>
                <div className="text-center">
                    <h2 className="text-sm font-semibold uppercase tracking-widest text-zinc-400">Director Mode</h2>
                    <p className="text-xs truncate max-w-[200px]">{post.title}</p>
                </div>
                <div className="w-10" /> {/* Spacer */}
            </div>

            {/* Shot Info Bar */}
            <div className="bg-zinc-800 p-4 border-b border-zinc-700">
                <div className="flex items-center justify-between mb-2">
                    <span className="text-xs font-bold text-blue-400 uppercase">Shot {currentShotIndex + 1} of {totalShots}</span>
                    <Badge variant="outline" className="border-blue-400 text-blue-400 uppercase text-[10px]">
                        {currentShot.framing}
                    </Badge>
                </div>
                <h3 className="text-sm font-medium leading-tight">{currentShot.instruction}</h3>
                {currentShot.dialogue && (
                    <div className="mt-2 p-2 bg-zinc-900 rounded border-l-2 border-blue-500">
                        <p className="text-xs text-zinc-400">Dialogue:</p>
                        <p className="text-sm italic">&quot;{currentShot.dialogue}&quot;</p>
                    </div>
                )}
            </div>

            {/* Camera / Preview Area */}
            <div className="relative flex-1 bg-black flex items-center justify-center overflow-hidden">
                {previewUrl ? (
                    <video
                        src={previewUrl}
                        className="w-full h-full object-cover"
                        controls
                        autoPlay
                        playsInline
                        loop
                        muted
                    />
                ) : (
                    <>
                        <video
                            ref={videoRef}
                            autoPlay
                            playsInline
                            muted
                            className="w-full h-full object-cover scale-x-[-1]"
                        />
                        {isRecording && (
                            <div className="absolute top-8 left-8 flex items-center gap-2 px-3 py-1 bg-red-600 rounded-full animate-pulse shadow-lg">
                                <div className="w-2 h-2 rounded-full bg-white transition-opacity" />
                                <span className="text-xs font-bold font-mono">REC {new Date(timer * 1000).toISOString().substr(14, 5)}</span>
                            </div>
                        )}
                        <div className="absolute inset-0 border-[2px] border-white/20 pointer-events-none">
                            {/* Grid lines or framing guides could go here */}
                        </div>
                    </>
                )}
            </div>

            {/* Progress Bar */}
            <div className="w-full bg-zinc-800 h-1">
                <div
                    className="h-full bg-blue-500 transition-all duration-500"
                    style={{ width: `${progress}%` }}
                />
            </div>

            {/* Controls */}
            <div className="p-8 bg-zinc-900/90 backdrop-blur-xl">
                {previewUrl ? (
                    <div className="flex gap-4">
                        <Button
                            variant="secondary"
                            className="flex-1 h-14 rounded-2xl bg-zinc-800 hover:bg-zinc-700"
                            onClick={handleRetake}
                        >
                            <RotateCcw className="h-5 w-5 mr-2" />
                            Retake
                        </Button>
                        <Button
                            className="flex-1 h-14 rounded-2xl bg-blue-600 hover:bg-blue-500"
                            onClick={handleSave}
                            disabled={isSaving}
                        >
                            <Save className="h-5 w-5 mr-2" />
                            {isSaving ? "Saving..." : "Save & Next"}
                        </Button>
                    </div>
                ) : (
                    <div className="flex items-center justify-center">
                        <button
                            className={`group relative flex items-center justify-center w-20 h-20 rounded-full border-4 ${isRecording ? 'border-red-500' : 'border-white'} transition-all active:scale-95`}
                            onClick={isRecording ? stopRecording : startRecording}
                        >
                            <div className={`rounded-full ${isRecording ? 'w-8 h-8 bg-red-500 rounded-sm' : 'w-14 h-14 bg-white'} transition-all group-hover:scale-105`} />
                        </button>
                    </div>
                )}

                {/* Navigation (Manual override if needed) */}
                <div className="flex items-center justify-between mt-6 px-4 text-zinc-500">
                    <button
                        disabled={currentShotIndex === 0}
                        onClick={() => setCurrentShotIndex(i => i - 1)}
                        className="disabled:opacity-20"
                    >
                        <ChevronLeft className="h-6 w-6" />
                    </button>
                    <span className="text-[10px] font-bold uppercase tracking-widest">Controls</span>
                    <button
                        disabled={currentShotIndex === totalShots - 1}
                        onClick={() => setCurrentShotIndex(i => i + 1)}
                        className="disabled:opacity-20"
                    >
                        <ChevronRight className="h-6 w-6" />
                    </button>
                </div>
            </div>
        </div>
    );
}

