import { memo } from "react";
import { motion } from "framer-motion";
import type { CaptionStyle, HighlightMode } from "@/lib/transcript/types";

interface CaptionWordProps {
  text: string;
  isActive: boolean;
  isPast: boolean;
  progress: number;
  style: CaptionStyle;
  index: number;
}

function CaptionWordInner({
  text,
  isActive,
  isPast,
  progress,
  style,
  index,
}: CaptionWordProps) {
  const getWordColor = () => {
    if (isActive) return style.activeColor;
    if (isPast) return style.textColor;
    return style.inactiveColor;
  };

  const getTextStroke = () => {
    if (style.strokeWidth > 0) {
      return `-${style.strokeWidth}px -${style.strokeWidth}px 0 ${style.strokeColor}, ${style.strokeWidth}px -${style.strokeWidth}px 0 ${style.strokeColor}, -${style.strokeWidth}px ${style.strokeWidth}px 0 ${style.strokeColor}, ${style.strokeWidth}px ${style.strokeWidth}px 0 ${style.strokeColor}`;
    }
    return undefined;
  };

  const baseStyle: React.CSSProperties = {
    fontFamily: style.fontFamily,
    fontWeight: style.fontWeight,
    letterSpacing: style.letterSpacing,
    display: "inline-block",
    position: "relative",
    marginRight: style.wordSpacing,
    textShadow: getTextStroke()
      ? `${getTextStroke()}, ${style.shadow}`
      : style.shadow,
    whiteSpace: "pre",
    transition: "color 0.08s ease",
  };

  const renderByMode = (mode: HighlightMode) => {
    switch (mode) {
      case "word-pop":
        return (
          <motion.span
            style={{
              ...baseStyle,
              color: getWordColor(),
            }}
            animate={{
              scale: isActive ? [1, 1.15, 1.08] : 1,
              opacity: isActive ? 1 : isPast ? 0.85 : 0.45,
            }}
            transition={{
              scale: { duration: 0.18, ease: "easeOut" },
              opacity: { duration: 0.1 },
            }}
          >
            {text}
          </motion.span>
        );

      case "underline-sweep":
        return (
          <motion.span
            style={{
              ...baseStyle,
              color: isActive || isPast ? style.textColor : style.inactiveColor,
            }}
            animate={{ opacity: isActive ? 1 : isPast ? 0.85 : 0.5 }}
            transition={{ duration: 0.1 }}
          >
            {text}
            {isActive && (
              <motion.span
                style={{
                  position: "absolute",
                  bottom: -2,
                  left: 0,
                  height: 3,
                  backgroundColor: style.activeColor,
                  borderRadius: 2,
                }}
                initial={{ width: "0%" }}
                animate={{ width: `${progress * 100}%` }}
                transition={{ duration: 0.05, ease: "linear" }}
              />
            )}
            {isPast && (
              <span
                style={{
                  position: "absolute",
                  bottom: -2,
                  left: 0,
                  width: "100%",
                  height: 3,
                  backgroundColor: style.activeColor,
                  borderRadius: 2,
                  opacity: 0.5,
                }}
              />
            )}
          </motion.span>
        );

      case "pill-glow":
        return (
          <motion.span
            style={{
              ...baseStyle,
              color: isActive ? "#FFFFFF" : isPast ? style.textColor : style.inactiveColor,
              position: "relative",
              zIndex: 1,
            }}
          >
            {isActive && (
              <motion.span
                style={{
                  position: "absolute",
                  inset: "-4px -8px",
                  backgroundColor: style.activeColor,
                  borderRadius: 8,
                  zIndex: -1,
                }}
                initial={{ opacity: 0, scale: 0.8 }}
                animate={{
                  opacity: 1,
                  scale: 1,
                  boxShadow: `0 0 16px ${style.activeColor}60, 0 0 32px ${style.activeColor}30`,
                }}
                exit={{ opacity: 0, scale: 0.8 }}
                transition={{ duration: 0.12, ease: "easeOut" }}
              />
            )}
            {text}
          </motion.span>
        );

      case "karaoke-fill":
        return (
          <span
            style={{
              ...baseStyle,
              position: "relative",
              color: isPast ? style.textColor : style.inactiveColor,
            }}
          >
            {text}
            {isActive && (
              <span
                style={{
                  position: "absolute",
                  left: 0,
                  top: 0,
                  width: `${progress * 100}%`,
                  overflow: "hidden",
                  color: style.activeColor,
                  whiteSpace: "nowrap",
                }}
              >
                {text}
              </span>
            )}
          </span>
        );

      case "word-highlight":
      default:
        return (
          <motion.span
            style={{
              ...baseStyle,
              color: getWordColor(),
            }}
            animate={{
              opacity: isActive ? 1 : isPast ? 0.85 : 0.45,
              y: isActive ? -1 : 0,
            }}
            transition={{ duration: 0.1, ease: "easeOut" }}
          >
            {text}
          </motion.span>
        );
    }
  };

  return renderByMode(style.highlightMode);
}

export const CaptionWord = memo(CaptionWordInner, (prev, next) => {
  if (prev.isActive !== next.isActive || prev.isPast !== next.isPast) return false;
  if (prev.text !== next.text) return false;
  if (
    prev.style.id !== next.style.id ||
    prev.style.fontSize !== next.style.fontSize ||
    prev.style.textTransform !== next.style.textTransform ||
    prev.style.strokeWidth !== next.style.strokeWidth ||
    prev.style.shadow !== next.style.shadow
  ) return false;
  if (prev.isActive && Math.abs(prev.progress - next.progress) > 0.008) return false;
  return true;
});

