import passport from "passport";
import { Strategy as GoogleStrategy } from "passport-google-oauth20";
import type { Express, RequestHandler, Request } from "express";
import { storage } from "./storage";
import jwt from "jsonwebtoken";
import { config } from "./config";

export async function setupAuth(app: Express) {
  // Passport initialization (stateless)
  app.use(passport.initialize());

  const clientID = process.env.GOOGLE_CLIENT_ID;
  const clientSecret = process.env.GOOGLE_CLIENT_SECRET;

  if (!clientID || !clientSecret) {
    console.warn("⚠️  Google OAuth not configured - GOOGLE_CLIENT_ID and GOOGLE_CLIENT_SECRET required");
    app.get("/api/login", (req, res) => {
      res.status(503).json({ 
        error: "Google OAuth not configured",
        message: "Please add GOOGLE_CLIENT_ID and GOOGLE_CLIENT_SECRET to your secrets"
      });
    });
    return;
  }

  const registeredStrategies = new Set<string>();

  // Resolve URLs once at startup (avoid using request headers for OAuth URLs)
  // Callback URL must always be `${PUBLIC_URL}/api/auth/google/callback`.
  const resolvedPublicUrl =
    (process.env.PUBLIC_URL ? process.env.PUBLIC_URL.replace(/\/$/, "") : null) ??
    // Dev fallback if PUBLIC_URL isn't set
    (process.env.NODE_ENV === "development" ? "http://localhost:5051" : null);

  if (!resolvedPublicUrl) {
    console.warn(
      "⚠️  PUBLIC_URL is not set. Google OAuth callback URL cannot be determined.\n" +
        "   Set PUBLIC_URL (e.g. http://localhost:5051) and restart the server."
    );
  }

  const callbackURL = `${resolvedPublicUrl}/api/auth/google/callback`;

  // In local dev, always redirect back to the Vite frontend after login
  const frontendBaseUrl = "http://localhost:5173";

  console.log(`[auth] Google OAuth callback URL: ${callbackURL}`);
  console.log(`[auth] Google OAuth post-login redirect URL: ${frontendBaseUrl}/`);

  const ensureStrategy = () => {
    const strategyName = `google:${callbackURL}`;

    if (!registeredStrategies.has(strategyName)) {
      console.log(`[auth] Registering strategy for callback: ${callbackURL}`);
      passport.use(
        strategyName,
        new GoogleStrategy(
          {
            clientID: clientID!,
            clientSecret: clientSecret!,
            callbackURL,
            proxy: true, // Required for Replit's reverse proxy infrastructure
          },
          async (accessToken, refreshToken, profile, done) => {
            try {
              const email = profile.emails?.[0]?.value;
              const firstName = profile.name?.givenName || profile.displayName?.split(" ")[0];
              const lastName = profile.name?.familyName || profile.displayName?.split(" ").slice(1).join(" ");
              const profileImageUrl = profile.photos?.[0]?.value;

              await storage.upsertUser({
                id: profile.id,
                email: email || null,
                firstName: firstName || null,
                lastName: lastName || null,
                profileImageUrl: profileImageUrl || null,
              });

              const user = {
                claims: {
                  sub: profile.id,
                  email,
                  first_name: firstName,
                  last_name: lastName,
                  profile_image_url: profileImageUrl,
                },
                accessToken,
                refreshToken,
              };

              return done(null, user);
            } catch (error) {
              return done(error as Error);
            }
          }
        )
      );
      registeredStrategies.add(strategyName);
    }
    return strategyName;
  };

  app.get("/api/login", (req, res, next) => {
    const strategyName = ensureStrategy();
    console.log(`[auth] Starting login flow, callback URL: ${callbackURL}`);
    passport.authenticate(strategyName, { 
      scope: ["profile", "email"],
    })(req, res, next);
  });

  app.get(
    "/api/auth/google/callback",
    (req, res, next) => {
      console.log("Google OAuth callback hit");
      console.log(`[auth] Callback received! Query params:`, req.query);
      console.log(`[auth] Callback headers:`, {
        host: req.headers.host,
        referer: req.headers.referer,
        origin: req.headers.origin,
        'x-forwarded-host': req.headers['x-forwarded-host'],
      });
      const strategyName = ensureStrategy();
      console.log(`[auth] Using strategy: ${strategyName}`);
      passport.authenticate(strategyName, async (err: any, user: any, info: any) => {
        if (err) {
          console.error("[auth] Authentication error:", {
            message: err.message,
            code: err.code,
            stack: err.stack?.split('\n')[0], // First line of stack only
          });
          return res.redirect("/?error=auth_error");
        }
        if (!user) {
          console.error("[auth] No user returned from OAuth:", {
            info: info?.message || info?.toString() || "Unknown reason",
            strategy: strategyName,
          });
          return res.redirect("/?error=auth_failed");
        }
        try {
          // Upsert user to ensure DB has a record
          await storage.upsertUser({
            id: user.claims.sub,
            email: user.claims.email || null,
            firstName: user.claims.first_name || null,
            lastName: user.claims.last_name || null,
            profileImageUrl: user.claims.profile_image_url || null,
          });

          const token = jwt.sign(
            {
              sub: user.claims.sub,
              email: user.claims.email,
              firstName: user.claims.first_name,
              lastName: user.claims.last_name,
            },
            config.auth.jwtSecret,
            { expiresIn: "7d" }
          );

          // Set cookie for web (HttpOnly)
          res.cookie("auth_token", token, {
            httpOnly: true,
            secure: process.env.NODE_ENV === "production",
            sameSite: "lax",
            domain: process.env.NODE_ENV === "development" ? "localhost" : undefined,
            path: "/",
            maxAge: 7 * 24 * 60 * 60 * 1000,
          });

          console.log(`[auth] ✅ Login successful - User ID: ${user.claims?.sub}`);
          console.log("[auth] set-cookie:", res.getHeader("set-cookie"));

          // Redirect only (no token in URL)
          return res.redirect(`${frontendBaseUrl}/`);
        } catch (loginErr: any) {
          console.error("[auth] Login processing error:", loginErr);
          return res.redirect("/?error=login_error");
        }
      })(req, res, next);
    }
  );

  // Stateless logout: clear cookie
  app.get("/api/logout", (_req, res) => {
    res.clearCookie("auth_token", {
      httpOnly: true,
      secure: process.env.NODE_ENV === "production",
      sameSite: "lax",
      domain: process.env.NODE_ENV === "development" ? "localhost" : undefined,
    });
    res.redirect("/");
  });
}

