import { useEffect, useRef, useState, useCallback, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { Play, Pause } from "lucide-react";
import { Button } from "@/components/ui/button";

interface WordTimestamp {
  word: string;
  start: number;
  end: number;
}

interface Caption {
  start: number;
  end: number;
  originalText: string;
  viralText: string;
  useViral: boolean;
  highlightWords: string[];
  words: WordTimestamp[];
  style: {
    font: string;
    baseTextColor: string;
    outlineColor: string;
    background: string;
    highlightTextColor: string;
    highlightBackground: string;
    position: string;
    animation: string;
  };
}

interface Transcription {
  id: number;
  videoId: number;
  userId: number;
  language: string;
  duration: number;
  captions: Caption[];
  createdAt: string;
}

interface AnimatedCaptionPlayerProps {
  videoId: string;
  videoSrc: string;
  title: string;
}

// Pre-computed timing index for O(1) caption/word lookup
interface TimingIndex {
  captionAt: (time: number) => Caption | null;
  wordIndexAt: (caption: Caption, time: number) => number;
}

function buildTimingIndex(captions: Caption[]): TimingIndex {
  // Sort captions by start time for binary search
  const sortedCaptions = [...captions].sort((a, b) => a.start - b.start);

  return {
    captionAt: (time: number) => {
      // Binary search for the active caption
      let left = 0;
      let right = sortedCaptions.length - 1;

      while (left <= right) {
        const mid = Math.floor((left + right) / 2);
        const cap = sortedCaptions[mid];

        if (time >= cap.start && time <= cap.end) {
          return cap;
        } else if (time < cap.start) {
          right = mid - 1;
        } else {
          left = mid + 1;
        }
      }
      return null;
    },
    wordIndexAt: (caption: Caption, time: number) => {
      // Binary search within words
      const words = caption.words;
      let left = 0;
      let right = words.length - 1;

      while (left <= right) {
        const mid = Math.floor((left + right) / 2);
        const word = words[mid];

        if (time >= word.start && time < word.end) {
          return mid;
        } else if (time < word.start) {
          right = mid - 1;
        } else {
          left = mid + 1;
        }
      }
      // Return closest word if not exact match
      return Math.max(0, Math.min(left, words.length - 1));
    }
  };
}

export function AnimatedCaptionPlayer({ videoId, videoSrc, title }: AnimatedCaptionPlayerProps) {
  const videoRef = useRef<HTMLVideoElement>(null);
  const rafRef = useRef<number>(0);
  const lastUpdateRef = useRef<{ captionStart: number; wordIndex: number }>({ captionStart: -1, wordIndex: -1 });
  const lastProgressUpdateRef = useRef<number>(0);

  const [isPlaying, setIsPlaying] = useState(false);
  const [currentCaption, setCurrentCaption] = useState<Caption | null>(null);
  const [currentWordIndex, setCurrentWordIndex] = useState<number>(0);
  const [progress, setProgress] = useState(0);

  // Fetch transcription data
  const { data: transcription } = useQuery<Transcription>({
    queryKey: ["/api/videos", videoId, "captions"],
  });

  // Build timing index once when transcription loads
  const timingIndex = useMemo(() => {
    if (!transcription?.captions) return null;
    return buildTimingIndex(transcription.captions);
  }, [transcription]);

  // High-frequency update loop using requestAnimationFrame
  const updateCaptions = useCallback(() => {
    const video = videoRef.current;
    if (!video) return;

    const time = video.currentTime;

    // Update captions only if timing index is available
    if (timingIndex) {
      const activeCaption = timingIndex.captionAt(time);

      // Only update state if something actually changed (reduces React re-renders)
      if (activeCaption) {
        const wordIdx = timingIndex.wordIndexAt(activeCaption, time);

        if (lastUpdateRef.current.captionStart !== activeCaption.start || 
            lastUpdateRef.current.wordIndex !== wordIdx) {
          lastUpdateRef.current = { captionStart: activeCaption.start, wordIndex: wordIdx };
          setCurrentCaption(activeCaption);
          setCurrentWordIndex(wordIdx);
        }
      } else if (lastUpdateRef.current.captionStart !== -1) {
        lastUpdateRef.current = { captionStart: -1, wordIndex: -1 };
        setCurrentCaption(null);
        setCurrentWordIndex(0);
      }
    }

    // Throttle progress bar updates to ~15fps to reduce re-renders
    const now = performance.now();
    if (now - lastProgressUpdateRef.current > 66) { // ~15fps
      lastProgressUpdateRef.current = now;
      setProgress((time / (video.duration || 1)) * 100);
    }

    // Continue the loop if playing (even if timingIndex not ready yet)
    if (!video.paused) {
      rafRef.current = requestAnimationFrame(updateCaptions);
    }
  }, [timingIndex]);

  // Start/stop the animation loop based on play state
  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    const handlePlay = () => {
      setIsPlaying(true);
      cancelAnimationFrame(rafRef.current);
      rafRef.current = requestAnimationFrame(updateCaptions);
    };

    const handlePause = () => {
      setIsPlaying(false);
      cancelAnimationFrame(rafRef.current);
    };

    const handleSeeked = () => {
      // Immediately update on seek
      updateCaptions();
    };

    video.addEventListener("play", handlePlay);
    video.addEventListener("pause", handlePause);
    video.addEventListener("seeked", handleSeeked);

    // If video is already playing when timingIndex becomes available, start the loop
    if (!video.paused) {
      cancelAnimationFrame(rafRef.current);
      rafRef.current = requestAnimationFrame(updateCaptions);
    }

    return () => {
      video.removeEventListener("play", handlePlay);
      video.removeEventListener("pause", handlePause);
      video.removeEventListener("seeked", handleSeeked);
      cancelAnimationFrame(rafRef.current);
    };
  }, [updateCaptions]);

  const togglePlayPause = () => {
    const video = videoRef.current;
    if (!video) return;

    if (video.paused) {
      video.play();
    } else {
      video.pause();
    }
  };

  // Render 3-4 words with current word highlighted (sliding window)
  const renderCaptions = () => {
    if (!currentCaption || currentWordIndex < 0) return null;

    const maxWordsToShow = 4;
    const words = currentCaption.words;

    // Calculate sliding window: show current word + context
    const windowStart = Math.max(0, currentWordIndex - 1);
    const windowEnd = Math.min(words.length, windowStart + maxWordsToShow);
    const visibleWords = words.slice(windowStart, windowEnd);

    return (
      <div className="caption-container" data-testid="caption-overlay">
        <div className="caption-words">
          {visibleWords.map((word, index) => {
            const actualIndex = windowStart + index;
            const isCurrentWord = actualIndex === currentWordIndex;
            const isHighlightWord = currentCaption.highlightWords.some(hw => 
              word.word.toLowerCase().includes(hw.toLowerCase())
            );

            return (
              <span
                key={`${word.start}-${actualIndex}`}
                className={`
                  caption-word
                  ${isCurrentWord ? 'current-word pop-in' : ''}
                  ${isHighlightWord && isCurrentWord ? 'highlight-word' : ''}
                `}
                data-testid={`caption-word-${actualIndex}`}
              >
                {word.word}
              </span>
            );
          })}
        </div>
      </div>
    );
  };

  return (
    <div className="relative w-full h-full bg-black rounded-lg overflow-hidden group" data-testid="animated-caption-player">
      <video
        ref={videoRef}
        src={videoSrc}
        className="w-full h-full object-contain"
        onClick={togglePlayPause}
        data-testid="video-element"
      />

      {/* Caption Overlay */}
      {renderCaptions()}

      {/* Play/Pause Overlay */}
      {!isPlaying && (
        <div className="absolute inset-0 flex items-center justify-center bg-black/30 backdrop-blur-[1px]">
          <Button
            size="icon"
            variant="outline"
            className="h-16 w-16 rounded-full backdrop-blur-sm border-2"
            onClick={togglePlayPause}
            data-testid="button-play-pause"
          >
            {isPlaying ? (
              <Pause className="h-8 w-8" />
            ) : (
              <Play className="h-8 w-8 ml-1" />
            )}
          </Button>
        </div>
      )}

      {/* Controls Overlay (shows on hover) */}
      <div className="absolute bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-black/80 via-black/40 to-transparent opacity-0 group-hover:opacity-100 transition-opacity">
        <div className="flex items-center gap-3">
          <Button
            size="icon"
            variant="ghost"
            onClick={togglePlayPause}
            className="h-10 w-10 text-white hover:bg-white/20"
            data-testid="button-control-play-pause"
          >
            {isPlaying ? (
              <Pause className="h-5 w-5" />
            ) : (
              <Play className="h-5 w-5" />
            )}
          </Button>
          <div className="flex-1">
            <div className="h-1 bg-white/20 rounded-full overflow-hidden">
              <div
                className="h-full bg-white transition-all"
                style={{
                  width: `${progress}%`,
                }}
              />
            </div>
          </div>
        </div>
      </div>

      <style>{`
        .caption-container {
          position: absolute;
          bottom: 15%;
          left: 50%;
          transform: translateX(-50%);
          max-width: 85%;
          pointer-events: none;
          z-index: 10;
        }

        .caption-words {
          display: flex;
          flex-wrap: nowrap;
          gap: 0.3em;
          justify-content: center;
          align-items: baseline;
          font-family: 'Inter', 'SF Pro Display', -apple-system, BlinkMacSystemFont, sans-serif;
          font-weight: 800;
          font-size: clamp(28px, 6vw, 48px);
          line-height: 1.1;
          text-align: center;
          text-transform: uppercase;
          letter-spacing: -0.02em;
        }

        .caption-word {
          color: #FFFFFF;
          -webkit-text-stroke: 2px #000;
          paint-order: stroke fill;
          text-shadow: 
            3px 3px 0 #000,
            -1px -1px 0 #000,
            1px -1px 0 #000,
            -1px 1px 0 #000,
            1px 1px 0 #000;
          display: inline-block;
          transform: scale(1);
          opacity: 0.7;
          transition: transform 0.08s ease-out, opacity 0.08s ease-out, color 0.08s ease-out;
          will-change: transform, opacity;
        }

        .caption-word.current-word {
          color: #FFD700;
          opacity: 1;
          transform: scale(1.12);
          -webkit-text-stroke: 2.5px #000;
          text-shadow: 
            3px 3px 0 #000,
            -1px -1px 0 #000,
            1px -1px 0 #000,
            -1px 1px 0 #000,
            1px 1px 0 #000,
            0 0 20px rgba(255, 215, 0, 0.5);
        }

        .caption-word.highlight-word {
          color: #FF4444;
          -webkit-text-stroke: 2.5px #000;
        }

        .caption-word.pop-in {
          animation: word-pop 0.12s cubic-bezier(0.34, 1.56, 0.64, 1) forwards;
        }

        @keyframes word-pop {
          0% {
            transform: scale(0.9);
            opacity: 0.5;
          }
          100% {
            transform: scale(1.12);
            opacity: 1;
          }
        }

        /* Responsive adjustments */
        @media (max-width: 640px) {
          .caption-container {
            bottom: 12%;
            max-width: 92%;
          }
          .caption-words {
            font-size: clamp(22px, 7vw, 32px);
            gap: 0.25em;
          }
          .caption-word {
            -webkit-text-stroke: 1.5px #000;
          }
        }
      `}</style>
    </div>
  );
}

