                />
                <div className="flex justify-between text-xs text-[#666666]">
                  <span>1</span>
                  <span>4+</span>
                </div>
              </div>
            </div>

            <div className="mt-10 p-6 bg-gray-50 rounded-3xl border border-gray-200 text-center">
