import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useRoute, useLocation } from "wouter";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { Slider } from "@/components/ui/slider";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { Progress } from "@/components/ui/progress";
import { 
  ArrowLeft, 
  Download, 
  Play, 
  Pause,
  SkipBack,
  SkipForward,
  Scissors,
  Type,
  Music,
  Sparkles
} from "lucide-react";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import type { Post, Clip } from "@shared/schema";

const MUSIC_STYLES = [
  "Upbeat & Energetic",
  "Calm & Relaxing",
  "Inspirational",
  "Corporate & Professional",
  "Fun & Playful",
];

export default function Editor() {
  const [, params] = useRoute("/editor/:id");
  const [, setLocation] = useLocation();
  const postId = params?.id;
  const { toast } = useToast();

  const [hasCaption, setHasCaption] = useState(true);
  const [selectedMusic, setSelectedMusic] = useState("Upbeat & Energetic");
  const [isPlaying, setIsPlaying] = useState(false);

  const { data: post, isLoading: postLoading } = useQuery<Post>({
    queryKey: ["/api/posts", postId],
    enabled: !!postId,
  });

  const { data: clips, isLoading: clipsLoading } = useQuery<Clip[]>({
    queryKey: ["/api/clips"],
  });

  const exportMutation = useMutation({
    mutationFn: (data: { hasCaption: boolean; musicStyle: string }) =>
      apiRequest("POST", "/api/videos/export", {
        postId,
        ...data,
      }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/videos"] });
      queryClient.invalidateQueries({ queryKey: ["/api/posts"] });
      queryClient.invalidateQueries({ queryKey: ["/api/posts", postId] });
      toast({
        title: "Video exported!",
        description: "Your video is ready to download.",
      });
      setLocation("/library");
    },
    onError: () => {
      toast({
        title: "Export failed",
        description: "Unable to export video. Please try again.",
        variant: "destructive",
      });
    },
  });

  const handleExport = () => {
    exportMutation.mutate({
      hasCaption,
      musicStyle: selectedMusic,
    });
  };

  if (postLoading || clipsLoading) {
    return (
      <div className="flex justify-center p-6">
        <div className="w-full max-w-7xl space-y-6">
          <Skeleton className="h-12 w-64" />
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            <Skeleton className="lg:col-span-2 h-[600px]" />
            <Skeleton className="h-[600px]" />
          </div>
        </div>
      </div>
    );
  }

  if (!post) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <h2 className="text-2xl font-semibold mb-2">Post not found</h2>
          <Button onClick={() => setLocation("/dashboard")}>Back to Dashboard</Button>
        </div>
      </div>
    );
  }

  const postClips = clips?.filter((c) => c.postId === postId) || [];

  // Show loading overlay when exporting video
  if (exportMutation.isPending) {
    return (
      <div className="min-h-screen flex items-center justify-center p-4">
        <Card className="w-full max-w-2xl mx-auto p-12">
          <div className="text-center space-y-6">
            <div className="inline-flex items-center justify-center w-20 h-20 rounded-full bg-primary/10 mb-4 animate-pulse">
              <Sparkles className="h-10 w-10 text-primary animate-spin" />
            </div>
            <div className="space-y-2">
              <h2 className="text-2xl font-semibold">Compiling Your Video</h2>
              <p className="text-muted-foreground">
                Merging clips, adding captions and music...
              </p>
            </div>
            <div className="space-y-3 max-w-md mx-auto">
              <Progress value={66} className="h-2" />
              <div className="space-y-2 text-sm text-muted-foreground">
                <div className="flex items-center justify-center gap-2">
                  <div className="flex gap-1">
                    <div className="w-2 h-2 rounded-full bg-primary animate-bounce" style={{ animationDelay: "0ms" }} />
                    <div className="w-2 h-2 rounded-full bg-primary animate-bounce" style={{ animationDelay: "150ms" }} />
                    <div className="w-2 h-2 rounded-full bg-primary animate-bounce" style={{ animationDelay: "300ms" }} />
                  </div>
                  <span>Processing {postClips.length} clips</span>
                </div>
                {hasCaption && (
                  <p className="text-xs">Adding text overlays...</p>
                )}
                <p className="text-xs">Mixing background music...</p>
              </div>
            </div>
          </div>
        </Card>
      </div>
    );
  }

  return (
    <div className="flex justify-center p-6">
      <div className="w-full max-w-7xl space-y-6">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-4">
            <Button
              variant="ghost"
              size="icon"
              onClick={() => setLocation(`/post/${postId}`)}
              data-testid="button-back"
            >
              <ArrowLeft className="h-5 w-5" />
            </Button>
            <div>
              <h1 className="text-3xl font-semibold tracking-tight">Video Editor</h1>
              <p className="text-muted-foreground mt-1">{post.title}</p>
            </div>
          </div>
          <Button
            size="lg"
            onClick={handleExport}
            disabled={exportMutation.isPending || postClips.length === 0}
            data-testid="button-export"
          >
            <Download className="h-5 w-5 mr-2" />
            {exportMutation.isPending ? "Exporting..." : "Export Video"}
          </Button>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          <div className="lg:col-span-2 space-y-4">
          <Card>
            <CardContent className="p-0">
              <div className="relative aspect-[9/16] bg-black rounded-t-xl overflow-hidden max-w-md mx-auto">
                <div className="w-full h-full flex items-center justify-center">
                  <div className="text-center space-y-4 p-8">
                    <div className="inline-flex items-center justify-center w-20 h-20 rounded-full bg-primary/10">
                      <Play className="h-10 w-10 text-primary" />
                    </div>
                    <div>
                      <h3 className="text-white text-lg font-semibold mb-2">
                        Video Preview
                      </h3>
                      <p className="text-white/70 text-sm">
                        {postClips.length > 0
                          ? "Preview functionality coming soon"
                          : "Record clips to see preview"}
                      </p>
                    </div>
                  </div>
                </div>
              </div>

              <div className="p-4 bg-card border-t space-y-4">
                <div className="flex items-center justify-center gap-2">
                  <Button
                    size="icon"
                    variant="ghost"
                    disabled
                    data-testid="button-skip-back"
                  >
                    <SkipBack className="h-5 w-5" />
                  </Button>
                  <Button
                    size="icon"
                    variant="default"
                    className="h-12 w-12 rounded-full"
                    onClick={() => setIsPlaying(!isPlaying)}
                    disabled={postClips.length === 0}
                    data-testid="button-play-pause"
                  >
                    {isPlaying ? (
                      <Pause className="h-6 w-6" />
                    ) : (
                      <Play className="h-6 w-6" />
                    )}
                  </Button>
                  <Button
                    size="icon"
                    variant="ghost"
                    disabled
                    data-testid="button-skip-forward"
                  >
                    <SkipForward className="h-5 w-5" />
                  </Button>
                </div>

                <Slider
                  value={[0]}
                  max={100}
                  step={1}
                  disabled={postClips.length === 0}
                  className="cursor-pointer"
                />

                <div className="flex items-center justify-between text-xs text-muted-foreground font-mono">
                  <span>0:00</span>
                  <span>
                    {Math.floor(postClips.reduce((sum, c) => sum + c.duration, 0) / 60)}:
                    {(postClips.reduce((sum, c) => sum + c.duration, 0) % 60)
                      .toString()
                      .padStart(2, "0")}
                  </span>
                </div>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Scissors className="h-5 w-5" />
                Timeline
              </CardTitle>
            </CardHeader>
            <CardContent>
              {postClips.length > 0 ? (
                <div className="flex gap-2 overflow-x-auto pb-2">
                  {postClips.map((clip, index) => (
                    <div
                      key={clip.id}
                      className="flex-shrink-0 w-24 space-y-2 group"
                      data-testid={`timeline-clip-${index}`}
                    >
                      <div className="aspect-[9/16] bg-muted rounded-lg overflow-hidden border-2 border-transparent hover:border-primary transition-colors">
                        {clip.thumbnail ? (
                          <img
                            src={clip.thumbnail}
                            alt={`Clip ${index + 1}`}
                            className="w-full h-full object-cover"
                          />
                        ) : (
                          <div className="w-full h-full flex items-center justify-center">
                            <Play className="h-6 w-6 text-muted-foreground" />
                          </div>
                        )}
                      </div>
                      <div className="text-center">
                        <p className="text-xs font-medium">Clip {index + 1}</p>
                        <p className="text-xs text-muted-foreground">{clip.duration}s</p>
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="text-center py-12 text-muted-foreground">
                  <p>No clips recorded yet</p>
                </div>
              )}
            </CardContent>
          </Card>
          </div>

          <div className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Type className="h-5 w-5" />
                Captions
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex items-center justify-between">
                <Label htmlFor="captions" className="cursor-pointer">
                  Auto-generate captions
                </Label>
                <Switch
                  id="captions"
                  checked={hasCaption}
                  onCheckedChange={setHasCaption}
                  data-testid="switch-captions"
