import { useState, useRef, useCallback, useEffect } from "react";
import { CaptionOverlay } from "@/components/captions/CaptionOverlay";
import { ControlsPanel } from "@/components/captions/ControlsPanel";
import { segmentWords } from "@/lib/transcript/segmenter";
import { SAMPLE_WORDS } from "@/lib/sampleTranscript";
import type { CaptionSettings, CaptionSegment } from "@/lib/transcript/types";
import {
  PlayIcon,
  PauseIcon,
  SpeakerWaveIcon,
  SpeakerXMarkIcon,
  ArrowPathIcon,
} from "@heroicons/react/24/solid";

const ASPECT_RATIOS = {
  "9:16": { width: 360, height: 640, label: "9:16" },
  "1:1": { width: 480, height: 480, label: "1:1" },
  "16:9": { width: 640, height: 360, label: "16:9" },
} as const;

type AspectRatioKey = keyof typeof ASPECT_RATIOS;

export default function CaptionsPlayground() {
  const videoRef = useRef<HTMLVideoElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isMuted, setIsMuted] = useState(true);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [aspectRatio, setAspectRatio] = useState<AspectRatioKey>("9:16");
  const [playbackRate, setPlaybackRate] = useState(1);

  const [settings, setSettings] = useState<CaptionSettings>({
    presetId: "opus-clean",
    fontSize: 42,
    lineCount: 2,
    position: "bottom",
    safeMargin: 5,
    uppercase: false,
    stroke: true,
    shadowEnabled: true,
  });

  const segments: CaptionSegment[] = segmentWords(SAMPLE_WORDS, {
    maxWordsPerLine: 4,
    maxDuration: 3.5,
    lineCount: settings.lineCount,
  });

  const handlePlayPause = useCallback(() => {
    const video = videoRef.current;
    if (!video) return;
    if (video.paused) {
      video.play();
      setIsPlaying(true);
    } else {
      video.pause();
      setIsPlaying(false);
    }
  }, []);

  const handleSeek = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const video = videoRef.current;
    if (!video) return;
    const time = Number(e.target.value);
    video.currentTime = time;
    setCurrentTime(time);
  }, []);

  const handleRestart = useCallback(() => {
    const video = videoRef.current;
    if (!video) return;
    video.currentTime = 0;
    video.play();
    setIsPlaying(true);
    setCurrentTime(0);
  }, []);

  const handleSpeedChange = useCallback(() => {
    const speeds = [0.5, 0.75, 1, 1.25, 1.5, 2];
    const currentIdx = speeds.indexOf(playbackRate);
    const nextIdx = (currentIdx + 1) % speeds.length;
    const newRate = speeds[nextIdx];
    setPlaybackRate(newRate);
    if (videoRef.current) {
      videoRef.current.playbackRate = newRate;
    }
  }, [playbackRate]);

  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    const handleTimeUpdate = () => setCurrentTime(video.currentTime);
    const handleLoadedMetadata = () => setDuration(video.duration);
    const handlePlay = () => setIsPlaying(true);
    const handlePause = () => setIsPlaying(false);
    const handleEnded = () => setIsPlaying(false);

    video.addEventListener("timeupdate", handleTimeUpdate);
    video.addEventListener("loadedmetadata", handleLoadedMetadata);
    video.addEventListener("play", handlePlay);
    video.addEventListener("pause", handlePause);
    video.addEventListener("ended", handleEnded);

    return () => {
      video.removeEventListener("timeupdate", handleTimeUpdate);
      video.removeEventListener("loadedmetadata", handleLoadedMetadata);
      video.removeEventListener("play", handlePlay);
      video.removeEventListener("pause", handlePause);
      video.removeEventListener("ended", handleEnded);
    };
  }, []);

  const formatTime = (t: number) => {
    const m = Math.floor(t / 60);
    const s = Math.floor(t % 60);
    return `${m}:${s.toString().padStart(2, "0")}`;
  };

  const ratio = ASPECT_RATIOS[aspectRatio];

  return (
    <div className="min-h-screen bg-gray-50 p-6">
      <div className="max-w-7xl mx-auto">
        <div className="mb-6">
          <h1 className="text-2xl font-bold text-[#111111] tracking-tight">
            Caption Studio
          </h1>
          <p className="text-sm text-[#666666] mt-1">
            Professional word-by-word animated captions
          </p>
        </div>

        <div className="flex flex-col lg:flex-row gap-6">
          <div className="flex-1 space-y-4">
            <div className="flex items-center gap-3 mb-3">
              <div className="flex gap-1.5 bg-white rounded-xl border border-gray-100 p-1">
                {(Object.keys(ASPECT_RATIOS) as AspectRatioKey[]).map((key) => (
                  <button
                    key={key}
                    onClick={() => setAspectRatio(key)}
                    className={`px-3 py-1.5 text-xs font-semibold rounded-lg transition-all ${
                      aspectRatio === key
                        ? "bg-[#3B82F6] text-white"
                        : "text-[#666666] hover:text-[#111111]"
                    }`}
                  >
                    {ASPECT_RATIOS[key].label}
                  </button>
                ))}
              </div>
              <button
                onClick={handleSpeedChange}
                className="px-3 py-1.5 text-xs font-bold rounded-lg bg-white border border-gray-100 text-[#111111] hover:bg-gray-50 transition-all"
              >
                {playbackRate}x
              </button>
            </div>

            <div className="flex justify-center">
              <div
                className="relative bg-black rounded-3xl overflow-hidden shadow-2xl"
                style={{
                  width: ratio.width,
                  height: ratio.height,
                  maxWidth: "100%",
                }}
              >
                <video
                  ref={videoRef}
                  className="w-full h-full object-cover"
                  playsInline
                  muted={isMuted}
                  loop
                  preload="auto"
                >
                  <source
                    src="https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/ForBiggerBlazes.mp4"
                    type="video/mp4"
                  />
                </video>

                <CaptionOverlay
                  segments={segments}
                  videoRef={videoRef}
                  settings={settings}
                  containerWidth={ratio.width}
                  containerHeight={ratio.height}
                />

                <div
                  className="absolute inset-0 flex items-center justify-center cursor-pointer group"
                  onClick={handlePlayPause}
                >
                  {!isPlaying && (
                    <div className="w-16 h-16 rounded-full bg-white/20 backdrop-blur-sm flex items-center justify-center group-hover:bg-white/30 transition-all">
                      <PlayIcon className="w-7 h-7 text-white ml-1" />
                    </div>
                  )}
                </div>
              </div>
            </div>

            <div className="bg-white rounded-3xl border border-gray-100 p-4 shadow-sm">
              <div className="flex items-center gap-3">
                <button
                  onClick={handlePlayPause}
                  className="w-9 h-9 rounded-full bg-[#3B82F6] text-white flex items-center justify-center hover:bg-[#2563EB] transition-colors shadow-md shadow-blue-200"
                >
                  {isPlaying ? (
                    <PauseIcon className="w-4 h-4" />
                  ) : (
                    <PlayIcon className="w-4 h-4 ml-0.5" />
                  )}
                </button>

                <button
                  onClick={handleRestart}
                  className="w-8 h-8 rounded-full bg-gray-50 text-[#666666] flex items-center justify-center hover:bg-gray-100 transition-colors"
                >
                  <ArrowPathIcon className="w-4 h-4" />
                </button>

                <span className="text-xs font-mono text-[#666666] min-w-[80px]">
                  {formatTime(currentTime)} / {formatTime(duration || 0)}
                </span>

                <input
                  type="range"
                  min={0}
                  max={duration || 100}
                  step={0.1}
                  value={currentTime}
                  onChange={handleSeek}
                  className="flex-1 h-1.5 bg-[#E2E8F0] rounded-lg appearance-none cursor-pointer accent-[#3B82F6]"
                />

                <button
                  onClick={() => setIsMuted(!isMuted)}
                  className="w-8 h-8 rounded-full bg-gray-50 text-[#666666] flex items-center justify-center hover:bg-gray-100 transition-colors"
                >
                  {isMuted ? (
                    <SpeakerXMarkIcon className="w-4 h-4" />
                  ) : (
                    <SpeakerWaveIcon className="w-4 h-4" />
                  )}
                </button>
              </div>
            </div>

            <div className="bg-white rounded-3xl border border-gray-100 p-4 shadow-sm">
              <h4 className="text-xs font-semibold text-[#666666] uppercase tracking-wider mb-3">
                Transcript Timeline
              </h4>
              <div className="relative h-8 bg-[#F1F5F9] rounded-lg overflow-hidden">
                {segments.map((seg, i) => {
                  const totalDur = duration || 25;
                  const left = (seg.start / totalDur) * 100;
                  const width = ((seg.end - seg.start) / totalDur) * 100;
                  const isActive =
                    currentTime >= seg.start && currentTime <= seg.end;
                  return (
                    <div
                      key={seg.id}
                      className={`absolute top-1 bottom-1 rounded transition-colors ${
                        isActive ? "bg-[#3B82F6]" : "bg-[#93C5FD]"
                      }`}
                      style={{ left: `${left}%`, width: `${Math.max(width, 0.5)}%` }}
                      title={seg.words.map((w) => w.text).join(" ")}
                    />
                  );
                })}
                <div
                  className="absolute top-0 bottom-0 w-0.5 bg-[#EF4444] z-10"
                  style={{ left: `${(currentTime / (duration || 25)) * 100}%` }}
                />
              </div>
              <div className="flex justify-between mt-1 text-[10px] text-[#94A3B8]">
                <span>0:00</span>
                <span>{formatTime(duration || 25)}</span>
              </div>
            </div>
          </div>

          <div className="w-full lg:w-80 xl:w-96 shrink-0">
            <ControlsPanel settings={settings} onChange={setSettings} />
          </div>
        </div>
      </div>
    </div>
  );
}

