import { useState, useEffect } from 'react';
import { View, Text, ScrollView, StyleSheet, Pressable, Image, RefreshControl, Dimensions } from 'react-native';
import { useRouter } from 'expo-router';
import { SafeAreaView } from 'react-native-safe-area-context';
import { Ionicons } from '@expo/vector-icons';
import { api } from '@/lib/api';
import { colors } from '@/lib/colors';

const { width } = Dimensions.get('window');
const CARD_WIDTH = (width - 52) / 2;

interface Video {
  id: number;
  title: string;
  duration: number;
  thumbnailUrl: string;
  status: string;
  createdAt: string;
}

interface Clip {
  id: number;
  duration: number;
  videoPath: string;
  createdAt: string;
}

export default function LibraryScreen() {
  const router = useRouter();
  const [activeTab, setActiveTab] = useState<'videos' | 'clips'>('videos');
  const [videos, setVideos] = useState<Video[]>([]);
  const [clips, setClips] = useState<Clip[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);

  const fetchData = async () => {
    try {
      const [videosData, clipsData] = await Promise.all([
        api.getVideos(),
        api.getClips(),
      ]);
      setVideos(videosData as Video[]);
      setClips(clipsData as Clip[]);
    } catch (err) {
      console.error('Failed to fetch library:', err);
    } finally {
      setIsLoading(false);
      setRefreshing(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const onRefresh = () => {
    setRefreshing(true);
    fetchData();
  };

  const formatDuration = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const handleVideoPress = (videoId: number) => {
    router.push(`/editor/${videoId}`);
  };

  return (
    <SafeAreaView style={styles.container} edges={['top']}>
      <View style={styles.header}>
        <Text style={styles.title}>Library</Text>
      </View>

      {/* Tabs */}
      <View style={styles.tabs}>
        <Pressable
          style={[styles.tab, activeTab === 'videos' && styles.tabActive]}
          onPress={() => setActiveTab('videos')}
        >
          <Text style={[styles.tabText, activeTab === 'videos' && styles.tabTextActive]}>
            Videos
          </Text>
        </Pressable>
        <Pressable
          style={[styles.tab, activeTab === 'clips' && styles.tabActive]}
          onPress={() => setActiveTab('clips')}
        >
          <Text style={[styles.tabText, activeTab === 'clips' && styles.tabTextActive]}>
            Clips
          </Text>
        </Pressable>
      </View>

      <ScrollView
        style={styles.content}
        contentContainerStyle={styles.grid}
        refreshControl={
          <RefreshControl
            refreshing={refreshing}
            onRefresh={onRefresh}
            tintColor={colors.white}
          />
        }
      >
        {activeTab === 'videos' ? (
          videos.length === 0 ? (
            <View style={styles.emptyState}>
              <Ionicons name="videocam-outline" size={64} color={colors.text.muted} />
              <Text style={styles.emptyText}>No videos yet</Text>
              <Text style={styles.emptySubtext}>Your exported videos will appear here</Text>
            </View>
          ) : (
            videos.map((video) => (
              <Pressable
                key={video.id}
                style={styles.card}
                onPress={() => handleVideoPress(video.id)}
              >
                <View style={styles.thumbnail}>
                  {video.thumbnailUrl ? (
                    <Image source={{ uri: video.thumbnailUrl }} style={styles.thumbnailImage} />
                  ) : (
                    <Ionicons name="videocam" size={32} color={colors.text.muted} />
                  )}
                  <View style={styles.durationBadge}>
                    <Text style={styles.durationText}>{formatDuration(video.duration)}</Text>
                  </View>
                </View>
                <Text style={styles.cardTitle} numberOfLines={2}>{video.title}</Text>
                <Text style={styles.cardDate}>
                  {new Date(video.createdAt).toLocaleDateString()}
                </Text>
              </Pressable>
            ))
          )
        ) : (
          clips.length === 0 ? (
            <View style={styles.emptyState}>
              <Ionicons name="film-outline" size={64} color={colors.text.muted} />
              <Text style={styles.emptyText}>No clips yet</Text>
              <Text style={styles.emptySubtext}>Record your first clip to get started</Text>
            </View>
          ) : (
            clips.map((clip) => (
              <View key={clip.id} style={styles.card}>
                <View style={styles.thumbnail}>
                  <Ionicons name="film" size={32} color={colors.text.muted} />
                  <View style={styles.durationBadge}>
                    <Text style={styles.durationText}>{formatDuration(clip.duration)}</Text>
                  </View>
                </View>
                <Text style={styles.cardTitle}>Clip #{clip.id}</Text>
                <Text style={styles.cardDate}>
                  {new Date(clip.createdAt).toLocaleDateString()}
                </Text>
              </View>
            ))
          )
        )}
      </ScrollView>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: colors.black,
  },
  header: {
    paddingHorizontal: 20,
