  DialogTitle,
} from "@/components/ui/dialog";
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";
import { 
  ArrowLeftIcon,
  XMarkIcon,
  VideoCameraIcon,
  CheckCircleIcon,
  ArrowPathIcon,
  SparklesIcon,
  SpeakerWaveIcon,
  FilmIcon,
  SwatchIcon,
  MusicalNoteIcon,
  BoltIcon,
  MicrophoneIcon,
  PencilSquareIcon,
