import { useState } from "react";
import { Button } from "@/components/ui/button";
import { useAuth } from "@/hooks/useAuth";
import { Loader2 } from "lucide-react";

export type PlanId = "free" | "starter" | "pro" | "studio";
export type BillingInterval = "monthly" | "yearly";

interface PaymentButtonProps {
  planId: PlanId;
  interval: BillingInterval;
  children: React.ReactNode;
  className?: string;
  variant?: "default" | "outline" | "ghost" | "secondary" | "destructive";
  size?: "default" | "sm" | "lg" | "icon";
  disabled?: boolean;
  onSuccess?: () => void;
  onError?: (error: Error) => void;
}

export function useCheckout() {
  const [loading, setLoading] = useState<string | null>(null);
  const { session, isAuthenticated, signInWithGoogle } = useAuth();

  const checkout = async (planId: PlanId, interval: BillingInterval): Promise<boolean> => {
    if (planId === "free") {
      return true;
    }

    if (!isAuthenticated || !session?.access_token) {
      sessionStorage.setItem("pendingPlan", planId);
      sessionStorage.setItem("pendingInterval", interval);
      signInWithGoogle();
      return false;
    }

    setLoading(planId);

    try {
      const supabaseUrl = import.meta.env.VITE_SUPABASE_URL || "https://iqfrjomoggddxwteuigk.supabase.co";
      const supabaseAnonKey = import.meta.env.VITE_SUPABASE_ANON_KEY || "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImlxZnJqb21vZ2dkZHh3dGV1aWdrIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NDYwNTM5MDAsImV4cCI6MjA2MTYyOTkwMH0.VJD2Fy3F7B8s_0pRCfLOMGjRNVJMhmMNrlVcsYJXcwQ";

      const response = await fetch(`${supabaseUrl}/functions/v1/stripe-checkout`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${session.access_token}`,
          "apikey": supabaseAnonKey,
        },
        body: JSON.stringify({
          plan: planId,
          interval: interval,
        }),
      });

      const data = await response.json();

      if (data.url) {
        window.location.replace(data.url);
        return true;
      } else {
        console.error("[Checkout] No URL received:", data);
        throw new Error(data.error || "Failed to create checkout session");
      }
    } catch (error) {
      console.error("[Checkout] Error:", error);
      throw error;
    } finally {
      setLoading(null);
    }
  };

  return { checkout, loading, isAuthenticated };
}

export function PaymentButton({
  planId,
  interval,
  children,
  className,
  variant = "default",
  size = "default",
  disabled = false,
  onSuccess,
  onError,
}: PaymentButtonProps) {
  const { checkout, loading, isAuthenticated } = useCheckout();
  const { signInWithGoogle } = useAuth();
  const isLoading = loading === planId;

  const handleClick = async (e: React.MouseEvent<HTMLButtonElement>) => {
    e.preventDefault();
    e.stopPropagation();

    if (planId === "free") {
      if (isAuthenticated) {
        window.location.href = "/onboarding";
      } else {
        signInWithGoogle();
      }
      return;
    }

    if (!isAuthenticated) {
      sessionStorage.setItem("pendingPlan", planId);
      sessionStorage.setItem("pendingInterval", interval);
      signInWithGoogle();
      return;
    }

    try {
      await checkout(planId, interval);
      onSuccess?.();
    } catch (error) {
      onError?.(error as Error);
    }
  };

  return (
    <Button
      onClick={handleClick}
      disabled={disabled || isLoading}
      variant={variant}
      size={size}
      className={className}
    >
      {isLoading ? (
        <>
          <Loader2 className="w-4 h-4 mr-2 animate-spin" />
          Processing...
        </>
      ) : (
        children
      )}
    </Button>
  );
}

export async function openBillingPortal(accessToken: string): Promise<string | null> {
  try {
    const response = await fetch("/api/stripe/billing-portal", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Bearer ${accessToken}`,
      },
      body: JSON.stringify({ returnUrl: window.location.href }),
    });

    const data = await response.json();

    if (data.url) {
      window.location.href = data.url;
      return data.url;
    }

    return null;
  } catch (error) {
    console.error("[BillingPortal] Error:", error);
    return null;
  }
}

