import { useState, useEffect } from "react";
import { useLocation } from "wouter";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { LockClosedIcon, ArrowRightIcon, SparklesIcon } from "@heroicons/react/24/outline";

const ACCESS_CODE = "navintaai";
const STORAGE_KEY = "navinta_access_granted";
const PUBLIC_ROUTES = ["/privacy", "/terms", "/pricing"];

interface AccessGateProps {
  children: React.ReactNode;
}

export function AccessGate({ children }: AccessGateProps) {
  const [location] = useLocation();
  const [hasAccess, setHasAccess] = useState<boolean | null>(null);
  const [code, setCode] = useState("");
  const [error, setError] = useState("");
  const [isShaking, setIsShaking] = useState(false);

  const isPublicRoute = PUBLIC_ROUTES.some(route => location.startsWith(route));

  useEffect(() => {
    const stored = localStorage.getItem(STORAGE_KEY);
    setHasAccess(stored === "true");
  }, []);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (code.toLowerCase().trim() === ACCESS_CODE) {
      localStorage.setItem(STORAGE_KEY, "true");
      setHasAccess(true);
      setError("");
    } else {
      setError("Invalid access code");
      setIsShaking(true);
      setTimeout(() => setIsShaking(false), 500);
    }
  };

  if (hasAccess === null) {
    return (
      <div className="min-h-screen bg-white flex items-center justify-center">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-gray-300"></div>
      </div>
    );
  }

  if (hasAccess || isPublicRoute) {
    return <>{children}</>;
  }

  return (
    <div className="bg-white min-h-screen flex flex-col items-center justify-center px-6">
      <div className="w-full max-w-sm space-y-12 animate-fade-in-up">
        <div className="text-center space-y-6">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-3xl bg-gray-50 border border-gray-200">
            <LockClosedIcon className="w-7 h-7 text-[#666666]" />
          </div>

          <div className="space-y-2">
            <span className="text-[#111111] text-2xl font-bold block tracking-tight">Navinta AI</span>
            <h1 className="text-xl font-medium text-[#111111]">
              Private Beta Access
            </h1>
            <p className="text-[#666666] text-base">
              Enter your access code to continue
            </p>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className={`${isShaking ? 'animate-shake' : ''}`}>
            <Input
              type="text"
              placeholder="Enter access code"
              value={code}
              onChange={(e) => {
                setCode(e.target.value);
                setError("");
              }}
              className="h-12 bg-white border-gray-200 text-[#111111] placeholder:text-[#9CA3AF] text-center text-sm tracking-widest uppercase focus:border-[#111111] focus:ring-[#111111] rounded-full shadow-sm"
              autoFocus
            />
          </div>

          {error && (
            <p className="text-red-500 text-sm text-center">
              {error}
            </p>
          )}

          <Button
            type="submit"
            className="w-full h-12 vyro-btn-primary font-medium text-sm"
          >
            <span>Continue</span>
            <ArrowRightIcon className="w-4 h-4 ml-2" />
          </Button>
        </form>

        <div className="text-center">
          <div className="flex items-center justify-center gap-2 text-gray-400 text-xs">
            <SparklesIcon className="w-3.5 h-3.5" />
            <span>AI-powered video production</span>
          </div>
        </div>
      </div>

      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          10%, 30%, 50%, 70%, 90% { transform: translateX(-4px); }
          20%, 40%, 60%, 80% { transform: translateX(4px); }
        }
        .animate-shake {
          animation: shake 0.5s ease-in-out;
        }
        @keyframes fade-in-up {
          from {
            opacity: 0;
            transform: translateY(8px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }
        .animate-fade-in-up {
          animation: fade-in-up 0.4s ease-out;
        }
      `}</style>
    </div>
  );
}

