import { useState, useRef, useEffect } from 'react';
import { View, Text, StyleSheet, Pressable, TextInput, ScrollView, Dimensions, Animated } from 'react-native';
import { useRouter } from 'expo-router';
import { SafeAreaView } from 'react-native-safe-area-context';
import { Ionicons } from '@expo/vector-icons';
import { api } from '@/lib/api';
import { colors } from '@/lib/colors';

const { width } = Dimensions.get('window');

interface OnboardingData {
  creatorType: string;
  audience: string;
  contentGoals: string[];
  duration: string;
  emotionalResult: string;
  cameraComfort: string;
  brandName: string;
  brandPersonality: string[];
}

const STEPS = [
  { id: 'creatorType', title: 'What type of creator are you?', type: 'single' },
  { id: 'audience', title: 'Who is your audience?', type: 'text' },
  { id: 'contentGoals', title: 'What are your content goals?', type: 'multi' },
  { id: 'duration', title: 'How long should your videos be?', type: 'single' },
  { id: 'emotionalResult', title: 'How do you want viewers to feel?', type: 'single' },
  { id: 'cameraComfort', title: 'How comfortable are you on camera?', type: 'single' },
  { id: 'brandName', title: 'What\'s your brand name?', type: 'text' },
  { id: 'brandPersonality', title: 'Describe your brand personality', type: 'multi' },
];

const OPTIONS: Record<string, string[]> = {
  creatorType: ['Solo Creator', 'Business Owner', 'Influencer', 'Educator', 'Entertainer', 'Other'],
  contentGoals: ['Grow Audience', 'Build Authority', 'Drive Sales', 'Educate', 'Entertain', 'Document'],
  duration: ['15-30 seconds', '30-60 seconds', '1-3 minutes', '3-10 minutes', '10+ minutes'],
  emotionalResult: ['Inspired', 'Educated', 'Entertained', 'Motivated', 'Connected', 'Impressed'],
  cameraComfort: ['Very Comfortable', 'Somewhat Comfortable', 'Still Learning', 'Camera Shy'],
  brandPersonality: ['Professional', 'Casual', 'Fun', 'Serious', 'Energetic', 'Calm', 'Bold', 'Minimal'],
};

export default function OnboardingScreen() {
  const router = useRouter();
  const [step, setStep] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const slideAnim = useRef(new Animated.Value(0)).current;
  const fadeAnim = useRef(new Animated.Value(1)).current;

  const [data, setData] = useState<OnboardingData>({
    creatorType: '',
    audience: '',
    contentGoals: [],
    duration: '',
    emotionalResult: '',
    cameraComfort: '',
    brandName: '',
    brandPersonality: [],
  });

  useEffect(() => {
    slideAnim.setValue(width);
    fadeAnim.setValue(0);
    Animated.parallel([
      Animated.timing(slideAnim, {
        toValue: 0,
        duration: 300,
        useNativeDriver: true,
      }),
      Animated.timing(fadeAnim, {
        toValue: 1,
        duration: 300,
        useNativeDriver: true,
      }),
    ]).start();
  }, [step]);

  const currentStep = STEPS[step];
  const progress = ((step + 1) / STEPS.length) * 100;

  const handleSelect = (value: string) => {
    const key = currentStep.id as keyof OnboardingData;

    if (currentStep.type === 'multi') {
      const currentArray = data[key] as string[];
      const newArray = currentArray.includes(value)
        ? currentArray.filter(v => v !== value)
        : [...currentArray, value];
      setData(prev => ({ ...prev, [key]: newArray }));
    } else {
      setData(prev => ({ ...prev, [key]: value }));
      if (step < STEPS.length - 1) {
        setTimeout(() => setStep(s => s + 1), 300);
      }
    }
  };

  const handleTextChange = (value: string) => {
    const key = currentStep.id as keyof OnboardingData;
    setData(prev => ({ ...prev, [key]: value }));
  };

  const handleNext = () => {
    if (step < STEPS.length - 1) {
      setStep(s => s + 1);
    } else {
      handleSubmit();
    }
  };

  const handleBack = () => {
    if (step > 0) {
      setStep(s => s - 1);
    } else {
      router.back();
    }
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      await api.submitOnboarding({
        brandName: data.brandName,
        brandPersonality: data.brandPersonality.join(', '),
        creatorType: data.creatorType,
        targetAudience: data.audience,
        contentGoals: data.contentGoals.join(', '),
        videoDuration: data.duration,
        desiredEmotion: data.emotionalResult,
        cameraComfort: data.cameraComfort,
      });
      router.replace('/(tabs)/dashboard');
    } catch (err: any) {
      console.error('Onboarding error:', err);
      router.replace('/(tabs)/dashboard');
    } finally {
      setIsSubmitting(false);
    }
  };

  const canProceed = () => {
    const key = currentStep.id as keyof OnboardingData;
    const value = data[key];
    if (Array.isArray(value)) return value.length > 0;
    return value.length > 0;
  };

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.header}>
        <Pressable style={styles.backButton} onPress={handleBack}>
          <Ionicons name="chevron-back" size={24} color={colors.white} />
        </Pressable>
        <View style={styles.progressContainer}>
          <View style={[styles.progressBar, { width: `${progress}%` }]} />
        </View>
        <Text style={styles.stepIndicator}>{step + 1}/{STEPS.length}</Text>
      </View>

      <Animated.View 
        style={[
          styles.content,
          {
            opacity: fadeAnim,
            transform: [{ translateX: slideAnim }],
          }
        ]}
      >
        <Text style={styles.title}>{currentStep.title}</Text>

        {currentStep.type === 'text' ? (
          <TextInput
            style={styles.textInput}
            value={data[currentStep.id as keyof OnboardingData] as string}
            onChangeText={handleTextChange}
            placeholder="Type your answer..."
            placeholderTextColor={colors.text.muted}
            autoFocus
          />
        ) : (
          <ScrollView style={styles.optionsContainer} showsVerticalScrollIndicator={false}>
            <View style={styles.optionsGrid}>
              {OPTIONS[currentStep.id]?.map((option) => {
                const isSelected = currentStep.type === 'multi'
                  ? (data[currentStep.id as keyof OnboardingData] as string[]).includes(option)
                  : data[currentStep.id as keyof OnboardingData] === option;

                return (
                  <Pressable
                    key={option}
                    style={[styles.optionButton, isSelected && styles.optionButtonSelected]}
                    onPress={() => handleSelect(option)}
                  >
                    <Text style={[styles.optionText, isSelected && styles.optionTextSelected]}>
                      {option}
                    </Text>
                    {isSelected && (
                      <Ionicons name="checkmark-circle" size={20} color={colors.accent} />
                    )}
                  </Pressable>
                );
              })}
            </View>
          </ScrollView>
        )}
      </Animated.View>

      <View style={styles.footer}>
        {(currentStep.type === 'multi' || currentStep.type === 'text') && (
          <Pressable
            style={[styles.nextButton, !canProceed() && styles.nextButtonDisabled]}
            onPress={handleNext}
            disabled={!canProceed() || isSubmitting}
          >
            <Text style={styles.nextButtonText}>
              {isSubmitting ? 'Creating Plan...' : step === STEPS.length - 1 ? 'Create My Plan' : 'Continue'}
            </Text>
          </Pressable>
        )}
      </View>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: colors.black,
  },
  header: {
    flexDirection: 'row',
    alignItems: 'center',
    paddingHorizontal: 16,
    paddingVertical: 12,
    gap: 12,
  },
  backButton: {
    width: 40,
    height: 40,
    alignItems: 'center',
    justifyContent: 'center',
  },
  progressContainer: {
    flex: 1,
    height: 4,
    backgroundColor: colors.background.elevated,
    borderRadius: 2,
    overflow: 'hidden',
  },
  progressBar: {
    height: '100%',
    backgroundColor: colors.accent,
    borderRadius: 2,
  },
  stepIndicator: {
    fontSize: 14,
    fontFamily: 'Inter-Medium',
    color: colors.text.muted,
    minWidth: 40,
    textAlign: 'right',
  },
  content: {
    flex: 1,
    paddingHorizontal: 24,
    paddingTop: 40,
  },
  title: {
    fontSize: 28,
    fontFamily: 'Inter-Bold',
    color: colors.white,
    marginBottom: 32,
  },
  textInput: {
    fontSize: 20,
    fontFamily: 'Inter-Regular',
    color: colors.white,
    borderBottomWidth: 2,
    borderBottomColor: colors.accent,
    paddingVertical: 16,
  },
  optionsContainer: {
    flex: 1,
  },
  optionsGrid: {
    gap: 12,
    paddingBottom: 24,
  },
  optionButton: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'space-between',
    backgroundColor: colors.background.elevated,
    borderWidth: 1,
    borderColor: colors.border.default,
    borderRadius: 16,
    paddingHorizontal: 24,
    paddingVertical: 20,
  },
  optionButtonSelected: {
    borderColor: colors.accent,
    backgroundColor: 'rgba(19, 91, 236, 0.1)',
  },
  optionText: {
    fontSize: 16,
    fontFamily: 'Inter-Medium',
    color: colors.white,
  },
  optionTextSelected: {
    color: colors.white,
  },
  footer: {
    padding: 24,
  },
  nextButton: {
    backgroundColor: colors.white,
    borderRadius: 16,
    paddingVertical: 18,
    alignItems: 'center',
  },
  nextButtonDisabled: {
    opacity: 0.5,
  },
  nextButtonText: {
    fontSize: 16,
    fontFamily: 'Inter-SemiBold',
    color: colors.black,
  },
});

