import { useState, useEffect } from 'react';
import { View, Text, ScrollView, StyleSheet, Pressable, RefreshControl } from 'react-native';
import { useRouter } from 'expo-router';
import { SafeAreaView } from 'react-native-safe-area-context';
import { Ionicons } from '@expo/vector-icons';
import { api } from '@/lib/api';
import { colors } from '@/lib/colors';

interface Post {
  id: number;
  title: string;
  scheduledDate: string;
  status: string;
  shots: { id: number; title: string }[];
}

interface Project {
  id: number;
  name: string;
  createdAt: string;
}

export default function DashboardScreen() {
  const router = useRouter();
  const [posts, setPosts] = useState<Post[]>([]);
  const [projects, setProjects] = useState<Project[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);

  const fetchData = async () => {
    try {
      const [postsData, projectsData] = await Promise.all([
        api.getPosts(),
        api.getProjects(),
      ]);
      setPosts(postsData as Post[]);
      setProjects(projectsData as Project[]);
    } catch (err) {
      console.error('Failed to fetch data:', err);
    } finally {
      setIsLoading(false);
      setRefreshing(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const onRefresh = () => {
    setRefreshing(true);
    fetchData();
  };

  const handlePostPress = (postId: number) => {
    router.push(`/director/${postId}`);
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'completed': return colors.success;
      case 'in_progress': return colors.accent;
      case 'scheduled': return colors.warning;
      default: return colors.text.muted;
    }
  };

  return (
    <SafeAreaView style={styles.container} edges={['top']}>
      <View style={styles.header}>
        <Text style={styles.title}>Dashboard</Text>
        <Pressable style={styles.addButton} onPress={() => router.push('/onboarding')}>
          <Ionicons name="add" size={24} color={colors.black} />
        </Pressable>
      </View>

      <ScrollView
        style={styles.content}
        refreshControl={
          <RefreshControl
            refreshing={refreshing}
            onRefresh={onRefresh}
            tintColor={colors.white}
          />
        }
      >
        {/* Upcoming Content */}
        <View style={styles.section}>
          <Text style={styles.sectionTitle}>Content Calendar</Text>

          {posts.length === 0 ? (
            <View style={styles.emptyState}>
              <Ionicons name="calendar-outline" size={48} color={colors.text.muted} />
              <Text style={styles.emptyText}>No content scheduled</Text>
              <Text style={styles.emptySubtext}>Create your first content plan</Text>
            </View>
          ) : (
            posts.map((post) => (
              <Pressable
                key={post.id}
                style={styles.postCard}
                onPress={() => handlePostPress(post.id)}
              >
                <View style={styles.postHeader}>
                  <Text style={styles.postTitle}>{post.title}</Text>
                  <View style={[styles.statusDot, { backgroundColor: getStatusColor(post.status) }]} />
                </View>
                <Text style={styles.postDate}>
                  {new Date(post.scheduledDate).toLocaleDateString('en-US', {
                    weekday: 'short',
                    month: 'short',
                    day: 'numeric',
                  })}
                </Text>
                <View style={styles.shotsPreview}>
                  <Ionicons name="videocam-outline" size={14} color={colors.text.muted} />
                  <Text style={styles.shotsCount}>{post.shots?.length || 0} shots</Text>
                </View>
              </Pressable>
            ))
          )}
        </View>

        {/* Recent Projects */}
        <View style={styles.section}>
          <Text style={styles.sectionTitle}>Recent Projects</Text>

          {projects.length === 0 ? (
            <View style={styles.emptyState}>
              <Ionicons name="folder-outline" size={48} color={colors.text.muted} />
              <Text style={styles.emptyText}>No projects yet</Text>
            </View>
          ) : (
            <ScrollView horizontal showsHorizontalScrollIndicator={false}>
              {projects.slice(0, 5).map((project) => (
                <View key={project.id} style={styles.projectCard}>
                  <Text style={styles.projectName}>{project.name}</Text>
                  <Text style={styles.projectDate}>
                    {new Date(project.createdAt).toLocaleDateString()}
                  </Text>
                </View>
              ))}
            </ScrollView>
          )}
        </View>
      </ScrollView>
    </SafeAreaView>
  );
}

