"use server"

import { auth } from "@/auth";
import { db } from "@/db";
import { transcriptions, videos } from "@/db/schema";
import { eq } from "drizzle-orm";
import { OpenAI } from "openai";
import { mkdir, rm, readFile } from "fs/promises";
import { join } from "path";
import ffmpeg from "fluent-ffmpeg";
import ffmpegStatic from "ffmpeg-static";
import { revalidatePath } from "next/cache";

if (ffmpegStatic) {
    ffmpeg.setFfmpegPath(ffmpegStatic);
}

const openai = new OpenAI({
    apiKey: process.env.OPENAI_API_KEY || "fallback",
});

const TEMP_DIR = join(process.cwd(), "tmp/captions");

const HIGHLIGHT_WORDS = {
    emotion: ["crazy", "insane", "wild", "unreal", "amazing", "incredible", "shocking"],
    money: ["broke", "million", "profit", "rich", "cash", "dollars", "free"],
    urgency: ["now", "today", "instantly", "fast", "quick", "hurry", "limited"]
};

const CAPTION_STYLE = {
    font: "bold sans-serif uppercase",
    baseTextColor: "white",
    outlineColor: "black",
    background: "rgba(0, 0, 0, 0.6)",
    highlightTextColor: "#FFD700",
    position: "bottom_center",
    animation: "pop"
};

interface WhisperWord {
    word: string;
    start: number;
    end: number;
}

interface WhisperTranscription {
    language: string;
    duration: number;
    words: WhisperWord[];
    text: string;
}

export async function generateCaptions(videoId: string) {
    const session = await auth();
    if (!session?.user?.id) throw new Error("Unauthorized");

    if (!process.env.OPENAI_API_KEY) {
        return generateMockCaptions(videoId, session.user.id);
    }

    const video = await db.query.videos.findFirst({
        where: eq(videos.id, videoId)
    });
    if (!video) throw new Error("Video not found");

    const jobDir = join(TEMP_DIR, `job-${videoId}-${Date.now()}`);
    await mkdir(jobDir, { recursive: true });

    const videoLocalPath = join(process.cwd(), "public", video.url);
    const audioPath = join(jobDir, "audio.wav");

    try {
        await new Promise((resolve, reject) => {
            ffmpeg(videoLocalPath)
                .outputOptions(["-vn", "-acodec pcm_s16le", "-ar 16000", "-ac 1"])
                .save(audioPath)
                .on("end", resolve)
                .on("error", reject);
        });

        const transcriptionResult = await openai.audio.transcriptions.create({
            file: await (async () => {
                const buffer = await readFile(audioPath);
                return buffer as unknown as File;
            })(),
            model: "whisper-1",
            response_format: "verbose_json",
            timestamp_granularities: ["segment", "word"]
        }) as unknown as WhisperTranscription;

        const words = transcriptionResult.words || [];
        const chunks = [];
        let currentChunkWords: WhisperWord[] = [];

        for (let i = 0; i < words.length; i++) {
            currentChunkWords.push(words[i]);
            if (currentChunkWords.length >= 3 || i === words.length - 1) {
                const originalText = currentChunkWords.map(w => w.word).join(" ");
                const viralResponse = await openai.chat.completions.create({
                    model: "gpt-4o-mini",
                    messages: [
                        { role: "system", content: "You are a viral content expert. Rewrite captions to be punchy, engaging, and viral-worthy (max 10 words). Only return the rewritten text." },
                        { role: "user", content: originalText }
                    ],
                    max_tokens: 50,
                    temperature: 0.8
                });

                const viralText = viralResponse.choices[0].message.content?.trim() || originalText;
                const highlightWordsFound = viralText.toLowerCase().split(/\W+/).filter(w =>
                    HIGHLIGHT_WORDS.emotion.includes(w) || HIGHLIGHT_WORDS.money.includes(w) || HIGHLIGHT_WORDS.urgency.includes(w)
                );

                chunks.push({
                    start: currentChunkWords[0].start,
                    end: currentChunkWords[currentChunkWords.length - 1].end,
                    originalText,
                    viralText,
                    useViral: true,
                    highlightWords: highlightWordsFound,
                    words: currentChunkWords.map(w => ({ word: w.word, start: w.start, end: w.end })),
                    style: CAPTION_STYLE
                });
                currentChunkWords = [];
            }
        }

        const result = {
            id: videoId, // Use videoId as ID for simplicity in mock-ups/handoffs
            text: transcriptionResult.text || "",
            captions: chunks
        };

        const existing = await db.query.transcriptions.findFirst({ where: eq(transcriptions.videoId, videoId) });
        if (existing) {
            await db.update(transcriptions).set({
                text: result.text,
                captions: result.captions as any
            }).where(eq(transcriptions.id, existing.id));
        } else {
            await db.insert(transcriptions).values({
                videoId,
                userId: session.user.id,
                language: transcriptionResult.language || "en",
                duration: Math.round(transcriptionResult.duration || 0),
                text: result.text,
                captions: result.captions as any
            });
        }

        revalidatePath(`/post/${videoId}/editor`);
        return result;
    } catch (err) {
        console.error("Caption generation failed:", err);
        return generateMockCaptions(videoId, session.user.id);
    } finally {
        await rm(jobDir, { recursive: true, force: true });
    }
}

async function generateMockCaptions(videoId: string, userId: string) {
    const mockCaptions = [
        {
            start: 0.0,
            end: 1.5,
            originalText: "Welcome to the future",
            viralText: "THE FUTURE IS HERE. 🚀",
            useViral: true,
            highlightWords: ["future"],
            words: [
                { word: "Welcome", start: 0.0, end: 0.5 },
                { word: "to", start: 0.5, end: 0.7 },
                { word: "the", start: 0.7, end: 1.0 },
                { word: "future", start: 1.0, end: 1.5 }
            ],
            style: CAPTION_STYLE
        }
    ];

    const result = {
        id: videoId,
        text: "Welcome to the future",
        captions: mockCaptions
    };

    await db.insert(transcriptions).values({
        videoId,
        userId,
        language: "en",
        duration: 2,
        text: result.text,
        captions: result.captions as any
    });
    return result;
}

export async function saveCaptions(id: string, captions: any[]) {
    const session = await auth();
    if (!session?.user?.id) throw new Error("Unauthorized");
    await db.update(transcriptions).set({ captions: captions as any }).where(eq(transcriptions.id, id));
    return { success: true };
}

export async function getCaptions(videoId: string) {
    const session = await auth();
    if (!session?.user?.id) return null;
    return db.query.transcriptions.findFirst({ where: eq(transcriptions.videoId, videoId) });
}

