import { useEffect, useRef } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { TIMING, EASE, DELAY } from "@/lib/animation";

gsap.registerPlugin(ScrollTrigger);

const mindsetLines = [
  "You don't need to edit.",
  "You don't need to plan.",
  "You don't need to think like a filmmaker.",
  "Navinta AI does that for you.",
];

export default function DirectorMindsetSection() {
  const containerRef = useRef<HTMLDivElement>(null);
  const lineRefs = useRef<(HTMLDivElement | null)[]>([]);

  useEffect(() => {
    if (!containerRef.current) return;

    const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    if (prefersReducedMotion) {
      gsap.set(lineRefs.current, { opacity: 1, y: 0 });
      return;
    }

    const ctx = gsap.context(() => {
      lineRefs.current.forEach((line) => {
        gsap.set(line, { opacity: 0, y: 60 });
      });

      const tl = gsap.timeline({
        scrollTrigger: {
          trigger: containerRef.current,
          start: "top top",
          end: "+=400%",
          scrub: 1,
          pin: true,
        },
      });

      lineRefs.current.forEach((line, i) => {
        const startTime = i * 2;

        tl.to(line, {
          opacity: 1,
          y: 0,
          duration: TIMING.SLOW,
          ease: EASE,
        }, startTime);

        if (i < mindsetLines.length - 1) {
          tl.to(line, {
            opacity: 0.3,
            scale: 0.95,
            duration: TIMING.SLOW,
            ease: EASE,
          }, startTime + TIMING.SLOW + DELAY.SHORT);
        }
      });

      tl.to(lineRefs.current[mindsetLines.length - 1], {
        scale: 1.03,
        duration: TIMING.SLOW,
        ease: EASE,
      }, (mindsetLines.length - 1) * 2 + TIMING.SLOW + DELAY.SHORT);

    }, containerRef);

    return () => ctx.revert();
  }, []);

  const setLineRef = (i: number) => (el: HTMLDivElement | null) => {
    lineRefs.current[i] = el;
  };

  return (
    <div ref={containerRef} className="h-screen flex items-center justify-center px-8 md:px-16 relative overflow-hidden">
      <div 
        className="absolute inset-0 opacity-[0.06] pointer-events-none"
        style={{
          background: 'radial-gradient(ellipse at 70% 40%, #4338CA 0%, transparent 50%)',
        }}
      />

      <div className="max-w-4xl mx-auto text-center relative z-10 space-y-6">
        {mindsetLines.map((line, i) => (
          <div
            key={i}
            ref={setLineRef(i)}
            className={`text-3xl md:text-5xl lg:text-6xl font-bold leading-tight ${
              i === mindsetLines.length - 1 
                ? 'text-[#B08A5A]' 
                : 'text-white/90'
            }`}
          >
            {line}
          </div>
        ))}
      </div>
    </div>
  );
}

