import { useEffect, useRef } from 'react';
import { View, Text, StyleSheet, Animated, Dimensions, Pressable } from 'react-native';
import { useRouter } from 'expo-router';
import { SafeAreaView } from 'react-native-safe-area-context';
import { useAuth } from '@/hooks/useAuth';
import { colors } from '@/lib/colors';

const { width, height } = Dimensions.get('window');

export default function LandingScreen() {
  const router = useRouter();
  const { isAuthenticated, hasAccess, isLoading } = useAuth();

  const clapAnim = useRef(new Animated.Value(0)).current;
  const fadeAnim = useRef(new Animated.Value(0)).current;
  const logoAnim = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    Animated.sequence([
      Animated.timing(clapAnim, {
        toValue: 1,
        duration: 800,
        useNativeDriver: true,
      }),
      Animated.delay(200),
      Animated.parallel([
        Animated.timing(fadeAnim, {
          toValue: 1,
          duration: 600,
          useNativeDriver: true,
        }),
        Animated.spring(logoAnim, {
          toValue: 1,
          tension: 50,
          friction: 8,
          useNativeDriver: true,
        }),
      ]),
    ]).start();
  }, []);

  useEffect(() => {
    if (!isLoading) {
      const timer = setTimeout(() => {
        if (isAuthenticated && hasAccess) {
          router.replace('/(tabs)/dashboard');
        }
      }, 2500);
      return () => clearTimeout(timer);
    }
  }, [isLoading, isAuthenticated, hasAccess]);

  const handleGetStarted = () => {
    if (hasAccess && isAuthenticated) {
      router.push('/(tabs)/dashboard');
    } else {
      router.push('/access');
    }
  };

  const clapRotation = clapAnim.interpolate({
    inputRange: [0, 0.3, 0.5, 0.7, 1],
    outputRange: ['-30deg', '0deg', '-15deg', '0deg', '0deg'],
  });

  const logoScale = logoAnim.interpolate({
    inputRange: [0, 1],
    outputRange: [0.8, 1],
  });

  return (
    <SafeAreaView style={styles.container}>
      {/* Clapperboard Animation */}
      <View style={styles.clapperboardContainer}>
        <Animated.View
          style={[
            styles.clapperTop,
            {
              transform: [
                { rotate: clapRotation },
                { translateY: -20 },
              ],
            },
          ]}
        >
          <View style={styles.clapperStripes}>
            {[...Array(5)].map((_, i) => (
              <View key={i} style={[styles.stripe, i % 2 === 0 && styles.stripeWhite]} />
            ))}
          </View>
        </Animated.View>
        <View style={styles.clapperBottom}>
          <Text style={styles.clapperText}>NAVINTA</Text>
        </View>
      </View>

      {/* Logo and Title */}
      <Animated.View
        style={[
          styles.heroContent,
          {
            opacity: fadeAnim,
            transform: [{ scale: logoScale }],
          },
        ]}
      >
        <Text style={styles.title}>NAVINTA</Text>
        <Text style={styles.subtitle}>Your AI-powered director</Text>

        <Pressable style={styles.ctaButton} onPress={handleGetStarted}>
          <Text style={styles.ctaText}>Get Started</Text>
        </Pressable>
      </Animated.View>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: colors.black,
    alignItems: 'center',
    justifyContent: 'center',
  },
  clapperboardContainer: {
    position: 'absolute',
    top: height * 0.25,
    alignItems: 'center',
  },
  clapperTop: {
    width: 120,
    height: 30,
    backgroundColor: colors.black,
    borderWidth: 2,
    borderColor: colors.white,
    overflow: 'hidden',
    transformOrigin: 'left center',
  },
  clapperStripes: {
    flexDirection: 'row',
    flex: 1,
  },
  stripe: {
    flex: 1,
    backgroundColor: colors.black,
  },
  stripeWhite: {
    backgroundColor: colors.white,
  },
  clapperBottom: {
    width: 120,
    height: 80,
    backgroundColor: colors.black,
    borderWidth: 2,
    borderColor: colors.white,
    alignItems: 'center',
    justifyContent: 'center',
  },
  clapperText: {
    color: colors.white,
    fontSize: 12,
    fontFamily: 'Inter-Bold',
    letterSpacing: 2,
  },
  heroContent: {
    alignItems: 'center',
    marginTop: height * 0.3,
  },
  title: {
    fontSize: 48,
    fontFamily: 'Inter-Bold',
    color: colors.white,
    letterSpacing: 4,
  },
  subtitle: {
    fontSize: 16,
    fontFamily: 'Inter-Regular',
    color: colors.text.secondary,
    marginTop: 12,
    letterSpacing: 2,
  },
  ctaButton: {
    marginTop: 48,
    backgroundColor: colors.white,
    paddingHorizontal: 48,
    paddingVertical: 16,
    borderRadius: 8,
  },
  ctaText: {
    color: colors.black,
    fontSize: 16,
    fontFamily: 'Inter-SemiBold',
    letterSpacing: 1,
  },
});

