import { useQuery, useMutation } from "@tanstack/react-query";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { Input } from "@/components/ui/input";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { Download, Search, Play, Calendar, Trash2, Sparkles } from "lucide-react";
import { useState } from "react";
import type { Video, Clip } from "@shared/schema";
import { formatDistanceToNow } from "date-fns";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { AnimatedCaptionPlayer } from "@/components/animated-caption-player";

export default function Library() {
  const [searchQuery, setSearchQuery] = useState("");

  const { data: videos, isLoading: videosLoading } = useQuery<Video[]>({
    queryKey: ["/api/videos"],
  });

  const { data: clips, isLoading: clipsLoading } = useQuery<Clip[]>({
    queryKey: ["/api/clips"],
  });

  const filteredVideos = videos?.filter((v) =>
    v.title.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <div className="flex justify-center p-6">
      <div className="w-full max-w-7xl space-y-6">
        <div>
          <h1 className="text-3xl font-semibold tracking-tight">Video Library</h1>
          <p className="text-muted-foreground mt-1">
            All your recorded clips and finished videos
          </p>
        </div>

        <div className="relative max-w-md">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Search videos..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="pl-10"
            data-testid="input-search"
          />
        </div>

        <Tabs defaultValue="videos" className="space-y-6">
        <TabsList>
          <TabsTrigger value="videos" data-testid="tab-videos">
            Finished Videos
          </TabsTrigger>
          <TabsTrigger value="clips" data-testid="tab-clips">
            Recorded Clips
          </TabsTrigger>
        </TabsList>

        <TabsContent value="videos" className="space-y-4">
          {videosLoading ? (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {[1, 2, 3].map((i) => (
                <Skeleton key={i} className="h-96" />
              ))}
            </div>
          ) : filteredVideos && filteredVideos.length > 0 ? (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {filteredVideos.map((video) => (
                <VideoCard key={video.id} video={video} />
              ))}
            </div>
          ) : (
            <div className="flex flex-col items-center justify-center py-16">
              <div className="text-center space-y-2">
                <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-muted mb-4">
                  <Play className="h-8 w-8 text-muted-foreground" />
                </div>
                <h3 className="text-xl font-semibold">No videos yet</h3>
                <p className="text-muted-foreground">
                  {searchQuery ? "No videos match your search" : "Start creating content to see your videos here"}
                </p>
              </div>
            </div>
          )}
        </TabsContent>

        <TabsContent value="clips" className="space-y-4">
          {clipsLoading ? (
            <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4">
              {[1, 2, 3, 4, 5, 6].map((i) => (
                <Skeleton key={i} className="aspect-[9/16]" />
              ))}
            </div>
          ) : clips && clips.length > 0 ? (
            <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4">
              {clips.map((clip) => (
                <ClipCard key={clip.id} clip={clip} />
              ))}
            </div>
          ) : (
            <div className="flex flex-col items-center justify-center py-16">
              <div className="text-center space-y-2">
                <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-muted mb-4">
                  <Calendar className="h-8 w-8 text-muted-foreground" />
                </div>
                <h3 className="text-xl font-semibold">No clips recorded</h3>
                <p className="text-muted-foreground">
                  Record your first shot to see clips here
                </p>
              </div>
            </div>
          )}
        </TabsContent>
        </Tabs>
      </div>
    </div>
  );
}

function VideoCard({ video }: { video: Video }) {
  const { toast } = useToast();
  const [isPlayerOpen, setIsPlayerOpen] = useState(false);

  // Check if captions exist
  const { data: transcription } = useQuery({
    queryKey: ["/api/videos", video.id, "captions"],
    retry: false,
  });

  const hasCaptions = !!transcription;

  const deleteMutation = useMutation({
    mutationFn: () => apiRequest("DELETE", `/api/videos/${video.id}`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/videos"] });
      toast({
        title: "Video deleted",
        description: "Your video has been removed from the library.",
      });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to delete video. Please try again.",
        variant: "destructive",
      });
    },
  });

  const generateCaptionsMutation = useMutation({
    mutationFn: () => apiRequest("POST", `/api/videos/${video.id}/transcribe`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/videos", video.id, "captions"] });
      toast({
        title: "Captions generated!",
        description: "Your video now has animated word-by-word captions.",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to generate captions. Please try again.",
        variant: "destructive",
      });
    },
  });

  const handleDownload = () => {
    window.open(`/api/videos/${video.id}/download`, "_blank");
  };

  return (
    <>
      <Card className="overflow-hidden hover-elevate active-elevate-2 transition-all group" data-testid={`card-video-${video.id}`}>
        <div className="relative aspect-[9/16] bg-muted">
          {video.thumbnail ? (
            <img
              src={video.thumbnail}
              alt={video.title}
              className="w-full h-full object-cover"
            />
          ) : (
            <div className="w-full h-full flex items-center justify-center">
              <Play className="h-16 w-16 text-muted-foreground" />
            </div>
          )}
          <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
          <div className="absolute bottom-0 left-0 right-0 p-4 opacity-0 group-hover:opacity-100 transition-opacity space-y-2">
            {hasCaptions ? (
              <Button 
                size="sm" 
                variant="outline" 
                className="w-full backdrop-blur-sm" 
                onClick={() => setIsPlayerOpen(true)}
                data-testid={`button-play-${video.id}`}
              >
                <Play className="h-4 w-4 mr-2" />
                Play with Captions
              </Button>
            ) : (
              <Button 
                size="sm" 
                variant="default" 
                className="w-full backdrop-blur-sm" 
                onClick={() => generateCaptionsMutation.mutate()}
                disabled={generateCaptionsMutation.isPending}
                data-testid={`button-generate-captions-${video.id}`}
              >
                {generateCaptionsMutation.isPending ? (
                  <>
                    <span className="animate-spin mr-2">⏳</span>
                    Generating...
                  </>
                ) : (
                  <>
                    <Sparkles className="h-4 w-4 mr-2" />
                    Generate Captions
                  </>
                )}
              </Button>
            )}
            <Button 
              size="sm" 
              variant="outline" 
              className="w-full backdrop-blur-sm" 
              onClick={handleDownload}
              data-testid={`button-download-${video.id}`}
            >
              <Download className="h-4 w-4 mr-2" />
              Download
            </Button>
            <AlertDialog>
              <AlertDialogTrigger asChild>
                <Button 
                  size="sm" 
                  variant="outline" 
                  className="w-full backdrop-blur-sm border-destructive text-destructive hover:bg-destructive hover:text-destructive-foreground"
                  data-testid={`button-delete-video-${video.id}`}
                >
                  <Trash2 className="h-4 w-4 mr-2" />
                  Delete
                </Button>
              </AlertDialogTrigger>
              <AlertDialogContent>
                <AlertDialogHeader>
                  <AlertDialogTitle>Delete video?</AlertDialogTitle>
                  <AlertDialogDescription>
                    This will permanently delete "{video.title}" from your library. This action cannot be undone.
                  </AlertDialogDescription>
                </AlertDialogHeader>
                <AlertDialogFooter>
                  <AlertDialogCancel>Cancel</AlertDialogCancel>
                  <AlertDialogAction
                    onClick={() => deleteMutation.mutate()}
                    className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
                  >
                    Delete
                  </AlertDialogAction>
                </AlertDialogFooter>
              </AlertDialogContent>
            </AlertDialog>
          </div>
        </div>
        <CardContent className="p-4 space-y-2">
          <h3 className="font-medium line-clamp-2 leading-tight">{video.title}</h3>
          <div className="flex items-center justify-between text-sm">
            <Badge variant="secondary" className="text-xs">
              {video.aspectRatio}
            </Badge>
            {video.exportedAt && (
              <span className="text-muted-foreground text-xs">
                {formatDistanceToNow(new Date(video.exportedAt), { addSuffix: true })}
              </span>
            )}
          </div>
        </CardContent>
      </Card>

      <Dialog open={isPlayerOpen} onOpenChange={setIsPlayerOpen}>
        <DialogContent className="max-w-4xl h-[90vh] p-6">
          <DialogHeader>
            <DialogTitle>{video.title}</DialogTitle>
          </DialogHeader>
          <div className="flex-1 min-h-0">
            <AnimatedCaptionPlayer 
              videoId={video.id}
              videoSrc={`/api/videos/${video.id}/download`}
              title={video.title}
            />
          </div>
        </DialogContent>
      </Dialog>
    </>
  );
}

function ClipCard({ clip }: { clip: Clip }) {
  const { toast } = useToast();

  const deleteMutation = useMutation({
    mutationFn: () => apiRequest("DELETE", `/api/clips/${clip.id}`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/clips"] });
      toast({
        title: "Clip deleted",
        description: "Your clip has been removed from the library.",
      });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to delete clip. Please try again.",
        variant: "destructive",
      });
    },
  });

  return (
    <div className="space-y-2 group" data-testid={`card-clip-${clip.id}`}>
      <div className="relative aspect-[9/16] bg-muted rounded-lg overflow-hidden hover-elevate active-elevate-2 transition-all">
        {clip.thumbnail ? (
          <img
            src={clip.thumbnail}
            alt={`Clip ${clip.shotId}`}
            className="w-full h-full object-cover"
          />
        ) : (
          <div className="w-full h-full flex items-center justify-center">
            <Play className="h-8 w-8 text-muted-foreground" />
          </div>
        )}
        <div className="absolute bottom-2 right-2 bg-black/75 text-white text-xs px-2 py-1 rounded">
          {clip.duration}s
        </div>
        <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity">
          <AlertDialog>
            <AlertDialogTrigger asChild>
              <Button 
                size="icon" 
                variant="outline" 
                className="h-8 w-8 backdrop-blur-sm border-destructive text-destructive hover:bg-destructive hover:text-destructive-foreground"
                data-testid={`button-delete-clip-${clip.id}`}
              >
                <Trash2 className="h-4 w-4" />
              </Button>
            </AlertDialogTrigger>
            <AlertDialogContent>
              <AlertDialogHeader>
                <AlertDialogTitle>Delete clip?</AlertDialogTitle>
                <AlertDialogDescription>
                  This will permanently delete this {clip.duration}s clip from your library. This action cannot be undone.
                </AlertDialogDescription>
              </AlertDialogHeader>
              <AlertDialogFooter>
                <AlertDialogCancel>Cancel</AlertDialogCancel>
                <AlertDialogAction
                  onClick={() => deleteMutation.mutate()}
                  className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
                >
                  Delete
                </AlertDialogAction>
              </AlertDialogFooter>
            </AlertDialogContent>
          </AlertDialog>
        </div>
      </div>
      {clip.recordedAt && (
        <p className="text-xs text-muted-foreground">
          {formatDistanceToNow(new Date(clip.recordedAt), { addSuffix: true })}
        </p>
      )}
    </div>
  );
}

