"use client";

import { useState, useRef, useTransition, useCallback } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { Button, Card, CardContent, CardHeader, CardTitle, Badge, cn } from "@repo/ui";
import { ArrowLeft, Download, Music, Type, CheckCircle2, Wand2 } from "lucide-react";
import { type Post, type Clip, type Transcription } from "@/db/schema";
import { exportVideo } from "@/app/actions/export";
import { uploadClip } from "@/app/actions/upload";
import { generateCaptions, saveCaptions } from "@/app/actions/captions";
import { CaptionPlayer } from "@/components/caption-player";

const MUSIC_STYLES = [
    "Upbeat & Energetic",
    "Cinematic & Emotional",
    "Lo-fi & Chill",
    "Corporate & Professional"
];

interface TranscriptionResult {
    id: string;
    text: string;
    captions: any[];
}

export function EditorClient({ post, transcription: initialTranscription }: { post: Post & { clips: Clip[] }, transcription?: Transcription }) {
    const router = useRouter();
    const [clips, setClips] = useState<Clip[]>(post.clips || []);
    const [transcription, setTranscription] = useState<TranscriptionResult | null>(initialTranscription as unknown as TranscriptionResult);
    const [captionText, setCaptionText] = useState(initialTranscription?.text || post.caption || "");
    const [hasCaption, setHasCaption] = useState(!!initialTranscription);
    const [selectedMusic, setSelectedMusic] = useState(post.musicVibe || "Upbeat & Energetic");
    const [currentTime, setCurrentTime] = useState(0);
    const [isExporting, startExport] = useTransition();
    const [isCapturing, startCaptions] = useTransition();

    const videoRef = useRef<HTMLVideoElement>(null);

    const handleFileUpload = useCallback(async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const formData = new FormData();
        formData.append("file", file);

        try {
            const newClip = await uploadClip(formData, post.projectId, post.id);
            setClips(prev => [...prev, newClip as unknown as Clip]);
        } catch (err) {
            console.error("Upload failed", err);
            alert("Upload failed");
        }
    }, [post.id, post.projectId]);

    const handleGenerateCaptions = () => {
        startCaptions(async () => {
            try {
                const result = await generateCaptions(post.id);
                setTranscription(result as unknown as TranscriptionResult);
                setCaptionText((result as any).text || "");
                setHasCaption(true);
            } catch (err) {
                console.error("Caption generation failed", err);
                alert("Failed to generate captions");
            }
        });
    };

    const handleExport = () => {
        startExport(async () => {
            const exportSettings = {
                hasCaption,
                musicStyle: selectedMusic,
                clips: clips.map(c => ({ url: c.url })) as any,
                captionText: captionText
            };
            await exportVideo(post.id, exportSettings);
            router.push("/dashboard");
        });
    };

    const activeClip = clips[0];

    return (
        <div className="flex justify-center p-6 pb-24">
            <div className="w-full max-w-7xl space-y-6">
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-4">
                        <Link href="/dashboard">
                            <Button variant="ghost" size="icon">
                                <ArrowLeft className="h-5 w-5" />
                            </Button>
                        </Link>
                        <div>
                            <h1 className="text-3xl font-semibold tracking-tight">Video Editor</h1>
                            <p className="text-muted-foreground mt-1">{post.title}</p>
                        </div>
                    </div>
                    <Button size="lg" onClick={handleExport} disabled={isExporting || clips.length === 0}>
                        <Download className="h-5 w-5 mr-2" />
                        {isExporting ? "Exporting..." : "Export Video"}
                    </Button>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    <div className="lg:col-span-2 space-y-4">
                        <Card className="bg-black/5 border-0 shadow-inner">
                            <CardContent className="p-0">
                                <div className="relative aspect-[9/16] bg-black rounded-lg overflow-hidden max-w-[360px] mx-auto shadow-2xl my-6 group">
                                    {activeClip ? (
                                        <video
                                            ref={videoRef}
                                            src={activeClip.url || ""}
                                            className="w-full h-full object-cover"
                                            controls={false}
                                            loop
                                            onTimeUpdate={(e) => setCurrentTime(e.currentTarget.currentTime)}
                                        />
                                    ) : (
                                        <div className="absolute inset-0 flex flex-col items-center justify-center text-zinc-500 gap-4">
                                            <Wand2 className="h-12 w-12 opacity-20" />
                                            <p className="text-sm">No clips recorded yet.</p>
                                            <Link href={`/director/${post.id}`}>
                                                <Button variant="outline">Go to Director Mode</Button>
                                            </Link>
                                        </div>
                                    )}
                                    {hasCaption && transcription?.captions && (
                                        <CaptionPlayer
                                            currentTime={currentTime}
                                            captions={transcription.captions}
                                        />
                                    )}
                                </div>
                            </CardContent>
                        </Card>

                        <Card>
                            <CardHeader className="flex flex-row items-center justify-between pb-2">
                                <CardTitle className="text-sm font-medium">Timeline</CardTitle>
                                <Badge variant="secondary">{clips.length} Clips</Badge>
                            </CardHeader>
                            <CardContent>
                                <div className="flex gap-2 overflow-x-auto pb-4 pt-2">
                                    <label className="flex-shrink-0 w-24 aspect-[9/16] flex flex-col items-center justify-center border-2 border-dashed rounded-md hover:border-primary cursor-pointer transition-colors bg-muted/50">
                                        <input type="file" accept="video/*" className="hidden" onChange={handleFileUpload} />
                                        <div className="p-2 bg-primary/10 rounded-full mb-2">
                                            <Download className="h-4 w-4 text-primary" />
                                        </div>
                                        <span className="text-[10px] font-medium">Add Clip</span>
                                    </label>
                                    {clips.map((clip) => (
                                        <div key={clip.id} className="relative group flex-shrink-0 w-24">
                                            <img src={clip.url || ""} alt="clip" className="w-full aspect-[9/16] object-cover rounded-md bg-black" />
                                        </div>
                                    ))}
                                </div>
                            </CardContent>
                        </Card>
                    </div>

                    <div className="space-y-6">
                        <Card>
                            <CardHeader>
                                <CardTitle className="flex items-center gap-2">
                                    <Type className="h-5 w-5 text-blue-500" />
                                    Viral Captions
                                </CardTitle>
                            </CardHeader>
                            <CardContent className="space-y-4">
                                <div className="flex items-center justify-between p-3 bg-muted rounded-lg border">
                                    <div className="space-y-0.5">
                                        <p className="text-sm font-medium uppercase tracking-tight">Enable Captions</p>
                                        <p className="text-xs text-muted-foreground">AI animated text overlay</p>
                                    </div>
                                    <Button
                                        variant={hasCaption ? "default" : "outline"}
                                        size="sm"
                                        onClick={() => setHasCaption(!hasCaption)}
                                    >
                                        {hasCaption ? "On" : "Off"}
                                    </Button>
                                </div>
                                <Button className="w-full" variant="outline" onClick={handleGenerateCaptions} disabled={isCapturing}>
                                    <Wand2 className="h-4 w-4 mr-2" />
                                    {isCapturing ? "Generating..." : "Generate with AI"}
                                </Button>
                            </CardContent>
                        </Card>

                        <Card>
                            <CardHeader>
                                <CardTitle className="flex items-center gap-2">
                                    <Music className="h-5 w-5 text-purple-500" />
                                    Background Music
                                </CardTitle>
                            </CardHeader>
                            <CardContent className="space-y-4">
                                {MUSIC_STYLES.map(style => (
                                    <div
                                        key={style}
                                        onClick={() => setSelectedMusic(style)}
                                        className={cn(
                                            "flex items-center justify-between p-3 rounded-lg border cursor-pointer transition-all",
                                            selectedMusic === style ? "bg-primary/5 border-primary shadow-sm" : "hover:bg-muted"
                                        )}
                                    >
                                        <span className="text-sm font-medium">{style}</span>
                                        {selectedMusic === style && (
                                            <CheckCircle2 className="h-4 w-4 text-primary" />
                                        )}
                                    </div>
                                ))}
                            </CardContent>
                        </Card>
                    </div>
                </div>
            </div>
        </div>
    );
}

