export default function TabsLayout() {
  const router = useRouter();
  const { isAuthenticated, hasAccess, isLoading } = useAuth();

  useEffect(() => {
    if (!isLoading && (!isAuthenticated || !hasAccess)) {
      router.replace('/access');
