import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const badgeVariants = cva(
  // Whitespace-nowrap: Badges should never wrap.
  "whitespace-nowrap inline-flex items-center rounded-md border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2" +
  " hover-elevate " ,
  {
    variants: {
      variant: {
        default:
          "border-transparent bg-primary text-primary-foreground shadow-xs",
        secondary: "border-transparent bg-secondary text-secondary-foreground",
        destructive:
          "border-transparent bg-destructive text-destructive-foreground shadow-xs",

        outline: " border [border-color:var(--badge-outline)] shadow-xs",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  },
)

export interface BadgeProps
  extends React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof badgeVariants> {}

function Badge({ className, variant, ...props }: BadgeProps) {
  return (
    <div className={cn(badgeVariants({ variant }), className)} {...props} />
  );
}

export { Badge, badgeVariants }

client/src/components/PhoneStageAnimatio.content:
import { useEffect, useRef, useState } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";

gsap.registerPlugin(ScrollTrigger);

interface MediaItem {
  id: number;
  type: "video" | "photo";
  thumbnail: string;
  url: string;
  width: number;
  height: number;
  alt?: string;
}

export default function PhoneStageAnimation() {
  const containerRef = useRef<HTMLDivElement>(null);
  const phoneRef = useRef<HTMLDivElement>(null);
  const phoneFrameRef = useRef<HTMLDivElement>(null);

  const scene1Ref = useRef<HTMLDivElement>(null);
  const scene2Ref = useRef<HTMLDivElement>(null);
  const scene3Ref = useRef<HTMLDivElement>(null);
  const scene4Ref = useRef<HTMLDivElement>(null);
  const scene5Ref = useRef<HTMLDivElement>(null);

  const onboardingCardsRef = useRef<(HTMLDivElement | null)[]>([]);
  const planCreatedRef = useRef<HTMLDivElement>(null);

  const shotCardsRef = useRef<(HTMLDivElement | null)[]>([]);
  const directorTimelineRef = useRef<HTMLDivElement>(null);
  const shotIndicatorsRef = useRef<(HTMLDivElement | null)[]>([]);

  const recordDotRef = useRef<HTMLDivElement>(null);
  const recordProgressRef = useRef<HTMLDivElement>(null);
  const recordShotsRef = useRef<(HTMLDivElement | null)[]>([]);
  const cutLineRef = useRef<HTMLDivElement>(null);

  const captionTextRef = useRef<HTMLDivElement>(null);
  const brollRef = useRef<HTMLDivElement>(null);
  const colorGradeRef = useRef<HTMLDivElement>(null);
  const waveformRef = useRef<HTMLDivElement>(null);
  const editTimelineRef = useRef<HTMLDivElement>(null);

  const exportCardRef = useRef<HTMLDivElement>(null);
  const exportBadgeRef = useRef<HTMLDivElement>(null);
  const libraryGridRef = useRef<HTMLDivElement>(null);

  const [isMobile, setIsMobile] = useState(false);
  const [media, setMedia] = useState<MediaItem[]>([]);
  const leftPanelsRef = useRef<(HTMLDivElement | null)[]>([]);
  const rightPanelsRef = useRef<(HTMLDivElement | null)[]>([]);

  useEffect(() => {
    const checkMobile = () => setIsMobile(window.innerWidth < 768);
    checkMobile();
    window.addEventListener("resize", checkMobile);
    return () => window.removeEventListener("resize", checkMobile);
  }, []);

  useEffect(() => {
    async function fetchMedia() {
      try {
        const response = await fetch("/api/pexels/media?count=8");
        if (!response.ok) return;
        const data = await response.json();
        setMedia(data.media || []);
      } catch (error) {
        console.error("Error fetching Pexels media:", error);
      }
    }
    if (!isMobile) {
      fetchMedia();
    }
  }, [isMobile]);

  useEffect(() => {
    if (!containerRef.current || !phoneRef.current) return;

    const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    if (prefersReducedMotion || isMobile) {
      if (scene1Ref.current) gsap.set(scene1Ref.current, { opacity: 0 });
      if (scene2Ref.current) gsap.set(scene2Ref.current, { opacity: 0 });
      if (scene3Ref.current) gsap.set(scene3Ref.current, { opacity: 0 });
      if (scene4Ref.current) gsap.set(scene4Ref.current, { opacity: 0 });
      if (scene5Ref.current) gsap.set(scene5Ref.current, { opacity: 1 });
      if (exportCardRef.current) gsap.set(exportCardRef.current, { opacity: 1, scale: 1, y: 0 });
      if (exportBadgeRef.current) gsap.set(exportBadgeRef.current, { opacity: 1, scale: 1 });
      if (libraryGridRef.current) gsap.set(libraryGridRef.current, { opacity: 1, y: 0 });
      return;
    }

    const ctx = gsap.context(() => {
      if (phoneRef.current) gsap.set(phoneRef.current, { scale: 0.95 });
      if (scene1Ref.current) gsap.set(scene1Ref.current, { opacity: 1 });
      if (scene2Ref.current) gsap.set(scene2Ref.current, { opacity: 0 });
      if (scene3Ref.current) gsap.set(scene3Ref.current, { opacity: 0 });
      if (scene4Ref.current) gsap.set(scene4Ref.current, { opacity: 0 });
      if (scene5Ref.current) gsap.set(scene5Ref.current, { opacity: 0 });

      const validOnboardingCardsInit = onboardingCardsRef.current.filter(Boolean);
      if (validOnboardingCardsInit.length > 0) {
        gsap.set(validOnboardingCardsInit, { opacity: 0, y: 40, scale: 0.95 });
      }
      if (planCreatedRef.current) gsap.set(planCreatedRef.current, { opacity: 0, scale: 0.8 });

      const validShotCards = shotCardsRef.current.filter(Boolean);
      if (validShotCards.length > 0) {
        gsap.set(validShotCards, { opacity: 0, x: 60 });
      }
      if (directorTimelineRef.current) gsap.set(directorTimelineRef.current, { opacity: 0, scaleX: 0, transformOrigin: "left" });
      const validShotIndicators = shotIndicatorsRef.current.filter(Boolean);
      if (validShotIndicators.length > 0) {
        gsap.set(validShotIndicators, { opacity: 0, scale: 0 });
      }

      if (recordDotRef.current) gsap.set(recordDotRef.current, { scale: 0 });
      if (recordProgressRef.current) gsap.set(recordProgressRef.current, { scaleX: 0, transformOrigin: "left" });
      const validRecordShots = recordShotsRef.current.filter(Boolean);
      if (validRecordShots.length > 0) {
        gsap.set(validRecordShots, { opacity: 0.3 });
      }
      if (cutLineRef.current) gsap.set(cutLineRef.current, { opacity: 0, scaleY: 0 });

      if (captionTextRef.current) gsap.set(captionTextRef.current, { opacity: 0 });
      if (brollRef.current) gsap.set(brollRef.current, { opacity: 0, x: 100 });
      if (colorGradeRef.current) gsap.set(colorGradeRef.current, { opacity: 0 });
      if (waveformRef.current) gsap.set(waveformRef.current, { opacity: 0, scaleX: 0, transformOrigin: "left" });
      if (editTimelineRef.current) gsap.set(editTimelineRef.current, { opacity: 0, y: 20 });

      if (exportCardRef.current) gsap.set(exportCardRef.current, { opacity: 0, scale: 0.8, y: 0 });
      if (exportBadgeRef.current) gsap.set(exportBadgeRef.current, { opacity: 0, scale: 0 });
      if (libraryGridRef.current) gsap.set(libraryGridRef.current, { opacity: 0, y: 40 });

      const leftPanels = leftPanelsRef.current.filter(Boolean);
      const rightPanels = rightPanelsRef.current.filter(Boolean);
      if (leftPanels.length > 0) {
        gsap.set(leftPanels, { opacity: 0, x: -120, rotateY: 25 });
      }
      if (rightPanels.length > 0) {
        gsap.set(rightPanels, { opacity: 0, x: 120, rotateY: -25 });
      }

      const tl = gsap.timeline({
        scrollTrigger: {
          trigger: containerRef.current,
          start: "top top",
          end: "+=500%",
          scrub: 1.5,
          pin: true,
        },
      });

      if (phoneRef.current) {
        tl.to(phoneRef.current, {
          scale: 1,
          duration: 1,
          ease: "power2.out",
        }, 0);
      }

      onboardingCardsRef.current.forEach((card, i) => {
        if (card) {
          tl.to(card, {
            opacity: 1,
            y: 0,
            scale: 1,
            duration: 1.5,
            ease: "power3.out",
          }, 0.3 + i * 0.4);
        }
      });

      if (onboardingCardsRef.current[0]) {
        tl.to(onboardingCardsRef.current[0], {
          borderColor: "#135bec",
          duration: 0.8,
        }, 2);
      }

      if (onboardingCardsRef.current[1]) {
        tl.to(onboardingCardsRef.current[1], {
          borderColor: "#135bec",
          duration: 0.8,
        }, 2.5);
      }

      if (onboardingCardsRef.current[2]) {
        tl.to(onboardingCardsRef.current[2], {
          borderColor: "#135bec",
          duration: 0.8,
        }, 3);
      }

      const validOnboardingCards = onboardingCardsRef.current.filter(Boolean);
      if (validOnboardingCards.length > 0) {
        tl.to(validOnboardingCards, {
          opacity: 0,
          scale: 0.9,
          y: -20,
          duration: 1,
          stagger: 0.1,
        }, 4);
      }

      if (planCreatedRef.current) {
        tl.to(planCreatedRef.current, {
          opacity: 1,
          scale: 1,
          duration: 1.2,
          ease: "back.out(1.5)",
        }, 4.5);

        tl.to(planCreatedRef.current, {
          opacity: 0,
          scale: 0.9,
          duration: 0.8,
        }, 6);
      }

      if (scene1Ref.current) {
        tl.to(scene1Ref.current, {
          opacity: 0,
          duration: 0.5,
        }, 6.5);
      }

      if (scene2Ref.current) {
        tl.to(scene2Ref.current, {
          opacity: 1,
          duration: 0.5,
        }, 6.5);
      }

      shotCardsRef.current.forEach((card, i) => {
        if (card) {
          tl.to(card, {
            opacity: 1,
            x: 0,
            duration: 1.2,
            ease: "power3.out",
          }, 7 + i * 0.3);
        }
      });

      if (directorTimelineRef.current) {
        tl.to(directorTimelineRef.current, {
          opacity: 1,
          scaleX: 1,
          duration: 1.5,
          ease: "power2.out",
        }, 8);
      }

      shotIndicatorsRef.current.forEach((indicator, i) => {
        if (indicator) {
          tl.to(indicator, {
            opacity: 1,
            scale: 1,
            duration: 0.6,
            ease: "back.out(2)",
          }, 8.5 + i * 0.3);
        }
      });

      if (scene2Ref.current) {
        tl.to(scene2Ref.current, {
          opacity: 0,
          duration: 0.5,
        }, 10);
      }

      if (scene3Ref.current) {
        tl.to(scene3Ref.current, {
          opacity: 1,
          duration: 0.5,
        }, 10);
      }

      if (recordDotRef.current) {
        tl.to(recordDotRef.current, {
          scale: 1,
          duration: 0.8,
          ease: "back.out(2)",
        }, 10.5);
      }

      if (recordProgressRef.current) {
        tl.to(recordProgressRef.current, {
          scaleX: 1,
          duration: 3,
          ease: "none",
        }, 11);
      }

      recordShotsRef.current.forEach((shot, i) => {
        if (shot) {
          tl.to(shot, {
            opacity: 1,
            backgroundColor: "#135bec",
            duration: 0.5,
          }, 11.5 + i * 0.8);
        }
      });

      if (cutLineRef.current) {
        tl.to(cutLineRef.current, {
          opacity: 1,
          scaleY: 1,
          duration: 0.3,
          ease: "power2.out",
        }, 13);

        tl.to(cutLineRef.current, {
          x: 40,
          duration: 0.5,
          ease: "power2.inOut",
        }, 13.3);

        tl.to(cutLineRef.current, {
          opacity: 0,
          duration: 0.3,
        }, 13.8);
      }

      if (scene3Ref.current) {
        tl.to(scene3Ref.current, {
          opacity: 0,
          duration: 0.5,
        }, 14.5);
      }

      if (scene4Ref.current) {
        tl.to(scene4Ref.current, {
          opacity: 1,
          duration: 0.5,
        }, 14.5);
      }

      if (captionTextRef.current) {
        tl.to(captionTextRef.current, {
          opacity: 1,
          duration: 2,
          ease: "power2.out",
        }, 15);
      }

      if (brollRef.current) {
        tl.to(brollRef.current, {
          opacity: 1,
          x: 0,
          duration: 1.5,
          ease: "power3.out",
        }, 15.5);
      }

      if (colorGradeRef.current) {
        tl.to(colorGradeRef.current, {
          opacity: 0.4,
          duration: 2,
          ease: "power2.out",
        }, 16);
      }

      if (waveformRef.current) {
        tl.to(waveformRef.current, {
          opacity: 1,
          scaleX: 1,
          duration: 2,
          ease: "power2.out",
        }, 16.5);
      }

      if (editTimelineRef.current) {
        tl.to(editTimelineRef.current, {
          opacity: 1,
          y: 0,
          duration: 1,
          ease: "power2.out",
        }, 17);
      }

      if (scene4Ref.current) {
        tl.to(scene4Ref.current, {
          opacity: 0,
          duration: 0.5,
        }, 19);
      }

      if (scene5Ref.current) {
        tl.to(scene5Ref.current, {
          opacity: 1,
          duration: 0.5,
        }, 19);
      }

      if (phoneFrameRef.current) {
        tl.to(phoneFrameRef.current, {
          scale: 0.85,
          duration: 1.5,
          ease: "power2.out",
        }, 19.5);
      }

      if (exportCardRef.current) {
        tl.to(exportCardRef.current, {
          opacity: 1,
          scale: 1,
          y: -60,
          duration: 1.5,
          ease: "power3.out",
        }, 20);

        tl.to(exportCardRef.current, {
          y: 0,
          duration: 1,
          ease: "power2.inOut",
        }, 22);
      }

      if (exportBadgeRef.current) {
        tl.to(exportBadgeRef.current, {
          opacity: 1,
          scale: 1,
          duration: 0.8,
          ease: "back.out(2)",
        }, 21);
      }

      if (libraryGridRef.current) {
        tl.to(libraryGridRef.current, {
          opacity: 1,
          y: 0,
          duration: 1.2,
          ease: "power2.out",
        }, 22.5);
      }

      leftPanels.forEach((panel, i) => {
        if (!panel) return;
        const startTime = 2 + i * 3;
        tl.to(panel, {
          opacity: 0.9,
          x: 0,
          rotateY: 0,
          duration: 2,
          ease: "power3.out",
        }, startTime);
        tl.to(panel, {
          y: -30 - i * 15,
          duration: 4,
          ease: "power1.inOut",
        }, startTime);
        tl.to(panel, {
          opacity: 0,
          x: -60,
          duration: 2,
          ease: "power2.in",
        }, startTime + 5);
      });

      rightPanels.forEach((panel, i) => {
        if (!panel) return;
        const startTime = 3 + i * 3;
        tl.to(panel, {
          opacity: 0.9,
          x: 0,
          rotateY: 0,
          duration: 2,
          ease: "power3.out",
        }, startTime);
        tl.to(panel, {
          y: -25 - i * 12,
          duration: 4,
          ease: "power1.inOut",
        }, startTime);
        tl.to(panel, {
          opacity: 0,
          x: 60,
          duration: 2,
          ease: "power2.in",
        }, startTime + 5);
      });

    }, containerRef);

    return () => ctx.revert();
  }, [isMobile, media]);

  const setOnboardingCardRef = (i: number) => (el: HTMLDivElement | null) => {
    onboardingCardsRef.current[i] = el;
  };

  const setShotCardRef = (i: number) => (el: HTMLDivElement | null) => {
    shotCardsRef.current[i] = el;
  };

  const setShotIndicatorRef = (i: number) => (el: HTMLDivElement | null) => {
    shotIndicatorsRef.current[i] = el;
  };

  const setRecordShotRef = (i: number) => (el: HTMLDivElement | null) => {
    recordShotsRef.current[i] = el;
  };

  const onboardingQuestions = [
    "What do you want people to feel?",
    "What's your brand about?",
    "How long should videos be?",
  ];

  const shots = [
    { num: 1, text: "Look at camera" },
    { num: 2, text: "Walk & gesture" },
    { num: 3, text: "Close-up reaction" },
  ];

  if (isMobile) {
    return (
      <div className="py-20 px-6 bg-black">
        <div className="max-w-sm mx-auto space-y-8">
          <div className="text-center mb-12">
            <h2 className="text-2xl font-bold text-white mb-2">The Complete Journey</h2>
            <p className="text-white/40 text-sm">From idea to published video</p>
          </div>

          <div className="space-y-6">
            <div className="flex items-start gap-4">
              <div className="w-10 h-10 rounded-full bg-[#135bec]/20 flex items-center justify-center flex-shrink-0">
                <span className="text-[#135bec] font-bold">1</span>
              </div>
              <div>
                <div className="text-white font-medium">Plan</div>
                <div className="text-white/40 text-sm">Answer questions about your brand and goals</div>
              </div>
            </div>

            <div className="flex items-start gap-4">
              <div className="w-10 h-10 rounded-full bg-[#135bec]/20 flex items-center justify-center flex-shrink-0">
                <span className="text-[#135bec] font-bold">2</span>
              </div>
              <div>
                <div className="text-white font-medium">Direct</div>
                <div className="text-white/40 text-sm">Get shot-by-shot guidance from AI</div>
              </div>
            </div>

            <div className="flex items-start gap-4">
              <div className="w-10 h-10 rounded-full bg-[#135bec]/20 flex items-center justify-center flex-shrink-0">
                <span className="text-[#135bec] font-bold">3</span>
              </div>
              <div>
                <div className="text-white font-medium">Record</div>
                <div className="text-white/40 text-sm">Follow prompts and record each shot</div>
              </div>
            </div>

            <div className="flex items-start gap-4">
              <div className="w-10 h-10 rounded-full bg-[#135bec]/20 flex items-center justify-center flex-shrink-0">
                <span className="text-[#135bec] font-bold">4</span>
              </div>
              <div>
                <div className="text-white font-medium">Edit</div>
                <div className="text-white/40 text-sm">AI adds captions, B-roll, and music</div>
              </div>
            </div>

            <div className="flex items-start gap-4">
              <div className="w-10 h-10 rounded-full bg-[#135bec]/20 flex items-center justify-center flex-shrink-0">
                <span className="text-[#135bec] font-bold">5</span>
              </div>
              <div>
                <div className="text-white font-medium">Export</div>
                <div className="text-white/40 text-sm">Download your professional video</div>
              </div>
            </div>
          </div>

          <div className="mt-10 p-4 rounded-2xl bg-white/5 border border-white/10">
            <div className="flex items-center gap-3">
              <div className="w-12 h-12 rounded-lg bg-[#135bec]/20 flex items-center justify-center">
                <div className="w-0 h-0 border-l-[10px] border-l-white border-y-[6px] border-y-transparent ml-1" />
              </div>
              <div>
                <div className="text-white text-sm font-medium">Your Video</div>
                <div className="text-white/40 text-xs">Ready to share</div>
              </div>
              <div className="ml-auto px-3 py-1 bg-[#135bec] rounded-full text-xs text-white">
                Exported
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div ref={containerRef} className="h-screen w-full flex items-center justify-center relative overflow-hidden bg-black">
      <div 
        ref={phoneRef}
        className="relative"
        style={{ 
          width: "clamp(300px, 45vw, 420px)",
          height: "clamp(550px, 75vh, 750px)",
          transformStyle: "preserve-3d",
          perspective: "1200px"
        }}
      >
        <div 
          ref={phoneFrameRef}
          className="absolute inset-0 rounded-[3rem] border-[6px] border-white/15 bg-black overflow-hidden"
        >
          <div className="absolute top-3 left-1/2 -translate-x-1/2 w-28 h-7 bg-black rounded-full border border-white/10 z-50" />

          <div className="absolute inset-4 rounded-[2.4rem] bg-black overflow-hidden">

            <div ref={scene1Ref} className="absolute inset-0 flex flex-col items-center justify-center p-6">
              <div className="text-white/40 text-xs uppercase tracking-widest mb-6">Getting to know you</div>

              <div className="space-y-4 w-full">
                {onboardingQuestions.map((q, i) => (
                  <div
                    key={i}
                    ref={setOnboardingCardRef(i)}
                    className="p-4 rounded-2xl bg-white/5 border border-white/10"
                  >
                    <div className="text-white/70 text-sm">{q}</div>
                    <div className="mt-2 flex gap-2">
                      <div className="px-3 py-1 rounded-full bg-white/10 text-white/40 text-xs">Option A</div>
                      <div className="px-3 py-1 rounded-full bg-white/10 text-white/40 text-xs">Option B</div>
                    </div>
                  </div>
                ))}
              </div>

              <div 
                ref={planCreatedRef}
                className="absolute inset-0 flex flex-col items-center justify-center"
              >
                <div className="w-16 h-16 rounded-full border-2 border-[#135bec] flex items-center justify-center mb-4">
                  <svg className="w-8 h-8 text-[#135bec]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                  </svg>
                </div>
                <div className="text-white text-lg font-medium">Plan Created</div>
                <div className="text-white/40 text-sm mt-1">Your content strategy is ready</div>
              </div>
            </div>

            <div ref={scene2Ref} className="absolute inset-0 flex flex-col p-5">
              <div className="flex items-center justify-between mb-4">
                <div className="text-white/40 text-xs uppercase tracking-widest">Director Mode</div>
                <div className="w-2 h-2 rounded-full bg-[#135bec]" />
              </div>

              <div className="flex-1 space-y-3">
                {shots.map((shot, i) => (
                  <div
                    key={i}
                    ref={setShotCardRef(i)}
                    className="p-4 rounded-xl bg-white/5 border border-white/10 flex items-center gap-4"
                  >
                    <div className="w-10 h-10 rounded-lg bg-[#135bec]/20 flex items-center justify-center text-[#135bec] font-bold">
                      {shot.num}
                    </div>
                    <div>
                      <div className="text-white text-sm font-medium">{shot.text}</div>
                      <div className="text-white/40 text-xs">~5 seconds</div>
                    </div>
                  </div>
                ))}
              </div>

              <div 
                ref={directorTimelineRef}
                className="mt-4 h-12 rounded-xl bg-white/5 border border-white/10 flex items-center px-4 gap-3"
              >
                {[0, 1, 2].map((i) => (
                  <div
                    key={i}
                    ref={setShotIndicatorRef(i)}
                    className="flex-1 h-2 rounded-full bg-white/20"
                  >
                    <div className="h-full rounded-full bg-[#135bec]" style={{ width: "0%" }} />
                  </div>
                ))}
              </div>
            </div>

            <div ref={scene3Ref} className="absolute inset-0 flex flex-col">
              <div className="flex-1 relative bg-white/5 m-4 rounded-2xl overflow-hidden">
