          </p>
          {musicInfo.trending.videoCount && (
            <p className="text-xs text-muted-foreground">
              {(musicInfo.trending.videoCount / 1000).toFixed(0)}K+ videos
            </p>
          )}
          <div className="pt-2 mt-2 border-t text-xs">
