import { Switch, Route } from "wouter";
import { queryClient } from "./lib/queryClient";
import { QueryClientProvider } from "@tanstack/react-query";
import { Toaster } from "@/components/ui/toaster";
import { TooltipProvider } from "@/components/ui/tooltip";
import { SidebarProvider, SidebarTrigger } from "@/components/ui/sidebar";
import { AppSidebar } from "@/components/app-sidebar";
import { ThemeProvider } from "@/components/theme-provider";
import { ThemeToggle } from "@/components/theme-toggle";
import { useAuth } from "@/hooks/useAuth";
import NotFound from "@/pages/not-found";
import Landing from "@/pages/landing";
import Onboarding from "@/pages/onboarding";
import Dashboard from "@/pages/dashboard";
import PostDetail from "@/pages/post-detail";
import DirectorMode from "@/pages/director-mode";
import Editor from "@/pages/editor";
import Library from "@/pages/library";
import BrandKitPage from "@/pages/brand-kit";
import Schedule from "@/pages/schedule";
import Analytics from "@/pages/analytics";

function App() {
  const style = {
    "--sidebar-width": "16rem",
    "--sidebar-width-icon": "3rem",
  };

  return (
    <QueryClientProvider client={queryClient}>
      <ThemeProvider defaultTheme="dark">
        <TooltipProvider>
          <AuthRouter sidebarStyle={style} />
          <Toaster />
        </TooltipProvider>
      </ThemeProvider>
    </QueryClientProvider>
  );
}

function AuthRouter({ sidebarStyle }: { sidebarStyle: any }) {
  const { isAuthenticated, isLoading } = useAuth();

  // Show landing page while loading or if not authenticated
  if (isLoading || !isAuthenticated) {
    return (
      <Switch>
        <Route path="/" component={Landing} />
        <Route component={Landing} />
      </Switch>
    );
  }

  // Show authenticated app with sidebar
  return (
    <SidebarProvider style={sidebarStyle as React.CSSProperties}>
      <Switch>
        <Route path="/onboarding" component={Onboarding} />
        <Route path="/director/:id" component={DirectorMode} />
        <Route>
          <div className="flex h-screen w-full">
            <AppSidebar />
            <div className="flex flex-col flex-1 overflow-hidden">
              <header className="flex items-center justify-between gap-4 p-4 border-b bg-background/95 backdrop-blur-xl sticky top-0 z-40">
                <SidebarTrigger data-testid="button-sidebar-toggle" />
                <ThemeToggle />
              </header>
              <main className="flex-1 overflow-auto">
                <Switch>
                  <Route path="/" component={Dashboard} />
                  <Route path="/dashboard" component={Dashboard} />
                  <Route path="/post/:id" component={PostDetail} />
                  <Route path="/editor/:id" component={Editor} />
                  <Route path="/library" component={Library} />
                  <Route path="/brand-kit" component={BrandKitPage} />
                  <Route path="/schedule" component={Schedule} />
                  <Route path="/analytics" component={Analytics} />
                  <Route component={NotFound} />
                </Switch>
              </main>
            </div>
          </div>
        </Route>
      </Switch>
    </SidebarProvider>
  );
}

export default App;

