"use client"

import { useState, useTransition } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { onboardingSchema, type OnboardingData } from "@/db/schema";
import { createContentPlan } from "../actions";
import { Button, Card, Input, Label } from "@repo/ui";
import { ChevronLeft, ChevronRight, Sparkles } from "lucide-react";

// Checkbox and RadioGroup aren't in @repo/ui yet, using simple HTML inputs for speed
// or we can quickly add them. For now, I'll use simple custom styled inputs to avoid huge file creates.

const STEPS = 7;

export default function Onboarding() {
    const [step, setStep] = useState(1);
    const [isPending, startTransition] = useTransition();

    const form = useForm<OnboardingData>({
        resolver: zodResolver(onboardingSchema),
        defaultValues: {
            brandName: "",
            businessType: "",
            targetAudience: "",
            contentGoals: [],
            platforms: [],
            postFrequency: "",
            tone: "",
            primaryColor: "#3B82F6",
            secondaryColor: "",
            accentColor: "",
        },
    });

    const contentGoals = form.watch("contentGoals");
    const platforms = form.watch("platforms");
    const postFrequency = form.watch("postFrequency");
    const tone = form.watch("tone");
    const primaryColor = form.watch("primaryColor");
    const secondaryColor = form.watch("secondaryColor");
    const accentColor = form.watch("accentColor");

    const onSubmit = (data: OnboardingData) => {
        startTransition(async () => {
            try {
                await createContentPlan(data);
            } catch (error) {
                console.error("Failed to create plan:", error);
                // In a real app, I'd show a toast here
            }
        });
    };

    const nextStep = async () => {
        const fieldsToValidate = getFieldsForStep(step);
        const isValid = await form.trigger(fieldsToValidate);
        if (isValid && step < STEPS) {
            setStep(step + 1);
        }
    };

    const prevStep = () => {
        if (step > 1) setStep(step - 1);
    };

    const progress = (step / STEPS) * 100;

    // Loading State
    if (isPending) {
        return (
            <div className="min-h-screen bg-background flex items-center justify-center p-4">
                <Card className="w-full max-w-2xl mx-auto p-12">
                    <div className="text-center space-y-6">
                        <div className="inline-flex items-center justify-center w-20 h-20 rounded-full bg-primary/10 mb-4 animate-pulse">
                            <Sparkles className="h-10 w-10 text-primary animate-spin" />
                        </div>
                        <div className="space-y-2">
                            <h2 className="text-2xl font-semibold">Creating Your Content Plan</h2>
                            <p className="text-muted-foreground">
                                Our AI is crafting personalized video ideas for your business...
                            </p>
                        </div>
                        {/* Simple Progress Bar */}
                        <div className="w-full bg-secondary h-2 rounded-full overflow-hidden">
                            <div className="h-full bg-primary animate-progress-indeterminate origin-left" />
                        </div>
                    </div>
                </Card>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-background flex items-center justify-center p-4">
            <Card className="w-full max-w-2xl mx-auto p-8">
                <div className="mb-8">
                    <div className="flex items-center justify-between mb-2">
                        <h2 className="text-sm font-medium text-muted-foreground">
                            Step {step} of {STEPS}
                        </h2>
                        <span className="text-sm font-medium">{Math.round(progress)}%</span>
                    </div>
                    {/* Progress Bar */}
                    <div className="w-full bg-secondary h-2 rounded-full overflow-hidden transition-all">
                        <div className="h-full bg-primary transition-all duration-300" style={{ width: `${progress}%` }} />
                    </div>
                </div>

                <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-8">
                    {step === 1 && (
                        <div className="space-y-6">
                            <div className="text-center mb-8">
                                <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-primary/10 mb-4">
                                    <Sparkles className="h-8 w-8 text-primary" />
                                </div>
                                <h1 className="text-3xl font-semibold tracking-tight mb-2">
                                    Welcome to Directr
                                </h1>
                                <p className="text-muted-foreground leading-relaxed">
                                    Let&apos;s create your personalized content strategy in just a few steps
                                </p>
                            </div>

                            <div className="space-y-4">
                                <Label htmlFor="brandName">What&apos;s your brand name?</Label>
                                <Input
                                    id="brandName"
                                    {...form.register("brandName")}
                                    placeholder="Enter your brand or business name"
                                    className="h-12 text-lg"
                                />
                                {form.formState.errors.brandName && (
                                    <p className="text-sm text-red-500">{form.formState.errors.brandName.message}</p>
                                )}
                            </div>

                            <div className="space-y-4">
                                <Label htmlFor="businessType">What type of business do you run?</Label>
                                <Input
                                    id="businessType"
                                    {...form.register("businessType")}
                                    placeholder="e.g., Fitness coaching, Coffee shop, Marketing agency"
                                    className="h-12"
                                />
                                {form.formState.errors.businessType && (
                                    <p className="text-sm text-red-500">{form.formState.errors.businessType.message}</p>
                                )}
                            </div>
                        </div>
                    )}

                    {step === 2 && (
                        <div className="space-y-6">
                            <div className="space-y-2">
                                <h2 className="text-2xl font-semibold">Who&apos;s your target audience?</h2>
                                <p className="text-muted-foreground">
                                    Help us understand who you&apos;re creating content for
                                </p>
                            </div>

                            <div className="space-y-4">
                                <Label htmlFor="targetAudience">Describe your ideal viewer</Label>
                                <Input
                                    id="targetAudience"
                                    {...form.register("targetAudience")}
                                    placeholder="e.g., Young professionals interested in fitness and wellness"
                                    className="h-12"
                                />
                                {form.formState.errors.targetAudience && (
                                    <p className="text-sm text-red-500">{form.formState.errors.targetAudience.message}</p>
                                )}
                            </div>
                        </div>
                    )}

                    {step === 3 && (
                        <div className="space-y-6">
                            <div className="space-y-2">
                                <h2 className="text-2xl font-semibold">What are your content goals?</h2>
                                <p className="text-muted-foreground">Select all that apply</p>
                            </div>

                            <div className="space-y-4">
                                {["Brand Awareness", "Generate Leads", "Drive Sales", "Build Community", "Educate Audience"].map((goal) => (
                                    <div key={goal} className="flex items-center space-x-3 p-4 rounded-lg border hover:bg-slate-50 transition-colors">
                                        <input
                                            type="checkbox"
                                            id={goal}
                                            value={goal}
                                            className="h-4 w-4 rounded border-gray-300 text-primary focus:ring-primary"
                                            checked={contentGoals.includes(goal)}
                                            onChange={(e) => {
                                                const checked = e.target.checked;
                                                const current = form.getValues("contentGoals");
                                                if (checked) {
                                                    form.setValue("contentGoals", [...current, goal]);
                                                } else {
                                                    form.setValue("contentGoals", current.filter(g => g !== goal));
                                                }
                                            }}
                                        />
                                        <Label htmlFor={goal} className="flex-1 cursor-pointer font-normal">
                                            {goal}
                                        </Label>
                                    </div>
                                ))}
                                {form.formState.errors.contentGoals && (
                                    <p className="text-sm text-red-500">{form.formState.errors.contentGoals.message}</p>
                                )}
                            </div>
                        </div>
                    )}

                    {step === 4 && (
                        <div className="space-y-6">
                            <div className="space-y-2">
                                <h2 className="text-2xl font-semibold">Which platforms will you post on?</h2>
                                <p className="text-muted-foreground">Choose your primary channels</p>
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                {["Instagram Reels", "TikTok", "YouTube Shorts", "Facebook"].map((platform) => (
                                    <div
                                        key={platform}
                                        className={`p-6 rounded-xl border-2 cursor-pointer transition-all ${platforms.includes(platform)
                                            ? "border-primary bg-primary/5"
                                            : "border-border hover:bg-slate-50"
                                            }`}
                                        onClick={() => {
                                            const current = form.getValues("platforms");
                                            if (current.includes(platform)) {
                                                form.setValue("platforms", current.filter(p => p !== platform));
                                            } else {
                                                form.setValue("platforms", [...current, platform]);
                                            }
                                        }}
                                    >
                                        <div className="text-center">
                                            <p className="font-medium">{platform}</p>
                                        </div>
                                    </div>
                                ))}
                                {form.formState.errors.platforms && (
                                    <p className="text-sm text-red-500 col-span-2">{form.formState.errors.platforms.message}</p>
                                )}
                            </div>
                        </div>
                    )}

                    {step === 5 && (
                        <div className="space-y-6">
                            <div className="space-y-2">
                                <h2 className="text-2xl font-semibold">How often do you want to post?</h2>
                                <p className="text-muted-foreground">Choose a sustainable cadence</p>
                            </div>

                            <div className="space-y-3">
                                {["2-3 times per week", "4-5 times per week", "Daily", "Custom"].map((frequency) => (
                                    <div
                                        key={frequency}
                                        className={`flex items-center space-x-3 p-4 rounded-lg border cursor-pointer transition-all ${postFrequency === frequency ? "border-primary bg-primary/5" : "hover:bg-slate-50"
                                            }`}
                                        onClick={() => form.setValue("postFrequency", frequency)}
                                    >
                                        <div className={`w-4 h-4 rounded-full border border-primary flex items-center justify-center`}>
                                            {postFrequency === frequency && <div className="w-2 h-2 rounded-full bg-primary" />}
                                        </div>
                                        <Label className="flex-1 cursor-pointer font-normal">
                                            {frequency}
                                        </Label>
                                    </div>
                                ))}
                            </div>
                            {form.formState.errors.postFrequency && (
                                <p className="text-sm text-red-500">{form.formState.errors.postFrequency.message}</p>
                            )}
                        </div>
                    )}

                    {step === 6 && (
                        <div className="space-y-6">
                            <div className="space-y-2">
                                <h2 className="text-2xl font-semibold">What&apos;s your content tone?</h2>
                                <p className="text-muted-foreground">Select the vibe that matches your brand</p>
                            </div>

                            <div className="space-y-3">
                                {["Professional", "Friendly & Casual", "Inspirational", "Educational", "Entertaining"].map((t) => (
                                    <div
                                        key={t}
                                        className={`flex items-center space-x-3 p-4 rounded-lg border cursor-pointer transition-all ${tone === t ? "border-primary bg-primary/5" : "hover:bg-slate-50"
                                            }`}
                                        onClick={() => form.setValue("tone", t)}
                                    >
                                        <div className={`w-4 h-4 rounded-full border border-primary flex items-center justify-center`}>
                                            {tone === t && <div className="w-2 h-2 rounded-full bg-primary" />}
                                        </div>
                                        <Label className="flex-1 cursor-pointer font-normal">
                                            {t}
                                        </Label>
                                    </div>
                                ))}
                            </div>
                            {form.formState.errors.tone && (
                                <p className="text-sm text-red-500">{form.formState.errors.tone.message}</p>
                            )}
                        </div>
                    )}

                    {step === 7 && (
                        <div className="space-y-6">
                            <div className="space-y-2">
                                <h2 className="text-2xl font-semibold">Set your brand colors</h2>
                                <p className="text-muted-foreground">These will be used in your video graphics</p>
                            </div>

                            <div className="space-y-6">
                                <div className="space-y-3">
                                    <Label htmlFor="primaryColor">Primary Color</Label>
                                    <div className="flex gap-4 items-center">
                                        <input
                                            type="color"
                                            id="primaryColor"
                                            {...form.register("primaryColor")}
                                            className="h-16 w-16 rounded-lg cursor-pointer border-2 border-border bg-background p-1"
                                        />
                                        <Input
                                            value={primaryColor}
                                            onChange={(e) => form.setValue("primaryColor", e.target.value)}
                                            placeholder="#3B82F6"
                                            className="flex-1 h-12"
                                        />
                                    </div>
                                    {form.formState.errors.primaryColor && (
                                        <p className="text-sm text-red-500">{form.formState.errors.primaryColor.message}</p>
                                    )}
                                </div>

                                <div className="space-y-3">
                                    <Label htmlFor="secondaryColor">Secondary Color (Optional)</Label>
                                    <div className="flex gap-4 items-center">
                                        <input
                                            type="color"
                                            id="secondaryColor"
                                            {...form.register("secondaryColor")}
                                            className="h-16 w-16 rounded-lg cursor-pointer border-2 border-border bg-background p-1"
                                        />
                                        <Input
                                            value={secondaryColor}
                                            onChange={(e) => form.setValue("secondaryColor", e.target.value)}
                                            placeholder="#10B981"
                                            className="flex-1 h-12"
                                        />
                                    </div>
                                </div>

                                <div className="space-y-3">
                                    <Label htmlFor="accentColor">Accent Color (Optional)</Label>
                                    <div className="flex gap-4 items-center">
                                        <input
                                            type="color"
                                            id="accentColor"
                                            {...form.register("accentColor")}
                                            className="h-16 w-16 rounded-lg cursor-pointer border-2 border-border bg-background p-1"
                                        />
                                        <Input
                                            value={accentColor}
                                            onChange={(e) => form.setValue("accentColor", e.target.value)}
                                            placeholder="#F59E0B"
                                            className="flex-1 h-12"
                                        />
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}

                    <div className="flex justify-between pt-6 border-t">
                        {step > 1 ? (
                            <Button
                                type="button"
                                variant="outline"
                                onClick={prevStep}
                            >
                                <ChevronLeft className="h-4 w-4 mr-2" />
                                Previous
                            </Button>
                        ) : (
                            <div />
                        )}

                        {step < STEPS ? (
                            <Button
                                type="button"
                                onClick={nextStep}
                            >
                                Next
                                <ChevronRight className="h-4 w-4 ml-2" />
                            </Button>
                        ) : (
                            <Button
                                type="submit"
                                disabled={isPending}
                            >
                                {isPending ? "Creating plan..." : "Create My Plan"}
                                <Sparkles className="h-4 w-4 ml-2" />
                            </Button>
                        )}
                    </div>
                </form>
            </Card>
        </div>
    );
}

function getFieldsForStep(step: number): (keyof OnboardingData)[] {
    switch (step) {
        case 1:
            return ["brandName", "businessType"];
        case 2:
            return ["targetAudience"];
        case 3:
            return ["contentGoals"];
        case 4:
            return ["platforms"];
        case 5:
            return ["postFrequency"];
        case 6:
            return ["tone"];
        case 7:
            return ["primaryColor"];
        default:
            return [];
    }
}

