/**
 * Environment variable validation and configuration
 * Fails fast with clear error messages if required variables are missing
 */

interface Config {
  database: {
    url: string;
  };
  auth: {
    googleClientId?: string;
    googleClientSecret?: string;
    publicUrl?: string;
    jwtSecret: string;
  };
  ai: {
    googleApiKey?: string;
    openaiApiKey?: string;
  };
  server: {
    port: number;
    nodeEnv: string;
  };
  cors: {
    origin?: string;
  };
}

function getRequiredEnv(key: string): string {
  const value = process.env[key];
  if (!value) {
    throw new Error(
      `Missing required environment variable: ${key}\n` +
      `Please set ${key} in your .env file or environment.\n` +
      `See .env.example for all required variables.`
    );
  }
  return value;
}

function getOptionalEnv(key: string): string | undefined {
  return process.env[key];
}

export function validateConfig(): Config {
  const config: Config = {
    database: {
      url: getRequiredEnv("DATABASE_URL"),
    },
    auth: {
      googleClientId: getOptionalEnv("GOOGLE_CLIENT_ID"),
      googleClientSecret: getOptionalEnv("GOOGLE_CLIENT_SECRET"),
      publicUrl: getOptionalEnv("PUBLIC_URL"),
      jwtSecret: getRequiredEnv("JWT_SECRET"),
    },
    ai: {
      googleApiKey: getOptionalEnv("GOOGLE_API_KEY"),
      openaiApiKey: getOptionalEnv("OPENAI_API_KEY"),
    },
    server: {
      port: parseInt(getRequiredEnv("PORT"), 10),
      nodeEnv: getOptionalEnv("NODE_ENV") || "development",
    },
    cors: {
      origin: getOptionalEnv("CORS_ORIGIN"),
    },
  };

  // Warn about missing optional but recommended variables
  if (!config.auth.googleClientId || !config.auth.googleClientSecret) {
    console.warn(
      "⚠️  Google OAuth not configured. Authentication endpoints will return 503.\n" +
      "   Set GOOGLE_CLIENT_ID and GOOGLE_CLIENT_SECRET to enable authentication."
    );
  }

  if (!config.ai.openaiApiKey) {
    console.warn(
      "⚠️  OPENAI_API_KEY not set. Content plan generation will fail.\n" +
      "   Set OPENAI_API_KEY to enable AI-powered content generation."
    );
  }

  return config;
}

export const config = validateConfig();

server/middleware/security.ts.content:
/**
 * Security middleware: CORS, Helmet headers, and OWASP protections
 * Implements comprehensive security headers and CORS configuration
 */

import cors from "cors";
import helmet from "helmet";
import type { Express, Request, Response, NextFunction } from "express";

export function setupSecurity(app: Express) {
  const isProduction = process.env.NODE_ENV === "production";

  // Security headers (Helmet) - OWASP recommended headers
  app.use(
    helmet({
      contentSecurityPolicy: {
        directives: {
          defaultSrc: ["'self'"],
          styleSrc: ["'self'", "'unsafe-inline'", "https://fonts.googleapis.com"],
          fontSrc: ["'self'", "https://fonts.gstatic.com"],
          scriptSrc: ["'self'"],
          imgSrc: ["'self'", "data:", "https:", "blob:"],
          mediaSrc: [
            "'self'",
            "blob:",
            "data:",
            "https://*.supabase.co",
            "https://*.supabase.in",
          ],
          connectSrc: [
            "'self'",
            "https://*.supabase.co",
            "https://*.supabase.in",
            "https://api.openai.com",
            "https://generativelanguage.googleapis.com",
            ...(isProduction ? [] : ["ws:", "wss:"]),
          ],
          frameSrc: ["'self'"],
          frameAncestors: ["'self'", "https://*.replit.app", "https://*.replit.dev", "https://*.repl.co", "https://navinta.org", "https://www.navinta.org"],
          objectSrc: ["'none'"],
          baseUri: ["'self'"],
          formAction: ["'self'"],
          upgradeInsecureRequests: isProduction ? [] : null,
        },
      },
      crossOriginEmbedderPolicy: false,
      crossOriginOpenerPolicy: false,
      hsts: {
        maxAge: 31536000,
        includeSubDomains: true,
        preload: true,
      },
      referrerPolicy: { policy: "strict-origin-when-cross-origin" },
      xssFilter: true,
      noSniff: true,
      ieNoOpen: true,
      frameguard: false,
    })
  );

  // Additional security headers
  app.use((_req: Request, res: Response, next: NextFunction) => {
    res.setHeader("X-Content-Type-Options", "nosniff");
    res.setHeader("X-XSS-Protection", "1; mode=block");
    res.setHeader("Permissions-Policy", "geolocation=(), microphone=(self), camera=(self)");
    if (isProduction) {
      res.setHeader("Cache-Control", "no-store, no-cache, must-revalidate, proxy-revalidate");
      res.setHeader("Pragma", "no-cache");
      res.setHeader("Expires", "0");
    }
    next();
  });

  // CORS configuration with strict origin control
  const publicUrl = process.env.PUBLIC_URL;
  const defaultProductionOrigins = publicUrl ? [publicUrl] : [];

  const allowedOrigins = process.env.CORS_ORIGIN
    ? process.env.CORS_ORIGIN.split(",").map(o => o.trim())
    : isProduction
    ? defaultProductionOrigins
    : ["http://localhost:5000", "http://localhost:5173", "http://0.0.0.0:5000"];

  const corsOptions: cors.CorsOptions = {
    origin: (origin, callback) => {
      if (!origin || allowedOrigins.includes(origin) || !isProduction) {
        callback(null, true);
      } else {
        callback(new Error("Not allowed by CORS"));
      }
    },
    credentials: true,
    methods: ["GET", "POST", "PATCH", "DELETE", "PUT", "OPTIONS"],
    allowedHeaders: ["Content-Type", "Authorization", "X-Requested-With"],
    exposedHeaders: ["RateLimit-Limit", "RateLimit-Remaining", "RateLimit-Reset"],
    maxAge: 86400,
  };

  app.use(cors(corsOptions));

  // Block requests with suspicious headers
  app.use((req: Request, res: Response, next: NextFunction) => {
    const contentType = req.headers["content-type"];
    if (req.method !== "GET" && req.method !== "HEAD" && req.method !== "OPTIONS") {
      if (contentType && !contentType.includes("application/json") &&
          !contentType.includes("multipart/form-data") &&
          !contentType.includes("application/x-www-form-urlencoded")) {
        return res.status(415).json({ error: "Unsupported content type" });
      }
    }
    next();
  });
}

