import { useEffect, useRef, useState } from "react";
import gsap from "gsap";

interface ClapperboardIntroProps {
  onComplete: () => void;
}

export default function ClapperboardIntro({ onComplete }: ClapperboardIntroProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const clapperRef = useRef<HTMLDivElement>(null);
  const armRef = useRef<HTMLDivElement>(null);
  const particlesRef = useRef<(HTMLDivElement | null)[]>([]);
  const [hasPlayed, setHasPlayed] = useState(false);

  useEffect(() => {
    const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    if (prefersReducedMotion) {
      onComplete();
      return;
    }

    if (!containerRef.current || !clapperRef.current || !armRef.current) return;

    const ctx = gsap.context(() => {
      gsap.set(clapperRef.current, { opacity: 0, scale: 0.9 });
      gsap.set(armRef.current, { rotateX: 0, transformOrigin: "bottom center" });
      gsap.set(particlesRef.current, { opacity: 0, scale: 0 });

      const tl = gsap.timeline({
        onComplete: () => {
          gsap.to(containerRef.current, {
            opacity: 0,
            duration: 0.5,
            ease: "power2.out",
            onComplete: () => {
              setHasPlayed(true);
              onComplete();
            }
          });
        }
      });

      tl.to(clapperRef.current, {
        opacity: 1,
        scale: 1,
        duration: 1,
        ease: "power3.out",
      }, 0.5);

      tl.to(armRef.current, {
        rotateX: -30,
        duration: 0.8,
        ease: "power2.out",
      }, 1.5);

      tl.to(armRef.current, {
        rotateX: 0,
        duration: 0.12,
        ease: "power4.in",
      }, 2.8);

      tl.to(containerRef.current, {
        x: "random(-2, 2)",
        y: "random(-1, 1)",
        duration: 0.05,
        repeat: 3,
        yoyo: true,
        ease: "none",
      }, 2.92);

      particlesRef.current.forEach((particle, i) => {
        const angle = (i / 12) * Math.PI * 2;
        const distance = 100 + Math.random() * 150;
        tl.to(particle, {
          opacity: 1,
          scale: 1,
          x: Math.cos(angle) * distance,
          y: Math.sin(angle) * distance,
          duration: 0.6,
          ease: "power2.out",
        }, 3);
      });

      particlesRef.current.forEach((particle) => {
        tl.to(particle, {
          opacity: 0,
          duration: 0.4,
          ease: "power2.in",
        }, 3.4);
      });

      tl.to(clapperRef.current, {
        opacity: 0,
        scale: 1.1,
        duration: 0.5,
        ease: "power2.out",
      }, 3.2);

    }, containerRef);

    return () => ctx.revert();
  }, [onComplete]);

  if (hasPlayed) return null;

  const setParticleRef = (i: number) => (el: HTMLDivElement | null) => {
    particlesRef.current[i] = el;
  };

  return (
    <div 
      ref={containerRef}
      className="fixed inset-0 z-[100] bg-black flex items-center justify-center"
    >
      {Array.from({ length: 12 }).map((_, i) => (
        <div
          key={i}
          ref={setParticleRef(i)}
          className="absolute w-px bg-white"
          style={{ height: 20 + Math.random() * 30 }}
        />
      ))}

      <div 
        ref={clapperRef}
        className="relative"
        style={{ 
          width: "clamp(180px, 30vw, 280px)",
          perspective: "800px"
        }}
      >
        <div 
          ref={armRef}
          className="relative z-10"
          style={{ transformStyle: "preserve-3d" }}
        >
          <svg viewBox="0 0 100 20" className="w-full">
            <rect x="0" y="0" width="100" height="20" fill="black" stroke="white" strokeWidth="1.5" rx="2" />
            <g>
              <rect x="5" y="0" width="12" height="20" fill="white" transform="skewX(-15)" />
              <rect x="25" y="0" width="12" height="20" fill="white" transform="skewX(-15)" />
              <rect x="45" y="0" width="12" height="20" fill="white" transform="skewX(-15)" />
              <rect x="65" y="0" width="12" height="20" fill="white" transform="skewX(-15)" />
              <rect x="85" y="0" width="12" height="20" fill="white" transform="skewX(-15)" />
            </g>
          </svg>
        </div>

        <div className="relative -mt-1">
          <svg viewBox="0 0 100 60" className="w-full">
            <rect x="0" y="0" width="100" height="60" fill="black" stroke="white" strokeWidth="1.5" rx="3" />
            <line x1="5" y1="12" x2="95" y2="12" stroke="white" strokeWidth="0.5" opacity="0.3" />
            <text x="50" y="10" textAnchor="middle" fill="white" fontSize="6" fontFamily="sans-serif" letterSpacing="0.2em">SCENE</text>
            <line x1="5" y1="25" x2="95" y2="25" stroke="white" strokeWidth="0.5" opacity="0.3" />
            <text x="25" y="38" textAnchor="middle" fill="white" fontSize="5" fontFamily="sans-serif" opacity="0.6">TAKE</text>
            <text x="25" y="48" textAnchor="middle" fill="white" fontSize="8" fontFamily="sans-serif" fontWeight="bold">01</text>
            <line x1="50" y1="28" x2="50" y2="52" stroke="white" strokeWidth="0.5" opacity="0.3" />
            <text x="75" y="38" textAnchor="middle" fill="white" fontSize="5" fontFamily="sans-serif" opacity="0.6">ROLL</text>
            <text x="75" y="48" textAnchor="middle" fill="white" fontSize="8" fontFamily="sans-serif" fontWeight="bold">A</text>
            <text x="50" y="58" textAnchor="middle" fill="white" fontSize="5" fontFamily="sans-serif" fontWeight="bold" letterSpacing="0.15em">NAVINTA</text>
          </svg>
        </div>
      </div>
    </div>
  );
}

