/* ============================================
   NAVINTA PRO DESIGN SYSTEM
   Enterprise-grade dark theme with glass effects
   ============================================ */

/* ANIMATION TOKENS */
:root {
  --ease-out-expo: cubic-bezier(0.16, 1, 0.3, 1);
  --ease-out-quart: cubic-bezier(0.25, 1, 0.5, 1);
  --ease-in-out-quart: cubic-bezier(0.76, 0, 0.24, 1);
  --duration-fast: 150ms;
  --duration-normal: 250ms;
  --duration-slow: 400ms;
  --duration-slower: 600ms;

  /* CINEMATIC COLOR PALETTE */
  --cinematic-ivory: #F5F1EC;
  --cinematic-bone: #E8E4DF;
  --cinematic-copper: #B08A5A;
  --cinematic-bronze: #9A7B4F;
  --cinematic-indigo: #4338CA;
  --cinematic-indigo-muted: rgba(67, 56, 202, 0.15);
  --cinematic-sage: rgba(132, 169, 140, 0.2);
}

/* LIGHT MODE (Default - Clean Professional) */
:root {
  --button-outline: rgba(0,0,0, .08);
  --badge-outline: rgba(0,0,0, .05);
  --opaque-button-border-intensity: 8;
  --elevate-1: rgba(0,0,0, .03);
  --elevate-2: rgba(0,0,0, .06);

  /* Core backgrounds - clean white */
  --background: 0 0% 100%;
  --foreground: 222 47% 11%;
  --border: 220 13% 91%;

  /* Cards - subtle elevation */
  --card: 0 0% 100%;
  --card-foreground: 222 47% 11%;
  --card-border: 220 13% 91%;

  /* Sidebar */
  --sidebar: 0 0% 98%;
  --sidebar-foreground: 222 47% 11%;
  --sidebar-border: 220 13% 91%;
  --sidebar-primary: 217 93% 50%;
  --sidebar-primary-foreground: 0 0% 100%;
  --sidebar-accent: 220 14% 96%;
  --sidebar-accent-foreground: 222 47% 11%;
  --sidebar-ring: 217 93% 50%;

  /* Popover */
  --popover: 0 0% 100%;
  --popover-foreground: 222 47% 11%;
  --popover-border: 220 13% 91%;

  /* Primary - Vibrant Blue #135bec */
  --primary: 217 93% 50%;
  --primary-foreground: 0 0% 100%;

  /* Indigo Accent - #4f46e5 */
  --indigo-accent: 243 75% 59%;

  /* Secondary */
  --secondary: 220 14% 96%;
  --secondary-foreground: 222 47% 11%;

  /* Muted */
  --muted: 220 14% 96%;
  --muted-foreground: 220 9% 46%;

  /* Accent */
  --accent: 220 14% 96%;
  --accent-foreground: 222 47% 11%;

  /* Destructive */
  --destructive: 0 72% 51%;
  --destructive-foreground: 0 0% 100%;

  /* Input & Ring */
  --input: 220 13% 91%;
  --ring: 217 93% 50%;

  /* Charts */
  --chart-1: 217 93% 50%;
  --chart-2: 243 75% 59%;
  --chart-3: 160 70% 50%;
  --chart-4: 30 85% 55%;
  --chart-5: 340 80% 55%;

  /* Typography - Clean Sans-Serif System */
  --font-sans: 'Inter', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  --font-display: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
  --font-serif: Georgia, serif;
  --font-mono: "SF Mono", Menlo, Monaco, "Courier New", monospace;

  /* Spacing & Radius */
  --radius: 0.5rem;
  --radius-lg: 1rem;
  --radius-xl: 1.5rem;
  --spacing: 0.25rem;
  --tracking-normal: -0.01em;

  /* Shadows */
  --shadow-2xs: 0px 1px 2px 0px hsl(0 0% 0% / 0.3);
  --shadow-xs: 0px 1px 3px 0px hsl(0 0% 0% / 0.4);
  --shadow-sm: 0px 2px 4px -1px hsl(0 0% 0% / 0.3), 0px 1px 2px -1px hsl(0 0% 0% / 0.4);
  --shadow: 0px 4px 8px -2px hsl(0 0% 0% / 0.4), 0px 2px 4px -2px hsl(0 0% 0% / 0.3);
  --shadow-md: 0px 8px 16px -4px hsl(0 0% 0% / 0.5), 0px 4px 6px -2px hsl(0 0% 0% / 0.3);
  --shadow-lg: 0px 12px 24px -6px hsl(0 0% 0% / 0.5), 0px 6px 10px -4px hsl(0 0% 0% / 0.4);
  --shadow-xl: 0px 20px 40px -8px hsl(0 0% 0% / 0.6), 0px 10px 16px -6px hsl(0 0% 0% / 0.4);
  --shadow-2xl: 0px 32px 64px -16px hsl(0 0% 0% / 0.7);

  /* Computed borders */
  --sidebar-primary-border: hsl(var(--sidebar-primary));
  --sidebar-accent-border: hsl(var(--sidebar-accent));
  --primary-border: hsl(var(--primary));
  --secondary-border: hsl(var(--secondary));
  --muted-border: hsl(var(--muted));
  --accent-border: hsl(var(--accent));
  --destructive-border: hsl(var(--destructive));
}

