import { useEffect, useRef, useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { Play, Pause } from "lucide-react";
import { Button } from "@/components/ui/button";

interface WordTimestamp {
  word: string;
  start: number;
  end: number;
}

interface Caption {
  start: number;
  end: number;
  originalText: string;
  viralText: string;
  useViral: boolean;
  highlightWords: string[];
  words: WordTimestamp[];
  style: {
    font: string;
    baseTextColor: string;
    outlineColor: string;
    background: string;
    highlightTextColor: string;
    highlightBackground: string;
    position: string;
    animation: string;
  };
}

interface Transcription {
  id: number;
  videoId: number;
  userId: number;
  language: string;
  duration: number;
  captions: Caption[];
  createdAt: string;
}

interface AnimatedCaptionPlayerProps {
  videoId: string;
  videoSrc: string;
  title: string;
}

export function AnimatedCaptionPlayer({ videoId, videoSrc, title }: AnimatedCaptionPlayerProps) {
  const videoRef = useRef<HTMLVideoElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [currentCaption, setCurrentCaption] = useState<Caption | null>(null);
  const [currentWordIndex, setCurrentWordIndex] = useState<number>(0);

  // Fetch transcription data
  const { data: transcription } = useQuery<Transcription>({
    queryKey: ["/api/videos", videoId, "captions"],
  });

  // Update current time and play state as video plays
  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    const handleTimeUpdate = () => {
      setCurrentTime(video.currentTime);
    };

    const handlePlay = () => setIsPlaying(true);
    const handlePause = () => setIsPlaying(false);

    video.addEventListener("timeupdate", handleTimeUpdate);
    video.addEventListener("play", handlePlay);
    video.addEventListener("pause", handlePause);

    return () => {
      video.removeEventListener("timeupdate", handleTimeUpdate);
      video.removeEventListener("play", handlePlay);
      video.removeEventListener("pause", handlePause);
    };
  }, []);

  // Update current caption based on video time
  useEffect(() => {
    if (!transcription?.captions) {
      setCurrentCaption(null);
      return;
    }

    const activeCaption = transcription.captions.find(
      (cap) => currentTime >= cap.start && currentTime <= cap.end
    );

    setCurrentCaption(activeCaption || null);

    // Find current word within the caption
    if (activeCaption) {
      const activeWordIndex = activeCaption.words.findIndex(
        (word) => currentTime >= word.start && currentTime < word.end
      );
      setCurrentWordIndex(activeWordIndex >= 0 ? activeWordIndex : 0);
    } else {
      setCurrentWordIndex(0);
    }
  }, [currentTime, transcription]);

  const togglePlayPause = () => {
    const video = videoRef.current;
    if (!video) return;

    if (video.paused) {
      video.play();
    } else {
      video.pause();
    }
  };

  // Render 3-4 words with current word highlighted (sliding window)
  const renderCaptions = () => {
    if (!currentCaption || currentWordIndex < 0) return null;

    const maxWordsToShow = 4;
    const words = currentCaption.words;

    // Calculate sliding window: show current word + context
    const windowStart = Math.max(0, currentWordIndex - 1);
    const windowEnd = Math.min(words.length, windowStart + maxWordsToShow);
    const visibleWords = words.slice(windowStart, windowEnd);

    return (
      <div className="caption-container" data-testid="caption-overlay">
        <div className="caption-words">
          {visibleWords.map((word, index) => {
            const actualIndex = windowStart + index;
            const isCurrentWord = actualIndex === currentWordIndex;
            const isHighlightWord = currentCaption.highlightWords.some(hw => 
              word.word.toLowerCase().includes(hw.toLowerCase())
            );

            return (
              <span
                key={`${word.start}-${actualIndex}`}
                className={`
                  caption-word
                  ${isCurrentWord ? 'current-word pop-in' : ''}
                  ${isHighlightWord && isCurrentWord ? 'highlight-word' : ''}
                `}
                data-testid={`caption-word-${actualIndex}`}
              >
                {word.word}
              </span>
            );
          })}
        </div>
      </div>
    );
  };

  return (
    <div className="relative w-full h-full bg-black rounded-lg overflow-hidden group" data-testid="animated-caption-player">
      <video
        ref={videoRef}
        src={videoSrc}
        className="w-full h-full object-contain"
        onClick={togglePlayPause}
        data-testid="video-element"
      />

      {/* Caption Overlay */}
      {renderCaptions()}

      {/* Play/Pause Overlay */}
      {!isPlaying && (
        <div className="absolute inset-0 flex items-center justify-center bg-black/30 backdrop-blur-[1px]">
          <Button
            size="icon"
            variant="outline"
            className="h-16 w-16 rounded-full backdrop-blur-sm border-2"
            onClick={togglePlayPause}
            data-testid="button-play-pause"
          >
            {isPlaying ? (
              <Pause className="h-8 w-8" />
            ) : (
              <Play className="h-8 w-8 ml-1" />
            )}
          </Button>
        </div>
      )}

      {/* Controls Overlay (shows on hover) */}
      <div className="absolute bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-black/80 via-black/40 to-transparent opacity-0 group-hover:opacity-100 transition-opacity">
        <div className="flex items-center gap-3">
          <Button
            size="icon"
            variant="ghost"
            onClick={togglePlayPause}
            className="h-10 w-10 text-white hover:bg-white/20"
            data-testid="button-control-play-pause"
          >
            {isPlaying ? (
              <Pause className="h-5 w-5" />
            ) : (
              <Play className="h-5 w-5" />
            )}
          </Button>
          <div className="flex-1">
            <div className="h-1 bg-white/20 rounded-full overflow-hidden">
              <div
                className="h-full bg-white transition-all"
                style={{
                  width: `${(currentTime / (videoRef.current?.duration || 1)) * 100}%`,
                }}
              />
            </div>
          </div>
        </div>
      </div>

      <style>{`
        .caption-container {
          position: absolute;
          bottom: 100px;
          left: 50%;
          transform: translateX(-50%);
          max-width: 90%;
          padding: 16px 24px;
          background: rgba(0, 0, 0, 0.75);
          border-radius: 16px;
          backdrop-filter: blur(8px);
          pointer-events: none;
        }

        .caption-words {
          display: flex;
          flex-wrap: wrap;
          gap: 8px;
          justify-content: center;
          align-items: center;
          font-family: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
          font-weight: 900;
          font-size: clamp(24px, 5vw, 36px);
          line-height: 1.2;
          text-align: center;
          text-transform: uppercase;
        }

        .caption-word {
          color: white;
          text-shadow: 
            -2px -2px 0 #000,
            2px -2px 0 #000,
            -2px 2px 0 #000,
            2px 2px 0 #000,
            0 0 8px rgba(0, 0, 0, 0.8);
          transition: all 0.2s ease;
          display: inline-block;
        }

        .caption-word.current-word {
          color: #FFD700;
          font-size: 1.15em;
          text-shadow: 
            -2px -2px 0 #000,
            2px -2px 0 #000,
            -2px 2px 0 #000,
            2px 2px 0 #000,
            0 0 12px rgba(255, 215, 0, 0.6),
            0 0 24px rgba(255, 215, 0, 0.4);
        }

        .caption-word.highlight-word {
          color: #FFD700;
          animation: pulse-glow 0.6s ease-in-out infinite alternate;
        }

        @keyframes pop-in {
          0% {
            transform: scale(0.8);
            opacity: 0;
          }
          50% {
            transform: scale(1.2);
          }
          100% {
            transform: scale(1);
            opacity: 1;
          }
        }

        .caption-word.pop-in {
          animation: pop-in 0.3s cubic-bezier(0.68, -0.55, 0.265, 1.55);
        }

        @keyframes pulse-glow {
          from {
            text-shadow: 
              -2px -2px 0 #000,
              2px -2px 0 #000,
              -2px 2px 0 #000,
              2px 2px 0 #000,
              0 0 12px rgba(255, 215, 0, 0.6);
          }
          to {
            text-shadow: 
              -2px -2px 0 #000,
              2px -2px 0 #000,
              -2px 2px 0 #000,
              2px 2px 0 #000,
              0 0 20px rgba(255, 215, 0, 0.9),
              0 0 30px rgba(255, 215, 0, 0.6);
