import { useEffect, useRef } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";

gsap.registerPlugin(ScrollTrigger);

export default function DirectorModePreview() {
  const containerRef = useRef<HTMLDivElement>(null);
  const questionnaireRef = useRef<HTMLDivElement>(null);
  const questionTitleRef = useRef<HTMLDivElement>(null);
  const optionsRef = useRef<(HTMLDivElement | null)[]>([]);
  const selectedOptionRef = useRef<HTMLDivElement>(null);
  const nextButtonRef = useRef<HTMLButtonElement>(null);
  const progressDotsRef = useRef<(HTMLDivElement | null)[]>([]);

  const windowRef = useRef<HTMLDivElement>(null);
  const toolButtonsRef = useRef<(HTMLDivElement | null)[]>([]);
  const cameraRef = useRef<HTMLDivElement>(null);
  const recordingDotRef = useRef<HTMLDivElement>(null);
  const shotInfoRef = useRef<HTMLDivElement>(null);
  const scriptLinesRef = useRef<(HTMLDivElement | null)[]>([]);
  const finishButtonRef = useRef<HTMLButtonElement>(null);
  const progressBarRef = useRef<HTMLDivElement>(null);
  const exportOverlayRef = useRef<HTMLDivElement>(null);
  const videoThumbRef = useRef<HTMLDivElement>(null);
  const leftPanelRef = useRef<HTMLDivElement>(null);
  const rightPanelRef = useRef<HTMLDivElement>(null);
  const bottomBarRef = useRef<HTMLDivElement>(null);
  const orbsRef = useRef<(HTMLDivElement | null)[]>([]);

  useEffect(() => {
    if (!containerRef.current) return;

    const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    if (prefersReducedMotion) {
      gsap.set(questionnaireRef.current, { opacity: 0 });
      gsap.set(windowRef.current, { opacity: 1 });
      return;
    }

    const ctx = gsap.context(() => {
      // Initial states
      gsap.set(orbsRef.current, { opacity: 0, scale: 0 });
      gsap.set(questionnaireRef.current, { opacity: 0, scale: 0.8, rotateY: -30 });
      gsap.set(questionTitleRef.current, { opacity: 0, y: -30 });
      gsap.set(optionsRef.current, { opacity: 0, x: -50, scale: 0.9 });
      gsap.set(selectedOptionRef.current, { borderColor: "rgba(19, 91, 236, 0.3)" });
      gsap.set(nextButtonRef.current, { opacity: 0, scale: 0.8 });
      gsap.set(progressDotsRef.current, { opacity: 0.3, scale: 0.8 });

      gsap.set(windowRef.current, { opacity: 0, scale: 0.6, rotateX: 40, rotateY: 30, transformPerspective: 1500 });
      gsap.set(leftPanelRef.current, { x: -150, opacity: 0, rotateY: -120 });
      gsap.set(rightPanelRef.current, { x: 150, opacity: 0, rotateY: 120 });
      gsap.set(bottomBarRef.current, { y: 80, opacity: 0, rotateX: 60 });
      gsap.set(toolButtonsRef.current, { opacity: 0, scale: 0, rotation: -360 });
      gsap.set(cameraRef.current, { opacity: 0, scale: 0.3, rotateY: 360 });
      gsap.set(recordingDotRef.current, { opacity: 0, scale: 0 });
      gsap.set(shotInfoRef.current, { opacity: 0, x: 120, rotateY: 60 });
      gsap.set(scriptLinesRef.current, { opacity: 0, x: 100, rotateZ: 20 });
      gsap.set(finishButtonRef.current, { opacity: 0, scale: 0.3, rotateZ: -45 });
      gsap.set(progressBarRef.current, { scaleX: 0, transformOrigin: "left" });
      gsap.set(exportOverlayRef.current, { opacity: 0 });
      gsap.set(videoThumbRef.current, { opacity: 0, scale: 0, rotateY: 360 });

      const tl = gsap.timeline({
        scrollTrigger: {
          trigger: containerRef.current,
          start: "top top",
          end: "+=400%",
          scrub: 1.5,
          pin: true,
        },
      });

      // ============================================
      // PHASE 1: QUESTIONNAIRE (0-30)
      // ============================================

      // 0-3: Orbs fade in
      tl.to(orbsRef.current, {
        opacity: 0.5,
        scale: 1,
        duration: 3,
        ease: "power3.out",
        stagger: 0.3,
      }, 0);

      // 2-6: Questionnaire card flies in
      tl.to(questionnaireRef.current, {
        opacity: 1,
        scale: 1,
        rotateY: 0,
        duration: 4,
        ease: "power3.out",
      }, 2);

      // 5-7: Question title fades in
      tl.to(questionTitleRef.current, {
        opacity: 1,
        y: 0,
        duration: 2,
        ease: "power3.out",
      }, 5);

      // 7-11: Options slide in one by one
      optionsRef.current.forEach((opt, i) => {
        tl.to(opt, {
          opacity: 1,
          x: 0,
          scale: 1,
          duration: 1,
          ease: "back.out(1.5)",
        }, 7 + i * 1);
      });

      // 12-14: One option gets selected (highlight)
      tl.to(selectedOptionRef.current, {
        borderColor: "#135bec",
        backgroundColor: "rgba(19, 91, 236, 0.15)",
        scale: 1.02,
        duration: 2,
        ease: "power3.out",
      }, 12);

      // 14-15: Selection settles
      tl.to(selectedOptionRef.current, {
        scale: 1,
        duration: 1,
        ease: "power2.inOut",
      }, 14);

      // 15-19: Progress dots fill in
      progressDotsRef.current.forEach((dot, i) => {
        tl.to(dot, {
          opacity: 1,
          scale: 1,
          backgroundColor: "#135bec",
          duration: 1,
          ease: "power3.out",
        }, 15 + i * 1);
      });

      // 19-21: Continue button appears
      tl.to(nextButtonRef.current, {
        opacity: 1,
        scale: 1,
        duration: 2,
        ease: "back.out(2)",
      }, 19);

      // 22-24: Button press animation
      tl.to(nextButtonRef.current, {
        scale: 0.9,
        duration: 1,
        ease: "power3.in",
      }, 22);

      tl.to(nextButtonRef.current, {
        scale: 1.05,
        duration: 1,
        ease: "power3.out",
      }, 23);

      // 25-28: Questionnaire fades out
      tl.to(questionnaireRef.current, {
        opacity: 0,
        scale: 0.8,
        rotateY: 30,
        duration: 3,
        ease: "power3.inOut",
      }, 25);

      // ============================================
      // PHASE 2: DIRECTOR MODE UI (28-70)
      // ============================================

      // 28-34: Main window flies in
      tl.to(windowRef.current, {
        opacity: 1,
        scale: 1,
        rotateX: 0,
        rotateY: 0,
        duration: 6,
        ease: "power3.out",
      }, 28);

      // 32-36: Left panel slides in
      tl.to(leftPanelRef.current, {
        x: 0,
        opacity: 1,
        rotateY: 0,
        duration: 4,
        ease: "power3.out",
      }, 32);

      // 34-38: Right panel slides in
      tl.to(rightPanelRef.current, {
        x: 0,
        opacity: 1,
        rotateY: 0,
        duration: 4,
        ease: "power3.out",
      }, 34);

      // 36-39: Bottom bar slides up
      tl.to(bottomBarRef.current, {
        y: 0,
        opacity: 1,
        rotateX: 0,
        duration: 3,
        ease: "power3.out",
      }, 36);

      // 38-50: Tool buttons appear and glow one by one
      toolButtonsRef.current.forEach((btn, i) => {
        const btnStart = 38 + i * 3;

        // Button appears
        tl.to(btn, {
          opacity: 1,
          scale: 1,
          rotation: 0,
          duration: 2,
          ease: "back.out(2)",
        }, btnStart);

        // Button glows
        tl.to(btn, {
          boxShadow: "0 0 40px rgba(19, 91, 236, 0.9)",
          duration: 1,
          ease: "power2.out",
        }, btnStart + 1);

        // Glow fades
        tl.to(btn, {
          boxShadow: "0 0 0px rgba(19, 91, 236, 0)",
          duration: 1,
          ease: "power2.out",
        }, btnStart + 2);
      });

      // 40-45: Camera preview appears
      tl.to(cameraRef.current, {
        opacity: 1,
        scale: 1,
        rotateY: 0,
        duration: 5,
        ease: "power3.out",
      }, 40);

      // 45-47: Recording dot appears
      tl.to(recordingDotRef.current, {
        opacity: 1,
        scale: 1,
        duration: 2,
        ease: "elastic.out(1, 0.5)",
      }, 45);

      // 44-48: Shot info slides in
      tl.to(shotInfoRef.current, {
        opacity: 1,
        x: 0,
        rotateY: 0,
        duration: 4,
        ease: "power3.out",
      }, 44);

      // 48-54: Script lines appear one by one
      scriptLinesRef.current.forEach((line, i) => {
        tl.to(line, {
          opacity: 1,
          x: 0,
          rotateZ: 0,
          duration: 1.5,
          ease: "power3.out",
        }, 48 + i * 1.5);
      });

      // ============================================
      // PHASE 3: FINISH & EXPORT (55-80)
      // ============================================

      // 55-57: Recording stops
      tl.to(recordingDotRef.current, {
        opacity: 0,
        scale: 3,
        duration: 2,
        ease: "power3.out",
      }, 55);

      // 57-60: Finish button appears
      tl.to(finishButtonRef.current, {
        opacity: 1,
        scale: 1,
        rotateZ: 0,
        duration: 3,
        ease: "back.out(2)",
      }, 57);

      // 60-62: Button glows
      tl.to(finishButtonRef.current, {
        boxShadow: "0 0 40px rgba(19, 91, 236, 0.8)",
        duration: 2,
        ease: "power2.out",
      }, 60);

      // 62-64: Button press
      tl.to(finishButtonRef.current, {
        scale: 0.85,
        duration: 1,
        ease: "power3.in",
      }, 62);

      tl.to(finishButtonRef.current, {
        scale: 1.1,
        boxShadow: "0 0 0px rgba(19, 91, 236, 0)",
        duration: 1,
        ease: "power3.out",
      }, 63);

      tl.to(finishButtonRef.current, {
        scale: 1,
        duration: 0.5,
        ease: "power3.out",
      }, 64);

      // 65-68: Export overlay fades in, camera fades out
      tl.to(exportOverlayRef.current, {
        opacity: 1,
        duration: 3,
        ease: "power3.out",
      }, 65);

      tl.to(cameraRef.current, {
        scale: 0.6,
        opacity: 0,
        duration: 3,
        ease: "power3.inOut",
      }, 65);

      // 68-76: Progress bar fills
      tl.to(progressBarRef.current, {
        scaleX: 1,
        duration: 8,
        ease: "power2.inOut",
      }, 68);

      // 76-80: Video thumbnail appears
      tl.to(videoThumbRef.current, {
        opacity: 1,
        scale: 1,
        rotateY: 0,
        duration: 4,
        ease: "back.out(1.5)",
      }, 76);

      // 79-80: Thumbnail glows and bounces
      tl.to(videoThumbRef.current, {
        boxShadow: "0 0 30px rgba(19, 91, 236, 0.6)",
        y: -10,
        duration: 1,
        ease: "power2.out",
      }, 79);

      tl.to(videoThumbRef.current, {
        y: 0,
        duration: 1,
        ease: "bounce.out",
      }, 80);

    }, containerRef);

    return () => ctx.revert();
  }, []);

  const setToolButtonRef = (index: number) => (el: HTMLDivElement | null) => {
    toolButtonsRef.current[index] = el;
  };

  const setScriptLineRef = (index: number) => (el: HTMLDivElement | null) => {
    scriptLinesRef.current[index] = el;
  };

  const setOrbRef = (index: number) => (el: HTMLDivElement | null) => {
    orbsRef.current[index] = el;
  };

  const setOptionRef = (index: number) => (el: HTMLDivElement | null) => {
    optionsRef.current[index] = el;
  };

  const setProgressDotRef = (index: number) => (el: HTMLDivElement | null) => {
    progressDotsRef.current[index] = el;
  };

  return (
    <div ref={containerRef} className="relative w-full max-w-4xl mx-auto py-10 min-h-[600px]" style={{ perspective: "1500px" }}>
      <div ref={setOrbRef(0)} className="absolute -top-10 left-10 w-48 h-48 rounded-full bg-[#135bec]/15 blur-3xl" />
      <div ref={setOrbRef(1)} className="absolute top-1/2 right-0 w-64 h-64 rounded-full bg-[#135bec]/10 blur-3xl" />
      <div ref={setOrbRef(2)} className="absolute bottom-0 left-1/4 w-40 h-40 rounded-full bg-[#135bec]/20 blur-3xl" />

      <div
        ref={questionnaireRef}
        className="absolute inset-x-0 top-0 bottom-0 flex items-center justify-center z-20"
        style={{ transformStyle: "preserve-3d" }}
      >
        <div className="bg-black border border-[#135bec]/30 rounded-2xl p-6 md:p-8 w-full max-w-md mx-4">
          <div className="flex justify-center gap-2 mb-6">
            {[0, 1, 2, 3].map((i) => (
              <div
                key={i}
                ref={setProgressDotRef(i)}
                className="w-2 h-2 rounded-full bg-white/20"
              />
            ))}
          </div>

          <div ref={questionTitleRef} className="text-center mb-6">
            <h3 className="text-xl md:text-2xl font-bold text-white mb-2">What type of content do you create?</h3>
            <p className="text-white/50 text-sm">Select the option that best describes you</p>
          </div>

          <div className="grid grid-cols-2 gap-3 mb-6">
            <div
              ref={setOptionRef(0)}
              className="p-3 border border-white/20 rounded-xl hover:border-[#135bec]/50 transition-colors cursor-pointer"
            >
              <div className="text-xl mb-1">🎬</div>
              <div className="text-white font-medium text-sm">YouTuber</div>
              <div className="text-white/40 text-xs">Long-form</div>
            </div>
            <div
              ref={setOptionRef(1)}
              className="p-3 border border-white/20 rounded-xl hover:border-[#135bec]/50 transition-colors cursor-pointer"
            >
              <div className="text-xl mb-1">📱</div>
              <div className="text-white font-medium text-sm">TikToker</div>
              <div className="text-white/40 text-xs">Short-form</div>
            </div>
            <div
              ref={(el) => { setOptionRef(2)(el); selectedOptionRef.current = el; }}
              className="p-3 border border-[#135bec]/30 rounded-xl cursor-pointer"
            >
              <div className="text-xl mb-1">💼</div>
              <div className="text-white font-medium text-sm">Business</div>
              <div className="text-white/40 text-xs">Marketing</div>
            </div>
            <div
              ref={setOptionRef(3)}
              className="p-3 border border-white/20 rounded-xl hover:border-[#135bec]/50 transition-colors cursor-pointer"
            >
              <div className="text-xl mb-1">🎓</div>
              <div className="text-white font-medium text-sm">Educator</div>
              <div className="text-white/40 text-xs">Teaching</div>
            </div>
          </div>

          <button
            ref={nextButtonRef}
            className="w-full h-10 bg-[#135bec] text-white font-medium rounded-xl flex items-center justify-center gap-2 text-sm"
          >
            Continue
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7l5 5m0 0l-5 5m5-5H6" />
            </svg>
          </button>
        </div>
      </div>

      <div 
        ref={windowRef}
        className="bg-black border border-[#135bec]/30 rounded-xl overflow-hidden shadow-2xl relative z-10"
        style={{ transformStyle: "preserve-3d" }}
      >
        <div className="flex items-center justify-between px-4 h-10 border-b border-[#135bec]/20">
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-red-500/60" />
            <div className="w-3 h-3 rounded-full bg-yellow-500/60" />
            <div className="w-3 h-3 rounded-full bg-green-500/60" />
          </div>
          <span className="text-[#135bec] text-sm font-medium">Director Mode</span>
          <div className="w-20" />
        </div>

        <div className="flex h-[360px]">
          <div 
            ref={leftPanelRef}
            className="w-24 border-r border-[#135bec]/20 p-3 flex flex-col gap-2"
            style={{ transformStyle: "preserve-3d" }}
          >
            <div
              ref={setToolButtonRef(0)}
              className="h-10 rounded border border-[#135bec]/40 flex items-center justify-center bg-[#135bec]/5"
              style={{ transformStyle: "preserve-3d" }}
            >
              <svg className="w-4 h-4 text-[#135bec]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M15.75 10.5l4.72-4.72a.75.75 0 011.28.53v11.38a.75.75 0 01-1.28.53l-4.72-4.72M4.5 18.75h9a2.25 2.25 0 002.25-2.25v-9a2.25 2.25 0 00-2.25-2.25h-9A2.25 2.25 0 002.25 7.5v9a2.25 2.25 0 002.25 2.25z" />
              </svg>
            </div>
            <div
              ref={setToolButtonRef(1)}
              className="h-10 rounded border border-[#135bec] bg-[#135bec]/20 flex items-center justify-center"
              style={{ transformStyle: "preserve-3d" }}
            >
              <svg className="w-4 h-4 text-[#135bec]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9.813 15.904L9 18.75l-.813-2.846a4.5 4.5 0 00-3.09-3.09L2.25 12l2.846-.813a4.5 4.5 0 003.09-3.09L9 5.25l.813 2.846a4.5 4.5 0 003.09 3.09L15.75 12l-2.846.813a4.5 4.5 0 00-3.09 3.09z" />
              </svg>
            </div>
            <div
              ref={setToolButtonRef(2)}
              className="h-10 rounded border border-[#135bec]/40 flex items-center justify-center bg-[#135bec]/5"
              style={{ transformStyle: "preserve-3d" }}
            >
              <svg className="w-4 h-4 text-[#135bec]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 9l10.5-3m0 6.553v3.75a2.25 2.25 0 01-1.632 2.163l-1.32.377a1.803 1.803 0 11-.99-3.467l2.31-.66a2.25 2.25 0 001.632-2.163zm0 0V2.25L9 5.25v10.303m0 0v3.75a2.25 2.25 0 01-1.632 2.163l-1.32.377a1.803 1.803 0 01-.99-3.467l2.31-.66A2.25 2.25 0 009 15.553z" />
              </svg>
            </div>
            <div
              ref={setToolButtonRef(3)}
              className="h-10 rounded border border-[#135bec]/40 flex items-center justify-center bg-[#135bec]/5"
              style={{ transformStyle: "preserve-3d" }}
            >
              <svg className="w-4 h-4 text-[#135bec]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M7.5 8.25h9m-9 3H12m-9.75 1.51c0 1.6 1.123 2.994 2.707 3.227 1.129.166 2.27.293 3.423.379.35.026.67.21.865.501L12 21l2.755-4.133a1.14 1.14 0 01.865-.501 48.172 48.172 0 003.423-.379c1.584-.233 2.707-1.626 2.707-3.228V6.741c0-1.602-1.123-2.995-2.707-3.228A48.394 48.394 0 0012 3c-2.392 0-4.744.175-7.043.513C3.373 3.746 2.25 5.14 2.25 6.741v6.018z" />
              </svg>
            </div>
          </div>

          <div className="flex-1 p-6 flex items-center justify-center relative">
            <div
              ref={cameraRef}
              className="w-full max-w-md aspect-video rounded-lg border border-[#135bec]/30 bg-black/50 flex flex-col items-center justify-center relative overflow-hidden"
              style={{ transformStyle: "preserve-3d" }}
            >
              <div
                ref={recordingDotRef}
                className="absolute top-3 left-3 flex items-center gap-2"
              >
                <div className="w-2 h-2 rounded-full bg-red-500 animate-pulse" />
                <span className="text-red-500 text-xs font-medium">REC</span>
              </div>
              <svg className="w-12 h-12 text-[#135bec]/50" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M5.25 5.653c0-.856.917-1.398 1.667-.986l11.54 6.348a1.125 1.125 0 010 1.971l-11.54 6.347a1.125 1.125 0 01-1.667-.985V5.653z" />
              </svg>
              <span className="text-[#135bec]/50 text-sm mt-2">Camera Preview</span>
            </div>

            <div
              ref={exportOverlayRef}
              className="absolute inset-0 bg-black/95 flex flex-col items-center justify-center z-10"
            >
              <div className="text-[#135bec] text-lg font-medium mb-4">Generating Video...</div>
              <div className="w-48 h-1 bg-[#135bec]/20 rounded-full overflow-hidden">
                <div
                  ref={progressBarRef}
                  className="h-full bg-[#135bec] rounded-full"
                />
              </div>
              <div
                ref={videoThumbRef}
                className="mt-6 w-32 aspect-video rounded border-2 border-[#135bec] bg-black flex items-center justify-center"
                style={{ transformStyle: "preserve-3d" }}
              >
                <svg className="w-8 h-8 text-[#135bec]" fill="currentColor" viewBox="0 0 24 24">
                  <path d="M5.25 5.653c0-.856.917-1.398 1.667-.986l11.54 6.348a1.125 1.125 0 010 1.971l-11.54 6.347a1.125 1.125 0 01-1.667-.985V5.653z" />
                </svg>
              </div>
              <div className="mt-3 text-[#135bec]/60 text-sm">my_video.mp4</div>
            </div>
          </div>

          <div 
            ref={rightPanelRef}
            className="w-48 border-l border-[#135bec]/20 p-4"
            style={{ transformStyle: "preserve-3d" }}
          >
            <div ref={shotInfoRef} style={{ transformStyle: "preserve-3d" }}>
              <div className="text-[#135bec] text-xs uppercase tracking-wider mb-2">Shot Info</div>
              <div className="h-3 w-24 bg-[#135bec]/30 rounded mb-3" />
              <div className="border border-[#135bec]/20 rounded p-3 mb-4">
                <div className="h-2 w-full bg-[#135bec]/20 rounded mb-2" />
                <div className="h-2 w-3/4 bg-[#135bec]/15 rounded mb-2" />
                <div className="h-2 w-5/6 bg-[#135bec]/10 rounded" />
              </div>
            </div>

            <div className="text-[#135bec] text-xs uppercase tracking-wider mb-2">Script</div>
            <div className="border border-[#135bec]/20 rounded p-3 space-y-2">
              <div ref={setScriptLineRef(0)} className="h-2 w-full bg-[#135bec]/30 rounded" />
              <div ref={setScriptLineRef(1)} className="h-2 w-4/5 bg-[#135bec]/25 rounded" />
              <div ref={setScriptLineRef(2)} className="h-2 w-full bg-[#135bec]/20 rounded" />
              <div ref={setScriptLineRef(3)} className="h-2 w-3/4 bg-[#135bec]/15 rounded" />
            </div>
          </div>
        </div>

        <div 
          ref={bottomBarRef}
          className="h-14 border-t border-[#135bec]/20 flex items-center justify-between px-4"
          style={{ transformStyle: "preserve-3d" }}
        >
          <div className="flex items-center gap-3">
            <div className="h-2 w-2 rounded-full bg-[#135bec]/40" />
            <div className="h-1 w-32 bg-[#135bec]/20 rounded-full" />
          </div>
          <button
