/**
 * Request validation middleware using Zod
 * Validates request bodies, query params, and route params
 */

import type { Request, Response, NextFunction } from "express";
import { z, ZodError } from "zod";
import { createError } from "./errorHandler";

interface ValidationSchemas {
  body?: z.ZodSchema;
  query?: z.ZodSchema;
  params?: z.ZodSchema;
}

/**
 * Validate request data against Zod schemas
 */
export function validate(schemas: ValidationSchemas) {
  return (req: Request, _res: Response, next: NextFunction) => {
    try {
      // Validate body
      if (schemas.body) {
        req.body = schemas.body.parse(req.body);
      }

      // Validate query
      if (schemas.query) {
        req.query = schemas.query.parse(req.query);
      }

      // Validate params
      if (schemas.params) {
        req.params = schemas.params.parse(req.params);
      }

      next();
    } catch (error) {
      if (error instanceof ZodError) {
        const validationError = createError(
          "Validation failed",
          422,
          "VALIDATION_ERROR",
          true
        );
        // Attach validation details to error
        (validationError as any).details = error.format();
        return next(validationError);
      }
      next(error);
    }
  };
}

/**
 * Helper to validate only request body
 */
export function validateBody<T extends z.ZodSchema>(schema: T) {
  return validate({ body: schema });
}

/**
 * Helper to validate only query parameters
 */
export function validateQuery<T extends z.ZodSchema>(schema: T) {
  return validate({ query: schema });
}

/**
 * Helper to validate only route parameters
 */
export function validateParams<T extends z.ZodSchema>(schema: T) {
  return validate({ params: schema });
}

