import { useQuery } from "@tanstack/react-query";
import { Badge } from "@/components/ui/badge";
import { Music, TrendingUp } from "lucide-react";
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip";

interface TrendingMusicBadgeProps {
  musicVibe: string;
}

interface TrendingMusicInfo {
  trending: {
    name: string;
    artist: string;
    vibe: string;
    platform: string;
    videoCount?: number;
  } | null;
  royaltyFree: boolean;
  source: string;
}

export function TrendingMusicBadge({ musicVibe }: TrendingMusicBadgeProps) {
  const { data: musicInfo } = useQuery<TrendingMusicInfo>({
    queryKey: [`/api/trending-music/${encodeURIComponent(musicVibe)}`],
    enabled: !!musicVibe,
  });

  if (!musicInfo?.trending) {
    return (
      <Badge variant="secondary" className="gap-1.5" data-testid="badge-music">
        <Music className="h-3 w-3" />
        {musicVibe}
      </Badge>
    );
  }

  return (
    <Tooltip>
      <TooltipTrigger asChild>
        <Badge variant="default" className="gap-1.5 cursor-help" data-testid="badge-trending-music">
          <TrendingUp className="h-3 w-3" />
          <Music className="h-3 w-3" />
          {musicInfo.trending.name}
        </Badge>
      </TooltipTrigger>
      <TooltipContent className="max-w-xs">
        <div className="space-y-1">
          <p className="font-semibold">{musicInfo.trending.name}</p>
          <p className="text-sm text-muted-foreground">by {musicInfo.trending.artist}</p>
          <p className="text-xs text-muted-foreground">
            Trending on {musicInfo.trending.platform}
          </p>
          {musicInfo.trending.videoCount && (
            <p className="text-xs text-muted-foreground">
              {(musicInfo.trending.videoCount / 1000).toFixed(0)}K+ videos
            </p>
          )}
          <div className="pt-2 mt-2 border-t text-xs">
            <p className="text-muted-foreground">
              {musicInfo.royaltyFree ? "Using royalty-free alternative" : "Music file needed"}
            </p>
            <p className="text-muted-foreground">{musicInfo.source}</p>
          </div>
        </div>
      </TooltipContent>
    </Tooltip>
  );
}

