import { CAPTION_PRESETS } from "@/lib/captionPresets";
import type { CaptionSettings, CaptionPosition } from "@/lib/transcript/types";

interface ControlsPanelProps {
  settings: CaptionSettings;
  onChange: (settings: CaptionSettings) => void;
}

export function ControlsPanel({ settings, onChange }: ControlsPanelProps) {
  const update = (partial: Partial<CaptionSettings>) => {
    onChange({ ...settings, ...partial });
  };

  return (
    <div className="space-y-5 p-5 bg-white rounded-2xl border border-gray-100 shadow-sm overflow-y-auto max-h-[calc(100vh-200px)]">
      <h3 className="text-base font-bold text-[#111111] tracking-tight">
        Caption Style
      </h3>

      <div className="space-y-3">
        <label className="text-xs font-semibold text-[#666666] uppercase tracking-wider">
          Preset
        </label>
        <div className="grid grid-cols-2 gap-2">
          {CAPTION_PRESETS.map((preset) => (
            <button
              key={preset.id}
              onClick={() => update({ presetId: preset.id })}
              className={`text-left px-3 py-2.5 rounded-xl text-sm font-medium transition-all ${
                settings.presetId === preset.id
                  ? "bg-[#3B82F6] text-white shadow-md shadow-blue-200"
                  : "bg-gray-50 text-[#111111] hover:bg-gray-100 border border-gray-100"
              }`}
            >
              {preset.name}
            </button>
          ))}
        </div>
      </div>

      <div className="h-px bg-gray-100" />

      <div className="space-y-3">
        <label className="text-xs font-semibold text-[#666666] uppercase tracking-wider">
          Font Size: {settings.fontSize}px
        </label>
        <input
          type="range"
          min={20}
          max={72}
          value={settings.fontSize}
          onChange={(e) => update({ fontSize: Number(e.target.value) })}
          className="w-full h-1.5 bg-[#E2E8F0] rounded-lg appearance-none cursor-pointer accent-[#3B82F6]"
        />
        <div className="flex justify-between text-xs text-[#94A3B8]">
          <span>20px</span>
          <span>72px</span>
        </div>
      </div>

      <div className="space-y-3">
        <label className="text-xs font-semibold text-[#666666] uppercase tracking-wider">
          Lines
        </label>
        <div className="flex gap-2">
          {([1, 2] as const).map((n) => (
            <button
              key={n}
              onClick={() => update({ lineCount: n })}
              className={`flex-1 py-2 rounded-xl text-sm font-medium transition-all ${
                settings.lineCount === n
                  ? "bg-[#3B82F6] text-white"
                  : "bg-gray-50 text-[#111111] border border-gray-100"
              }`}
            >
              {n} Line{n > 1 ? "s" : ""}
            </button>
          ))}
        </div>
      </div>

      <div className="space-y-3">
        <label className="text-xs font-semibold text-[#666666] uppercase tracking-wider">
          Position
        </label>
        <div className="flex gap-2">
          {(["top", "middle", "bottom"] as CaptionPosition[]).map((pos) => (
            <button
              key={pos}
              onClick={() => update({ position: pos })}
              className={`flex-1 py-2 rounded-xl text-sm font-medium capitalize transition-all ${
                settings.position === pos
                  ? "bg-[#3B82F6] text-white"
                  : "bg-gray-50 text-[#111111] border border-gray-100"
              }`}
            >
              {pos}
            </button>
          ))}
        </div>
      </div>

      <div className="space-y-3">
        <label className="text-xs font-semibold text-[#666666] uppercase tracking-wider">
          Safe Margin: {settings.safeMargin}%
        </label>
        <input
          type="range"
          min={0}
          max={20}
          value={settings.safeMargin}
          onChange={(e) => update({ safeMargin: Number(e.target.value) })}
          className="w-full h-1.5 bg-[#E2E8F0] rounded-lg appearance-none cursor-pointer accent-[#3B82F6]"
        />
      </div>

      <div className="h-px bg-gray-100" />

      <div className="space-y-3">
        <label className="text-xs font-semibold text-[#666666] uppercase tracking-wider">
          Options
        </label>
        <div className="space-y-2">
          <label className="flex items-center gap-3 cursor-pointer group">
            <div
              onClick={() => update({ uppercase: !settings.uppercase })}
              className={`w-9 h-5 rounded-full relative transition-colors cursor-pointer ${
                settings.uppercase ? "bg-[#3B82F6]" : "bg-[#CBD5E1]"
              }`}
            >
              <div
                className={`absolute top-0.5 w-4 h-4 rounded-full bg-white shadow transition-transform ${
                  settings.uppercase ? "translate-x-4" : "translate-x-0.5"
                }`}
              />
            </div>
            <span className="text-sm text-[#111111]">Uppercase</span>
          </label>
          <label className="flex items-center gap-3 cursor-pointer group">
            <div
              onClick={() => update({ stroke: !settings.stroke })}
              className={`w-9 h-5 rounded-full relative transition-colors cursor-pointer ${
                settings.stroke ? "bg-[#3B82F6]" : "bg-[#CBD5E1]"
              }`}
            >
              <div
                className={`absolute top-0.5 w-4 h-4 rounded-full bg-white shadow transition-transform ${
                  settings.stroke ? "translate-x-4" : "translate-x-0.5"
                }`}
              />
            </div>
            <span className="text-sm text-[#111111]">Text Stroke</span>
          </label>
          <label className="flex items-center gap-3 cursor-pointer group">
            <div
              onClick={() => update({ shadowEnabled: !settings.shadowEnabled })}
              className={`w-9 h-5 rounded-full relative transition-colors cursor-pointer ${
                settings.shadowEnabled ? "bg-[#3B82F6]" : "bg-[#CBD5E1]"
              }`}
            >
              <div
                className={`absolute top-0.5 w-4 h-4 rounded-full bg-white shadow transition-transform ${
                  settings.shadowEnabled ? "translate-x-4" : "translate-x-0.5"
                }`}
              />
            </div>
            <span className="text-sm text-[#111111]">Shadow</span>
          </label>
        </div>
      </div>

      <div className="h-px bg-gray-100" />

      <div className="p-3 bg-gray-50 rounded-xl">
        <p className="text-xs text-[#666666] leading-relaxed">
          <span className="font-semibold text-[#111111]">Tip:</span> Each preset includes a different animation style. Try "Bold Pop" for scale effects, "Karaoke Underline" for sweep animations, or "Caption Pro" for fill effects.
        </p>
      </div>
    </div>
  );
}

