import { useRef, useCallback, useState, useEffect, memo } from "react";
import { CaptionLine } from "./CaptionLine";
import { getTimelineState } from "@/lib/transcript/timeline";
import { getPresetById } from "@/lib/captionPresets";
import type { CaptionSegment, CaptionPosition, CaptionSettings, TimelineState } from "@/lib/transcript/types";

interface CaptionOverlayProps {
  segments: CaptionSegment[];
  videoRef: React.RefObject<HTMLVideoElement | null>;
  settings: CaptionSettings;
  containerWidth?: number;
  containerHeight?: number;
}

function CaptionOverlayInner({
  segments,
  videoRef,
  settings,
  containerWidth,
  containerHeight,
}: CaptionOverlayProps) {
  const [timelineState, setTimelineState] = useState<TimelineState>({
    activeSegmentIndex: -1,
    activeWordIndex: -1,
    wordProgress: 0,
    segment: null,
  });

  const rafRef = useRef<number>(0);
  const prevStateRef = useRef<string>("");

  const updateCaptions = useCallback(() => {
    const video = videoRef.current;
    if (!video) {
      rafRef.current = requestAnimationFrame(updateCaptions);
      return;
    }

    const currentTime = video.currentTime;
    const state = getTimelineState(currentTime, segments);

    const stateKey = `${state.activeSegmentIndex}-${state.activeWordIndex}-${Math.round(state.wordProgress * 100)}`;
    if (stateKey !== prevStateRef.current) {
      prevStateRef.current = stateKey;
      setTimelineState(state);
    }

    rafRef.current = requestAnimationFrame(updateCaptions);
  }, [segments, videoRef]);

  useEffect(() => {
    rafRef.current = requestAnimationFrame(updateCaptions);
    return () => {
      if (rafRef.current) cancelAnimationFrame(rafRef.current);
    };
  }, [updateCaptions]);

  const preset = getPresetById(settings.presetId);
  const effectiveStyle = {
    ...preset,
    fontSize: settings.fontSize,
    textTransform: settings.uppercase ? ("uppercase" as const) : preset.textTransform,
    shadow: settings.shadowEnabled ? preset.shadow : "none",
    strokeWidth: settings.stroke ? preset.strokeWidth : 0,
  };

  const getPositionStyle = (position: CaptionPosition, margin: number): React.CSSProperties => {
    const base: React.CSSProperties = {
      position: "absolute",
      left: `${margin}%`,
      right: `${margin}%`,
      display: "flex",
      justifyContent: "center",
      pointerEvents: "none",
      zIndex: 10,
    };

    switch (position) {
      case "top":
        return { ...base, top: `${margin + 5}%` };
      case "middle":
        return { ...base, top: "50%", transform: "translateY(-50%)" };
      case "bottom":
      default:
        return { ...base, bottom: `${margin + 5}%` };
    }
  };

  const getBackgroundStyle = (): React.CSSProperties => {
    switch (effectiveStyle.backgroundMode) {
      case "pill":
        return {
          padding: "8px 20px",
          borderRadius: 24,
          backgroundColor: effectiveStyle.backgroundColor,
        };
      case "box":
        return {
          padding: "12px 24px",
          borderRadius: 8,
          backgroundColor: effectiveStyle.backgroundColor,
        };
      case "glass":
        return {
          padding: "10px 22px",
          borderRadius: 16,
          backgroundColor: effectiveStyle.backgroundColor,
          backdropFilter: "blur(12px)",
          WebkitBackdropFilter: "blur(12px)",
          border: "1px solid rgba(255,255,255,0.1)",
        };
      default:
        return {};
    }
  };

  if (!timelineState.segment) return null;

  return (
    <div
      style={{
        ...getPositionStyle(settings.position, settings.safeMargin),
        fontSize: effectiveStyle.fontSize,
      }}
    >
      <div style={getBackgroundStyle()}>
        <CaptionLine
          segment={timelineState.segment}
          activeWordIndex={timelineState.activeWordIndex}
          wordProgress={timelineState.wordProgress}
          style={effectiveStyle}
          lineCount={settings.lineCount}
        />
      </div>
    </div>
  );
}

export const CaptionOverlay = memo(CaptionOverlayInner);

