import { GoogleGenerativeAI } from "@google/generative-ai";
import { type OnboardingData } from "@/db/schema";

const genAI = new GoogleGenerativeAI(process.env.GOOGLE_GENERATIVE_AI_API_KEY || "");

export interface GeneratedPost {
    weekNumber: number;
    dayNumber: number;
    title: string;
    concept: string;
    platform: string;
    brollSuggestions: string[];
    musicVibe: string;
    shotList: Array<{
        id: string;
        shotNumber: number;
        instruction: string;
        cameraAngle: string;
        framing: string;
        dialogue: string;
        duration: number;
        completed: boolean;
    }>;
    caption: string;
    hashtags: string[];
}

export interface GeneratedPlan {
    posts: GeneratedPost[];
}

export async function generateContentPlan(data: OnboardingData): Promise<GeneratedPlan> {
    const model = genAI.getGenerativeModel({ model: "gemini-1.5-flash" });

    // Determine post frequency logic (Spec Part 1 Step 2)
    let postsPerWeek = 2;
    if (data.postFrequency === "4-5") postsPerWeek = 4;
    else if (data.postFrequency === "Daily") postsPerWeek = 7;

    const prompt = `
You are a professional social media content strategist. Generate a 4-week content calendar for the following business:
Brand: ${data.brandName}
Audience: ${data.targetAudience}
Primary Goal: ${data.contentGoals.join(", ")}
Content Tone: ${data.tone}
Platforms: ${data.platforms.join(", ")}

Create ${postsPerWeek} posts per week (total 4 weeks, total ${postsPerWeek * 4} posts). 
For EACH post, provide:
1. weekNumber (1-4)
2. dayNumber (1-7)
3. title (Punchy headline)
4. concept (The core hook and idea)
5. brollSuggestions (A list of 3-5 background footage ideas)
6. musicVibe (The style of music, e.g., "Upbeat Pop", "Moody Lo-Fi")
7. shotList (A list of 3-5 specific shots needed to film this, each with: id, shotNumber, instruction, cameraAngle, framing, dialogue, duration in seconds)
8. platform (Valid values: "Instagram Reels", "TikTok", "YouTube Shorts")
9. caption (Ready-to-post social media caption)
10. hashtags (Relevant tags)

Return the result STRICTLY as a JSON object with this structure:
{
  "posts": [
    {
      "weekNumber": 1,
      "dayNumber": 1,
      "title": "...",
      "concept": "...",
      "platform": "Instagram Reels",
      "brollSuggestions": ["...", "..."],
      "musicVibe": "Upbeat",
      "shotList": [
        { "id": "s1", "shotNumber": 1, "instruction": "...", "cameraAngle": "...", "framing": "...", "dialogue": "...", "duration": 5, "completed": false }
      ],
      "caption": "...",
      "hashtags": ["...", "..."]
    }
  ]
}
`;

    if (!process.env.GOOGLE_GENERATIVE_AI_API_KEY) {
        console.warn("GOOGLE_GENERATIVE_AI_API_KEY is missing, falling back to mock.");
        return generateMockPlan(postsPerWeek);
    }

    try {
        const result = await model.generateContent(prompt);
        const text = result.response.text();
        const jsonMatch = text.match(/\{[\s\S]*\}/);
        if (jsonMatch) {
            return JSON.parse(jsonMatch[0]) as GeneratedPlan;
        }
        throw new Error("Failed to parse JSON from AI response");
    } catch (err) {
        console.error("AI Generation failed:", err);
        return generateMockPlan(postsPerWeek);
    }
}

async function generateMockPlan(postsPerWeek: number): Promise<GeneratedPlan> {
    const mockResult = [];
    for (let w = 1; w <= 4; w++) {
        for (let d = 1; d <= postsPerWeek; d++) {
            mockResult.push({
                weekNumber: w,
                dayNumber: d,
                title: `Post ${w}-${d}: Growing your Brand`,
                concept: "Share a tip about how to scale effectively.",
                platform: ["Instagram Reels", "TikTok", "YouTube Shorts"][(w + d) % 3],
                brollSuggestions: ["Walking through office", "Close up of computer"],
                musicVibe: "Energetic",
                shotList: [
                    { id: `s${w}${d}1`, shotNumber: 1, instruction: "Intro to camera", cameraAngle: "Eye level", framing: "Medium", dialogue: "Scaling is hard, but here is one tip.", duration: 5, completed: false },
                    { id: `s${w}${d}2`, shotNumber: 2, instruction: "Showing product", cameraAngle: "Top down", framing: "Close up", dialogue: "", duration: 3, completed: false }
                ],
                caption: "Scaling is the key to success. #growth #brand",
                hashtags: ["growth", "brand"]
            });
        }
    }
    return { posts: mockResult as GeneratedPost[] };
}

