import { useEffect, useRef, useState } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { TIMING, EASE, STAGGER, DELAY } from "@/lib/animation";

gsap.registerPlugin(ScrollTrigger);

interface MediaItem {
  id: number;
  type: 'video' | 'photo';
  url: string;
  aspectRatio: '16:9' | '9:16' | '1:1';
}

export default function HumanProofSection() {
  const containerRef = useRef<HTMLDivElement>(null);
  const titleRef = useRef<HTMLHeadingElement>(null);
  const subtitleRef = useRef<HTMLParagraphElement>(null);
  const frameRefs = useRef<(HTMLDivElement | null)[]>([]);
  const [media, setMedia] = useState<MediaItem[]>([]);

  useEffect(() => {
    async function fetchMedia() {
      try {
        const res = await fetch('/api/pexels/media');
        if (res.ok) {
          const data = await res.json();
          const items: MediaItem[] = data.slice(0, 6).map((item: any, i: number) => ({
            id: item.id,
            type: item.type || 'photo',
            url: item.type === 'video' 
              ? item.video_files?.[0]?.link || item.image 
              : item.src?.medium || item.image,
            aspectRatio: ['16:9', '9:16', '1:1', '16:9', '9:16', '1:1'][i] as any,
          }));
          setMedia(items);
        }
      } catch (e) {
        console.error('Failed to fetch Pexels media:', e);
      }
    }
    fetchMedia();
  }, []);

  useEffect(() => {
    if (!containerRef.current || media.length === 0) return;

    const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    if (prefersReducedMotion) {
      gsap.set([titleRef.current, subtitleRef.current], { opacity: 1 });
      gsap.set(frameRefs.current, { opacity: 1, y: 0, scale: 1 });
      return;
    }

    const ctx = gsap.context(() => {
      gsap.set(titleRef.current, { opacity: 0, y: 60 });
      gsap.set(subtitleRef.current, { opacity: 0, y: 40 });
      frameRefs.current.forEach((frame, i) => {
        gsap.set(frame, { 
          opacity: 0, 
          y: 80 + (i * 20), 
          scale: 0.9,
          rotateY: (i % 2 === 0 ? -8 : 8),
        });
      });

      const tl = gsap.timeline({
        scrollTrigger: {
          trigger: containerRef.current,
          start: "top 70%",
          end: "bottom 30%",
          scrub: 1,
        },
      });

      tl.to(titleRef.current, {
        opacity: 1,
        y: 0,
        duration: TIMING.MEDIUM,
        ease: EASE,
      }, 0);

      tl.to(subtitleRef.current, {
        opacity: 1,
        y: 0,
        duration: TIMING.MEDIUM,
        ease: EASE,
      }, TIMING.MEDIUM);

      frameRefs.current.forEach((frame, i) => {
        tl.to(frame, {
          opacity: 1,
          y: 0,
          scale: 1,
          rotateY: 0,
          duration: TIMING.MEDIUM,
          ease: EASE,
        }, TIMING.MEDIUM * 2 + DELAY.SHORT + i * STAGGER.NORMAL);
      });

    }, containerRef);

    return () => ctx.revert();
  }, [media]);

  const setFrameRef = (i: number) => (el: HTMLDivElement | null) => {
    frameRefs.current[i] = el;
  };

  const getAspectClass = (ratio: string) => {
    switch (ratio) {
      case '16:9': return 'aspect-video';
      case '9:16': return 'aspect-[9/16]';
      default: return 'aspect-square';
    }
  };

  const getGridClass = (index: number) => {
    const positions = [
      'col-span-2 row-span-1',
      'col-span-1 row-span-2',
      'col-span-1 row-span-1',
      'col-span-1 row-span-1',
      'col-span-1 row-span-2',
      'col-span-2 row-span-1',
    ];
    return positions[index] || 'col-span-1';
  };

  return (
    <div ref={containerRef} className="min-h-screen py-40 px-8 md:px-16 relative overflow-hidden">
      <div 
        className="absolute inset-0 opacity-[0.05] pointer-events-none"
        style={{
          background: 'radial-gradient(ellipse at 30% 50%, #14B8A6 0%, transparent 60%)',
        }}
      />

      <div className="max-w-6xl mx-auto">
        <div className="text-center mb-16">
          <p className="emotional-phrase mb-4">Real stories, real creators</p>
          <h2 
            ref={titleRef}
            className="text-3xl md:text-5xl font-bold mb-4"
          >
            Made by <span className="text-[#B08A5A]">real people</span>
          </h2>
          <p 
            ref={subtitleRef}
            className="text-white/50 text-lg max-w-xl mx-auto"
          >
            Not editors. Not filmmakers. Just people with something to say.
          </p>
        </div>

        <div className="grid grid-cols-3 md:grid-cols-4 gap-4 auto-rows-[200px]">
          {media.map((item, i) => (
            <div
              key={item.id}
              ref={setFrameRef(i)}
              className={`${getGridClass(i)} relative rounded-xl overflow-hidden border border-white/10 bg-white/5`}
              style={{ perspective: '1000px' }}
            >
              {item.type === 'video' ? (
                <video
                  src={item.url}
                  className="w-full h-full object-cover"
                  autoPlay
                  muted
                  loop
                  playsInline
                />
              ) : (
                <img
                  src={item.url}
                  alt="Creator"
                  className="w-full h-full object-cover"
                  loading="lazy"
                />
              )}
              <div className="absolute inset-0 bg-gradient-to-t from-black/40 to-transparent" />
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

