/**
 * Rate limiting middleware
 * Protects authentication, upload, and expensive endpoints
 */

import rateLimit from "express-rate-limit";
import type { Express } from "express";

// General API rate limiter (applied to all /api routes)
export const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: {
    error: {
      message: "Too many requests from this IP, please try again later",
      code: "RATE_LIMIT_EXCEEDED",
    },
  },
  standardHeaders: true, // Return rate limit info in `RateLimit-*` headers
  legacyHeaders: false,
});

// Strict rate limiter for authentication endpoints
export const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // Limit each IP to 5 login attempts per windowMs
  message: {
    error: {
      message: "Too many authentication attempts, please try again later",
      code: "AUTH_RATE_LIMIT_EXCEEDED",
    },
  },
  skipSuccessfulRequests: true, // Don't count successful requests
});

// Rate limiter for upload/export endpoints (expensive operations)
export const uploadLimiter = rateLimit({
  windowMs: 60 * 60 * 1000, // 1 hour
  max: 10, // Limit each IP to 10 uploads/exports per hour
  message: {
    error: {
      message: "Too many upload requests, please try again later",
      code: "UPLOAD_RATE_LIMIT_EXCEEDED",
    },
  },
});

// Rate limiter for AI/transcription endpoints (expensive operations)
export const aiLimiter = rateLimit({
  windowMs: 60 * 60 * 1000, // 1 hour
  max: 20, // Limit each IP to 20 AI requests per hour
  message: {
    error: {
      message: "Too many AI requests, please try again later",
      code: "AI_RATE_LIMIT_EXCEEDED",
    },
  },
});

export function setupRateLimiting(app: Express) {
  // Apply general API limiter to all /api routes
  app.use("/api", apiLimiter);
}

