"use client";

import Link from "next/link";
import { useRouter } from "next/navigation";
import { Button } from "@repo/ui";
import { Calendar, CheckCircle2, Download, PlayCircle, Edit } from "lucide-react";
import { Card, CardHeader, CardTitle, CardContent, Badge } from "@repo/ui";
import { TrendingMusicBadge } from "./trending-music-badge";
import { type Post } from "@/db/schema";
import { cn } from "@repo/ui";

interface PostCardProps {
    post: Post;
}

export function PostCard({ post }: PostCardProps) {
    const router = useRouter();
    const statusConfig: Record<string, { icon: React.ElementType; color: string; label: string }> = {
        planned: { icon: Calendar, color: "bg-blue-500/10 text-blue-500", label: "Planned" },
        recording: { icon: PlayCircle, color: "bg-orange-500/10 text-orange-500", label: "Recording" },
        editing: { icon: Edit, color: "bg-purple-500/10 text-purple-500", label: "Editing" },
        completed: { icon: CheckCircle2, color: "bg-green-500/10 text-green-500", label: "Completed" },
        scheduled: { icon: Calendar, color: "bg-indigo-500/10 text-indigo-500", label: "Scheduled" },
    };

    const config = statusConfig[post.status as string] || statusConfig.planned;
    const StatusIcon = config.icon;

    const handleCardClick = () => {
        const target = post.status === "completed" ? `/post/${post.id}/editor` : `/director/${post.id}`;
        router.push(target);
    };

    return (
        <div onClick={handleCardClick} className="block h-full cursor-pointer group">
            <Card className="h-full hover:shadow-lg transition-all border-border hover:border-primary/50">
                <CardHeader className="space-y-3 pb-3">
                    <div className="flex items-start justify-between gap-2">
                        <Badge variant="outline" className="font-mono text-xs">
                            Day {post.dayNumber}
                        </Badge>
                        <div className={cn("inline-flex items-center gap-1.5 px-2 py-1 rounded-md text-xs font-medium", config.color)}>
                            <StatusIcon className="h-3 w-3" />
                            {config.label}
                        </div>
                    </div>
                    <CardTitle className="text-lg leading-tight line-clamp-2 group-hover:text-primary transition-colors">
                        {post.title}
                    </CardTitle>
                    <div className="flex items-center gap-2" onClick={(e) => e.stopPropagation()}>
                        <Link href={post.status === "completed" ? `/post/${post.id}/editor` : `/director/${post.id}`} className="flex-1">
                            <Button variant="outline" className="w-full">
                                {post.status === "completed" ? "View in Editor" : "Go to Director"}
                            </Button>
                        </Link>
                        {post.status === "completed" && post.videoUrl && (
                            <a href={post.videoUrl} download={`video-${post.id}.mp4`} target="_blank" rel="noreferrer">
                                <Button variant="secondary" size="icon" title="Download Video">
                                    <Download className="h-4 w-4" />
                                </Button>
                            </a>
                        )}
                    </div>
                </CardHeader>
                <CardContent className="space-y-3">
                    <p className="text-sm text-muted-foreground line-clamp-3">
                        {post.concept}
                    </p>
                    <div className="flex flex-wrap items-center gap-2 pt-2 border-t">
                        <Badge variant="secondary" className="text-xs">
                            {post.platform}
                        </Badge>
                        {post.musicVibe && <TrendingMusicBadge musicVibe={post.musicVibe} />}
                    </div>
                    <div className="flex items-center justify-between text-xs text-muted-foreground">
                        <span>{post.shotList?.length || 0} shots</span>
                    </div>
                </CardContent>
            </Card>
        </div>
    );
}

client/src/pages/billing-success.tsx.content:
import { useEffect, useState, useRef } from "react";
import { useLocation } from "wouter";
import { CheckCircleIcon, SparklesIcon, ArrowPathIcon } from "@heroicons/react/24/solid";
import { Button } from "@/components/ui/button";
import { useQueryClient } from "@tanstack/react-query";
import gsap from "gsap";
import { useSyncSubscription, useEntitlements } from "@/hooks/useEntitlements";

export default function BillingSuccess() {
  const [, setLocation] = useLocation();
  const [countdown, setCountdown] = useState(8);
  const [syncAttempts, setSyncAttempts] = useState(0);
  const [syncStatus, setSyncStatus] = useState<"pending" | "syncing" | "success" | "error">("pending");
  const containerRef = useRef<HTMLDivElement>(null);
  const queryClient = useQueryClient();
  const { mutateAsync: syncSubscription } = useSyncSubscription();
  const { data: entitlement, refetch } = useEntitlements({ forceRefresh: true });

  useEffect(() => {
    let cancelled = false;

    async function pollForSubscription() {
      setSyncStatus("syncing");

      for (let i = 0; i < 5; i++) {
        if (cancelled) return;
        setSyncAttempts(i + 1);

        try {
          await new Promise(resolve => setTimeout(resolve, 2000));

          const { data: currentData } = await refetch();
          if (currentData && currentData.plan !== "free") {
            setSyncStatus("success");
            queryClient.invalidateQueries({ queryKey: ["/api/subscription"] });
            queryClient.invalidateQueries({ queryKey: ["user"] });
            return;
          }

          try {
            await syncSubscription();
          } catch (syncErr) {
            console.log(`[BillingSuccess] Sync attempt ${i + 1} - sync endpoint failed (may not have customer yet):`, syncErr);
          }

          const { data: updated } = await refetch();
          if (updated && updated.plan !== "free") {
            setSyncStatus("success");
            queryClient.invalidateQueries({ queryKey: ["/api/subscription"] });
            queryClient.invalidateQueries({ queryKey: ["user"] });
            return;
          }
        } catch (error) {
          console.error(`[BillingSuccess] Sync attempt ${i + 1} failed:`, error);
        }
      }

      if (!cancelled) {
        setSyncStatus("error");
        queryClient.invalidateQueries({ queryKey: ["/api/subscription"] });
        queryClient.invalidateQueries({ queryKey: ["user"] });
      }
    }

    pollForSubscription();

    return () => { cancelled = true; };
  }, [syncSubscription, refetch, queryClient]);

  useEffect(() => {
    if (containerRef.current) {
      const tl = gsap.timeline();
      tl.fromTo(
        containerRef.current.querySelector(".success-icon"),
        { scale: 0, opacity: 0 },
        { scale: 1, opacity: 1, duration: 0.5, ease: "back.out(1.7)" }
      )
        .fromTo(
          containerRef.current.querySelector(".success-title"),
          { opacity: 0, y: 20 },
          { opacity: 1, y: 0, duration: 0.4 },
          "-=0.2"
        )
        .fromTo(
          containerRef.current.querySelector(".success-message"),
          { opacity: 0, y: 20 },
          { opacity: 1, y: 0, duration: 0.4 },
          "-=0.2"
        )
        .fromTo(
          containerRef.current.querySelector(".success-button"),
          { opacity: 0, y: 20 },
          { opacity: 1, y: 0, duration: 0.4 },
          "-=0.2"
        );
    }
  }, []);

  useEffect(() => {
    if (syncStatus === "syncing") return;

    const timer = window.setInterval(() => {
      setCountdown((prev) => {
        if (prev <= 1) {
          clearInterval(timer);
          setLocation("/dashboard");
          return 0;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(timer);
  }, [setLocation, syncStatus]);

  return (
    <div className="min-h-screen bg-white flex items-center justify-center p-6">
      <div ref={containerRef} className="max-w-md w-full text-center space-y-6">
        <div className="success-icon inline-flex items-center justify-center w-20 h-20 rounded-full bg-emerald-100">
          <CheckCircleIcon className="w-12 h-12 text-emerald-500" />
        </div>

        <div className="space-y-3">
          <h1 className="success-title text-3xl font-bold text-[#111111]">
            {syncStatus === "syncing" ? "Activating your plan..." : "Welcome to the team!"}
          </h1>
          <p className="success-message text-[#666666]">
            {syncStatus === "syncing" ? (
              <span className="flex items-center justify-center gap-2">
                <ArrowPathIcon className="w-4 h-4 animate-spin" />
                Syncing subscription (attempt {syncAttempts}/5)...
              </span>
            ) : syncStatus === "error" ? (
              "Your payment was successful! If your plan doesn't appear, visit your dashboard to refresh."
            ) : (
              `Your subscription is now active. You have full access to all your ${entitlement?.plan || "new"} plan features.`
            )}
          </p>
        </div>

        <div className="success-button pt-4 space-y-4">
          <Button
            onClick={() => setLocation("/dashboard")}
            disabled={syncStatus === "syncing"}
            className="w-full h-12 rounded-full bg-[#111111] text-white font-medium hover:opacity-90 transition-all duration-200 disabled:opacity-50"
          >
            <SparklesIcon className="w-5 h-5 mr-2" />
            Go to Dashboard
          </Button>
          <p className="text-sm text-[#666666]">
            {syncStatus === "syncing" 
              ? "Please wait while we activate your plan..." 
              : `Redirecting in ${countdown} seconds...`}
          </p>
        </div>
      </div>
    </div>
  );
}

