import { useEffect, useRef } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";

gsap.registerPlugin(ScrollTrigger);

export default function PhoneToEditorSection() {
  const containerRef = useRef<HTMLDivElement>(null);
  const phoneRef = useRef<HTMLDivElement>(null);
  const screenRef = useRef<HTMLDivElement>(null);
  const recordUIRef = useRef<HTMLDivElement>(null);
  const editorUIRef = useRef<HTMLDivElement>(null);
  const clipsRef = useRef<(HTMLDivElement | null)[]>([]);
  const timelineRef = useRef<HTMLDivElement>(null);
  const captionsRef = useRef<HTMLDivElement>(null);
  const exportRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!containerRef.current || !phoneRef.current) return;

    const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    if (prefersReducedMotion) {
      gsap.set(phoneRef.current, { rotateY: 0, scale: 1 });
      gsap.set(recordUIRef.current, { opacity: 0 });
      gsap.set(editorUIRef.current, { opacity: 1 });
      gsap.set(clipsRef.current, { opacity: 1, x: 0, scale: 1 });
      gsap.set(timelineRef.current, { scaleX: 1 });
      gsap.set(captionsRef.current, { opacity: 1, y: 0 });
      gsap.set(exportRef.current, { opacity: 1, scale: 1 });
      return;
    }

    const ctx = gsap.context(() => {
      gsap.set(phoneRef.current, { rotateY: -15, scale: 0.9 });
      gsap.set(recordUIRef.current, { opacity: 1 });
      gsap.set(editorUIRef.current, { opacity: 0 });
      gsap.set(clipsRef.current, { opacity: 0, x: 100, scale: 0.8 });
      gsap.set(timelineRef.current, { scaleX: 0, transformOrigin: "left" });
      gsap.set(captionsRef.current, { opacity: 0, y: 20 });
      gsap.set(exportRef.current, { opacity: 0, scale: 0.8 });

      const tl = gsap.timeline({
        scrollTrigger: {
          trigger: containerRef.current,
          start: "top top",
          end: "+=400%",
          scrub: 1,
          pin: true,
        },
      });

      tl.to(phoneRef.current, {
        rotateY: 0,
        scale: 1,
        duration: 2,
        ease: "power2.out",
      }, 0);

      tl.to(recordUIRef.current, {
        opacity: 0,
        duration: 1,
        ease: "power2.out",
      }, 2);

      tl.to(editorUIRef.current, {
        opacity: 1,
        duration: 1,
        ease: "power2.out",
      }, 2.5);

      clipsRef.current.forEach((clip, i) => {
        tl.to(clip, {
          opacity: 1,
          x: 0,
          scale: 1,
          duration: 1.5,
          ease: "power2.out",
        }, 3 + i * 0.5);
      });

      tl.to(timelineRef.current, {
        scaleX: 1,
        duration: 3,
        ease: "power2.out",
      }, 4);

      tl.to(captionsRef.current, {
        opacity: 1,
        y: 0,
        duration: 1.5,
        ease: "power2.out",
      }, 6);

      tl.to(phoneRef.current, {
        rotateY: 5,
        scale: 1.05,
        duration: 2,
        ease: "power2.out",
      }, 7);

      tl.to(exportRef.current, {
        opacity: 1,
        scale: 1,
        duration: 1.5,
        ease: "back.out(1.5)",
      }, 8);

    }, containerRef);

    return () => ctx.revert();
  }, []);

  const setClipRef = (i: number) => (el: HTMLDivElement | null) => {
    clipsRef.current[i] = el;
  };

  return (
    <div ref={containerRef} className="h-screen w-full flex items-center justify-center relative overflow-hidden">
      <div 
        ref={phoneRef}
        className="relative"
        style={{ 
          width: "clamp(280px, 40vw, 400px)",
          height: "clamp(500px, 70vh, 700px)",
          transformStyle: "preserve-3d",
          perspective: "1000px"
        }}
      >
        <div className="absolute inset-0 rounded-[3rem] border-[6px] border-white/20 bg-black overflow-hidden shadow-2xl">
          <div className="absolute top-3 left-1/2 -translate-x-1/2 w-24 h-6 bg-black rounded-full border border-white/10" />

          <div ref={screenRef} className="absolute inset-4 rounded-[2.2rem] bg-black overflow-hidden">
            <div ref={recordUIRef} className="absolute inset-0 flex flex-col items-center justify-center">
              <div className="w-20 h-20 rounded-full border-4 border-white/80 flex items-center justify-center mb-6">
                <div className="w-6 h-6 rounded-full bg-red-500 animate-pulse" />
              </div>
              <div className="text-white/60 text-sm">Recording...</div>
              <div className="mt-4 w-32 h-1 bg-white/20 rounded-full overflow-hidden">
                <div className="h-full w-1/3 bg-red-500 rounded-full" />
              </div>
            </div>

            <div ref={editorUIRef} className="absolute inset-0 flex flex-col p-4">
              <div className="flex-1 relative bg-black/50 rounded-xl overflow-hidden mb-3">
                <div className="absolute inset-0 flex items-center justify-center">
                  <div className="w-12 h-12 rounded-full border-2 border-[#135bec] flex items-center justify-center">
                    <div className="w-0 h-0 border-l-[12px] border-l-[#135bec] border-y-[8px] border-y-transparent ml-1" />
                  </div>
                </div>

                <div 
                  ref={captionsRef}
                  className="absolute bottom-4 left-4 right-4 text-center"
                >
                  <span className="px-3 py-1 bg-black/80 rounded text-sm text-white">
                    "This is how we built our product..."
                  </span>
                </div>
              </div>

              <div className="space-y-2">
                <div 
                  ref={timelineRef}
                  className="h-2 bg-[#135bec]/30 rounded-full"
                >
                  <div className="h-full w-2/3 bg-[#135bec] rounded-full" />
                </div>

                <div className="flex gap-2">
                  {[1, 2, 3].map((_, i) => (
                    <div
                      key={i}
                      ref={setClipRef(i)}
                      className="flex-1 h-12 rounded-lg bg-white/10 border border-white/20 flex items-center justify-center"
                    >
                      <div className="w-6 h-6 rounded bg-[#135bec]/30" />
                    </div>
                  ))}
                </div>
              </div>

              <div 
                ref={exportRef}
                className="mt-3 py-2 bg-[#135bec] rounded-lg text-center text-sm font-medium"
              >
                Export Video
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="absolute bottom-20 left-1/2 -translate-x-1/2 flex gap-8 text-sm text-white/40">
        <span>Record</span>
        <span className="text-[#135bec]">→</span>
        <span>Cut</span>
        <span className="text-[#135bec]">→</span>
        <span>Caption</span>
        <span className="text-[#135bec]">→</span>
        <span>Export</span>
      </div>
    </div>
  );
}

