"use client";

import { useEffect, useState } from "react";
import { cn } from "@repo/ui";

interface Word {
    word: string;
    start: number;
    end: number;
}

interface Caption {
    start: number;
    end: number;
    viralText: string;
    highlightWords: string[];
    words: Word[];
    style: {
        font: string;
        baseTextColor: string;
        highlightTextColor: string;
        background: string;
        position: string;
        animation: string;
    };
}

interface CaptionPlayerProps {
    currentTime: number;
    captions: Caption[];
}

export function CaptionPlayer({ currentTime, captions }: CaptionPlayerProps) {
    const activeCaption = captions.find(c => currentTime >= c.start && currentTime < c.end) || null;

    if (!activeCaption) return null;

    return (
        <div className="absolute inset-x-0 bottom-[15%] flex justify-center px-6 pointer-events-none select-none z-30">
            <div
                className="flex flex-wrap justify-center gap-x-2 gap-y-1 text-center bg-black/40 backdrop-blur-sm p-4 rounded-2xl border border-white/10"
                style={{
                    fontFamily: "'Inter', sans-serif",
                    fontWeight: 900,
                    textTransform: 'uppercase'
                }}
            >
                {activeCaption.words.map((w, i) => {
                    const isActive = currentTime >= w.start && currentTime < w.end;
                    const isHighlighted = activeCaption.highlightWords.some(hw =>
                        w.word.toLowerCase().includes(hw.toLowerCase())
                    );

                    return (
                        <span
                            key={i}
                            className={cn(
                                "inline-block transition-all duration-100",
                                isActive ? "scale-125 z-10" : "scale-100 opacity-80",
                                isHighlighted ? "text-yellow-400" : "text-white"
                            )}
                            style={{
                                textShadow: '2px 2px 0px rgba(0,0,0,0.8)',
                                transform: isActive ? 'translateY(-4px) scale(1.3)' : 'none'
                            }}
                        >
                            {w.word}
                        </span>
                    );
                })}
            </div>
        </div>
    );
}

server/middleware/aiKillSwitch.ts.content:
/**
 * AI Kill Switch Middleware
 * Provides a global toggle to disable all AI features
 * Set DISABLE_AI=true to disable all AI endpoints
 */

import type { Request, Response, NextFunction } from "express";
import { config } from "../config";

export function aiKillSwitch(req: Request, res: Response, next: NextFunction) {
  if (config.ai.disabled) {
    const requestId = (req as any).requestId || "unknown";
    const userId = (req as any).user?.sub || "anonymous";
    console.log(`[AI-DISABLED] [${requestId}] [user:${userId}] Blocked AI request to ${req.path}`);

    return res.status(503).json({
      error: {
        message: "AI features are temporarily disabled for maintenance",
        code: "AI_DISABLED",
      },
    });
  }
  next();
}

export function logAIRequest(endpoint: string) {
  return (req: Request, _res: Response, next: NextFunction) => {
    const requestId = (req as any).requestId || "unknown";
    const userId = (req as any).user?.sub || "anonymous";
    console.log(`[AI-REQUEST] [${requestId}] [user:${userId}] ${endpoint}`);
    next();
  };
}

