import { useEffect, useRef } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { TIMING, EASE, STAGGER, DELAY } from "@/lib/animation";

gsap.registerPlugin(ScrollTrigger);

export default function HeroAnimation() {
  const containerRef = useRef<HTMLDivElement>(null);
  const lettersRef = useRef<(HTMLSpanElement | null)[]>([]);
  const subtextRef = useRef<HTMLDivElement>(null);
  const subtextCharsRef = useRef<(HTMLSpanElement | null)[]>([]);

  const letters = "NAVINTA".split("");
  const subtextContent = "Your AI-powered director";

  useEffect(() => {
    if (!containerRef.current) return;

    const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    if (prefersReducedMotion) {
      gsap.set(lettersRef.current, { opacity: 1, y: 0, rotateY: 0, z: 0 });
      gsap.set(subtextCharsRef.current, { opacity: 1 });
      return;
    }

    const ctx = gsap.context(() => {
      lettersRef.current.forEach((letter, i) => {
        const depth = -200 - (Math.random() * 300);
        const offsetY = -50 + (Math.random() * 100);
        const rotateY = -30 + (Math.random() * 60);
        gsap.set(letter, { 
          opacity: 0, 
          y: offsetY,
          z: depth,
          rotateY: rotateY,
          rotateX: Math.random() * 20 - 10,
        });
      });
      gsap.set(subtextCharsRef.current, { opacity: 0 });

      const entranceTl = gsap.timeline({ delay: DELAY.MEDIUM });

      lettersRef.current.forEach((letter, i) => {
        entranceTl.to(letter, {
          opacity: 1,
          y: 0,
          z: 0,
          rotateY: 0,
          rotateX: 0,
          duration: TIMING.SLOW,
          ease: EASE,
        }, i * STAGGER.NORMAL);
      });

      entranceTl.to(subtextCharsRef.current, {
        opacity: 1,
        duration: TIMING.FAST,
        ease: EASE,
        stagger: 0.03,
      }, TIMING.SLOW + DELAY.MEDIUM);

      const scrollTl = gsap.timeline({
        scrollTrigger: {
          trigger: containerRef.current,
          start: "top top",
          end: "+=200%",
          pin: true,
          scrub: 1,
          anticipatePin: 1,
        },
      });

      lettersRef.current.forEach((letter, i) => {
        scrollTl.to(letter, {
          rotateY: i % 2 === 0 ? 8 : -8,
          y: i % 2 === 0 ? -5 : 5,
          duration: 2,
          ease: EASE,
        }, 0);
      });

      scrollTl.to(containerRef.current, {
        scale: 0.85,
        y: "-30vh",
        duration: 3,
        ease: EASE,
      }, 2);

      scrollTl.to([...lettersRef.current, subtextRef.current], {
        opacity: 0,
        y: -50,
        stagger: STAGGER.TIGHT,
        duration: 1.5,
        ease: EASE,
      }, 4);

    }, containerRef);

    return () => ctx.revert();
  }, []);

  const setLetterRef = (i: number) => (el: HTMLSpanElement | null) => {
    lettersRef.current[i] = el;
  };

  const setSubtextCharRef = (i: number) => (el: HTMLSpanElement | null) => {
    subtextCharsRef.current[i] = el;
  };

  return (
    <div
      ref={containerRef}
      className="h-screen w-full bg-black flex items-center justify-center overflow-hidden relative"
      style={{ perspective: "1200px" }}
    >
      <div className="ambient-light" />
      <div className="light-sweep" />

      <div className="relative z-10 text-center" style={{ transformStyle: "preserve-3d" }}>
        <div 
          className="flex justify-center gap-0 md:gap-1 text-breathe"
          style={{ perspective: "1000px", transformStyle: "preserve-3d" }}
        >
          {letters.map((letter, i) => (
            <span
              key={i}
              ref={setLetterRef(i)}
              className="inline-block font-bold tracking-tight text-[#F5F1EC] parallax-float"
              style={{ 
                fontSize: "clamp(3rem, 12vw, 8rem)",
                transformStyle: "preserve-3d",
                textShadow: "0 0 80px rgba(176, 138, 90, 0.15)",
              }}
            >
              {letter}
            </span>
          ))}
        </div>

        <div
          ref={subtextRef}
          className="mt-8 md:mt-10 text-lg md:text-xl text-[#B08A5A]/60 tracking-widest font-light"
        >
          {subtextContent.split("").map((char, i) => (
            <span
              key={i}
              ref={setSubtextCharRef(i)}
              className="inline-block"
              style={{ whiteSpace: char === " " ? "pre" : "normal" }}
            >
              {char}
            </span>
          ))}
        </div>
      </div>
    </div>
  );
}

