import { useState, useRef, useEffect } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useRoute, useLocation } from "wouter";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Progress } from "@/components/ui/progress";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  ArrowLeft,
  Download,
  Play,
  Pause,
  Trash2,
  ChevronLeft,
  ChevronRight,
  Merge,
  Sparkles,
  Type,
  Check,
  AlertCircle,
} from "lucide-react";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import type { Video, Transcription } from "@shared/schema";

interface CaptionSegment {
  start: number;
  end: number;
  originalText: string;
  viralText: string;
  useViral: boolean;
  highlightWords: string[];
  style: {
    font: string;
    baseTextColor: string;
    outlineColor: string;
    background: string;
    highlightTextColor: string;
    highlightBackground: string;
    position: string;
    animation: string;
  };
}

interface StyleSettings {
  stylePreset: string;
  fontSize: string;
  position: string;
  animation: string;
}

const STYLE_PRESETS = ["Minimal", "Bold", "Cinematic"];
const FONT_SIZES = ["S", "M", "L"];
const POSITIONS = ["Top", "Center", "Bottom"];
const ANIMATIONS = ["Fade", "Pop", "Slide"];

const DEFAULT_STYLE_SETTINGS: StyleSettings = {
  stylePreset: "Bold",
  fontSize: "M",
  position: "Bottom",
  animation: "Pop",
};

export default function PreviewCaptions() {
  const [, params] = useRoute("/videos/:videoId/preview");
  const [, setLocation] = useLocation();
  const videoId = params?.videoId;
  const { toast } = useToast();

  const videoRef = useRef<HTMLVideoElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [captionsEnabled, setCaptionsEnabled] = useState(true);
  const [styleSettings, setStyleSettings] = useState<StyleSettings>(DEFAULT_STYLE_SETTINGS);
  const [captions, setCaptions] = useState<CaptionSegment[]>([]);
  const [hasUnsavedChanges, setHasUnsavedChanges] = useState(false);

  const { data: video, isLoading: videoLoading } = useQuery<Video>({
    queryKey: ["/api/videos", videoId],
    queryFn: async () => {
      const res = await apiRequest("GET", `/api/videos/${videoId}`);
      return res.json();
    },
    enabled: !!videoId,
  });

  const { data: transcription, isLoading: transcriptionLoading } = useQuery<Transcription | null>({
    queryKey: ["/api/transcriptions", videoId],
    queryFn: async () => {
      try {
        const res = await apiRequest("GET", `/api/videos/${videoId}/captions`);
        return res.json();
      } catch (err: any) {
        if (err.message?.startsWith("404:")) return null;
        throw err;
      }
    },
    enabled: !!videoId,
  });

  useEffect(() => {
    if (transcription) {
      setCaptions(transcription.captions || []);
      if (transcription.styleSettings) {
        setStyleSettings(transcription.styleSettings as StyleSettings);
      }
    }
  }, [transcription]);

  const saveCaptionsMutation = useMutation({
    mutationFn: async (data: { captions: CaptionSegment[]; styleSettings: StyleSettings }) => {
      if (!transcription?.id) {
        throw new Error("No transcription found to save");
      }
      return apiRequest("PUT", `/api/transcriptions/${transcription.id}`, data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/transcriptions", videoId] });
      setHasUnsavedChanges(false);
      toast({
        title: "Captions saved",
        description: "Your changes have been saved.",
      });
    },
    onError: () => {
      toast({
        title: "Save failed",
        description: "Unable to save captions. Please try again.",
        variant: "destructive",
      });
    },
  });

  const exportMutation = useMutation({
    mutationFn: async () => {
      if (hasUnsavedChanges) {
        await saveCaptionsMutation.mutateAsync({ captions, styleSettings });
      }
      return apiRequest("POST", `/api/videos/${videoId}/export-with-captions`, {
        captions,
        styleSettings,
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/videos"] });
      queryClient.invalidateQueries({ queryKey: ["/api/transcriptions", videoId] });
      toast({
        title: "Video exported!",
        description: "Your video with captions is ready.",
      });
      setLocation("/library");
    },
    onError: (error: any) => {
      let description = "Unable to export video. Please try again.";
      const msg = error?.message || "";
      if (msg.includes("EXPORT_LIMIT_REACHED")) {
        description = "You've reached your daily export limit. Upgrade your plan for more exports.";
      } else if (msg.includes("402") || msg.includes("SUBSCRIPTION_REQUIRED")) {
        description = "A subscription is required to export videos.";
      } else if (msg.includes("Failed to process video") || msg.includes("VIDEO_PROCESSING_ERROR")) {
        description = "Video processing failed. Please check your clips and try again.";
      }
      toast({
        title: "Export failed",
        description,
        variant: "destructive",
      });
    },
  });

  const handlePlayPause = () => {
    if (videoRef.current) {
      if (isPlaying) {
        videoRef.current.pause();
      } else {
        videoRef.current.play();
      }
      setIsPlaying(!isPlaying);
    }
  };

  const handleTimeUpdate = () => {
    if (videoRef.current) {
      setCurrentTime(videoRef.current.currentTime);
    }
  };

  const handleLoadedMetadata = () => {
    if (videoRef.current) {
      setDuration(videoRef.current.duration);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    if (videoRef.current) {
      videoRef.current.currentTime = time;
      setCurrentTime(time);
    }
  };

  const getCurrentCaption = () => {
    if (!captionsEnabled) return null;
    return captions.find(
      (cap) => currentTime >= cap.start && currentTime <= cap.end
    );
  };

  const updateCaption = (index: number, updates: Partial<CaptionSegment>) => {
    const newCaptions = [...captions];
    newCaptions[index] = { ...newCaptions[index], ...updates };
    setCaptions(newCaptions);
    setHasUnsavedChanges(true);
  };

  const nudgeTiming = (index: number, field: "start" | "end", delta: number) => {
    const newCaptions = [...captions];
    const newValue = Math.max(0, (newCaptions[index][field] || 0) + delta);
    newCaptions[index] = { ...newCaptions[index], [field]: newValue };
    setCaptions(newCaptions);
    setHasUnsavedChanges(true);
  };

  const deleteCaption = (index: number) => {
    const newCaptions = captions.filter((_, i) => i !== index);
    setCaptions(newCaptions);
    setHasUnsavedChanges(true);
  };

  const mergeWithNext = (index: number) => {
    if (index >= captions.length - 1) return;
    const newCaptions = [...captions];
    const current = newCaptions[index];
    const next = newCaptions[index + 1];
    newCaptions[index] = {
      ...current,
      end: next.end,
      originalText: `${current.originalText} ${next.originalText}`,
      viralText: `${current.viralText} ${next.viralText}`,
    };
    newCaptions.splice(index + 1, 1);
    setCaptions(newCaptions);
    setHasUnsavedChanges(true);
  };

  const updateStyleSettings = (updates: Partial<StyleSettings>) => {
    setStyleSettings((prev) => ({ ...prev, ...updates }));
    setHasUnsavedChanges(true);
  };

  const handleSave = () => {
    saveCaptionsMutation.mutate({ captions, styleSettings });
  };

  const handleExport = () => {
    exportMutation.mutate();
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    const ms = Math.floor((seconds % 1) * 10);
    return `${mins}:${secs.toString().padStart(2, "0")}.${ms}`;
  };

  const currentCaption = getCurrentCaption();

  const getFontSizeClass = () => {
    switch (styleSettings.fontSize) {
      case "S": return "text-sm";
      case "L": return "text-2xl";
      default: return "text-lg";
    }
  };

  const getPositionClass = () => {
    switch (styleSettings.position) {
      case "Top": return "top-8";
      case "Center": return "top-1/2 -translate-y-1/2";
      default: return "bottom-16";
    }
  };

  const getAnimationClass = () => {
    switch (styleSettings.animation) {
      case "Fade": return "animate-fade-in";
      case "Slide": return "animate-slide-up";
      default: return "animate-pop";
    }
  };

  const getStylePresetClasses = () => {
    switch (styleSettings.stylePreset) {
      case "Minimal":
        return "text-white/90 font-normal";
      case "Cinematic":
        return "text-amber-100 font-serif italic";
      default:
        return "text-white font-bold drop-shadow-[0_2px_4px_rgba(0,0,0,0.8)]";
    }
  };

  const needsReExport = transcription?.updatedAt && transcription?.lastExportedAt 
    ? new Date(transcription.updatedAt) > new Date(transcription.lastExportedAt)
    : false;

  if (videoLoading || transcriptionLoading) {
    return (
      <div className="min-h-screen bg-white p-6">
        <div className="w-full space-y-6">
          <Skeleton className="h-12 w-64 bg-gray-100" />
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <Skeleton className="aspect-[9/16] max-h-[70vh] bg-gray-100 rounded-3xl" />
            <Skeleton className="h-[70vh] bg-gray-100 rounded-3xl" />
          </div>
        </div>
      </div>
    );
  }

  if (!video) {
    return (
      <div className="min-h-screen bg-white flex items-center justify-center">
        <div className="text-center">
          <h2 className="text-2xl font-semibold text-[#111111] mb-4">Video not found</h2>
          <Button onClick={() => setLocation("/library")} className="bg-[#111111] hover:bg-[#333333] text-white rounded-full px-6">
            Back to Library
          </Button>
        </div>
      </div>
    );
  }

  if (exportMutation.isPending) {
    return (
      <div className="min-h-screen bg-white flex items-center justify-center p-4">
        <div className="w-full max-w-2xl mx-auto p-12 bg-white rounded-3xl border border-gray-200 shadow-sm">
          <div className="text-center space-y-6">
            <div className="inline-flex items-center justify-center w-20 h-20 rounded-full bg-gray-50 mb-4 animate-pulse">
              <Sparkles className="h-10 w-10 text-[#111111] animate-spin" />
            </div>
            <div className="space-y-2">
              <h2 className="text-2xl font-semibold text-[#111111]">Exporting Your Video</h2>
              <p className="text-[#666666]">
                Burning captions into video...
              </p>
            </div>
            <Progress value={66} className="h-2 bg-gray-100" />
          </div>
        </div>
      </div>
    );
  }

  const videoUrl = (video as any).signedUrl
    || (video.videoPath
      ? `/api/storage/videos/${video.videoPath}`
      : video.videoData?.startsWith("http")
        ? video.videoData
        : `/uploads/videos/${video.videoData}`);

  return (
    <div className="min-h-screen bg-white">
      <div className="w-full px-4 py-6 sm:px-6 lg:px-10">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-4">
            <Button
              variant="ghost"
              size="icon"
              onClick={() => setLocation(`/director/${video.postId}`)}
              className="text-[#666666] hover:text-[#111111] hover:bg-gray-50 rounded-full"
            >
              <ArrowLeft className="h-5 w-5" />
            </Button>
            <div>
              <h1 className="text-xl font-semibold text-[#111111]">{video.title}</h1>
              <p className="text-sm text-[#666666]">Preview & Edit Captions</p>
            </div>
          </div>

          {hasUnsavedChanges && (
            <div className="flex items-center gap-2 text-amber-600 text-sm">
              <AlertCircle className="h-4 w-4" />
              Unsaved changes
            </div>
          )}
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          <div className="space-y-4">
            <div className="relative bg-white rounded-3xl overflow-hidden border border-gray-200 shadow-sm">
              <div className="relative aspect-[9/16] max-h-[70vh] mx-auto bg-gray-50 rounded-t-3xl">
                <video
                  ref={videoRef}
                  src={videoUrl}
                  className="w-full h-full object-contain"
                  onTimeUpdate={handleTimeUpdate}
                  onLoadedMetadata={handleLoadedMetadata}
                  onEnded={() => setIsPlaying(false)}
                  playsInline
                  crossOrigin="anonymous"
                />

                {captionsEnabled && currentCaption && (
                  <div
                    className={`absolute left-4 right-4 ${getPositionClass()} text-center pointer-events-none`}
                  >
                    <span
                      className={`inline-block px-4 py-2 rounded-lg ${getFontSizeClass()} ${getStylePresetClasses()} ${getAnimationClass()}`}
                      style={{
                        backgroundColor: styleSettings.stylePreset === "Minimal" 
                          ? "rgba(0,0,0,0.5)" 
                          : styleSettings.stylePreset === "Cinematic"
                            ? "rgba(0,0,0,0.7)"
                            : "transparent",
                      }}
                    >
                      {currentCaption.useViral ? currentCaption.viralText : currentCaption.originalText}
                    </span>
                  </div>
                )}
              </div>

              <div className="p-4 bg-white border-t border-gray-200">
                <div className="flex items-center gap-4">
                  <Button
                    variant="ghost"
                    size="icon"
                    onClick={handlePlayPause}
                    className="text-[#111111] hover:bg-gray-50 rounded-full"
                  >
                    {isPlaying ? <Pause className="h-5 w-5" /> : <Play className="h-5 w-5" />}
                  </Button>

                  <span className="text-sm text-[#666666] w-16 font-mono">
                    {formatTime(currentTime)}
                  </span>

                  <input
                    type="range"
                    min={0}
                    max={duration}
                    step={0.1}
                    value={currentTime}
                    onChange={handleSeek}
                    className="flex-1 h-2 rounded-full appearance-none bg-gray-100 cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-4 [&::-webkit-slider-thumb]:h-4 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-[#111111]"
                  />

                  <span className="text-sm text-[#666666] w-16 text-right font-mono">
                    {formatTime(duration)}
                  </span>
                </div>

                <div className="flex items-center gap-4 mt-4">
                  <div className="flex items-center gap-2">
                    <Switch
                      id="captions-toggle"
                      checked={captionsEnabled}
                      onCheckedChange={setCaptionsEnabled}
                    />
                    <Label htmlFor="captions-toggle" className="text-[#666666] text-sm">
                      Show Captions
                    </Label>
                  </div>
                </div>
              </div>
            </div>
          </div>

          <div className="space-y-4">
            <div className="bg-white rounded-3xl border border-gray-200 shadow-sm overflow-hidden">
              <div className="px-5 py-4 border-b border-gray-200">
                <h3 className="text-[#111111] text-lg font-semibold flex items-center gap-2">
                  <Type className="h-5 w-5 text-[#111111]" />
                  Caption Style
                </h3>
              </div>
              <div className="p-5 space-y-5">
                <div className="space-y-2">
                  <Label className="text-[#666666] text-sm font-medium">Style Preset</Label>
                  <Select
                    value={styleSettings.stylePreset}
                    onValueChange={(v) => updateStyleSettings({ stylePreset: v })}
                  >
                    <SelectTrigger className="bg-white border-gray-200 text-[#111111] rounded-xl">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent className="bg-white border-gray-200 rounded-xl">
                      {STYLE_PRESETS.map((preset) => (
                        <SelectItem key={preset} value={preset} className="text-[#111111]">
                          {preset}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label className="text-[#666666] text-sm font-medium">Font Size</Label>
                  <div className="flex gap-2">
                    {FONT_SIZES.map((size) => (
                      <Button
                        key={size}
                        variant={styleSettings.fontSize === size ? "default" : "outline"}
                        size="sm"
                        onClick={() => updateStyleSettings({ fontSize: size })}
                        className={styleSettings.fontSize === size 
                          ? "bg-[#111111] hover:bg-[#333333] text-white rounded-full" 
                          : "border border-gray-200 text-[#666666] hover:text-[#111111] hover:bg-gray-50 rounded-full"
                        }
                      >
                        {size}
                      </Button>
                    ))}
                  </div>
                </div>

                <div className="space-y-2">
                  <Label className="text-[#666666] text-sm font-medium">Position</Label>
                  <div className="flex gap-2">
                    {POSITIONS.map((pos) => (
                      <Button
                        key={pos}
                        variant={styleSettings.position === pos ? "default" : "outline"}
                        size="sm"
                        onClick={() => updateStyleSettings({ position: pos })}
                        className={styleSettings.position === pos 
                          ? "bg-[#111111] hover:bg-[#333333] text-white rounded-full" 
                          : "border border-gray-200 text-[#666666] hover:text-[#111111] hover:bg-gray-50 rounded-full"
                        }
                      >
                        {pos}
                      </Button>
                    ))}
                  </div>
                </div>

                <div className="space-y-2">
                  <Label className="text-[#666666] text-sm font-medium">Animation</Label>
                  <Select
                    value={styleSettings.animation}
                    onValueChange={(v) => updateStyleSettings({ animation: v })}
                  >
                    <SelectTrigger className="bg-white border-gray-200 text-[#111111] rounded-xl">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent className="bg-white border-gray-200 rounded-xl">
                      {ANIMATIONS.map((anim) => (
                        <SelectItem key={anim} value={anim} className="text-[#111111]">
                          {anim}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </div>
            </div>

            <div className="bg-white rounded-3xl border border-gray-200 shadow-sm overflow-hidden max-h-[400px] flex flex-col">
              <div className="px-5 py-4 border-b border-gray-200 flex-shrink-0">
                <h3 className="text-[#111111] text-lg font-semibold">
                  Caption Timeline ({captions.length} segments)
                </h3>
              </div>
              <div className="overflow-y-auto flex-1 p-4 space-y-3">
                {captions.length === 0 ? (
                  <div className="text-center py-8 space-y-3">
                    <p className="text-[#666666] text-sm">
                      {transcription ? "No caption segments found." : "Captions are being generated..."}
                    </p>
                    {!transcription && (
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => queryClient.invalidateQueries({ queryKey: ["/api/transcriptions", videoId] })}
                        className="border border-gray-200 text-[#666666] rounded-full"
                      >
                        Refresh
                      </Button>
                    )}
                  </div>
                ) : (
                  captions.map((caption, index) => {
                    const isActive = currentTime >= caption.start && currentTime <= caption.end;
                    return (
                      <div
                        key={index}
                        className={`p-3 rounded-xl border transition-all ${
                          isActive 
                            ? "bg-gray-50 border-[#111111]/20" 
                            : "bg-white border-gray-200 hover:border-gray-300"
                        }`}
                      >
                        <div className="flex items-center justify-between mb-2">
                          <span className="text-xs text-[#666666] font-mono">
                            {formatTime(caption.start)} - {formatTime(caption.end)}
                          </span>
                          <div className="flex items-center gap-1">
                            <Button
                              variant="ghost"
                              size="icon"
                              className="h-6 w-6 text-[#666666] hover:text-[#111111] hover:bg-gray-50"
                              onClick={() => nudgeTiming(index, "start", -0.1)}
                              title="Start earlier"
                            >
                              <ChevronLeft className="h-3 w-3" />
                            </Button>
                            <Button
                              variant="ghost"
                              size="icon"
                              className="h-6 w-6 text-[#666666] hover:text-[#111111] hover:bg-gray-50"
                              onClick={() => nudgeTiming(index, "end", 0.1)}
                              title="End later"
                            >
                              <ChevronRight className="h-3 w-3" />
                            </Button>
                            {index < captions.length - 1 && (
                              <Button
                                variant="ghost"
                                size="icon"
                                className="h-6 w-6 text-[#666666] hover:text-[#111111] hover:bg-gray-50"
                                onClick={() => mergeWithNext(index)}
                                title="Merge with next"
                              >
                                <Merge className="h-3 w-3" />
                              </Button>
                            )}
                            <Button
                              variant="ghost"
                              size="icon"
                              className="h-6 w-6 text-[#666666] hover:text-red-500 hover:bg-red-50"
                              onClick={() => deleteCaption(index)}
                              title="Delete"
                            >
                              <Trash2 className="h-3 w-3" />
                            </Button>
                          </div>
                        </div>
                        <Input
                          value={caption.useViral ? caption.viralText : caption.originalText}
                          onChange={(e) => updateCaption(index, {
                            [caption.useViral ? "viralText" : "originalText"]: e.target.value
                          })}
                          className="bg-white border-gray-200 text-[#111111] text-sm rounded-lg"
                        />
                      </div>
                    );
                  })
                )}
              </div>
            </div>
          </div>
        </div>

        <div className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-lg border-t border-gray-200 p-4 z-50">
          <div className="w-full px-4 sm:px-6 lg:px-10 flex items-center justify-between">
            <Button
              variant="outline"
              onClick={() => setLocation(`/director/${video.postId}`)}
              className="border border-gray-200 text-[#666666] hover:text-[#111111] hover:bg-gray-50 rounded-full"
            >
              <ArrowLeft className="h-4 w-4 mr-2" />
              Back to Shots
            </Button>

            <div className="flex items-center gap-3">
              {hasUnsavedChanges && (
                <Button
                  variant="outline"
                  onClick={handleSave}
                  disabled={saveCaptionsMutation.isPending}
                  className="border border-gray-200 text-[#666666] hover:text-[#111111] hover:bg-gray-50 rounded-full"
                >
                  {saveCaptionsMutation.isPending ? (
                    <>Saving...</>
                  ) : (
                    <>
                      <Check className="h-4 w-4 mr-2" />
                      Save Changes
                    </>
                  )}
                </Button>
              )}

              {needsReExport && (
                <span className="text-amber-600 text-sm flex items-center gap-1">
                  <AlertCircle className="h-4 w-4" />
                  Re-export needed
                </span>
              )}

              <Button
                onClick={handleExport}
                disabled={exportMutation.isPending}
                className="bg-[#111111] hover:bg-[#333333] text-white rounded-full px-6"
              >
                <Download className="h-4 w-4 mr-2" />
                Export Video
              </Button>
            </div>
          </div>
        </div>

        <div className="h-20" />
      </div>

      <style>{`
        @keyframes fade-in {
          from { opacity: 0; }
          to { opacity: 1; }
        }
        @keyframes pop {
          0% { transform: scale(0.8); opacity: 0; }
          50% { transform: scale(1.05); }
          100% { transform: scale(1); opacity: 1; }
        }
        @keyframes slide-up {
          from { transform: translateY(20px); opacity: 0; }
          to { transform: translateY(0); opacity: 1; }
        }
        .animate-fade-in { animation: fade-in 0.3s ease-out; }
        .animate-pop { animation: pop 0.3s ease-out; }
        .animate-slide-up { animation: slide-up 0.3s ease-out; }
      `}</style>
    </div>
  );
}

