import type { Express } from "express";
import { createServer, type Server } from "http";
import { readFileSync } from "fs";
import { join } from "path";
import { storage } from "./storage";
import { generateContentPlan } from "./lib/openai";
import { videoProcessor } from "./lib/videoProcessor";
import { trendingMusicService } from "./lib/trendingMusic";
import { onboardingSchema, insertPostSchema, insertClipSchema } from "@shared/schema";
import { setupAuth } from "./googleAuth";
import { requireAuth } from "./middleware/authJwt";
import { authLimiter, uploadLimiter, aiLimiter } from "./middleware/rateLimit";
import { asyncHandler, createError } from "./middleware/errorHandler";
import { publicRoutesMiddleware } from "./middleware/publicRoutes";

// Read version from package.json
let appVersion = "1.0.0";
try {
  const packageJson = JSON.parse(
    readFileSync(join(process.cwd(), "package.json"), "utf-8")
  );
  appVersion = packageJson.version || "1.0.0";
} catch {
  // Fallback if package.json can't be read
}

// Track server start time for uptime calculation
const serverStartTime = Date.now();

export async function registerRoutes(app: Express): Promise<Server> {
  // Public routes middleware (must be before auth setup)
  app.use(publicRoutesMiddleware);

  // Health check endpoint (public, no auth required)
  app.get("/api/health", async (_req, res) => {
    const uptime = Math.floor((Date.now() - serverStartTime) / 1000);
    res.json({
      ok: true,
      uptime,
      env: process.env.NODE_ENV || "development",
      version: appVersion,
    });
  });

  // Google OAuth: Setup authentication
  await setupAuth(app);

  // Global JWT guard for /api (skips known public routes)
  app.use("/api", (req, res, next) => {
    if ((req as any).isPublicRoute) return next();
    return requireAuth(req as any, res, next);
  });

  // Apply rate limiting to auth endpoints
  app.use("/api/login", authLimiter);
  app.use("/api/auth/google/callback", authLimiter);

  // Google OAuth: Get current user
  app.get('/api/auth/user', requireAuth, asyncHandler(async (req: any, res) => {
    const authUser = req.user;
    if (!authUser?.sub) {
      throw createError("Unauthorized", 401, "UNAUTHORIZED");
    }
    const user = await storage.getUser(authUser.sub);
    if (!user) {
      throw createError("User not found", 404, "USER_NOT_FOUND");
    }
    res.json(user);
  }));

  // Onboarding - Creates project, brand kit and content plan
  app.post("/api/onboarding", requireAuth, aiLimiter, asyncHandler(async (req: any, res) => {
    const userId = req.user.sub;
    const data = onboardingSchema.parse(req.body);

      // Create default project for the user
      const project = await storage.createProject({
        userId,
        name: data.brandName,
        description: `${data.businessType} - ${data.targetAudience}`,
      });

      // Create brand kit
      await storage.createOrUpdateBrandKit({
        projectId: project.id,
        userId,
        brandName: data.brandName,
        primaryColor: data.primaryColor,
        secondaryColor: data.secondaryColor,
        accentColor: data.accentColor,
        logoUrl: "",
        fonts: {},
      });

      // Generate content plan with AI
      const aiPlan = await generateContentPlan(data);

      // Create content plan
      const contentPlan = await storage.createContentPlan({
        projectId: project.id,
        userId,
        brandKitId: null,
        businessType: data.businessType,
        targetAudience: data.targetAudience,
        contentGoals: data.contentGoals,
        platforms: data.platforms,
        postFrequency: data.postFrequency,
        tone: data.tone,
      });

      // Create all posts from AI plan
      for (const postData of aiPlan.posts) {
        await storage.createPost({
          projectId: project.id,
          contentPlanId: contentPlan.id,
          userId,
          weekNumber: postData.weekNumber,
          dayNumber: postData.dayNumber,
          title: postData.title,
          concept: postData.concept,
          platform: postData.platform,
          shotList: postData.shotList,
          brollSuggestions: postData.brollSuggestions,
          caption: postData.caption,
          hashtags: postData.hashtags,
          musicVibe: postData.musicVibe,
          status: "planned",
          scheduledFor: null,
        });
      }

      res.json({ success: true, project, contentPlan });
  }));

  // Get content plan with posts
  app.get("/api/content-plan", requireAuth, async (req: any, res) => {
    try {
      const userId = req.user.sub;

      // Get user's default project
      const projects = await storage.getProjects(userId);
      if (projects.length === 0) {
        return res.json(null);
      }
      const defaultProject = projects[0];

      const plan = await storage.getContentPlan(defaultProject.id, userId);
      if (!plan) {
        return res.json(null);
      }

      // Include posts in the response
      const posts = await storage.getPosts(defaultProject.id, userId);
      res.json({
        ...plan,
        posts: posts,
      });
    } catch (error) {
      res.status(500).json({ error: "Failed to fetch content plan" });
    }
  });

  // Get all posts
  app.get("/api/posts", requireAuth, async (req: any, res) => {
    try {
      const userId = req.user.sub;

      // Get user's default project
      const projects = await storage.getProjects(userId);
      if (projects.length === 0) {
        return res.json([]);
      }
      const defaultProject = projects[0];

      const posts = await storage.getPosts(defaultProject.id, userId);
      res.json(posts);
    } catch (error) {
      res.status(500).json({ error: "Failed to fetch posts" });
    }
  });

  // Get single post
  app.get("/api/posts/:id", requireAuth, async (req: any, res) => {
    try {
      const userId = req.user.sub;
      const post = await storage.getPost(req.params.id, userId);
      if (!post) {
        return res.status(404).json({ error: "Post not found" });
      }
      res.json(post);
    } catch (error) {
      res.status(500).json({ error: "Failed to fetch post" });
    }
  });

  // Update post shot completion
  app.patch("/api/posts/:postId/shots/:shotId", requireAuth, async (req: any, res) => {
    try {
      const userId = req.user.sub;
      const { completed } = req.body;
      const post = await storage.updatePostShot(
        req.params.postId,
        req.params.shotId,
        userId,
        completed
      );
      res.json(post);
    } catch (error) {
      res.status(500).json({ error: "Failed to update shot" });
    }
  });

  // Update post status
  app.patch("/api/posts/:id/status", requireAuth, async (req: any, res) => {
    try {
      const userId = req.user.sub;
      const { status } = req.body;
      const post = await storage.updatePostStatus(req.params.id, userId, status);
      res.json(post);
    } catch (error) {
      res.status(500).json({ error: "Failed to update post status" });
    }
  });

  // Get brand kit
  app.get("/api/brand-kit", requireAuth, async (req: any, res) => {
    try {
      const userId = req.user.sub;

      // Get user's default project
      const projects = await storage.getProjects(userId);
      if (projects.length === 0) {
        return res.json(null);
      }
      const defaultProject = projects[0];

      const brandKit = await storage.getBrandKit(defaultProject.id, userId);
      res.json(brandKit || null);
    } catch (error) {
      res.status(500).json({ error: "Failed to fetch brand kit" });
    }
  });

  // Create/update brand kit
  app.post("/api/brand-kit", requireAuth, async (req: any, res) => {
    try {
      const userId = req.user.sub;

      // Get user's default project
      const projects = await storage.getProjects(userId);
      if (projects.length === 0) {
        return res.status(400).json({ error: "No project found. Please complete onboarding first." });
      }
      const defaultProject = projects[0];

      const brandKit = await storage.createOrUpdateBrandKit({
        ...req.body,
        projectId: defaultProject.id,
        userId,
      });
      res.json(brandKit);
    } catch (error) {
      res.status(500).json({ error: "Failed to save brand kit" });
    }
  });

  // Get all clips
  app.get("/api/clips", requireAuth, async (req: any, res) => {
    try {
      const userId = req.user.sub;
      const clips = await storage.getClips(userId);
      res.json(clips);
    } catch (error) {
      res.status(500).json({ error: "Failed to fetch clips" });
    }
  });

  // Create clip
  app.post("/api/clips", requireAuth, async (req: any, res) => {
    try {
      const userId = req.user.sub;

      // Validate required fields
      const validation = insertClipSchema.safeParse({
        ...req.body,
        userId,
      });

      if (!validation.success) {
        return res.status(400).json({ 
          error: "Invalid clip data", 
          details: validation.error.format() 
        });
      }

      const clip = await storage.createClip(validation.data);
      res.json(clip);
    } catch (error: any) {
      console.error("Error saving clip:", error);
      res.status(500).json({ 
        error: "Failed to save clip",
        message: error.message 
      });
    }
  });

  // Delete clip
  app.delete("/api/clips/:id", requireAuth, async (req: any, res) => {
    try {
      const userId = req.user.sub;
      await storage.deleteClip(req.params.id, userId);
      res.json({ success: true });
    } catch (error: any) {
      console.error("Delete clip error:", error);
      if (error.message.includes("not found") || error.message.includes("Unauthorized")) {
        res.status(404).json({ error: error.message });
      } else {
        res.status(500).json({ error: "Failed to delete clip" });
      }
    }
  });

  // Get all videos
  app.get("/api/videos", requireAuth, async (req: any, res) => {
    try {
      const userId = req.user.sub;
      const videos = await storage.getVideos(userId);
      res.json(videos);
    } catch (error) {
      res.status(500).json({ error: "Failed to fetch videos" });
    }
  });

  // Export video with real FFmpeg processing
  app.post("/api/videos/export", requireAuth, uploadLimiter, asyncHandler(async (req: any, res) => {
    const userId = req.user.sub;
    const { postId, hasCaption, musicStyle } = req.body;

    // Get post for title
    const post = await storage.getPost(postId, userId);
    if (!post) {
      throw createError("Post not found", 404, "POST_NOT_FOUND");
    }

    // Get clips for this post
    const clips = await storage.getClipsByPost(postId);
    if (clips.length === 0) {
      throw createError("No clips found for this post", 400, "NO_CLIPS_FOUND");
    }

    const totalDuration = clips.reduce((sum, clip) => sum + clip.duration, 0);

    console.log(`Starting video processing for post ${postId} with ${clips.length} clips`);

    // Process video with FFmpeg
    const videoId = await videoProcessor.processVideo({
      clips,
      post,
      hasCaption,
      musicStyle,
    });

    console.log(`Video processed successfully: ${videoId}`);

    // Create video record with the actual video file ID
    const video = await storage.createVideo({
      postId,
      userId,
      title: post.title,
      videoData: videoId, // Store the filename instead of base64
      thumbnail: "",
      duration: totalDuration,
      aspectRatio: "9:16",
      hasCaption,
      musicStyle,
    });

    // Update post status
    await storage.updatePostStatus(postId, userId, "completed");

    res.json(video);
  }));

  // Download video file
  app.get("/api/videos/:id/download", requireAuth, async (req: any, res) => {
    try {
      const userId = req.user.sub;
      const video = await storage.getVideo(req.params.id, userId);
      if (!video) {
        return res.status(404).json({ error: "Video not found" });
      }

      const videoPath = await videoProcessor.getVideoPath(video.videoData);
      const exists = await videoProcessor.videoExists(video.videoData);

      if (!exists) {
        return res.status(404).json({ error: "Video file not found" });
      }

      res.download(videoPath, `${video.title}.mp4`);
    } catch (error) {
      console.error("Download error:", error);
      res.status(500).json({ error: "Failed to download video" });
    }
  });

  // Delete video
  app.delete("/api/videos/:id", requireAuth, async (req: any, res) => {
    try {
      const userId = req.user.sub;
      await storage.deleteVideo(req.params.id, userId);
      res.json({ success: true });
    } catch (error: any) {
      console.error("Delete video error:", error);
      if (error.message.includes("not found") || error.message.includes("Unauthorized")) {
        res.status(404).json({ error: error.message });
      } else {
        res.status(500).json({ error: "Failed to delete video" });
      }
    }
  });

  // Transcription API Routes

  // POST /api/videos/:videoId/transcribe - Run transcription pipeline on a video
  app.post("/api/videos/:videoId/transcribe", requireAuth as any, aiLimiter, asyncHandler(async (req: any, res) => {
    const userId = req.user.sub;
    const { videoId } = req.params;

    // Check if video exists and belongs to user
    const video = await storage.getVideo(videoId, userId);
    if (!video) {
      throw createError("Video not found", 404, "VIDEO_NOT_FOUND");
    }

    // Check if transcription already exists
    const existingTranscription = await storage.getTranscription(videoId, userId);
    if (existingTranscription) {
      return res.json(existingTranscription);
    }

    // Get video file path
    const videoPath = await videoProcessor.getVideoPath(video.videoData);
    const exists = await videoProcessor.videoExists(video.videoData);
    if (!exists) {
      throw createError("Video file not found", 404, "VIDEO_FILE_NOT_FOUND");
    }

    // Import transcription service
    const { transcribeVideo } = await import("./lib/transcriptionService.js");

    try {
      // Run transcription pipeline
      const result = await transcribeVideo(videoPath);

      // Save to database
      const transcription = await storage.createTranscription({
        videoId,
        userId,
        language: result.language,
        duration: result.duration,
        captions: result.captions,
      });

      res.json(transcription);
    } catch (error: any) {
      // Handle specific transcription errors
      if (error.message.includes("OPENAI_API_KEY")) {
        throw createError("OpenAI API key not configured", 503, "SERVICE_UNAVAILABLE", true);
      }
      throw createError(`Transcription failed: ${error.message}`, 500, "TRANSCRIPTION_FAILED", true);
    }
  }));

  // GET /api/videos/:videoId/captions - Get existing captions for a video
  app.get("/api/videos/:videoId/captions", requireAuth as any, asyncHandler(async (req: any, res) => {
    const userId = req.user.sub;
    const { videoId } = req.params;

    // Get transcription
    const transcription = await storage.getTranscription(videoId, userId);

    if (!transcription) {
      throw createError("No transcription found for this video", 404, "TRANSCRIPTION_NOT_FOUND");
    }

    res.json(transcription);
  }));

  // Get trending music tracks
  app.get("/api/trending-music", async (req, res) => {
    try {
      const tracks = await trendingMusicService.getTrendingTracks();
      res.json(tracks);
    } catch (error) {
      console.error("Failed to fetch trending music:", error);
      res.status(500).json({ error: "Failed to fetch trending music" });
    }
  });

  // Get trending music info for a specific vibe
  app.get("/api/trending-music/:vibe", async (req, res) => {
    try {
      const vibe = decodeURIComponent(req.params.vibe);
      const info = await trendingMusicService.getTrendingMusicInfo(vibe);
      res.json(info);
    } catch (error) {
      console.error("Failed to fetch trending music info:", error);
      res.status(500).json({ error: "Failed to fetch trending music info" });
    }
  });

  const httpServer = createServer(app);
  return httpServer;
}

