import Constants from 'expo-constants';
import { supabase } from './supabase';

const API_URL = Constants.expoConfig?.extra?.apiUrl || process.env.EXPO_PUBLIC_API_URL || '';

if (!API_URL) {
  console.warn('[API] API_URL is not configured. API calls will fail.');
}

async function getAuthHeader(): Promise<Record<string, string>> {
  const { data: { session } } = await supabase.auth.getSession();
  if (session?.access_token) {
    return { Authorization: `Bearer ${session.access_token}` };
  }
  return {};
}

async function request<T>(
  endpoint: string,
  options: RequestInit = {}
): Promise<T> {
  const authHeader = await getAuthHeader();

  const response = await fetch(`${API_URL}${endpoint}`, {
    ...options,
    headers: {
      'Content-Type': 'application/json',
      ...authHeader,
      ...options.headers,
    },
  });

  if (!response.ok) {
    const error = await response.json().catch(() => ({ message: 'Request failed' }));
    throw new Error(error.message || `HTTP ${response.status}`);
  }

  return response.json();
}

export const api = {
  get: <T>(endpoint: string) => request<T>(endpoint, { method: 'GET' }),

  post: <T>(endpoint: string, data?: unknown) => 
    request<T>(endpoint, {
      method: 'POST',
      body: data ? JSON.stringify(data) : undefined,
    }),

  put: <T>(endpoint: string, data?: unknown) =>
    request<T>(endpoint, {
      method: 'PUT',
      body: data ? JSON.stringify(data) : undefined,
    }),

  delete: <T>(endpoint: string) => request<T>(endpoint, { method: 'DELETE' }),

  // User & Auth
  getCurrentUser: () => api.get('/api/auth/user'),

  // Projects
  getProjects: () => api.get('/api/projects'),
  getProject: (id: string) => api.get(`/api/projects/${id}`),

  // Posts (content calendar)
  getPosts: () => api.get('/api/posts'),
  getPost: (id: string) => api.get(`/api/posts/${id}`),

  // Onboarding
  submitOnboarding: (data: unknown) => api.post('/api/onboarding', data),

  // Clips
  getClips: () => api.get('/api/clips'),
  uploadClip: async (formData: FormData) => {
    const authHeader = await getAuthHeader();
    const response = await fetch(`${API_URL}/api/clips/upload`, {
      method: 'POST',
      headers: authHeader,
      body: formData,
    });
    if (!response.ok) {
      const error = await response.json().catch(() => ({ message: 'Upload failed' }));
      throw new Error(error.message);
    }
    return response.json();
  },

  // Videos
  getVideos: () => api.get('/api/videos'),
  getVideo: (id: string) => api.get(`/api/videos/${id}`),
  exportVideo: (id: string) => api.post(`/api/videos/${id}/export`),

  // Transcription
  getTranscription: (videoId: string) => api.get(`/api/videos/${videoId}/captions`),

  // Account
  deleteAccount: () => api.delete('/api/auth/account'),
};

