import { useEffect, useRef } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { TIMING, EASE, STAGGER, DELAY } from "@/lib/animation";

gsap.registerPlugin(ScrollTrigger);

const aiFeatures = [
  { text: "AI Script", position: "left" },
  { text: "AI Cuts", position: "right" },
  { text: "AI B-roll", position: "top" },
  { text: "AI Captions", position: "bottom" },
];

export default function AIPowerSection() {
  const containerRef = useRef<HTMLDivElement>(null);
  const titleRef = useRef<HTMLHeadingElement>(null);
  const featuresRef = useRef<(HTMLDivElement | null)[]>([]);
  const gridRef = useRef<HTMLDivElement>(null);
  const glowRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!containerRef.current) return;

    const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    if (prefersReducedMotion) {
      gsap.set(titleRef.current, { opacity: 1 });
      gsap.set(featuresRef.current, { opacity: 1, x: 0, y: 0 });
      return;
    }

    const ctx = gsap.context(() => {
      gsap.set(titleRef.current, { opacity: 0, scale: 0.9 });
      gsap.set(glowRef.current, { opacity: 0, scale: 0.5 });

      featuresRef.current.forEach((feature, i) => {
        const pos = aiFeatures[i].position;
        const x = pos === "left" ? -200 : pos === "right" ? 200 : 0;
        const y = pos === "top" ? -150 : pos === "bottom" ? 150 : 0;
        gsap.set(feature, { opacity: 0, x, y, scale: 0.8 });
      });

      const tl = gsap.timeline({
        scrollTrigger: {
          trigger: containerRef.current,
          start: "top 70%",
          end: "bottom 30%",
          scrub: 1,
        },
      });

      tl.to(glowRef.current, {
        opacity: 0.6,
        scale: 1,
        duration: TIMING.SLOW,
        ease: EASE,
      }, 0);

      tl.to(titleRef.current, {
        opacity: 1,
        scale: 1,
        duration: TIMING.MEDIUM,
        ease: EASE,
      }, TIMING.SLOW);

      featuresRef.current.forEach((feature, i) => {
        tl.to(feature, {
          opacity: 1,
          x: 0,
          y: 0,
          scale: 1,
          duration: TIMING.MEDIUM,
          ease: EASE,
        }, TIMING.SLOW + TIMING.MEDIUM + DELAY.SHORT + i * STAGGER.LOOSE);
      });

    }, containerRef);

    return () => ctx.revert();
  }, []);

  const setFeatureRef = (i: number) => (el: HTMLDivElement | null) => {
    featuresRef.current[i] = el;
  };

  return (
    <div ref={containerRef} className="min-h-screen flex items-center justify-center py-40 px-8 md:px-16 relative overflow-hidden atmosphere-indigo">

      <div className="max-w-4xl mx-auto text-center relative z-10">
        <p className="emotional-phrase mb-4">Intelligence that feels invisible</p>
        <h2 
          ref={titleRef}
          className="text-4xl md:text-6xl font-bold mb-16"
        >
          Powered by <span className="text-[#4338CA]">AI</span>
        </h2>

        <div 
          ref={gridRef}
          className="grid grid-cols-2 gap-6 max-w-xl mx-auto"
        >
          {aiFeatures.map((feature, i) => (
            <div
              key={feature.text}
              ref={setFeatureRef(i)}
              className="group p-6 rounded-xl border border-white/10 bg-black/30 backdrop-blur-sm hover:border-[#4338CA]/50 transition-all duration-300 hover:scale-105 ai-pulse cursor-glow"
            >
              <div className="text-xl font-semibold mb-2 text-[#F5F1EC]">{feature.text}</div>
              <div className="w-full h-1 bg-white/10 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-[#4338CA] rounded-full transition-all duration-500 group-hover:w-full"
                  style={{ width: "60%" }}
                />
              </div>
            </div>
          ))}
        </div>

        <p className="mt-12 text-[#F5F1EC]/50 max-w-lg mx-auto">
          Every feature is designed to save you time and make you look professional.
        </p>
      </div>
    </div>
  );
}

