import { useState, useRef, useEffect } from 'react';
import { View, Text, StyleSheet, Pressable, Alert, ActivityIndicator } from 'react-native';
import { CameraView, CameraType, useCameraPermissions, useMicrophonePermissions } from 'expo-camera';
import { SafeAreaView } from 'react-native-safe-area-context';
import { Ionicons } from '@expo/vector-icons';
import { useRouter } from 'expo-router';
import { colors } from '@/lib/colors';
import { api } from '@/lib/api';

export default function RecordScreen() {
  const router = useRouter();
  const cameraRef = useRef<CameraView>(null);
  const [facing, setFacing] = useState<CameraType>('front');
  const [isRecording, setIsRecording] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [recordingTime, setRecordingTime] = useState(0);
  const [cameraPermission, requestCameraPermission] = useCameraPermissions();
  const [micPermission, requestMicPermission] = useMicrophonePermissions();
  const timerRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    return () => {
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    };
  }, []);

  const requestPermissions = async () => {
    const camera = await requestCameraPermission();
    const mic = await requestMicPermission();
    return camera.granted && mic.granted;
  };

  if (!cameraPermission || !micPermission) {
    return (
      <View style={styles.container}>
        <Text style={styles.permissionText}>Loading...</Text>
      </View>
    );
  }

  if (!cameraPermission.granted || !micPermission.granted) {
    return (
      <SafeAreaView style={styles.container}>
        <View style={styles.permissionContainer}>
          <Ionicons name="videocam-off-outline" size={64} color={colors.text.muted} />
          <Text style={styles.permissionTitle}>Camera Access Required</Text>
          <Text style={styles.permissionText}>
            Navinta AI needs camera and microphone access to record your videos
          </Text>
          <Pressable style={styles.permissionButton} onPress={requestPermissions}>
            <Text style={styles.permissionButtonText}>Grant Access</Text>
          </Pressable>
        </View>
      </SafeAreaView>
    );
  }

  const toggleCameraFacing = () => {
    setFacing(current => (current === 'back' ? 'front' : 'back'));
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const startRecording = async () => {
    if (!cameraRef.current) return;

    setIsRecording(true);
    setRecordingTime(0);

    timerRef.current = setInterval(() => {
      setRecordingTime(prev => prev + 1);
    }, 1000);

    try {
      const video = await cameraRef.current.recordAsync({
        maxDuration: 180,
      });

      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
      setIsRecording(false);

      if (video) {
        setIsUploading(true);
        try {
          const formData = new FormData();
          formData.append('video', {
            uri: video.uri,
            type: 'video/mp4',
            name: `clip_${Date.now()}.mp4`,
          } as any);
          formData.append('duration', String(recordingTime));

          await api.uploadClip(formData);

          Alert.alert(
            'Clip Saved',
            'Your clip has been uploaded to your library.',
            [
              { text: 'View Library', onPress: () => router.push('/(tabs)/library') },
              { text: 'Record Another', style: 'cancel' },
            ]
          );
        } catch (uploadErr) {
          console.error('Upload error:', uploadErr);
          Alert.alert('Upload Failed', 'Failed to save clip. Please try again.');
        } finally {
          setIsUploading(false);
        }
      }
    } catch (err) {
      console.error('Recording error:', err);
      setIsRecording(false);
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    }
  };

  const stopRecording = () => {
    if (cameraRef.current) {
      cameraRef.current.stopRecording();
    }
    if (timerRef.current) {
      clearInterval(timerRef.current);
    }
    setIsRecording(false);
  };

  return (
    <View style={styles.container}>
      <CameraView
        ref={cameraRef}
        style={styles.camera}
        facing={facing}
        mode="video"
      >
        <SafeAreaView style={styles.overlay}>
          {/* Top Controls */}
          <View style={styles.topControls}>
            <Pressable style={styles.iconButton} onPress={() => router.back()}>
              <Ionicons name="close" size={28} color={colors.white} />
            </Pressable>

            {isRecording && (
              <View style={styles.recordingIndicator}>
                <View style={styles.recordingDot} />
                <Text style={styles.recordingTime}>{formatTime(recordingTime)}</Text>
              </View>
            )}

            <Pressable style={styles.iconButton} onPress={toggleCameraFacing}>
              <Ionicons name="camera-reverse-outline" size={28} color={colors.white} />
            </Pressable>
          </View>

          {/* Bottom Controls */}
          <View style={styles.bottomControls}>
            {isUploading ? (
              <View style={styles.uploadingContainer}>
                <ActivityIndicator size="large" color={colors.white} />
                <Text style={styles.uploadingText}>Saving clip...</Text>
              </View>
            ) : (
              <Pressable
                style={[styles.recordButton, isRecording && styles.recordButtonActive]}
                onPress={isRecording ? stopRecording : startRecording}
              >
                {isRecording ? (
                  <View style={styles.stopIcon} />
                ) : (
                  <View style={styles.recordDot} />
                )}
              </Pressable>
            )}
          </View>
        </SafeAreaView>
      </CameraView>
    </View>
  );
}

const styles = StyleSheet.create({
