import { auth } from "@/auth";
import { redirect } from "next/navigation";
import { db } from "@/db";
import { posts, transcriptions } from "@/db/schema";
import { eq, and } from "drizzle-orm";
import { EditorClient } from "./client";

export default async function EditorPage({ params }: { params: { id: string } }) {
    const session = await auth();

    if (!session?.user?.id) {
        redirect("/login");
    }

    const userPost = await db.query.posts.findFirst({
        where: and(eq(posts.id, params.id), eq(posts.userId, session.user.id)),
        with: {
            clips: true,
        },
    });

    if (!userPost) {
        redirect("/dashboard");
    }

    const transcriptionsData = await db.query.transcriptions.findFirst({
        where: and(eq(transcriptions.resourceId, params.id), eq(transcriptions.resourceType, "post")),
    });

    return (
        <EditorClient post={userPost} transcription={transcriptionsData} />
    );
}

