legacy/client/src/pages/director-mode.ts.content:
import { useState, useRef, useEffect } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useRoute, useLocation } from "wouter";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { Skeleton } from "@/components/ui/skeleton";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { 
  ArrowLeft, 
  Video, 
  Circle, 
  Square, 
  CheckCircle2, 
  Camera,
  RotateCcw,
  Play,
  X,
  Sparkles,
  Instagram,
  Download
} from "lucide-react";
import { SiInstagram } from "react-icons/si";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import type { Post } from "@shared/schema";

export default function DirectorMode() {
  const [, params] = useRoute("/director/:id");
  const [, setLocation] = useLocation();
  const postId = params?.id;
  const { toast } = useToast();

  const [isRecording, setIsRecording] = useState(false);
  const [recordedBlob, setRecordedBlob] = useState<Blob | null>(null);
  const [currentShotIndex, setCurrentShotIndex] = useState(0);
  const [recordingTime, setRecordingTime] = useState(0);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [showSuccessDialog, setShowSuccessDialog] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<number | null>(null);

  const { data: post, isLoading } = useQuery<Post>({
    queryKey: ["/api/posts", postId],
    enabled: !!postId,
  });

  const updateShotMutation = useMutation({
    mutationFn: ({ shotId, completed }: { shotId: string; completed: boolean }) =>
      apiRequest("PATCH", `/api/posts/${postId}/shots/${shotId}`, { completed }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/posts", postId] });
    },
  });

  const saveClipMutation = useMutation({
    mutationFn: async (data: { shotId: string; blob: Blob; duration: number }) => {
      const base64 = await new Promise<string>((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(data.blob);
      });

      return apiRequest("POST", "/api/clips", {
        postId,
        shotId: data.shotId,
        duration: data.duration,
        videoData: base64,
      });
    },
    onSuccess: () => {
      toast({
        title: "Shot saved!",
        description: "Your clip has been recorded successfully.",
      });
      queryClient.invalidateQueries({ queryKey: ["/api/clips"] });
    },
  });

  const finishVideoMutation = useMutation({
    mutationFn: async () => {
      const musicStyle = post?.musicVibe || "Upbeat & Energetic";
      const response = await apiRequest("POST", "/api/videos/export", {
        postId,
        hasCaption: true,
        musicStyle,
      });
      return response;
    },
    onSuccess: () => {
      setShowSuccessDialog(true);
      queryClient.invalidateQueries({ queryKey: ["/api/videos"] });
    },
    onError: () => {
      toast({
        title: "Export failed",
        description: "Unable to create your video. Please try again.",
        variant: "destructive",
      });
    },
  });

  useEffect(() => {
    startCamera();
    return () => {
      stopCamera();
    };
  }, []);

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: "user", width: 1080, height: 1920 },
        audio: true,
      });
      setStream(mediaStream);
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
      }
    } catch (err) {
      toast({
        title: "Camera Error",
        description: "Unable to access camera. Please check permissions.",
        variant: "destructive",
      });
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach((track) => track.stop());
    }
  };

  const startRecording = () => {
    if (!stream) return;

    chunksRef.current = [];
    const mediaRecorder = new MediaRecorder(stream, {
      mimeType: "video/webm;codecs=vp8,opus",
    });

    mediaRecorder.ondataavailable = (e) => {
      if (e.data.size > 0) {
        chunksRef.current.push(e.data);
      }
    };

    mediaRecorder.onstop = () => {
      const blob = new Blob(chunksRef.current, { type: "video/webm" });
      setRecordedBlob(blob);
    };

    mediaRecorder.start();
    mediaRecorderRef.current = mediaRecorder;
    setIsRecording(true);
    setRecordingTime(0);

    timerRef.current = window.setInterval(() => {
      setRecordingTime((prev) => prev + 1);
    }, 1000);
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    }
  };

  const saveShot = () => {
    if (!recordedBlob || !post) return;

    const currentShot = post.shotList[currentShotIndex];
    saveClipMutation.mutate({
      shotId: currentShot.id,
      blob: recordedBlob,
      duration: recordingTime,
    });

    updateShotMutation.mutate({
      shotId: currentShot.id,
      completed: true,
    });

    setRecordedBlob(null);
    setRecordingTime(0);

    if (currentShotIndex < post.shotList.length - 1) {
      setCurrentShotIndex(currentShotIndex + 1);
    }
  };

  const retakeShot = () => {
    setRecordedBlob(null);
    setRecordingTime(0);
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <Skeleton className="w-full max-w-md aspect-[9/16]" />
      </div>
    );
  }

  if (!post) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <div className="text-center">
          <h2 className="text-2xl font-semibold mb-2">Post not found</h2>
          <Button onClick={() => setLocation("/dashboard")}>Back to Dashboard</Button>
        </div>
      </div>
    );
  }

  const currentShot = post.shotList[currentShotIndex];
  const completedShots = post.shotList.filter((s) => s.completed).length;
  const progress = (completedShots / post.shotList.length) * 100;

  return (
    <div className="min-h-screen bg-background">
      <div className="sticky top-0 z-50 bg-background/95 backdrop-blur-xl border-b">
        <div className="max-w-7xl mx-auto p-4 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <Button
              variant="ghost"
              size="icon"
              onClick={() => setLocation(`/post/${postId}`)}
              data-testid="button-exit"
            >
              <X className="h-5 w-5" />
            </Button>
            <div>
              <h2 className="font-semibold">{post.title}</h2>
              <p className="text-sm text-muted-foreground">
                Shot {currentShotIndex + 1} of {post.shotList.length}
              </p>
            </div>
          </div>
          <div className="flex items-center gap-3">
            {completedShots === post.shotList.length ? (
              <Button
                size="lg"
                onClick={() => finishVideoMutation.mutate()}
                disabled={finishVideoMutation.isPending}
                data-testid="button-finish-video"
              >
                <Sparkles className="h-5 w-5 mr-2" />
                {finishVideoMutation.isPending ? "Creating Video..." : "Finish Video"}
              </Button>
            ) : (
              <>
                <span className="text-sm text-muted-foreground">
                  {completedShots}/{post.shotList.length} completed
                </span>
                <div className="w-32">
                  <Progress value={progress} className="h-2" />
                </div>
              </>
            )}
          </div>
        </div>
      </div>

      <div className="flex flex-col lg:flex-row min-h-[calc(100vh-73px)]">
        <div className="flex-1 flex items-center justify-center p-6 bg-muted/30">
          <div className="w-full max-w-md">
            <div className="relative aspect-[9/16] bg-black rounded-xl overflow-hidden">
              {recordedBlob ? (
                <video
                  src={URL.createObjectURL(recordedBlob)}
                  className="w-full h-full object-cover"
                  controls
                  autoPlay
                  loop
                />
              ) : (
                <video
                  ref={videoRef}
                  autoPlay
                  playsInline
                  muted
                  className="w-full h-full object-cover"
                />
              )}

              {isRecording && (
                <div className="absolute top-4 right-4 flex items-center gap-2 bg-red-500 text-white px-3 py-1.5 rounded-full font-mono text-sm">
                  <Circle className="h-3 w-3 fill-current animate-pulse" />
                  {formatTime(recordingTime)}
                </div>
              )}
            </div>

            <div className="mt-6 flex items-center justify-center gap-4">
              {!recordedBlob ? (
                <>
                  {!isRecording ? (
                    <Button
                      size="lg"
                      variant="default"
                      className="h-16 w-16 rounded-full p-0"
                      onClick={startRecording}
                      data-testid="button-record"
                    >
                      <Circle className="h-8 w-8 fill-current" />
                    </Button>
                  ) : (
                    <Button
                      size="lg"
                      variant="destructive"
                      className="h-16 w-16 rounded-full p-0"
                      onClick={stopRecording}
                      data-testid="button-stop"
                    >
                      <Square className="h-8 w-8" />
                    </Button>
                  )}
                </>
              ) : (
                <>
                  <Button
                    size="lg"
                    variant="outline"
                    onClick={retakeShot}
                    data-testid="button-retake"
                  >
                    <RotateCcw className="h-5 w-5 mr-2" />
                    Retake
                  </Button>
                  <Button
                    size="lg"
                    onClick={saveShot}
                    disabled={saveClipMutation.isPending}
                    data-testid="button-save-shot"
                  >
                    <CheckCircle2 className="h-5 w-5 mr-2" />
                    {saveClipMutation.isPending ? "Saving..." : "Save Shot"}
                  </Button>
                </>
              )}
            </div>
          </div>
        </div>

        <div className="w-full lg:w-96 p-6 space-y-6 bg-background border-l overflow-y-auto">
          <Card className="border-l-4 border-l-primary">
            <CardContent className="p-6 space-y-4">
              <div className="flex items-center gap-2">
                <Badge>Shot {currentShot.shotNumber}</Badge>
                <Badge variant="outline">{currentShot.duration}s</Badge>
              </div>

              <div>
                <h3 className="font-semibold text-lg mb-2">Instruction</h3>
                <p className="leading-relaxed">{currentShot.instruction}</p>
              </div>

              <div className="grid grid-cols-2 gap-4 pt-4 border-t">
                <div>
                  <p className="text-xs text-muted-foreground mb-1">Camera Angle</p>
                  <p className="font-medium text-sm">{currentShot.cameraAngle}</p>
                </div>
                <div>
                  <p className="text-xs text-muted-foreground mb-1">Framing</p>
                  <p className="font-medium text-sm">{currentShot.framing}</p>
                </div>
              </div>

              {currentShot.dialogue && (
                <div className="pt-4 border-t">
                  <p className="text-xs text-muted-foreground mb-2">Say</p>
                  <div className="p-3 rounded-md bg-primary/10">
                    <p className="italic">"{currentShot.dialogue}"</p>
                  </div>
                </div>
              )}
            </CardContent>
          </Card>

          <div className="space-y-2">
            <h4 className="text-sm font-medium text-muted-foreground">All Shots</h4>
            {post.shotList.map((shot, index) => (
              <button
                key={shot.id}
                onClick={() => setCurrentShotIndex(index)}
                className={`w-full p-3 rounded-lg border text-left transition-all hover-elevate ${
                  index === currentShotIndex
                    ? "border-primary bg-primary/5"
                    : shot.completed
                    ? "border-green-500/50 bg-green-500/5"
                    : ""
                }`}
                data-testid={`shot-selector-${index}`}
              >
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <span className="text-sm font-medium">Shot {shot.shotNumber}</span>
                    {shot.completed && (
                      <CheckCircle2 className="h-4 w-4 text-green-500" />
                    )}
                  </div>
                  <span className="text-xs text-muted-foreground">{shot.duration}s</span>
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>

      <Dialog open={showSuccessDialog} onOpenChange={setShowSuccessDialog}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <div className="mx-auto mb-4 flex h-16 w-16 items-center justify-center rounded-full bg-green-500/10">
              <CheckCircle2 className="h-8 w-8 text-green-500" />
            </div>
            <DialogTitle className="text-center text-2xl">Video Ready!</DialogTitle>
            <DialogDescription className="text-center">
              Your video has been automatically edited with captions and music. Ready to share with the world!
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-3 mt-4">
            <Button
              size="lg"
              className="w-full"
              onClick={() => {
                setShowSuccessDialog(false);
                setLocation("/library");
              }}
              data-testid="button-view-library"
            >
              <Download className="h-5 w-5 mr-2" />
              Download & View in Library
            </Button>
            <Button
              size="lg"
              variant="outline"
              className="w-full"
              onClick={() => {
                window.open("https://www.instagram.com/", "_blank");
              }}
              data-testid="button-upload-instagram"
            >
              <SiInstagram className="h-5 w-5 mr-2" />
              Upload to Instagram
            </Button>
            <div className="pt-4 border-t">
              <p className="text-sm text-muted-foreground text-center mb-3">
                <strong>How to upload to Instagram:</strong>
              </p>
              <ol className="text-xs text-muted-foreground space-y-2 pl-4">
                <li>1. Download your video from the Library</li>
                <li>2. Open Instagram app on your phone</li>
                <li>3. Tap + and select Reel</li>
                <li>4. Upload your video and add the caption we created</li>
                <li>5. Use the hashtags from your content plan</li>
              </ol>
            </div>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

function formatTime(seconds: number): string {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, "0")}`;
}

