"use server"

import { auth } from "@/auth";
import { db } from "@/db";
import { projects, brandKits, contentPlans, posts } from "@/db/schema";
import { onboardingSchema, type OnboardingData } from "@/db/schema";
import { generateContentPlan, type GeneratedPost } from "@/lib/ai/generate";
import { redirect } from "next/navigation";
import { revalidatePath } from "next/cache";

export async function createContentPlan(data: OnboardingData) {
    const session = await auth();

    if (!session?.user?.id) {
        throw new Error("Unauthorized");
    }

    const userId = session.user.id;

    // Validate data
    const validated = onboardingSchema.parse(data);

    // 1. Create Project
    const [project] = await db.insert(projects).values({
        userId,
        name: validated.brandName,
        description: `${validated.businessType} - ${validated.targetAudience}`,
    }).returning();

    // 2. Create Brand Kit
    await db.insert(brandKits).values({
        projectId: project.id,
        userId,
        brandName: validated.brandName,
        primaryColor: validated.primaryColor,
        secondaryColor: validated.secondaryColor || null,
        accentColor: validated.accentColor || null,
        fonts: {},
    });

    // 3. Generate Content Plan (Mock AI)
    const aiPlan = await generateContentPlan(validated);

    // 4. Create Content Plan Record
    const [contentPlan] = await db.insert(contentPlans).values({
        projectId: project.id,
        userId,
        businessType: validated.businessType,
        targetAudience: validated.targetAudience,
        contentGoals: validated.contentGoals,
        platforms: validated.platforms,
        postFrequency: validated.postFrequency,
        tone: validated.tone,
    }).returning();

    // 5. Create Posts
    if (aiPlan.posts.length > 0) {
        await db.insert(posts).values(
            aiPlan.posts.map((post: GeneratedPost) => ({
                projectId: project.id,
                contentPlanId: contentPlan.id,
                userId,
                weekNumber: post.weekNumber,
                dayNumber: post.dayNumber,
                title: post.title,
                concept: post.concept,
                platform: post.platform,
                shotList: post.shotList,
                brollSuggestions: post.brollSuggestions,
                caption: post.caption,
                hashtags: post.hashtags,
                musicVibe: post.musicVibe,
                status: "planned" as const
            }))
        );
    }

    revalidatePath("/dashboard");
    redirect("/dashboard");
}

