import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { Plus, PlayCircle, Edit, Calendar as CalendarIcon, CheckCircle2 } from "lucide-react";
import { Link } from "wouter";
import { TrendingMusicBadge } from "@/components/trending-music-badge";
import type { Post, ContentPlan } from "@shared/schema";

export default function Dashboard() {
  const { data: contentPlan, isLoading: planLoading } = useQuery<ContentPlan>({
    queryKey: ["/api/content-plan"],
  });

  const { data: posts, isLoading: postsLoading } = useQuery<Post[]>({
    queryKey: ["/api/posts"],
  });

  if (!contentPlan && !planLoading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[80vh] p-4">
        <div className="text-center space-y-4 max-w-md">
          <div className="inline-flex items-center justify-center w-20 h-20 rounded-full bg-primary/10 mb-4">
            <CalendarIcon className="h-10 w-10 text-primary" />
          </div>
          <h2 className="text-3xl font-semibold">No Content Plan Yet</h2>
          <p className="text-muted-foreground leading-relaxed">
            Let's create your personalized content strategy to get started with professional video content.
          </p>
          <Link href="/onboarding">
            <Button size="lg" className="mt-6" data-testid="button-create-plan">
              <Plus className="h-5 w-5 mr-2" />
              Create Content Plan
            </Button>
          </Link>
        </div>
      </div>
    );
  }

  if (planLoading || postsLoading) {
    return (
      <div className="flex justify-center p-6">
        <div className="w-full max-w-7xl space-y-6">
          <Skeleton className="h-32 w-full" />
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            {[1, 2, 3, 4].map((i) => (
              <Skeleton key={i} className="h-64" />
            ))}
          </div>
        </div>
      </div>
    );
  }

  const groupedPosts = groupPostsByWeek(posts || []);

  return (
    <div className="flex justify-center p-6">
      <div className="w-full max-w-7xl space-y-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-semibold tracking-tight">Content Calendar</h1>
            <p className="text-muted-foreground mt-1">
              Your 4-week personalized video plan
            </p>
          </div>
          <Link href="/onboarding">
            <Button variant="outline" data-testid="button-new-plan">
              <Plus className="h-4 w-4 mr-2" />
              New Plan
            </Button>
          </Link>
        </div>

        {contentPlan && (
          <Card>
            <CardHeader>
              <CardTitle>Plan Overview</CardTitle>
              <CardDescription>
                {contentPlan.platforms.join(", ")} • {contentPlan.postFrequency}
              </CardDescription>
            </CardHeader>
            <CardContent>
              <div className="flex flex-wrap gap-2">
                {contentPlan.contentGoals.map((goal) => (
                  <Badge key={goal} variant="secondary">
                    {goal}
                  </Badge>
                ))}
              </div>
            </CardContent>
          </Card>
        )}

        <div className="space-y-8">
          {[1, 2, 3, 4].map((weekNum) => (
            <div key={weekNum} className="space-y-4">
              <h2 className="text-xl font-semibold">Week {weekNum}</h2>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                {groupedPosts[weekNum]?.map((post) => (
                  <PostCard key={post.id} post={post} />
                ))}
                {(!groupedPosts[weekNum] || groupedPosts[weekNum].length === 0) && (
                  <Card className="border-dashed">
                    <CardContent className="flex items-center justify-center h-64">
                      <p className="text-muted-foreground text-sm">No posts scheduled</p>
                    </CardContent>
                  </Card>
                )}
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

function PostCard({ post }: { post: Post }) {
  const statusConfig = {
    planned: { icon: CalendarIcon, color: "bg-blue-500/10 text-blue-500", label: "Planned" },
    recording: { icon: PlayCircle, color: "bg-orange-500/10 text-orange-500", label: "Recording" },
    editing: { icon: Edit, color: "bg-purple-500/10 text-purple-500", label: "Editing" },
    completed: { icon: CheckCircle2, color: "bg-green-500/10 text-green-500", label: "Completed" },
    scheduled: { icon: CalendarIcon, color: "bg-indigo-500/10 text-indigo-500", label: "Scheduled" },
  };

  const config = statusConfig[post.status as keyof typeof statusConfig] || statusConfig.planned;
  const StatusIcon = config.icon;

  return (
    <Link href={`/post/${post.id}`}>
      <Card className="hover-elevate active-elevate-2 cursor-pointer transition-all h-full" data-testid={`card-post-${post.id}`}>
        <CardHeader className="space-y-3">
          <div className="flex items-start justify-between gap-2">
            <Badge variant="outline" className="font-mono text-xs">
              Day {post.dayNumber}
            </Badge>
            <div className={`inline-flex items-center gap-1.5 px-2 py-1 rounded-md text-xs font-medium ${config.color}`}>
              <StatusIcon className="h-3 w-3" />
              {config.label}
            </div>
          </div>
          <CardTitle className="text-lg leading-tight line-clamp-2">
            {post.title}
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-3">
          <p className="text-sm text-muted-foreground line-clamp-3">
            {post.concept}
          </p>
          <div className="flex flex-wrap items-center gap-2 pt-2 border-t">
            <Badge variant="secondary" className="text-xs">
              {post.platform}
            </Badge>
            {post.musicVibe && <TrendingMusicBadge musicVibe={post.musicVibe} />}
          </div>
          <div className="flex items-center justify-between text-xs text-muted-foreground">
            <span>{post.shotList.length} shots</span>
          </div>
        </CardContent>
      </Card>
    </Link>
  );
}

function groupPostsByWeek(posts: Post[]): Record<number, Post[]> {
  return posts.reduce((acc, post) => {
    if (!acc[post.weekNumber]) {
      acc[post.weekNumber] = [];
    }
    acc[post.weekNumber].push(post);
    return acc;
  }, {} as Record<number, Post[]>);
}

