import "dotenv/config";
import express, { type Request, Response, NextFunction } from "express";
import cookieParser from "cookie-parser";
import { registerRoutes } from "./routes";
import { setupVite, serveStatic, log } from "./vite";
import { promises as fs } from "fs";
import path from "path";
// Validate environment variables on startup (fails fast if missing)
import "./config";
// Security middleware
import { setupSecurity } from "./middleware/security";
import { setupRateLimiting } from "./middleware/rateLimit";
import { requestIdMiddleware, errorHandler } from "./middleware/errorHandler";

const app = express();

declare module 'http' {
  interface IncomingMessage {
    rawBody: unknown
  }
}

// Request ID middleware (must be first)
app.use(requestIdMiddleware);

// Security middleware (CORS, Helmet)
app.set("trust proxy", 1);
setupSecurity(app);

// Cookie parser (required for JWT-from-cookie)
app.use(cookieParser());

// Public health check (no auth) – must come before any auth-protected routes
app.get("/api/health", (_req, res) => {
  console.log("Health check hit");
  res.status(200).json({ status: "ok" });
});

// Body parsing
app.use(express.json({
  limit: '100mb',
  verify: (req, _res, buf) => {
    req.rawBody = buf;
  }
}));
app.use(express.urlencoded({ extended: false, limit: '100mb' }));

// Rate limiting (applied to /api routes)
setupRateLimiting(app);

// Dev convenience: when running Vite separately, redirect "/" on the backend to the Vite dev server
if (process.env.NODE_ENV === "development" && process.env.SKIP_VITE_MIDDLEWARE) {
  const viteUrl = process.env.VITE_DEV_URL ?? "http://localhost:5173";
  app.get("/", (_req, res) => res.redirect(viteUrl));
}

app.use((req, res, next) => {
  const start = Date.now();
  const path = req.path;
  let capturedJsonResponse: Record<string, any> | undefined = undefined;

  const originalResJson = res.json;
  res.json = function (bodyJson, ...args) {
    capturedJsonResponse = bodyJson;
    return originalResJson.apply(res, [bodyJson, ...args]);
  };

  res.on("finish", () => {
    const duration = Date.now() - start;
    if (path.startsWith("/api")) {
      const requestId = (req as any).requestId || "unknown";
      let logLine = `[${requestId}] ${req.method} ${path} ${res.statusCode} in ${duration}ms`;
      if (capturedJsonResponse) {
        logLine += ` :: ${JSON.stringify(capturedJsonResponse)}`;
      }

      if (logLine.length > 120) {
        logLine = logLine.slice(0, 119) + "…";
      }

      log(logLine);
    }
  });

  next();
});

(async () => {
  // Ensure upload directories exist
  const uploadsDir = path.join(process.cwd(), "server/uploads");
  const clipsDir = path.join(uploadsDir, "clips");
  const videosDir = path.join(uploadsDir, "videos");
  const tempDir = path.join(uploadsDir, "temp");

  await fs.mkdir(uploadsDir, { recursive: true });
  await fs.mkdir(clipsDir, { recursive: true });
  await fs.mkdir(videosDir, { recursive: true });
  await fs.mkdir(tempDir, { recursive: true });
  log("Upload directories initialized");

  const server = await registerRoutes(app);

  // Error handler (must be last, after all routes)
  app.use(errorHandler);

  // Note: Music files should be manually added to server/assets/music/
  // See server/assets/music/README.md for instructions

  // importantly only setup vite in development and after
  // setting up all the other routes so the catch-all route
  // doesn't interfere with the other routes
  // Skip Vite middleware if SKIP_VITE_MIDDLEWARE is set (when running separate dev servers)
  if (app.get("env") === "development" && !process.env.SKIP_VITE_MIDDLEWARE) {
    await setupVite(app, server);
  } else if (app.get("env") !== "development") {
    serveStatic(app);
  }

  const port = Number(process.env.PORT);
  console.log("[boot] process.env.PORT =", process.env.PORT);
  if (!port) {
    throw new Error("PORT env var not set");
  }
  const host = "localhost";

  server.listen({ port, host }, () => {
    console.log("serving on port", port);
  });

  // Graceful shutdown handling
  const shutdown = (signal: string) => {
    log(`Received ${signal}, shutting down gracefully...`);
    server.close(() => {
      log("HTTP server closed");
      process.exit(0);
    });

    // Force shutdown after 10 seconds
    setTimeout(() => {
      log("Forcing shutdown after timeout");
      process.exit(1);
    }, 10000);
  };

  process.on("SIGTERM", () => shutdown("SIGTERM"));
  process.on("SIGINT", () => shutdown("SIGINT"));

  // Handle uncaught errors
  process.on("uncaughtException", (error) => {
    console.error("Uncaught Exception:", error);
    shutdown("uncaughtException");
  });

  process.on("unhandledRejection", (reason, promise) => {
    console.error("Unhandled Rejection at:", promise, "reason:", reason);
    // Don't shutdown on unhandled rejection, just log it
    // (some libraries may have unhandled rejections that don't crash the app)
  });
})();

