import OpenAI from "openai";
import type { OnboardingData } from "@shared/schema";

// This is using OpenAI API for AI-powered content generation
// Using gpt-4 for complex reasoning and content strategy tasks

function getOpenAIClient(): OpenAI {
  if (!process.env.OPENAI_API_KEY) {
    throw new Error("OPENAI_API_KEY environment variable is required. Please add your OpenAI API key to use AI-powered content generation.");
  }
  return new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
}

interface ContentPlanResult {
  posts: Array<{
    weekNumber: number;
    dayNumber: number;
    title: string;
    concept: string;
    platform: string;
    shotList: Array<{
      id: string;
      shotNumber: number;
      instruction: string;
      cameraAngle: string;
      framing: string;
      dialogue: string;
      duration: number;
      completed: boolean;
    }>;
    brollSuggestions: string[];
    caption: string;
    hashtags: string[];
    musicVibe: string;
  }>;
}

export async function generateContentPlan(data: OnboardingData): Promise<ContentPlanResult> {
  const postsPerWeek = data.postFrequency.includes("2-3") ? 2 : 
                       data.postFrequency.includes("4-5") ? 4 : 
                       data.postFrequency.includes("Daily") ? 7 : 3;

  const prompt = `You are a professional social media content strategist. Generate a 4-week content calendar for the following business:

Brand: ${data.brandName}
Business Type: ${data.businessType}
Target Audience: ${data.targetAudience}
Content Goals: ${data.contentGoals.join(", ")}
Platforms: ${data.platforms.join(", ")}
Posting Frequency: ${data.postFrequency}
Tone: ${data.tone}

Create ${postsPerWeek} posts per week (total 4 weeks). For each post, provide:
1. Title (catchy, engaging)
2. Concept (brief description of the video idea)
3. Platform (choose from the provided platforms)
4. Shot list with 3-5 shots, each including:
   - Shot number
   - Clear instruction for what to film
   - Camera angle (e.g., "eye level", "slightly above", "low angle")
   - Framing (e.g., "close-up", "medium shot", "wide shot")
   - Dialogue (what to say, if applicable)
   - Duration in seconds (5-15 seconds per shot)
5. B-roll suggestions (2-3 items)
6. Caption (engaging, 1-2 sentences)
7. Hashtags (5-8 relevant tags without the # symbol)
8. Music vibe (e.g., "upbeat", "calm", "inspiring")

Return ONLY valid JSON matching this exact structure:
{
  "posts": [
    {
      "weekNumber": 1,
      "dayNumber": 1,
      "title": "string",
      "concept": "string",
      "platform": "string",
      "shotList": [
        {
          "id": "shot-1-1",
          "shotNumber": 1,
          "instruction": "string",
          "cameraAngle": "string",
          "framing": "string",
          "dialogue": "string",
          "duration": 10,
          "completed": false
        }
      ],
      "brollSuggestions": ["string"],
      "caption": "string",
      "hashtags": ["string"],
      "musicVibe": "string"
    }
  ]
}`;

  try {
    const openai = getOpenAIClient();
    const completion = await openai.chat.completions.create({
      model: "gpt-4",
      messages: [
        {
          role: "system",
          content: "You are a professional social media content strategist. Always return valid JSON only, no markdown formatting.",
        },
        {
          role: "user",
          content: prompt,
        },
      ],
      response_format: { type: "json_object" },
      temperature: 0.7,
    });

    const text = completion.choices[0]?.message?.content;
    if (!text) {
      throw new Error("No response from OpenAI");
    }

    const parsed = JSON.parse(text);
    return parsed as ContentPlanResult;
  } catch (error: any) {
    console.error("OpenAI API error:", error.message);
    throw new Error("Failed to generate content plan. Please check your OpenAI API key and try again.");
  }
}

