import { useState, useEffect, useRef } from 'react';
import { View, Text, StyleSheet, Pressable, ScrollView, Dimensions, Alert, Animated } from 'react-native';
import { useLocalSearchParams, useRouter } from 'expo-router';
import { SafeAreaView } from 'react-native-safe-area-context';
import { CameraView, CameraType, useCameraPermissions, useMicrophonePermissions } from 'expo-camera';
import { Ionicons } from '@expo/vector-icons';
import { api } from '@/lib/api';
import { colors } from '@/lib/colors';

const { width, height } = Dimensions.get('window');

interface Shot {
  id: number;
  shotNumber: number;
  title: string;
  description: string;
  shotType: string;
  duration: number;
  notes: string;
}

interface Post {
  id: number;
  title: string;
  status: string;
  shots: Shot[];
}

export default function DirectorModeScreen() {
  const { postId } = useLocalSearchParams<{ postId: string }>();
  const router = useRouter();
  const cameraRef = useRef<CameraView>(null);

  const [post, setPost] = useState<Post | null>(null);
  const [currentShotIndex, setCurrentShotIndex] = useState(0);
  const [isRecording, setIsRecording] = useState(false);
  const [recordingTime, setRecordingTime] = useState(0);
  const [completedShots, setCompletedShots] = useState<Set<number>>(new Set());
  const [facing, setFacing] = useState<CameraType>('front');

  const [cameraPermission, requestCameraPermission] = useCameraPermissions();
  const [micPermission, requestMicPermission] = useMicrophonePermissions();

  const timerRef = useRef<NodeJS.Timeout | null>(null);
  const progressAnim = useRef(new Animated.Value(0)).current;
  const fadeAnim = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    fetchPost();
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [postId]);

  useEffect(() => {
    fadeAnim.setValue(0);
    Animated.timing(fadeAnim, {
      toValue: 1,
      duration: 300,
      useNativeDriver: true,
    }).start();
  }, [currentShotIndex]);

  const fetchPost = async () => {
    try {
      const data = await api.getPost(postId);
      setPost(data as Post);
    } catch (err) {
      console.error('Failed to fetch post:', err);
      Alert.alert('Error', 'Failed to load content');
    }
  };

  const currentShot = post?.shots?.[currentShotIndex];

  const startRecording = async () => {
    if (!cameraRef.current || !currentShot) return;

    setIsRecording(true);
    setRecordingTime(0);
    progressAnim.setValue(0);

    const duration = currentShot.duration || 10;

    timerRef.current = setInterval(() => {
      setRecordingTime(prev => {
        const newTime = prev + 1;
        Animated.timing(progressAnim, {
          toValue: (newTime / duration) * 100,
          duration: 1000,
          useNativeDriver: false,
        }).start();

        if (newTime >= duration) {
          stopRecording();
        }
        return newTime;
      });
    }, 1000);

    try {
      const video = await cameraRef.current.recordAsync({
        maxDuration: duration,
      });

      if (video) {
        setCompletedShots(prev => new Set([...prev, currentShot.id]));

        const formData = new FormData();
        formData.append('video', {
          uri: video.uri,
          type: 'video/mp4',
          name: 'clip.mp4',
        } as any);
        formData.append('postId', postId);
        formData.append('shotId', String(currentShot.id));
        formData.append('duration', String(recordingTime));

        try {
          await api.uploadClip(formData);
        } catch (err) {
          console.error('Upload error:', err);
        }
      }
    } catch (err) {
      console.error('Recording error:', err);
    }
  };

  const stopRecording = () => {
    if (cameraRef.current) {
      cameraRef.current.stopRecording();
    }
    if (timerRef.current) {
      clearInterval(timerRef.current);
    }
    setIsRecording(false);
    Animated.timing(progressAnim, {
      toValue: 100,
      duration: 200,
      useNativeDriver: false,
    }).start();
  };

  const nextShot = () => {
    if (post?.shots && currentShotIndex < post.shots.length - 1) {
      setCurrentShotIndex(i => i + 1);
      progressAnim.setValue(0);
    }
  };

  const prevShot = () => {
    if (currentShotIndex > 0) {
      setCurrentShotIndex(i => i - 1);
      progressAnim.setValue(0);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const requestPermissions = async () => {
    await requestCameraPermission();
    await requestMicPermission();
  };

  if (!cameraPermission?.granted || !micPermission?.granted) {
    return (
      <SafeAreaView style={styles.container}>
        <View style={styles.permissionContainer}>
          <Ionicons name="videocam-outline" size={64} color={colors.text.muted} />
          <Text style={styles.permissionTitle}>Camera Access Required</Text>
          <Text style={styles.permissionText}>
            Director Mode needs camera and microphone access to record your shots
          </Text>
          <Pressable style={styles.permissionButton} onPress={requestPermissions}>
            <Text style={styles.permissionButtonText}>Grant Access</Text>
          </Pressable>
          <Pressable style={styles.secondaryButton} onPress={() => router.back()}>
            <Text style={styles.secondaryButtonText}>Go Back</Text>
          </Pressable>
        </View>
      </SafeAreaView>
    );
  }

  const progressWidth = progressAnim.interpolate({
    inputRange: [0, 100],
    outputRange: ['0%', '100%'],
  });

  return (
    <View style={styles.container}>
      <CameraView
        ref={cameraRef}
        style={styles.camera}
        facing={facing}
        mode="video"
      >
        <SafeAreaView style={styles.overlay}>
          <View style={styles.header}>
            <Pressable style={styles.closeButton} onPress={() => router.back()}>
              <Ionicons name="close" size={28} color={colors.white} />
            </Pressable>
            <Text style={styles.headerTitle} numberOfLines={1}>
              {post?.title || 'Loading...'}
            </Text>
            <Pressable style={styles.flipButton} onPress={() => setFacing(f => f === 'front' ? 'back' : 'front')}>
              <Ionicons name="camera-reverse-outline" size={24} color={colors.white} />
            </Pressable>
          </View>

          {currentShot && (
            <Animated.View style={[styles.shotCard, { opacity: fadeAnim }]}>
              <View style={styles.shotHeader}>
                <Text style={styles.shotNumber}>Shot {currentShot.shotNumber}</Text>
                <Text style={styles.shotType}>{currentShot.shotType}</Text>
              </View>
              <Text style={styles.shotTitle}>{currentShot.title}</Text>
              <Text style={styles.shotDescription}>{currentShot.description}</Text>
              {currentShot.notes && (
                <Text style={styles.shotNotes}>{currentShot.notes}</Text>
              )}
            </Animated.View>
          )}

          {isRecording && (
            <View style={styles.progressContainer}>
              <Animated.View style={[styles.progressBar, { width: progressWidth }]} />
            </View>
          )}

          <View style={styles.bottomControls}>
            <View style={styles.shotNav}>
              <Pressable 
                style={[styles.navButton, currentShotIndex === 0 && styles.navButtonDisabled]} 
                onPress={prevShot}
                disabled={currentShotIndex === 0}
              >
                <Ionicons name="chevron-back" size={24} color={colors.white} />
              </Pressable>

              <Text style={styles.shotCounter}>
                {currentShotIndex + 1} / {post?.shots?.length || 0}
              </Text>

              <Pressable 
                style={[styles.navButton, currentShotIndex >= (post?.shots?.length || 0) - 1 && styles.navButtonDisabled]} 
                onPress={nextShot}
                disabled={currentShotIndex >= (post?.shots?.length || 0) - 1}
              >
                <Ionicons name="chevron-forward" size={24} color={colors.white} />
              </Pressable>
            </View>

            <Pressable
              style={[styles.recordButton, isRecording && styles.recordButtonActive]}
              onPress={isRecording ? stopRecording : startRecording}
            >
              {isRecording ? (
                <View style={styles.stopIcon} />
              ) : (
                <View style={styles.recordDot} />
              )}
            </Pressable>

            <View style={styles.timerContainer}>
              {isRecording ? (
                <Text style={styles.timerText}>{formatTime(recordingTime)}</Text>
              ) : (
                <Text style={styles.timerHint}>Tap to record</Text>
