import { gsap } from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import { 
  FilmIcon,
  ChatBubbleLeftRightIcon,
  ScissorsIcon,
  PhotoIcon,
  GlobeAltIcon
} from '@heroicons/react/24/outline';
import { TIMING, EASE, STAGGER } from '@/lib/animation';

gsap.registerPlugin(ScrollTrigger);

const PILLARS = [
  {
    icon: FilmIcon,
    title: 'Thinks in Shots',
    subtitle: 'Not prompts',
    description: 'Navinta AI plans your content as real shots and scenes, not abstract prompts. Every video has structure.',
  },
  {
    icon: ChatBubbleLeftRightIcon,
    title: 'Director Onboarding',
    subtitle: 'Not generic',
    description: 'Deep understanding of your audience, brand, and goals. Every plan is tailored to you.',
  },
  {
    icon: ScissorsIcon,
    title: 'Smart Editing',
    subtitle: 'No ugly cuts',
    description: 'AI removes pauses, stitches clips, and creates seamless transitions. No jump cuts.',
  },
  {
    icon: PhotoIcon,
    title: 'Intelligent B-Roll',
    subtitle: 'Context-aware',
    description: 'Automatic suggestions for b-roll that actually makes sense for your content.',
  },
  {
    icon: GlobeAltIcon,
    title: 'Export Everywhere',
    subtitle: 'Every platform',
    description: 'One recording, every format. TikTok, Reels, YouTube Shorts, LinkedIn, and more.',
  },
];

export default function Pillars() {
  const containerRef = useRef<HTMLDivElement>(null);
  const titleRef = useRef<HTMLDivElement>(null);
  const pillarRefs = useRef<(HTMLDivElement | null)[]>([]);

  useEffect(() => {
    const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    if (prefersReducedMotion) return;

    const ctx = gsap.context(() => {
      gsap.set(titleRef.current, { opacity: 0, y: 40 });
      pillarRefs.current.forEach(el => {
        gsap.set(el, { opacity: 0, y: 60, scale: 0.95 });
      });

      const tl = gsap.timeline({
        scrollTrigger: {
          trigger: containerRef.current,
          start: 'top 70%',
          end: 'center center',
          scrub: 1,
        },
      });

      tl.to(titleRef.current, {
        opacity: 1,
        y: 0,
        duration: TIMING.SLOW,
        ease: EASE,
      }, 0);

      pillarRefs.current.forEach((pillar, i) => {
        tl.to(pillar, {
          opacity: 1,
          y: 0,
          scale: 1,
          duration: TIMING.MEDIUM,
          ease: EASE,
        }, TIMING.MEDIUM + i * STAGGER.LOOSE);
      });

    }, containerRef);

    return () => ctx.revert();
  }, []);

  return (
    <section 
      ref={containerRef}
      className="relative min-h-screen py-32 px-8 bg-black overflow-hidden"
      aria-labelledby="pillars-title"
    >
      <div className="absolute inset-0 opacity-[0.02] pointer-events-none">
        <div 
          className="absolute inset-0"
          style={{
            background: 'radial-gradient(ellipse at 50% 0%, rgba(67, 56, 202, 0.2) 0%, transparent 60%)',
          }}
        />
      </div>

      <div className="max-w-6xl mx-auto relative z-10">
        <div ref={titleRef} className="text-center mb-20">
          <p className="text-[#4338CA] uppercase tracking-[0.2em] text-sm mb-4">Differentiation</p>
          <h2 id="pillars-title" className="font-display text-4xl md:text-5xl lg:text-6xl text-[#F5F1EC] mb-6">
            How Navinta AI <span className="italic text-[#B08A5A]">Thinks</span>
          </h2>
          <p className="text-[#F5F1EC]/50 max-w-2xl mx-auto text-lg">
            Not just another AI tool. A director that understands video production.
          </p>
        </div>

        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
          {PILLARS.map((pillar, i) => {
            const Icon = pillar.icon;
            return (
              <div
                key={pillar.title}
                ref={el => { pillarRefs.current[i] = el; }}
                className="group relative p-8 rounded-2xl border border-white/5 bg-gradient-to-b from-white/[0.02] to-transparent hover:border-[#B08A5A]/20 transition-colors duration-500"
              >
                <div className="absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity duration-500 rounded-2xl overflow-hidden">
                  <div 
                    className="absolute inset-0"
                    style={{
                      background: 'radial-gradient(ellipse at 50% 100%, rgba(176, 138, 90, 0.05) 0%, transparent 70%)',
                    }}
                  />
                </div>

                <div className="relative z-10">
                  <div className="w-12 h-12 rounded-xl border border-white/10 bg-white/[0.02] flex items-center justify-center mb-6 group-hover:border-[#B08A5A]/30 transition-colors duration-500">
                    <Icon className="w-6 h-6 text-[#F5F1EC]/60 group-hover:text-[#B08A5A] transition-colors duration-500" />
                  </div>

                  <h3 className="font-display text-xl text-[#F5F1EC] mb-1">{pillar.title}</h3>
                  <p className="text-[#B08A5A]/60 text-sm mb-4">{pillar.subtitle}</p>
                  <p className="text-[#F5F1EC]/40 text-sm leading-relaxed">{pillar.description}</p>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
}

