import { useRef, useEffect } from 'react';
import { gsap } from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import { TIMING, EASE } from '@/lib/animation';

gsap.registerPlugin(ScrollTrigger);

const STAGES = [
  {
    id: 'idea',
    title: 'Share Your Vision',
    subtitle: 'Quick questions, smart answers',
    description: 'Tell us what you want to create. Navinta AI asks the right questions to understand your content.',
  },
  {
    id: 'plan',
    title: 'AI Creates Your Plan',
    subtitle: 'Shot-by-shot guidance',
    description: 'Get a complete shooting script with exact shots, angles, and talking points.',
  },
  {
    id: 'record',
    title: 'Director Mode',
    subtitle: 'Your AI teleprompter',
    description: 'Follow on-screen prompts. Record each shot with confidence. No memorization needed.',
  },
  {
    id: 'edit',
    title: 'Invisible Editing',
    subtitle: 'Smart cuts, smooth flow',
    description: 'Pauses removed. Clips stitched. B-roll added. Captions synced. All automatic.',
  },
  {
    id: 'polish',
    title: 'Final Polish',
    subtitle: 'Professional finish',
    description: 'Color grading, motion smoothing, and music perfectly timed to your content.',
  },
  {
    id: 'publish',
    title: 'Export Everywhere',
    subtitle: 'Every platform, every format',
    description: 'One video becomes many. 9:16, 1:1, 16:9. Ready for TikTok, Reels, YouTube, LinkedIn.',
  },
];

export default function StoryRail() {
  const containerRef = useRef<HTMLDivElement>(null);
  const phoneRef = useRef<HTMLDivElement>(null);
  const stageRefs = useRef<(HTMLDivElement | null)[]>([]);
  const progressRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

    if (prefersReducedMotion) {
      stageRefs.current.forEach((stage) => {
        if (stage) {
          gsap.set(stage, { opacity: 1, y: 0, scale: 1 });
        }
      });
      if (progressRef.current) {
        gsap.set(progressRef.current, { scaleY: 1 });
      }
      if (phoneRef.current) {
        gsap.set(phoneRef.current, { rotateY: 0, rotateX: 0, scale: 1 });
      }
      return;
    }

    const ctx = gsap.context(() => {
      const totalStages = STAGES.length;

      const tl = gsap.timeline({
        scrollTrigger: {
          trigger: containerRef.current,
          start: 'top top',
          end: `+=${totalStages * 100}%`,
          scrub: 1,
          pin: true,
          anticipatePin: 1,
        },
      });

      stageRefs.current.forEach((stage, i) => {
        if (!stage) return;
        const progress = i / (totalStages - 1);

        tl.to(stage, {
          opacity: 1,
          y: 0,
          scale: 1,
          duration: TIMING.MEDIUM,
          ease: EASE,
        }, progress);

        if (i < totalStages - 1) {
          tl.to(stage, {
            opacity: 0,
            y: -30,
            scale: 0.95,
            duration: TIMING.FAST,
            ease: EASE,
          }, progress + 0.4);
        }
      });

      tl.to(progressRef.current, {
        scaleY: 1,
        duration: 1,
        ease: 'linear',
      }, 0);

      const phoneEl = phoneRef.current;
      if (phoneEl) {
        tl.to(phoneEl, {
          rotateY: 0,
          rotateX: 0,
          scale: 1,
          duration: TIMING.FAST,
          ease: EASE,
        }, 0.2);

        tl.to(phoneEl, {
          boxShadow: '0 0 60px rgba(176, 138, 90, 0.3)',
          duration: TIMING.FAST,
        }, 0.5);

        tl.to(phoneEl, {
          boxShadow: '0 0 80px rgba(67, 56, 202, 0.4)',
          duration: TIMING.FAST,
        }, 0.7);
      }

    }, containerRef);

    return () => ctx.revert();
  }, []);

  return (
    <section 
      ref={containerRef}
      className="relative min-h-screen bg-black overflow-hidden"
      aria-label="How Navinta AI Works"
    >
      <div className="absolute inset-0 opacity-[0.03] pointer-events-none">
        <div 
