/**
 * Security middleware: CORS, Helmet headers, and rate limiting
 */

import cors from "cors";
import helmet from "helmet";
import type { Express } from "express";

export function setupSecurity(app: Express) {
  // Security headers (Helmet)
  app.use(
    helmet({
      contentSecurityPolicy: {
        directives: {
          defaultSrc: ["'self'"],
          styleSrc: ["'self'", "'unsafe-inline'"], // Required for inline styles
          scriptSrc: ["'self'", "'unsafe-inline'", "'unsafe-eval'"], // Required for Vite in dev
          imgSrc: ["'self'", "data:", "https:"], // Allow images from any HTTPS source
          connectSrc: ["'self'", "https://api.openai.com", "https://generativelanguage.googleapis.com"],
        },
      },
      crossOriginEmbedderPolicy: false, // Disable for compatibility
    })
  );

  // CORS configuration
  // Important for local dev:
  // - Frontend runs on http://localhost:5173
  // - Backend runs on http://localhost:PORT
  // - Session auth requires credentials + an explicit origin (not "*")
  const devOrigin = "http://localhost:5173";
  const corsOptions = {
    origin: process.env.CORS_ORIGIN
      ? process.env.CORS_ORIGIN.split(",")
      : process.env.NODE_ENV === "production"
      ? false // No CORS in production by default (set CORS_ORIGIN explicitly)
      : devOrigin,
    credentials: true, // Required for session cookies
    methods: ["GET", "POST", "PATCH", "DELETE", "PUT", "OPTIONS"],
    allowedHeaders: ["Content-Type", "Authorization"],
  };

  app.use(cors(corsOptions));
}

