import { useRef, useEffect } from "react";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";

gsap.registerPlugin(ScrollTrigger);

export default function SolutionSection() {
  const sectionRef = useRef<HTMLElement>(null);
  const headingRef = useRef<HTMLDivElement>(null);
  const card1Ref = useRef<HTMLDivElement>(null);
  const card2Ref = useRef<HTMLDivElement>(null);
  const gradient1Ref = useRef<HTMLDivElement>(null);
  const gradient2Ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const ctx = gsap.context(() => {
      gsap.from(headingRef.current, {
        y: 50,
        opacity: 0,
        duration: 0.8,
        ease: "power3.out",
        scrollTrigger: { trigger: headingRef.current, start: "top 85%" },
      });

      gsap.from(card1Ref.current, {
        y: 80,
        opacity: 0,
        duration: 0.9,
        ease: "power3.out",
        scrollTrigger: { trigger: card1Ref.current, start: "top 85%" },
      });

      gsap.from(card2Ref.current, {
        y: 80,
        opacity: 0,
        duration: 0.9,
        delay: 0.15,
        ease: "power3.out",
        scrollTrigger: { trigger: card2Ref.current, start: "top 85%" },
      });

      gsap.to(gradient1Ref.current, {
        yPercent: -8,
        ease: "none",
        scrollTrigger: {
          trigger: card1Ref.current,
          start: "top bottom",
          end: "bottom top",
          scrub: true,
        },
      });

      gsap.to(gradient2Ref.current, {
        yPercent: -8,
        ease: "none",
        scrollTrigger: {
          trigger: card2Ref.current,
          start: "top bottom",
          end: "bottom top",
          scrub: true,
        },
      });
    }, sectionRef);

    return () => ctx.revert();
  }, []);

  return (
    <section ref={sectionRef} className="py-24 px-6 bg-white">
      <div className="max-w-6xl mx-auto">
        <div ref={headingRef} className="max-w-xl mb-14">
          <h2 className="text-4xl md:text-5xl font-medium tracking-tight text-[#111111] mb-4">
            Create videos you're proud to share.
          </h2>
          <p className="text-lg text-[#666666] leading-relaxed">
            Answer a few questions. Get a shot-by-shot plan. Record with
            guidance. Export a polished video — no editor, no stress.
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <div ref={card1Ref}>
            <div className="h-[500px] bg-[#f9f9f9] rounded-3xl p-8 flex flex-col relative overflow-hidden">
              <div ref={gradient1Ref} className="absolute inset-[-15%] bg-gradient-to-b from-[#ede9fe] to-[#c4b5fd] rounded-3xl z-0" />
              <div className="mt-auto relative z-10">
                <span className="bg-black/60 text-white backdrop-blur px-6 py-3 rounded-full text-sm inline-block mb-6">
                  a 30-second brand intro for Instagram ✦
                </span>
              </div>
            </div>
            <div className="mt-5 px-1">
              <h3 className="text-xl font-semibold text-[#111111] mb-1">
                AI-powered planning
              </h3>
              <p className="text-[#666666] text-sm leading-relaxed">
                Describe your goal and Navinta builds a shot-by-shot plan — hooks,
                transitions, and timing included.
              </p>
            </div>
          </div>

          <div ref={card2Ref}>
            <div className="h-[500px] bg-[#f9f9f9] rounded-3xl p-8 relative overflow-hidden">
              <div ref={gradient2Ref} className="absolute inset-[-15%] bg-gradient-to-b from-[#fce7f3] to-[#f9a8d4] rounded-3xl z-0" />
              <div className="absolute bottom-8 left-8 right-8 z-10 flex flex-col gap-3">
                <span className="bg-black/60 text-white backdrop-blur px-6 py-3 rounded-full text-sm inline-block">
                  Add b-roll and captions
                </span>
                <span className="bg-black/40 text-white/80 backdrop-blur px-6 py-3 rounded-full text-sm inline-block">
                  Applying edits...
                </span>
              </div>
            </div>
            <div className="mt-5 px-1">
              <h3 className="text-xl font-semibold text-[#111111] mb-1">
                Edit like a director
              </h3>
              <p className="text-[#666666] text-sm leading-relaxed">
                AI adds captions, inserts b-roll, and polishes your cuts — so
                the final video looks professionally edited.
              </p>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

