import React from "react";
import { useCurrentFrame, interpolate, spring, useVideoConfig } from "remotion";
import { captionStylePacks } from "../styles/presets";
import type { CaptionSegment } from "../../schemas/editDecision.schema";

interface CaptionTrackProps {
  captions: CaptionSegment[];
}

export const CaptionTrack: React.FC<CaptionTrackProps> = ({ captions }) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  return (
    <>
      {captions.map((caption) => {
        if (frame < caption.startFrame || frame >= caption.endFrame) return null;

        const stylePack = captionStylePacks[caption.stylePackId] || captionStylePacks.default;
        const localFrame = frame - caption.startFrame;
        const duration = caption.endFrame - caption.startFrame;

        let opacity = 1;
        let transform = "translateX(-50%)";

        if (caption.animationType === "pop-in") {
          const scale = spring({
            frame: localFrame,
            fps,
            config: { damping: 12, stiffness: 200, mass: 0.5 },
          });
          opacity = interpolate(localFrame, [0, 4], [0, 1], { extrapolateRight: "clamp" });
          transform = `translateX(-50%) scale(${scale})`;
        } else if (caption.animationType === "fade-in") {
          opacity = interpolate(localFrame, [0, 8], [0, 1], { extrapolateRight: "clamp" });
        } else if (caption.animationType === "karaoke") {
          opacity = 1;
        }

        const fadeOut = interpolate(localFrame, [duration - 5, duration], [1, 0], {
          extrapolateLeft: "clamp",
          extrapolateRight: "clamp",
        });
        opacity *= fadeOut;

        const karaokeProgress =
          caption.animationType === "karaoke"
            ? interpolate(localFrame, [0, duration], [0, 1], { extrapolateRight: "clamp" })
            : null;

        return (
          <div
            key={caption.id}
            style={{
              position: "absolute",
              bottom: "12%",
              left: "50%",
              transform,
              opacity,
              fontFamily: stylePack.fontFamily,
              fontSize: stylePack.fontSize,
              fontWeight: stylePack.fontWeight,
              color: stylePack.color,
              backgroundColor: stylePack.backgroundColor,
              padding: stylePack.padding,
              borderRadius: stylePack.borderRadius,
              textShadow: stylePack.textShadow,
              textTransform: stylePack.textTransform as React.CSSProperties["textTransform"],
              whiteSpace: "nowrap",
              zIndex: 100,
            }}
          >
            {karaokeProgress !== null ? (
              <span style={{ position: "relative", display: "inline-block" }}>
                <span style={{ color: "rgba(255,255,255,0.4)" }}>{caption.text}</span>
                <span
                  style={{
                    position: "absolute",
                    left: 0,
                    top: 0,
                    color: stylePack.color,
                    overflow: "hidden",
                    whiteSpace: "nowrap",
                    width: `${karaokeProgress * 100}%`,
                  }}
                >
                  {caption.text}
                </span>
              </span>
            ) : (
              caption.text
            )}
          </div>
        );
      })}
    </>
  );
};

