import { useState, useEffect, useCallback } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useRoute, useLocation } from "wouter";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { Progress } from "@/components/ui/progress";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  ArrowLeft,
  Download,
  Play,
  Loader2,
  Film,
  Palette,
  Type,
  Sparkles,
  CheckCircle2,
  AlertCircle,
  RefreshCw,
} from "lucide-react";
import { apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";

const COLOR_PRESETS = [
  { value: "none", label: "None" },
  { value: "warm", label: "Warm" },
  { value: "cool", label: "Cool" },
  { value: "vintage", label: "Vintage" },
  { value: "noir", label: "Noir" },
  { value: "vivid", label: "Vivid" },
];

const CAPTION_ANIMATIONS = [
  { value: "none", label: "None" },
  { value: "pop-in", label: "Pop In" },
  { value: "karaoke", label: "Karaoke" },
  { value: "fade-in", label: "Fade In" },
  { value: "typewriter", label: "Typewriter" },
];

const TRANSITION_TYPES = [
  { value: "cut", label: "Cut" },
  { value: "crossfade", label: "Crossfade" },
  { value: "blur-dissolve", label: "Blur Dissolve" },
];

const ASPECT_RATIOS = [
  { value: "9:16", label: "Vertical (9:16)" },
  { value: "1:1", label: "Square (1:1)" },
  { value: "16:9", label: "Landscape (16:9)" },
];

interface RenderJobStatus {
  id: string;
  status: "queued" | "rendering" | "completed" | "failed";
  progress: number;
  videoId: string;
  createdAt: string;
  completedAt?: string;
  downloadUrl?: string;
  error?: string;
}

export default function PreviewEdit() {
  const [, params] = useRoute("/preview/:videoId");
  const [, setLocation] = useLocation();
  const videoId = params?.videoId;
  const { toast } = useToast();

  const [colorPreset, setColorPreset] = useState("none");
  const [captionAnimation, setCaptionAnimation] = useState("pop-in");
  const [transitionType, setTransitionType] = useState("crossfade");
  const [aspectRatio, setAspectRatio] = useState("9:16");
  const [activeJobId, setActiveJobId] = useState<string | null>(null);
  const [isPolling, setIsPolling] = useState(false);

  const { data: video, isLoading: videoLoading } = useQuery({
    queryKey: ["/api/videos", videoId],
    enabled: !!videoId,
  });

  const { data: jobStatus, refetch: refetchJob } = useQuery<RenderJobStatus>({
    queryKey: ["/api/render/jobs", activeJobId],
    enabled: !!activeJobId && isPolling,
    refetchInterval: isPolling ? 2000 : false,
  });

  useEffect(() => {
    if (jobStatus?.status === "completed" || jobStatus?.status === "failed") {
      setIsPolling(false);
      if (jobStatus.status === "completed") {
        toast({
          title: "Export Complete",
          description: "Your video is ready for download.",
        });
      } else if (jobStatus.status === "failed") {
        toast({
          title: "Export Failed",
          description: jobStatus.error || "Something went wrong during rendering.",
          variant: "destructive",
        });
      }
    }
  }, [jobStatus?.status]);

  const enqueueRender = useMutation({
    mutationFn: async (watermark: boolean) => {
      const res = await apiRequest("POST", "/api/render/enqueue", {
        videoId,
        watermark,
        edl: (video as any)?.edlJson || null,
        style: {
          colorPreset,
          captionAnimation,
          transitionType,
          aspectRatio,
        },
      });
      return res.json();
    },
    onSuccess: (data: { jobId: string }) => {
      setActiveJobId(data.jobId);
      setIsPolling(true);
      toast({
        title: "Render Started",
        description: "Your video is being processed. This may take a moment.",
      });
    },
    onError: () => {
      toast({
        title: "Failed to start render",
        description: "Please try again.",
        variant: "destructive",
      });
    },
  });

  const handleExport = useCallback(
    (watermark: boolean) => {
      enqueueRender.mutate(watermark);
    },
    [enqueueRender]
  );

  const handleDownload = useCallback(() => {
    if (jobStatus?.downloadUrl) {
      const a = document.createElement("a");
      a.href = jobStatus.downloadUrl;
      a.download = `navinta-${videoId}.mp4`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
    }
  }, [jobStatus?.downloadUrl, videoId]);

  if (videoLoading) {
    return (
      <div className="min-h-screen bg-white p-6">
        <div className="max-w-6xl mx-auto">
          <Skeleton className="h-10 w-48 mb-6 bg-gray-100" />
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            <Skeleton className="h-[600px] col-span-2 bg-gray-100 rounded-3xl" />
            <Skeleton className="h-[600px] bg-gray-100 rounded-3xl" />
          </div>
        </div>
      </div>
    );
  }

  const isRenderActive =
    activeJobId && (jobStatus?.status === "queued" || jobStatus?.status === "rendering");

  return (
    <div className="min-h-screen bg-white text-[#111111]">
      <div className="max-w-6xl mx-auto p-6">
        <div className="flex items-center gap-4 mb-6">
          <Button
            variant="ghost"
            size="icon"
            onClick={() => setLocation("/library")}
            className="text-[#666666] hover:text-[#111111] hover:bg-gray-50 rounded-full"
          >
            <ArrowLeft className="h-5 w-5" />
          </Button>
          <div>
            <h1 className="text-xl font-semibold text-[#111111]">
              {(video as any)?.title || "Preview & Export"}
            </h1>
            <p className="text-sm text-[#666666]">
              Adjust style settings and export your video
            </p>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          <div className="lg:col-span-2">
            <Card className="bg-white border border-gray-200 rounded-3xl overflow-hidden">
              <div
                className="relative w-full bg-gray-50 flex items-center justify-center"
                style={{
                  aspectRatio: aspectRatio === "9:16" ? "9/16" : aspectRatio === "1:1" ? "1/1" : "16/9",
                  maxHeight: "65vh",
                }}
              >
                {(video as any)?.thumbnail ? (
                  <img
                    src={(video as any).thumbnail}
                    alt="Video preview"
                    className="max-w-full max-h-full object-contain"
                  />
                ) : (
                  <div className="flex flex-col items-center gap-3 text-[#666666]">
                    <Film className="h-16 w-16" />
                    <p className="text-sm">Preview will appear here after rendering</p>
                  </div>
                )}

                <div className="absolute bottom-4 left-4 right-4 flex items-center gap-2">
                  <Button
                    size="sm"
                    variant="secondary"
                    className="bg-white/80 hover:bg-white text-[#111111] backdrop-blur-sm rounded-full"
                    disabled
                  >
                    <Play className="h-4 w-4 mr-1" />
                    Preview
                  </Button>
                </div>
              </div>
            </Card>

            {isRenderActive && (
              <Card className="mt-4 bg-white border border-gray-200 rounded-3xl">
                <CardContent className="p-4">
                  <div className="flex items-center gap-3 mb-3">
                    <Loader2 className="h-5 w-5 animate-spin text-blue-500" />
                    <span className="text-sm font-medium text-[#111111]">
                      {jobStatus?.status === "queued"
                        ? "Queued - Waiting to start..."
                        : `Rendering... ${jobStatus?.progress || 0}%`}
                    </span>
                  </div>
                  <Progress
                    value={jobStatus?.progress || 0}
                    className="h-2 bg-gray-100"
                  />
                </CardContent>
              </Card>
            )}

            {jobStatus?.status === "completed" && (
              <Card className="mt-4 bg-white border border-green-200 rounded-3xl">
                <CardContent className="p-4">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                      <CheckCircle2 className="h-5 w-5 text-green-500" />
                      <span className="text-sm font-medium text-green-700">
                        Export complete
                      </span>
                    </div>
                    <Button
                      size="sm"
                      onClick={handleDownload}
                      className="bg-green-600 hover:bg-green-700 text-white rounded-full"
                    >
                      <Download className="h-4 w-4 mr-1" />
                      Download MP4
                    </Button>
                  </div>
                </CardContent>
              </Card>
            )}

            {jobStatus?.status === "failed" && (
              <Card className="mt-4 bg-white border border-red-200 rounded-3xl">
                <CardContent className="p-4">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                      <AlertCircle className="h-5 w-5 text-red-500" />
                      <div>
                        <span className="text-sm font-medium text-red-700">
                          Render failed
                        </span>
                        <p className="text-xs text-red-500 mt-0.5">
                          {jobStatus.error}
                        </p>
                      </div>
                    </div>
                    <Button
                      size="sm"
                      variant="outline"
                      onClick={() => handleExport(true)}
                      className="border-red-200 text-red-600 hover:bg-red-50 rounded-full"
                    >
                      <RefreshCw className="h-4 w-4 mr-1" />
                      Retry
                    </Button>
                  </div>
                </CardContent>
              </Card>
            )}
          </div>

          <div className="space-y-4">
            <Card className="bg-white border border-gray-200 rounded-3xl">
              <CardHeader className="pb-3">
                <CardTitle className="text-sm font-medium flex items-center gap-2 text-[#111111]">
                  <Palette className="h-4 w-4 text-blue-500" />
                  Style Settings
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div>
                  <Label className="text-xs text-[#666666] mb-1.5 block">
                    Aspect Ratio
                  </Label>
